async function loadCampaignFollowerCountMap(campaignIds: string[]) {
  if (!db || campaignIds.length === 0) return new Map<string, number>();

  const rows = await db
    .select({
      campaignId: creatorCampaignFollows.campaignId,
      count: sql<number>`count(*)::int`,
    })
    .from(creatorCampaignFollows)
    .where(inArray(creatorCampaignFollows.campaignId, campaignIds))
    .groupBy(creatorCampaignFollows.campaignId);

  return new Map(rows.map((row) => [row.campaignId, Number(row.count ?? 0)]));
}

function canViewerSeeCreatorPost(input: {
  post: Pick<CreatorPostRecord, "creatorUserId" | "visibility">;
  viewerId?: string | null;
  followedCreatorIds?: Set<string>;
  memberCreatorIds?: Set<string>;
}) {
  const { post, viewerId, followedCreatorIds = new Set<string>(), memberCreatorIds = new Set<string>() } = input;
  if (viewerId && post.creatorUserId === viewerId) return true;
  if (post.visibility === "public") return true;
  if (!viewerId) return false;
  if (post.visibility === "followers") return followedCreatorIds.has(post.creatorUserId);
  if (post.visibility === "members") return memberCreatorIds.has(post.creatorUserId);
  return false;
}

function creatorPostAudienceLabel(post: Pick<CreatorPostRecord, "creatorUserId" | "visibility">, viewerId?: string | null) {
  if (viewerId && post.creatorUserId === viewerId) return "You";
  if (post.visibility === "members") return "Members";
  if (post.visibility === "followers") return "Followers";
  return "Public";
}

function creatorDropSortTime(drop: Pick<CreatorDropRecord, "scheduledFor">) {
  return drop.scheduledFor.getTime();
}

function getCreatorDropStatus(drop: Pick<CreatorDropRecord, "isPublished" | "scheduledFor">, now = new Date()): CreatorDropStatus {
  const scheduledTime = creatorDropSortTime(drop);
  const nowTime = now.getTime();

  if (!drop.isPublished || scheduledTime > nowTime) return "upcoming";
  if (scheduledTime <= nowTime - CREATOR_DROP_ARCHIVE_WINDOW_MS) return "archived";
  return "live";
}

function isCreatorDropVisibleForLifecycle(drop: Pick<CreatorDropRecord, "isPublished" | "scheduledFor">, options: {
  now?: Date;
  includeArchived?: boolean;
} = {}) {
  if (!drop.isPublished) return false;
  const status = getCreatorDropStatus(drop, options.now);
  return options.includeArchived ? true : status !== "archived";
}

function canViewerSeeCreatorDrop(input: {
  drop: Pick<CreatorDropRecord, "creatorUserId" | "visibility" | "isPublished" | "scheduledFor">;
  viewerId?: string | null;
  followedCreatorIds?: Set<string>;
  memberCreatorIds?: Set<string>;
  includeArchived?: boolean;
  now?: Date;
}) {
  const {
    drop,
    viewerId,
    followedCreatorIds = new Set<string>(),
    memberCreatorIds = new Set<string>(),
    includeArchived = false,
    now,
  } = input;
  if (viewerId && drop.creatorUserId === viewerId) return true;
  if (!isCreatorDropVisibleForLifecycle(drop, { now, includeArchived })) return false;
  if (drop.visibility === "public") return true;
  if (!viewerId) return false;
  if (drop.visibility === "followers") return followedCreatorIds.has(drop.creatorUserId);
  if (drop.visibility === "members") return memberCreatorIds.has(drop.creatorUserId);
  return false;
}

function creatorDropAudienceLabel(drop: Pick<CreatorDropRecord, "creatorUserId" | "visibility">, viewerId?: string | null) {
  if (viewerId && drop.creatorUserId === viewerId) return "You";
  if (drop.visibility === "members") return "Members";
  if (drop.visibility === "followers") return "Followers";
  return "Public";
}

async function loadCreatorDropForViewer(dropId: string, viewerId?: string | null) {
  if (!db || !dropId) return null;

  const rows = await db
    .select()
    .from(creatorDrops)
    .where(eq(creatorDrops.id, dropId))
    .limit(1);

  const drop = rows[0];
  if (!drop) return null;

  const [followedCreatorIds, memberCreatorIds] = await Promise.all([
    loadFollowedCreatorIdsForUser(viewerId),
    loadActiveMembershipCreatorIdsForUser(viewerId),
  ]);

  const isCreator = Boolean(viewerId && drop.creatorUserId === viewerId);
  const canView = canViewerSeeCreatorDrop({
    drop,
    viewerId,
    followedCreatorIds,
    memberCreatorIds,
    includeArchived: true,
  });

  if (!isCreator && !canView) return null;

  return {
    drop,
    viewerId: viewerId ?? null,
    isCreator,
    followedCreatorIds,
    memberCreatorIds,
  };
}

function canViewerSeeCreatorRoadmapItem(input: {
  item: Pick<CreatorRoadmapRecord, "creatorUserId" | "visibility">;
  viewerId?: string | null;
  followedCreatorIds?: Set<string>;
  memberCreatorIds?: Set<string>;
}) {
  const { item, viewerId, followedCreatorIds = new Set<string>(), memberCreatorIds = new Set<string>() } = input;
  if (viewerId && item.creatorUserId === viewerId) return true;
  if (item.visibility === "public") return true;
  if (!viewerId) return false;
  if (item.visibility === "followers") return followedCreatorIds.has(item.creatorUserId);
  if (item.visibility === "members") return memberCreatorIds.has(item.creatorUserId);
  return false;
}

function canViewerSeeCreatorCampaign(input: {
  campaign: Pick<CreatorCampaignRecord, "creatorUserId" | "visibility" | "startsAt" | "endsAt" | "isActive" | "createdAt" | "rolloutMode" | "startsWithAudience" | "unlockFollowersAt" | "unlockPublicAt" | "rolloutNotes" | "isRolloutActive" | "isRolloutPaused" | "rolloutPausedAt">;
  viewerId?: string | null;
  followedCreatorIds?: Set<string>;
  memberCreatorIds?: Set<string>;
}) {
  const { campaign, viewerId, followedCreatorIds = new Set<string>(), memberCreatorIds = new Set<string>() } = input;
  if (viewerId && campaign.creatorUserId === viewerId) return true;
  const rollout = deriveCreatorCampaignRollout(campaign);
  if (rollout.currentAudience === "public") return true;
  if (!viewerId) return false;
  if (rollout.currentAudience === "followers") {
    return followedCreatorIds.has(campaign.creatorUserId) || memberCreatorIds.has(campaign.creatorUserId);
  }
  if (rollout.currentAudience === "members") return memberCreatorIds.has(campaign.creatorUserId);
  return false;
}

function creatorCampaignAudienceLabel(campaign: Pick<CreatorCampaignRecord, "creatorUserId" | "visibility">, viewerId?: string | null) {
  if (viewerId && campaign.creatorUserId === viewerId) return "You";
  if (campaign.visibility === "members") return "Members";
  if (campaign.visibility === "followers") return "Followers";
  return "Public";
}

function getCreatorCampaignState(campaign: Pick<CreatorCampaignRecord, "startsAt" | "endsAt" | "isActive">, now = new Date()): CreatorCampaignState {
  if (!campaign.isActive) {
    if (campaign.startsAt && campaign.startsAt > now) return "upcoming";
    return "past";
  }
  if (campaign.startsAt && campaign.startsAt > now) return "upcoming";
  if (campaign.endsAt && campaign.endsAt < now) return "past";
  return "active";
}

function rolloutAudienceOrder(audience: CreatorCampaignRolloutAudience) {
  switch (audience) {
    case "members":
      return 0;
    case "followers":
      return 1;
    case "public":
    default:
      return 2;
  }
}

function clampRolloutAudienceToVisibility(
  audience: CreatorCampaignRolloutAudience,
  visibility: CreatorCampaignVisibility,
): CreatorCampaignRolloutAudience {
  if (visibility === "members") return "members";
  if (visibility === "followers" && audience === "public") return "followers";
  return audience;
}

function defaultStartsWithAudienceForRollout(
  mode: CreatorCampaignRolloutMode,
  visibility: CreatorCampaignVisibility,
): CreatorCampaignRolloutAudience {
  const requested = mode === "members_first"
    ? "members"
    : mode === "followers_first"
      ? "followers"
      : mode === "public_first"
        ? "public"
        : visibility === "members"
          ? "members"
          : visibility === "followers"
            ? "followers"
            : "members";
  return clampRolloutAudienceToVisibility(requested, visibility);
}

function audienceUnlockStatePrefix(isScheduled: boolean, audience: CreatorCampaignRolloutAudience): CreatorCampaignRolloutState {
  if (isScheduled) {
    if (audience === "members") return "scheduled_for_members";
    if (audience === "followers") return "scheduled_for_followers";
    return "scheduled_for_public";
  }
  if (audience === "members") return "live_for_members";
  if (audience === "followers") return "live_for_followers";
  return "live_for_public";
}

function deriveCreatorCampaignRollout(
  campaign: Pick<CreatorCampaignRecord, "visibility" | "startsAt" | "endsAt" | "isActive" | "createdAt" | "rolloutMode" | "startsWithAudience" | "unlockFollowersAt" | "unlockPublicAt" | "rolloutNotes" | "isRolloutActive" | "isRolloutPaused" | "rolloutPausedAt">,
  now = new Date(),
) {
  const campaignState = getCreatorCampaignState(campaign, now);
  const visibility = campaign.visibility as CreatorCampaignVisibility;
  const rolloutMode = (campaign.rolloutMode as CreatorCampaignRolloutMode | null) ?? "public_first";
  const normalizedStoredStartsWithAudience = normalizeCreatorCampaignRolloutAudience(campaign.startsWithAudience);
  const initialAudience = clampRolloutAudienceToVisibility(
    ((rolloutMode === "staged"
      ? normalizedStoredStartsWithAudience
      : defaultStartsWithAudienceForRollout(rolloutMode, visibility))
      ?? defaultStartsWithAudienceForRollout(rolloutMode, visibility)),
    visibility,
  );
  const finalAudience = clampRolloutAudienceToVisibility("public", visibility);
  const startsAt = campaign.startsAt ?? campaign.createdAt ?? null;
  const followerUnlockAt = campaign.unlockFollowersAt ?? null;
  const publicUnlockAt = campaign.unlockPublicAt ?? null;
  const rolloutActive = Boolean(campaign.isRolloutActive);
  const isRolloutPaused = Boolean(campaign.isRolloutPaused);
  const pausedAt = campaign.rolloutPausedAt ?? null;
  const progressionNow = isRolloutPaused && pausedAt ? pausedAt : now;

  const stageTimeline = [{ audience: initialAudience, unlockAt: startsAt }];
  if (rolloutActive && rolloutAudienceOrder(initialAudience) < rolloutAudienceOrder("followers") && visibility !== "members" && followerUnlockAt) {
    stageTimeline.push({ audience: "followers" as const, unlockAt: followerUnlockAt });
  }
  if (rolloutActive && rolloutAudienceOrder(initialAudience) < rolloutAudienceOrder("public") && visibility === "public" && publicUnlockAt) {
    stageTimeline.push({ audience: "public" as const, unlockAt: publicUnlockAt });
  }

  const normalizedTimeline = stageTimeline
    .map((entry) => ({
      audience: clampRolloutAudienceToVisibility(entry.audience, visibility),
      unlockAt: entry.unlockAt,
    }))
    .sort((a, b) => {
      const timeA = a.unlockAt?.getTime() ?? 0;
      const timeB = b.unlockAt?.getTime() ?? 0;
      return timeA - timeB || rolloutAudienceOrder(a.audience) - rolloutAudienceOrder(b.audience);
    })
    .filter((entry, index, array) => index === 0 || array[index - 1]?.audience !== entry.audience);

  const effectiveTimeline = rolloutActive
    ? normalizedTimeline
    : [{ audience: finalAudience, unlockAt: startsAt }];

  let currentAudience = rolloutActive ? initialAudience : finalAudience;
  let nextUnlockAt: Date | null = null;
  let nextAudience: CreatorCampaignRolloutAudience | null = null;

  if (campaignState !== "past") {
    for (let index = 0; index < effectiveTimeline.length; index += 1) {
      const entry = effectiveTimeline[index];
      if (!entry) continue;
      const unlockAt = entry.unlockAt;
      if (unlockAt && unlockAt > progressionNow) {
        currentAudience = effectiveTimeline[Math.max(0, index - 1)]?.audience ?? entry.audience;
        nextUnlockAt = unlockAt;
        nextAudience = entry.audience;
        break;
      }
      currentAudience = entry.audience;
    }
  }

  if (campaignState === "past") {
    currentAudience = finalAudience;
  }

  const isScheduled = Boolean(startsAt && startsAt > progressionNow);
  const reachedFinalAudience = currentAudience === finalAudience;
  const state: CreatorCampaignRolloutState = campaignState === "past"
    ? "completed"
    : reachedFinalAudience && rolloutActive && finalAudience === "public" && initialAudience !== "public"
      ? "fully_open"
      : reachedFinalAudience && rolloutActive && finalAudience !== "public" && initialAudience !== finalAudience
        ? "fully_open"
        : audienceUnlockStatePrefix(isScheduled, currentAudience);

  return {
    rolloutMode,
    startsWithAudience: initialAudience,
    finalAudience,
    currentAudience,
    nextAudience,
    nextUnlockAt: nextUnlockAt ? nextUnlockAt.toISOString() : null,
    unlockFollowersAt: followerUnlockAt ? followerUnlockAt.toISOString() : null,
    unlockPublicAt: publicUnlockAt ? publicUnlockAt.toISOString() : null,
    rolloutNotes: campaign.rolloutNotes?.trim() ? campaign.rolloutNotes.trim() : null,
    isRolloutActive: rolloutActive,
    isRolloutPaused,
    pausedAt: pausedAt ? pausedAt.toISOString() : null,
    state,
    timeline: effectiveTimeline.map((entry) => ({
      audience: entry.audience,
      unlockAt: entry.unlockAt ? entry.unlockAt.toISOString() : null,
      isCurrent: entry.audience === currentAudience,
    })),
  };
}

function buildCampaignRolloutSuggestion(input: {
  campaign: Pick<CreatorCampaignRecord, "visibility">;
  audienceFit?: {
    bestAudienceFit: CreatorCampaignRolloutAudience | null;
    bestAudienceFitConfidence: CreatorCampaignAudienceFitConfidence;
    bestAudienceFitReason: string | null;
  } | null;
}) {
  const visibility = input.campaign.visibility as CreatorCampaignVisibility;
  const suggestedMode = visibility === "members"
    ? "members_first"
    : input.audienceFit?.bestAudienceFit === "members"
      ? "members_first"
      : input.audienceFit?.bestAudienceFit === "followers"
        ? "followers_first"
        : "public_first";

  const note = visibility === "members"
    ? "This campaign can only ever open to active members, so a member-first rollout is the clearest fit."
    : visibility === "followers"
      ? "Followers are the widest audience this campaign can ever reach, so keep rollout steps inside follower/member access."
      : input.audienceFit?.bestAudienceFit === "members"
        ? "Audience-fit signals lean member-driven, so starting with members should keep the launch focused."
        : input.audienceFit?.bestAudienceFit === "followers"
          ? "Audience-fit signals lean follower-heavy, so a follower-first rollout is a good lightweight default."
          : "This campaign looks broad enough for public reach, so a public-first rollout is the simplest fit.";

  return {
    suggestedMode,
    reason: input.audienceFit?.bestAudienceFitReason ?? note,
    confidence: input.audienceFit?.bestAudienceFitConfidence ?? "none",
  };
}

function normalizeCampaignRolloutUpdate(input: {
  campaign: Pick<CreatorCampaignRecord, "visibility" | "startsAt" | "rolloutMode" | "startsWithAudience" | "unlockFollowersAt" | "unlockPublicAt" | "rolloutNotes" | "isRolloutActive" | "isRolloutPaused" | "rolloutPausedAt">;
  payload: Partial<{
    rolloutMode: CreatorCampaignRolloutMode;
    startsWithAudience: CreatorCampaignRolloutAudience | null;
    unlockFollowersAt: string | null;
    unlockPublicAt: string | null;
    rolloutNotes: string | null;
    isRolloutActive: boolean;
  }>;
}) {
  const visibility = input.campaign.visibility as CreatorCampaignVisibility;
  const rolloutMode = input.payload.rolloutMode ?? (input.campaign.rolloutMode as CreatorCampaignRolloutMode | null) ?? "public_first";
  const normalizedStoredStartsWithAudience = normalizeCreatorCampaignRolloutAudience(input.campaign.startsWithAudience);
  const startsWithAudience = clampRolloutAudienceToVisibility(
    (input.payload.startsWithAudience ?? normalizedStoredStartsWithAudience ?? defaultStartsWithAudienceForRollout(rolloutMode, visibility)),
    visibility,
  );
  const unlockFollowersAt = visibility === "members"
    ? null
    : input.payload.unlockFollowersAt !== undefined
      ? toNullableDate(input.payload.unlockFollowersAt)
      : input.campaign.unlockFollowersAt;
  const unlockPublicAt = visibility !== "public"
    ? null
    : input.payload.unlockPublicAt !== undefined
      ? toNullableDate(input.payload.unlockPublicAt)
      : input.campaign.unlockPublicAt;

  const isRolloutActive = input.payload.isRolloutActive ?? input.campaign.isRolloutActive;

  return {
    rolloutMode,
    startsWithAudience,
    unlockFollowersAt,
    unlockPublicAt,
    rolloutNotes: input.payload.rolloutNotes !== undefined
      ? (input.payload.rolloutNotes?.trim() ? input.payload.rolloutNotes.trim() : null)
      : (input.campaign.rolloutNotes?.trim() ? input.campaign.rolloutNotes.trim() : null),
    isRolloutActive,
    isRolloutPaused: isRolloutActive ? input.campaign.isRolloutPaused : false,
    rolloutPausedAt: isRolloutActive ? (input.campaign.rolloutPausedAt ?? null) : null,
  };
}

function getNextRolloutUnlockField(
  campaign: Pick<CreatorCampaignRecord, "visibility" | "startsAt" | "endsAt" | "isActive" | "createdAt" | "rolloutMode" | "startsWithAudience" | "unlockFollowersAt" | "unlockPublicAt" | "rolloutNotes" | "isRolloutActive" | "isRolloutPaused" | "rolloutPausedAt">,
  now = new Date(),
) {
  const rollout = deriveCreatorCampaignRollout(campaign, now);
  if (!rollout.isRolloutActive || !rollout.nextAudience) {
    return { rollout, field: null as const };
  }
  if (rollout.nextAudience === "followers") {
    return { rollout, field: "unlockFollowersAt" as const };
  }
  if (rollout.nextAudience === "public") {
    return { rollout, field: "unlockPublicAt" as const };
  }
  return { rollout, field: null as const };
}

function assertCampaignSupportsUnlockControls(
  campaign: Pick<CreatorCampaignRecord, "visibility" | "startsAt" | "endsAt" | "isActive" | "createdAt" | "rolloutMode" | "startsWithAudience" | "unlockFollowersAt" | "unlockPublicAt" | "rolloutNotes" | "isRolloutActive" | "isRolloutPaused" | "rolloutPausedAt">,
  action: CreatorCampaignUnlockControlAction,
  now = new Date(),
) {
  const { rollout, field } = getNextRolloutUnlockField(campaign, now);
  if (!rollout.isRolloutActive) {
    throw new Error("Unlock controls only apply to campaigns using rollout sequencing.");
  }
  if (action === "pause" || action === "resume") {
    return { rollout, field };
  }
  if (!field || !rollout.nextAudience) {
    throw new Error("No follower/public unlock is available for control right now.");
  }
  return { rollout, field };
}

function shiftCampaignUnlocksForResume(
  campaign: Pick<CreatorCampaignRecord, "visibility" | "startsAt" | "endsAt" | "isActive" | "createdAt" | "rolloutMode" | "startsWithAudience" | "unlockFollowersAt" | "unlockPublicAt" | "rolloutNotes" | "isRolloutActive" | "isRolloutPaused" | "rolloutPausedAt">,
  resumedAt: Date,
) {
  if (!campaign.isRolloutPaused || !campaign.rolloutPausedAt) {
    return {
      unlockFollowersAt: campaign.unlockFollowersAt ?? null,
      unlockPublicAt: campaign.unlockPublicAt ?? null,
    };
  }

  const pausedAt = campaign.rolloutPausedAt;
  const pauseDurationMs = Math.max(0, resumedAt.getTime() - pausedAt.getTime());
  if (!pauseDurationMs) {
    return {
      unlockFollowersAt: campaign.unlockFollowersAt ?? null,
      unlockPublicAt: campaign.unlockPublicAt ?? null,
    };
  }

  const { rollout, field } = getNextRolloutUnlockField(campaign, pausedAt);
  if (!rollout.nextAudience || !field) {
    return {
      unlockFollowersAt: campaign.unlockFollowersAt ?? null,
      unlockPublicAt: campaign.unlockPublicAt ?? null,
    };
  }

  const shiftedFollowersAt = campaign.unlockFollowersAt
    ? new Date(campaign.unlockFollowersAt.getTime() + (field === "unlockFollowersAt" ? pauseDurationMs : 0))
    : null;
  const shiftedPublicAt = campaign.unlockPublicAt
    ? new Date(campaign.unlockPublicAt.getTime() + pauseDurationMs)
    : null;

  return {
    unlockFollowersAt: shiftedFollowersAt,
    unlockPublicAt: shiftedPublicAt,
  };
}

function formatCampaignRolloutResponse(
  campaign: Pick<CreatorCampaignRecord, "id" | "visibility" | "startsAt" | "endsAt" | "isActive" | "createdAt" | "rolloutMode" | "startsWithAudience" | "unlockFollowersAt" | "unlockPublicAt" | "rolloutNotes" | "isRolloutActive" | "isRolloutPaused" | "rolloutPausedAt">,
  audienceFitItem?: {
    bestAudienceFit: CreatorCampaignRolloutAudience | null;
    bestAudienceFitConfidence: CreatorCampaignAudienceFitConfidence;
    bestAudienceFitReason: string | null;
  } | null,
) {
  const rollout = deriveCreatorCampaignRollout(campaign);
  return {
    ok: true,
    campaignId: campaign.id,
    rollout: {
      rolloutMode: rollout.rolloutMode,
      startsWithAudience: rollout.startsWithAudience,
      unlockFollowersAt: rollout.unlockFollowersAt,
      unlockPublicAt: rollout.unlockPublicAt,
      rolloutNotes: rollout.rolloutNotes,
      isRolloutActive: rollout.isRolloutActive,
      isRolloutPaused: rollout.isRolloutPaused,
      pausedAt: rollout.pausedAt,
    },
    derivedState: rollout,
    audienceFitSuggestion: buildCampaignRolloutSuggestion({
      campaign,
      audienceFit: audienceFitItem
        ? {
          bestAudienceFit: audienceFitItem.bestAudienceFit,
          bestAudienceFitConfidence: audienceFitItem.bestAudienceFitConfidence,
          bestAudienceFitReason: audienceFitItem.bestAudienceFitReason,
        }
        : null,
    }),
  };
}

function serializeCreatorCampaign(
  campaign: CreatorCampaignRecord,
  options: {
    viewerId?: string | null;
    creator?: { id: string; username: string | null; avatar: string | null } | null;
    counts?: Partial<Record<CreatorCampaignTargetType, number>>;
    followerCount?: number;
    isFollowing?: boolean;
  } = {},
) {
  const counts = options.counts ?? {};
  const isOwner = Boolean(options.viewerId && campaign.creatorUserId === options.viewerId);
  const rollout = deriveCreatorCampaignRollout(campaign);
  return {
    id: campaign.id,
    creatorUserId: campaign.creatorUserId,
    slug: campaign.slug,
    name: campaign.name,
    description: campaign.description ?? null,
    visibility: campaign.visibility as CreatorCampaignVisibility,
    audienceLabel: creatorCampaignAudienceLabel(campaign, options.viewerId),
    startsAt: campaign.startsAt ? campaign.startsAt.toISOString() : null,
    endsAt: campaign.endsAt ? campaign.endsAt.toISOString() : null,
    isActive: Boolean(campaign.isActive),
    isPinned: Boolean(campaign.isPinned),
    state: getCreatorCampaignState(campaign),
    rollout: rollout ?? undefined,
    route: `/drinks/campaigns/${encodeURIComponent(campaign.slug)}`,
    followerCount: Number(options.followerCount ?? 0),
    isFollowing: Boolean(options.isFollowing),
    isOwner,
    canFollow: Boolean(options.viewerId && !isOwner),
    counts: {
      collections: Number(counts.collection ?? 0),
      drops: Number(counts.drop ?? 0),
      promos: Number(counts.promo ?? 0),
      challenges: Number(counts.challenge ?? 0),
      posts: Number(counts.post ?? 0),
      roadmap: Number(counts.roadmap ?? 0),
      total: Number(
        (counts.collection ?? 0)
        + (counts.drop ?? 0)
        + (counts.promo ?? 0)
        + (counts.challenge ?? 0)
        + (counts.post ?? 0)
        + (counts.roadmap ?? 0)
      ),
    },
    createdAt: campaign.createdAt.toISOString(),
    updatedAt: campaign.updatedAt.toISOString(),
    creator: options.creator
      ? {
        userId: options.creator.id,
        username: options.creator.username ?? null,
        avatar: options.creator.avatar ?? null,
        route: `/drinks/creator/${encodeURIComponent(options.creator.id)}`,
      }
      : null,
  };
}

async function loadPinnedCampaignForCreator(creatorUserId: string) {
  if (!db || !creatorUserId) return null;

  const rows = await db
    .select()
    .from(creatorCampaigns)
    .where(and(eq(creatorCampaigns.creatorUserId, creatorUserId), eq(creatorCampaigns.isPinned, true)))
    .limit(1);

  return rows[0] ?? null;
}

async function setPinnedCampaignForCreator(creatorUserId: string, campaignId: string) {
  if (!db) throw new Error("Database unavailable");

  await db.transaction(async (tx) => {
    await tx
      .update(creatorCampaigns)
      .set({ isPinned: false, updatedAt: new Date() })
      .where(and(eq(creatorCampaigns.creatorUserId, creatorUserId), eq(creatorCampaigns.isPinned, true)));

    await tx
      .update(creatorCampaigns)
      .set({ isPinned: true, updatedAt: new Date() })
      .where(and(eq(creatorCampaigns.id, campaignId), eq(creatorCampaigns.creatorUserId, creatorUserId)));
  });

  return loadCampaignForOwnerOrThrow(campaignId, creatorUserId);
}

async function clearPinnedCampaignForCreator(creatorUserId: string, campaignId?: string | null) {
  if (!db) throw new Error("Database unavailable");

  const conditions = [eq(creatorCampaigns.creatorUserId, creatorUserId), eq(creatorCampaigns.isPinned, true)];
  if (campaignId) {
    conditions.push(eq(creatorCampaigns.id, campaignId));
  }

  const rows = await db
    .update(creatorCampaigns)
    .set({ isPinned: false, updatedAt: new Date() })
    .where(and(...conditions))
    .returning();

  return rows[0] ?? null;
}

async function loadCreatorCampaignLinksByCampaignIds(campaignIds: string[]) {
  if (!db || campaignIds.length === 0) return new Map<string, CreatorCampaignLinkRecord[]>();
  const rows = await db
    .select()
    .from(creatorCampaignLinks)
    .where(inArray(creatorCampaignLinks.campaignId, campaignIds))
    .orderBy(asc(creatorCampaignLinks.sortOrder), asc(creatorCampaignLinks.createdAt));

  const map = new Map<string, CreatorCampaignLinkRecord[]>();
  for (const row of rows) {
    const current = map.get(row.campaignId) ?? [];
    current.push(row);
    map.set(row.campaignId, current);
  }
  return map;
}

function serializeCreatorCampaignVariant(variant: CreatorCampaignCtaVariantRecord, metrics?: {
  views?: number;
  clicks?: number;
  follows?: number;
  rsvps?: number;
  approximatePurchases?: number;
  approximateMemberships?: number;
}) {
  return {
    id: variant.id,
    campaignId: variant.campaignId,
    label: variant.label,
    headline: variant.headline ?? null,
    subheadline: variant.subheadline ?? null,
    ctaText: variant.ctaText,
    ctaTargetType: variant.ctaTargetType as CreatorCampaignCtaTargetType,
    isActive: Boolean(variant.isActive),
    createdAt: variant.createdAt.toISOString(),
    updatedAt: variant.updatedAt.toISOString(),
    metrics: {
      views: Number(metrics?.views ?? 0),
      clicks: Number(metrics?.clicks ?? 0),
      follows: Number(metrics?.follows ?? 0),
      rsvps: Number(metrics?.rsvps ?? 0),
      approximatePurchases: Number(metrics?.approximatePurchases ?? 0),
      approximateMemberships: Number(metrics?.approximateMemberships ?? 0),
    },
  };
}

function getCampaignEngagementSessionKey(req: Request) {
  const sessionId = typeof (req as Request & { sessionID?: string }).sessionID === "string"
    ? (req as Request & { sessionID?: string }).sessionID
    : null;
  const userAgent = String(req.get("user-agent") ?? "").slice(0, 80);
  const ip = String(req.ip ?? "").slice(0, 40);
  return [sessionId, ip, userAgent].filter(Boolean).join(":").slice(0, 160) || null;
}

async function loadCreatorCampaignVariantsByCampaignIds(campaignIds: string[]) {
  if (!db || campaignIds.length === 0) return new Map<string, CreatorCampaignCtaVariantRecord[]>();

  const rows = await db
    .select()
    .from(creatorCampaignCtaVariants)
    .where(inArray(creatorCampaignCtaVariants.campaignId, campaignIds))
    .orderBy(desc(creatorCampaignCtaVariants.isActive), asc(creatorCampaignCtaVariants.createdAt));

  const map = new Map<string, CreatorCampaignCtaVariantRecord[]>();
  for (const row of rows) {
    const current = map.get(row.campaignId) ?? [];
    current.push(row);
    map.set(row.campaignId, current);
  }
  return map;
}

async function trackCreatorCampaignVariantEvent(input: {
  campaignId: string;
  variantId: string;
  eventType: CreatorCampaignVariantEventType;
  userId?: string | null;
  sessionKey?: string | null;
  metadata?: typeof creatorCampaignVariantEvents.$inferInsert.metadata;
}) {
  if (!db) return;
  await db.insert(creatorCampaignVariantEvents).values(insertCreatorCampaignVariantEventSchema.parse({
    campaignId: input.campaignId,
    variantId: input.variantId,
    eventType: input.eventType,
    userId: input.userId ?? null,
    sessionKey: input.sessionKey ?? null,
    metadata: input.metadata ?? null,
  }));
}

async function trackCreatorCampaignSpotlightEvent(input: {
  campaignId: string;
  eventType: CreatorCampaignSpotlightEventType;
  surface: CreatorCampaignSpotlightSurface;
  userId?: string | null;
  sessionKey?: string | null;
  metadata?: typeof creatorCampaignSpotlightEvents.$inferInsert.metadata;
}) {
  if (!db) return;
  await db.insert(creatorCampaignSpotlightEvents).values(insertCreatorCampaignSpotlightEventSchema.parse({
    campaignId: input.campaignId,
    eventType: input.eventType,
    surface: input.surface,
    userId: input.userId ?? null,
    sessionKey: input.sessionKey ?? null,
    metadata: input.metadata ?? null,
  }));
}

function isCreatorCampaignSurface(value: string | null | undefined): value is CreatorCampaignSurface {
  return Boolean(value && CREATOR_CAMPAIGN_SURFACE_VALUES.includes(value as CreatorCampaignSurface));
}

function resolveCreatorCampaignSurface(value: string | null | undefined): CreatorCampaignSurface {
  return isCreatorCampaignSurface(value) ? value : "direct_or_unknown";
}

