async function buildCampaignTemplateBlueprint(campaign: CreatorCampaignRecord): Promise<CreatorCampaignTemplateBlueprint> {
  if (!db) throw new Error("Database unavailable");

  const [links, variants] = await Promise.all([
    db
      .select()
      .from(creatorCampaignLinks)
      .where(eq(creatorCampaignLinks.campaignId, campaign.id))
      .orderBy(asc(creatorCampaignLinks.sortOrder), asc(creatorCampaignLinks.createdAt)),
    loadCreatorCampaignVariantsByCampaignIds([campaign.id]).then((map) => map.get(campaign.id) ?? []),
  ]);

  const dropIds = links.filter((link) => link.targetType === "drop").map((link) => link.targetId);
  const postIds = links.filter((link) => link.targetType === "post").map((link) => link.targetId);
  const roadmapIds = links.filter((link) => link.targetType === "roadmap").map((link) => link.targetId);

  const [drops, posts, roadmap] = await Promise.all([
    dropIds.length ? db.select().from(creatorDrops).where(inArray(creatorDrops.id, dropIds)) : Promise.resolve([] as CreatorDropRecord[]),
    postIds.length ? db.select().from(creatorPosts).where(inArray(creatorPosts.id, postIds)) : Promise.resolve([] as CreatorPostRecord[]),
    roadmapIds.length ? db.select().from(creatorRoadmapItems).where(inArray(creatorRoadmapItems.id, roadmapIds)) : Promise.resolve([] as CreatorRoadmapRecord[]),
  ]);

  const dropMap = new Map(drops.map((item) => [item.id, item]));
  const postMap = new Map(posts.map((item) => [item.id, item]));
  const roadmapMap = new Map(roadmap.map((item) => [item.id, item]));

  return creatorCampaignTemplateBlueprintSchema.parse({
    campaign: {
      name: campaign.name,
      description: campaign.description ?? null,
      visibility: campaign.visibility,
      startsAt: campaign.startsAt ? campaign.startsAt.toISOString() : null,
      endsAt: campaign.endsAt ? campaign.endsAt.toISOString() : null,
      isActive: Boolean(campaign.isActive),
    },
    links: links.map((link) => ({
      targetType: link.targetType,
      targetId: link.targetId,
      sortOrder: Number(link.sortOrder ?? 0),
    })),
    variants: variants.map((variant) => ({
      label: variant.label,
      headline: variant.headline ?? null,
      subheadline: variant.subheadline ?? null,
      ctaText: variant.ctaText,
      ctaTargetType: variant.ctaTargetType,
      isActive: Boolean(variant.isActive),
    })),
    linkedDrafts: {
      drops: links
        .filter((link) => link.targetType === "drop")
        .map((link) => dropMap.get(link.targetId))
        .filter((item): item is CreatorDropRecord => Boolean(item))
        .map((drop) => ({
          sourceId: drop.id,
          title: drop.title,
          description: drop.description ?? null,
          dropType: drop.dropType,
          visibility: drop.visibility,
          scheduledFor: drop.scheduledFor ? drop.scheduledFor.toISOString() : null,
          linkedCollectionId: drop.linkedCollectionId ?? null,
          linkedChallengeId: drop.linkedChallengeId ?? null,
          linkedPromotionId: drop.linkedPromotionId ?? null,
          recapNotes: drop.recapNotes ?? null,
        })),
      posts: links
        .filter((link) => link.targetType === "post")
        .map((link) => postMap.get(link.targetId))
        .filter((item): item is CreatorPostRecord => Boolean(item))
        .map((post) => ({
          sourceId: post.id,
          title: post.title,
          body: post.body,
          postType: post.postType,
          visibility: post.visibility,
          linkedCollectionId: post.linkedCollectionId ?? null,
          linkedChallengeId: post.linkedChallengeId ?? null,
        })),
      roadmap: links
        .filter((link) => link.targetType === "roadmap")
        .map((link) => roadmapMap.get(link.targetId))
        .filter((item): item is CreatorRoadmapRecord => Boolean(item))
        .map((item) => ({
          sourceId: item.id,
          title: item.title,
          description: item.description ?? null,
          itemType: item.itemType,
          visibility: item.visibility,
          linkedCollectionId: item.linkedCollectionId ?? null,
          linkedChallengeId: item.linkedChallengeId ?? null,
          scheduledFor: item.scheduledFor ? item.scheduledFor.toISOString() : null,
          releasedAt: item.releasedAt ? item.releasedAt.toISOString() : null,
          status: item.status,
        })),
    },
    defaults: {
      resetDates: true,
      copyLinkedDrafts: true,
      copyCtaVariants: true,
    },
  });
}

function serializeCreatorCampaignTemplate(template: CreatorCampaignTemplateRecord) {
  const blueprint = creatorCampaignTemplateBlueprintSchema.parse(template.blueprint);
  return {
    id: template.id,
    creatorUserId: template.creatorUserId,
    sourceCampaignId: template.sourceCampaignId ?? null,
    name: template.name,
    description: template.description ?? null,
    campaignName: blueprint.campaign.name,
    campaignDescription: blueprint.campaign.description,
    visibility: blueprint.campaign.visibility,
    defaults: blueprint.defaults,
    counts: {
      linkedItems: blueprint.links.length,
      drops: blueprint.linkedDrafts.drops.length,
      posts: blueprint.linkedDrafts.posts.length,
      roadmap: blueprint.linkedDrafts.roadmap.length,
      variants: blueprint.variants.length,
    },
    createdAt: template.createdAt.toISOString(),
    updatedAt: template.updatedAt.toISOString(),
  };
}

function serializeCreatorCampaignPlaybookProfile(profile: CreatorCampaignPlaybookProfileRecord) {
  const preferredExperimentTypes = Array.isArray(profile.preferredExperimentTypes)
    ? profile.preferredExperimentTypes
        .map((value) => String(value))
        .filter((value): value is CreatorCampaignExperimentType => creatorCampaignExperimentTypeSchema.safeParse(value).success)
    : [];

  return {
    id: profile.id,
    creatorUserId: profile.creatorUserId,
    parentPlaybookProfileId: profile.parentPlaybookProfileId ?? null,
    sourceCampaignId: profile.sourceCampaignId ?? null,
    derivedFromType: (profile.derivedFromType as CreatorCampaignPlaybookDerivedFromType | null) ?? null,
    versionLabel: profile.versionLabel ?? null,
    name: profile.name,
    description: profile.description ?? null,
    visibilityStrategy: (profile.visibilityStrategy as CreatorCampaignVisibility | null) ?? null,
    rolloutMode: (profile.rolloutMode as CreatorCampaignRolloutMode) ?? "public_first",
    startsWithAudience: normalizeCreatorCampaignPlaybookProfileStartsWithAudience(profile.startsWithAudience),
    recommendedFollowerUnlockDelayHours: profile.recommendedFollowerUnlockDelayHours ?? null,
    recommendedPublicUnlockDelayHours: profile.recommendedPublicUnlockDelayHours ?? null,
    preferredCtaDirection: (profile.preferredCtaDirection as CreatorCampaignPlaybookCtaDirection | null) ?? null,
    preferredExperimentTypes,
    preferredAudienceFit: normalizeCreatorCampaignPlaybookPreferredAudienceFit(profile.preferredAudienceFit),
    notes: profile.notes ?? null,
    createdAt: profile.createdAt.toISOString(),
    updatedAt: profile.updatedAt.toISOString(),
  };
}

function inferPreferredAudienceFitFromCampaign(campaign: Pick<CreatorCampaignRecord, "visibility" | "startsWithAudience">): CreatorCampaignPlaybookPreferredAudienceFit | null {
  const candidate = normalizeCreatorCampaignPlaybookPreferredAudienceFit(campaign.startsWithAudience);
  if (candidate === "members" || candidate === "followers" || candidate === "public") return candidate;
  if (campaign.visibility === "members" || campaign.visibility === "followers" || campaign.visibility === "public") {
    return campaign.visibility as CreatorCampaignPlaybookPreferredAudienceFit;
  }
  return null;
}

const PLAYBOOK_EVOLUTION_STRATEGY_FIELDS = [
  "visibilityStrategy",
  "rolloutMode",
  "startsWithAudience",
  "recommendedFollowerUnlockDelayHours",
  "recommendedPublicUnlockDelayHours",
  "preferredCtaDirection",
  "preferredExperimentTypes",
  "preferredAudienceFit",
  "description",
  "notes",
] as const;

async function loadCreatorCampaignPlaybookLineageCollection(creatorUserId: string) {
  if (!db) throw new Error("Database unavailable");

  const profiles = await db
    .select()
    .from(creatorCampaignPlaybookProfiles)
    .where(eq(creatorCampaignPlaybookProfiles.creatorUserId, creatorUserId))
    .orderBy(desc(creatorCampaignPlaybookProfiles.updatedAt), desc(creatorCampaignPlaybookProfiles.createdAt));

  const parentIds = [...new Set(profiles.map((profile) => profile.parentPlaybookProfileId).filter((value): value is string => Boolean(value)))];
  const sourceCampaignIds = [...new Set(profiles.map((profile) => profile.sourceCampaignId).filter((value): value is string => Boolean(value)))];

  const [parents, sourceCampaigns] = await Promise.all([
    parentIds.length
      ? db
          .select({
            id: creatorCampaignPlaybookProfiles.id,
            name: creatorCampaignPlaybookProfiles.name,
            versionLabel: creatorCampaignPlaybookProfiles.versionLabel,
          })
          .from(creatorCampaignPlaybookProfiles)
          .where(and(
            eq(creatorCampaignPlaybookProfiles.creatorUserId, creatorUserId),
            inArray(creatorCampaignPlaybookProfiles.id, parentIds),
          ))
      : Promise.resolve([] as Array<{ id: string; name: string; versionLabel: string | null }>),
    sourceCampaignIds.length
      ? db
          .select({
            id: creatorCampaigns.id,
            name: creatorCampaigns.name,
            slug: creatorCampaigns.slug,
          })
          .from(creatorCampaigns)
          .where(and(
            eq(creatorCampaigns.creatorUserId, creatorUserId),
            inArray(creatorCampaigns.id, sourceCampaignIds),
          ))
      : Promise.resolve([] as Array<{ id: string; name: string; slug: string }>),
  ]);

  const parentById = new Map(parents.map((item) => [item.id, item]));
  const sourceCampaignById = new Map(sourceCampaigns.map((item) => [item.id, item]));
  const childCountByParentId = new Map<string, number>();
  for (const profile of profiles) {
    if (!profile.parentPlaybookProfileId) continue;
    childCountByParentId.set(profile.parentPlaybookProfileId, (childCountByParentId.get(profile.parentPlaybookProfileId) ?? 0) + 1);
  }

  const items = profiles.map((profile) => {
    const serialized = serializeCreatorCampaignPlaybookProfile(profile);
    const parent = profile.parentPlaybookProfileId ? parentById.get(profile.parentPlaybookProfileId) ?? null : null;
    const sourceCampaign = profile.sourceCampaignId ? sourceCampaignById.get(profile.sourceCampaignId) ?? null : null;
    const basedOnLabel = parent
      ? `Forked from ${parent.name}${parent.versionLabel ? ` (${parent.versionLabel})` : ""}`
      : sourceCampaign
        ? `Based on campaign ${sourceCampaign.name}`
        : null;

    return {
      ...serialized,
      childCount: childCountByParentId.get(profile.id) ?? 0,
      parentPlaybook: parent
        ? {
            id: parent.id,
            name: parent.name,
            versionLabel: parent.versionLabel ?? null,
          }
        : null,
      sourceCampaign: sourceCampaign
        ? {
            id: sourceCampaign.id,
            name: sourceCampaign.name,
            slug: sourceCampaign.slug,
            route: `/drinks/campaigns/${encodeURIComponent(sourceCampaign.slug)}`,
          }
        : null,
      basedOnLabel,
    };
  });

  return {
    items,
    itemById: new Map(items.map((item) => [item.id, item])),
  };
}

function roundPlaybookMetric(value: number | null | undefined, digits = 1) {
  if (typeof value !== "number" || !Number.isFinite(value)) return null;
  const factor = 10 ** digits;
  return Math.round(value * factor) / factor;
}

function playbookScorecardLabel(input: { averageOutcomeScore: number; appliedCount: number }): CreatorCampaignPlaybookScorecardLabel {
  if (input.appliedCount <= 0) return "promising";
  if (input.appliedCount === 1) {
    if (input.averageOutcomeScore >= 8) return "promising";
    if (input.averageOutcomeScore <= -6) return "weak";
    return "mixed";
  }
  if (input.averageOutcomeScore >= 12) return "strong";
  if (input.averageOutcomeScore >= 2) return "promising";
  if (input.averageOutcomeScore <= -8) return "weak";
  return "mixed";
}

function playbookOutcomeStrengthLabel(value: CreatorCampaignPlaybookScorecardLabel) {
  switch (value) {
    case "strong":
      return "Strong past results";
    case "promising":
      return "Promising, limited history";
    case "weak":
      return "Weaker past results";
    default:
      return "Mixed historical results";
  }
}


function playbookDriftSeverityLabel(value: CreatorCampaignPlaybookDriftSeverity) {
  switch (value) {
    case "aligned":
      return "Aligned";
    case "watch":
      return "Watch for drift";
    case "drifted":
      return "Drifted";
    default:
      return "Misaligned";
  }
}

function playbookDriftSeverityVariant(value: CreatorCampaignPlaybookDriftSeverity): "default" | "secondary" | "outline" | "destructive" {
  switch (value) {
    case "aligned":
      return "default";
    case "watch":
      return "secondary";
    case "drifted":
      return "outline";
    default:
      return "destructive";
  }
}

function playbookRealignActionLabel(value: CreatorCampaignPlaybookRealignAction) {
  switch (value) {
    case "realign_campaign":
      return "Realign campaign";
    case "update_playbook":
      return "Update playbook";
    default:
      return "Keep new direction";
  }
}

function formatPlaybookDelayLabel(value: number | null | undefined, fallback: string) {
  if (typeof value !== "number" || !Number.isFinite(value)) return fallback;
  if (value <= 0) return "same day";
  if (value < 24) return `${value}h`;
  if (value % 24 === 0) {
    const days = value / 24;
    return days === 1 ? "1 day" : `${days} days`;
  }
  return `${value}h`;
}

function buildCreatorCampaignPlaybookDriftSummary(input: {
  driftScore: number;
  severity: CreatorCampaignPlaybookDriftSeverity;
  mismatchCount: number;
  recommendation: CreatorCampaignPlaybookRealignAction;
}) {
  if (input.severity === "aligned") {
    return "Campaign and playbook are still directionally aligned. No major strategy realign is showing right now.";
  }
  if (input.recommendation === "realign_campaign") {
    return input.driftScore >= 60
      ? "Campaign has moved materially away from its applied playbook, so the next cleanest move is to realign the campaign before more signal drifts." 
      : "Some strategic drift is showing, and the safest next step is to realign the campaign with the original playbook.";
  }
  if (input.recommendation === "update_playbook") {
    return input.mismatchCount >= 3
      ? "The campaign is repeatedly behaving differently from the saved playbook, but the current direction still looks viable enough to consider updating the playbook." 
      : "The campaign is bending away from the saved playbook in a few places, and the new direction may be worth folding back into the playbook.";
  }
  return "The campaign has drifted from the applied playbook, but current signal suggests the newer direction is worth keeping for now.";
}

async function loadCreatorCampaignPlaybookDriftCollection(creatorUserId: string, campaignId?: string | null) {
  if (!db) throw new Error("Database unavailable");

  const campaignFilters = [
    eq(creatorCampaigns.creatorUserId, creatorUserId),
    isNotNull(creatorCampaigns.appliedPlaybookProfileId),
  ];
  if (campaignId) {
    campaignFilters.push(eq(creatorCampaigns.id, campaignId));
  }

  const campaigns = await db
    .select()
    .from(creatorCampaigns)
    .where(and(...campaignFilters))
    .orderBy(desc(creatorCampaigns.updatedAt), desc(creatorCampaigns.createdAt));

  if (!campaigns.length) {
    return {
      items: [] as Array<Record<string, unknown>>,
      summary: {
        appliedCampaignCount: 0,
        driftedCount: 0,
        misalignedCount: 0,
        recommendedRealignCount: 0,
      },
      attributionNotes: [
        "Playbook drift stays creator-private and only evaluates campaigns where a saved playbook is still explicitly applied.",
        campaignId
          ? "This campaign does not have an applied playbook right now, so there is no drift layer to compare."
          : "No creator-owned campaigns with an applied playbook were found, so there is nothing to compare yet.",
      ],
      generatedAt: new Date().toISOString(),
    };
  }

  const profileIds = [...new Set(campaigns.map((campaign) => campaign.appliedPlaybookProfileId).filter((value): value is string => Boolean(value)))];
  const campaignIds = campaigns.map((campaign) => campaign.id);

  const [profiles, audienceFit, health, readiness, outcomes, variantsMap, experimentRows] = await Promise.all([
    db
      .select()
      .from(creatorCampaignPlaybookProfiles)
      .where(and(
        eq(creatorCampaignPlaybookProfiles.creatorUserId, creatorUserId),
        inArray(creatorCampaignPlaybookProfiles.id, profileIds),
      )),
    loadCreatorCampaignAudienceFit(creatorUserId),
    loadCreatorCampaignHealth(creatorUserId),
    loadCreatorCampaignLaunchReadiness(creatorUserId),
    loadCreatorCampaignPlaybookOutcomeCollection(creatorUserId),
    loadCreatorCampaignVariantsByCampaignIds(campaignIds),
    db
      .select()
      .from(creatorCampaignExperiments)
      .where(inArray(creatorCampaignExperiments.campaignId, campaignIds))
      .orderBy(desc(creatorCampaignExperiments.updatedAt), desc(creatorCampaignExperiments.createdAt)),
  ]);

  const profileById = new Map(profiles.map((profile) => [profile.id, profile]));
  const parentProfileIds = [...new Set(profiles.map((profile) => profile.parentPlaybookProfileId).filter((value): value is string => Boolean(value)))];
  const sourceCampaignIds = [...new Set(profiles.map((profile) => profile.sourceCampaignId).filter((value): value is string => Boolean(value)))];
  const [parentProfiles, sourceCampaigns] = await Promise.all([
    parentProfileIds.length
      ? db
          .select({
            id: creatorCampaignPlaybookProfiles.id,
            name: creatorCampaignPlaybookProfiles.name,
            versionLabel: creatorCampaignPlaybookProfiles.versionLabel,
          })
          .from(creatorCampaignPlaybookProfiles)
          .where(and(
            eq(creatorCampaignPlaybookProfiles.creatorUserId, creatorUserId),
            inArray(creatorCampaignPlaybookProfiles.id, parentProfileIds),
          ))
      : Promise.resolve([] as Array<{ id: string; name: string; versionLabel: string | null }>),
    sourceCampaignIds.length
      ? db
          .select({
            id: creatorCampaigns.id,
            name: creatorCampaigns.name,
            slug: creatorCampaigns.slug,
          })
          .from(creatorCampaigns)
          .where(and(
            eq(creatorCampaigns.creatorUserId, creatorUserId),
            inArray(creatorCampaigns.id, sourceCampaignIds),
          ))
      : Promise.resolve([] as Array<{ id: string; name: string; slug: string }>),
  ]);
  const parentProfileById = new Map(parentProfiles.map((item) => [item.id, item]));
  const sourceCampaignById = new Map(sourceCampaigns.map((item) => [item.id, item]));
  const audienceFitByCampaignId = new Map(audienceFit.items.map((item) => [item.campaignId, item]));
  const healthByCampaignId = new Map(health.items.map((item) => [item.campaignId, item]));
  const readinessByCampaignId = new Map<string, Array<typeof readiness.items[number]>>();
  for (const item of readiness.items) {
    const current = readinessByCampaignId.get(item.campaignId) ?? [];
    current.push(item);
    readinessByCampaignId.set(item.campaignId, current);
  }
  const outcomeByPlaybookId = new Map(outcomes.items.map((item) => [String((item as { playbookId: string }).playbookId), item]));
  const experimentsByCampaignId = new Map<string, CreatorCampaignExperimentRecord[]>();
  for (const row of experimentRows) {
    const current = experimentsByCampaignId.get(row.campaignId) ?? [];
    current.push(row);
    experimentsByCampaignId.set(row.campaignId, current);
  }

  const items = campaigns.flatMap((campaign) => {
    const profileId = campaign.appliedPlaybookProfileId;
    if (!profileId) return [];
    const profile = profileById.get(profileId);
    if (!profile) return [];

    const serializedProfile = serializeCreatorCampaignPlaybookProfile(profile);
    const lineageParent = profile.parentPlaybookProfileId ? parentProfileById.get(profile.parentPlaybookProfileId) ?? null : null;
    const lineageSourceCampaign = profile.sourceCampaignId ? sourceCampaignById.get(profile.sourceCampaignId) ?? null : null;
    const startAnchor = campaign.startsAt ?? campaign.createdAt ?? null;
    const actualFollowerDelay = diffHoursBetween(startAnchor, campaign.unlockFollowersAt);
    const actualPublicDelay = diffHoursBetween(startAnchor, campaign.unlockPublicAt);
    const variants = variantsMap.get(campaign.id) ?? [];
    const inferredCtaDirection = inferPreferredCtaDirectionFromVariants(variants);
    const audienceFitItem = audienceFitByCampaignId.get(campaign.id) ?? null;
    const healthItem = healthByCampaignId.get(campaign.id) ?? null;
    const readinessItems = readinessByCampaignId.get(campaign.id) ?? [];
    const readinessAverage = readinessItems.length
      ? roundPlaybookMetric(readinessItems.reduce((sum, item) => sum + item.readinessScore, 0) / readinessItems.length)
      : null;
    const experiments = experimentsByCampaignId.get(campaign.id) ?? [];
    const recentExperimentTypes = uniqueStringList(experiments.map((item) => item.experimentType), 5)
      .filter((value): value is CreatorCampaignExperimentType => creatorCampaignExperimentTypeSchema.safeParse(value).success);
    const experimentOverlap = serializedProfile.preferredExperimentTypes.filter((value) => recentExperimentTypes.includes(value));
    const profileOutcome = outcomeByPlaybookId.get(profile.id) as ({
      scorecardLabel?: CreatorCampaignPlaybookScorecardLabel;
      strongestUseCase?: string | null;
      confidenceNote?: string | null;
      appliedCount?: number;
    } & Record<string, unknown>) | undefined;

    const mismatches: Array<{ key: string; label: string; detail: string; weight: number }> = [];
    const alignedSignals: string[] = [];

    if (serializedProfile.visibilityStrategy && campaign.visibility !== serializedProfile.visibilityStrategy) {
      mismatches.push({
        key: "visibility_strategy",
        label: "Visibility strategy moved",
        detail: `Campaign is ${formatPlaybookAudienceLabel(campaign.visibility)} while the playbook expects ${formatPlaybookAudienceLabel(serializedProfile.visibilityStrategy)} visibility.`,
        weight: 18,
      });
    } else if (serializedProfile.visibilityStrategy) {
      alignedSignals.push(`Visibility still matches the playbook's ${formatPlaybookAudienceLabel(serializedProfile.visibilityStrategy)} emphasis.`);
    }

    if (campaign.rolloutMode !== serializedProfile.rolloutMode) {
      mismatches.push({
        key: "rollout_mode",
        label: "Rollout mode changed",
        detail: `Campaign is using ${campaign.rolloutMode.replaceAll("_", " ")} while the playbook expects ${serializedProfile.rolloutMode.replaceAll("_", " ")}.`,
        weight: 18,
      });
    } else {
      alignedSignals.push(`Rollout mode is still ${serializedProfile.rolloutMode.replaceAll("_", " ")} as saved in the playbook.`);
    }

    if (serializedProfile.startsWithAudience && (campaign.startsWithAudience ?? null) !== serializedProfile.startsWithAudience) {
      mismatches.push({
        key: "starts_with_audience",
        label: "Starting audience changed",
        detail: `Campaign starts with ${formatPlaybookAudienceLabel(campaign.startsWithAudience ?? campaign.visibility)} while the playbook starts with ${formatPlaybookAudienceLabel(serializedProfile.startsWithAudience)}.`,
        weight: 12,
      });
    } else if (serializedProfile.startsWithAudience) {
      alignedSignals.push(`Starting audience still lines up with ${formatPlaybookAudienceLabel(serializedProfile.startsWithAudience)}.`);
    }

    if (serializedProfile.recommendedFollowerUnlockDelayHours !== null) {
      if (actualFollowerDelay === null) {
        mismatches.push({
          key: "follower_unlock_delay",
          label: "Follower unlock timing missing",
          detail: `The playbook expects a follower unlock after ${formatPlaybookDelayLabel(serializedProfile.recommendedFollowerUnlockDelayHours, "not used")}, but this campaign has no follower unlock timing set.`,
          weight: 10,
        });
      } else if (Math.abs(actualFollowerDelay - serializedProfile.recommendedFollowerUnlockDelayHours) >= 24) {
        mismatches.push({
          key: "follower_unlock_delay",
          label: "Follower timing drifted",
          detail: `Follower unlock now runs at ${formatPlaybookDelayLabel(actualFollowerDelay, "not used")} vs ${formatPlaybookDelayLabel(serializedProfile.recommendedFollowerUnlockDelayHours, "not used")} in the playbook.`,
          weight: Math.abs(actualFollowerDelay - serializedProfile.recommendedFollowerUnlockDelayHours) >= 72 ? 12 : 8,
        });
      } else {
        alignedSignals.push(`Follower timing is still close to the playbook's ${formatPlaybookDelayLabel(serializedProfile.recommendedFollowerUnlockDelayHours, "not used")} pattern.`);
      }
    }

    if (serializedProfile.recommendedPublicUnlockDelayHours !== null) {
      if (actualPublicDelay === null) {
        mismatches.push({
          key: "public_unlock_delay",
          label: "Public unlock timing missing",
          detail: `The playbook expects public unlock after ${formatPlaybookDelayLabel(serializedProfile.recommendedPublicUnlockDelayHours, "same day")}, but this campaign has no public unlock timing set.`,
          weight: 10,
        });
      } else if (Math.abs(actualPublicDelay - serializedProfile.recommendedPublicUnlockDelayHours) >= 24) {
        mismatches.push({
          key: "public_unlock_delay",
          label: "Public timing drifted",
          detail: `Public unlock now runs at ${formatPlaybookDelayLabel(actualPublicDelay, "same day")} vs ${formatPlaybookDelayLabel(serializedProfile.recommendedPublicUnlockDelayHours, "same day")} in the playbook.`,
          weight: Math.abs(actualPublicDelay - serializedProfile.recommendedPublicUnlockDelayHours) >= 72 ? 12 : 8,
        });
      } else {
        alignedSignals.push(`Public timing still roughly matches the playbook's ${formatPlaybookDelayLabel(serializedProfile.recommendedPublicUnlockDelayHours, "same day")}.`);
      }
    }

    if (serializedProfile.preferredCtaDirection && serializedProfile.preferredCtaDirection !== "mixed") {
      if (!inferredCtaDirection) {
        mismatches.push({
          key: "cta_direction",
          label: "CTA direction is thin",
          detail: `The playbook leans ${formatPlaybookCtaDirectionLabel(serializedProfile.preferredCtaDirection)}, but this campaign does not yet show a clear CTA direction.`,
          weight: 6,
        });
      } else if (inferredCtaDirection !== serializedProfile.preferredCtaDirection && inferredCtaDirection !== "mixed") {
        mismatches.push({
          key: "cta_direction",
          label: "CTA focus changed",
          detail: `CTA focus now leans ${formatPlaybookCtaDirectionLabel(inferredCtaDirection)} instead of ${formatPlaybookCtaDirectionLabel(serializedProfile.preferredCtaDirection)}.`,
          weight: 12,
        });
      } else {
        alignedSignals.push(`CTA direction still points toward ${formatPlaybookCtaDirectionLabel(serializedProfile.preferredCtaDirection)}.`);
      }
    }

    if (serializedProfile.preferredAudienceFit && audienceFitItem?.bestAudienceFit && audienceFitItem.bestAudienceFitConfidence !== "none") {
      if (audienceFitItem.bestAudienceFit !== serializedProfile.preferredAudienceFit) {
        mismatches.push({
          key: "audience_fit",
          label: "Audience fit shifted",
          detail: `Current audience signal looks ${formatPlaybookAudienceLabel(audienceFitItem.bestAudienceFit)}-leaning, not ${formatPlaybookAudienceLabel(serializedProfile.preferredAudienceFit)} like the playbook.`,
          weight: audienceFitItem.bestAudienceFitConfidence === "high" ? 12 : 8,
        });
      } else {
        alignedSignals.push(`Audience fit still looks strongest with ${formatPlaybookAudienceLabel(serializedProfile.preferredAudienceFit)} viewers.`);
      }
    }

    if (serializedProfile.preferredExperimentTypes.length > 0) {
      if (recentExperimentTypes.length > 0 && experimentOverlap.length === 0) {
        mismatches.push({
          key: "experiment_mix",
          label: "Fix pattern changed",
          detail: `Recent experiments are not overlapping with this playbook's preferred fix patterns yet.`,
          weight: 8,
        });
      } else if (experimentOverlap.length > 0) {
        alignedSignals.push(`Recent experiments still overlap with the playbook (${experimentOverlap.slice(0, 2).map((value) => value.replaceAll("_", " ")).join(", ")}).`);
      }
    }

    const driftScore = Math.max(0, Math.min(100, mismatches.reduce((sum, item) => sum + item.weight, 0)));
    const severity: CreatorCampaignPlaybookDriftSeverity = driftScore >= 60
      ? "misaligned"
      : driftScore >= 35
        ? "drifted"
        : driftScore >= 15
          ? "watch"
          : "aligned";

    const isHealthy = healthItem?.healthState === "thriving" || healthItem?.healthState === "healthy";
    const isAtRisk = healthItem?.healthState === "at_risk" || healthItem?.healthState === "watch";
    const strongPlaybookHistory = profileOutcome?.scorecardLabel === "strong" || profileOutcome?.scorecardLabel === "promising";

    const recommendedAction: CreatorCampaignPlaybookRealignAction = severity === "aligned"
      ? "keep_new_direction"
      : ((severity === "misaligned" || (severity === "drifted" && isAtRisk)) && strongPlaybookHistory)
        ? "realign_campaign"
        : (isHealthy && severity !== "aligned" && (profileOutcome?.appliedCount ?? 0) >= 1)
          ? "update_playbook"
          : (isHealthy && severity !== "aligned")
            ? "keep_new_direction"
            : strongPlaybookHistory
              ? "realign_campaign"
              : "keep_new_direction";

    const decisions = [
      {
        action: "realign_campaign" as CreatorCampaignPlaybookRealignAction,
        recommended: recommendedAction === "realign_campaign",
        title: recommendedAction === "realign_campaign" ? "Realign the campaign to the saved playbook" : "Realign if you still trust the saved strategy",
        note: strongPlaybookHistory
          ? `This playbook already has ${playbookOutcomeStrengthLabel(profileOutcome?.scorecardLabel as CreatorCampaignPlaybookScorecardLabel ?? "mixed").toLowerCase()} for this creator, so reverting the drift may be the lower-risk move.`
          : "Use this when the drift feels accidental and you want the campaign to return to the saved rollout, audience, CTA, or timing pattern.",
        targetRoute: "/drinks/creator-dashboard#campaigns",
      },
      {
        action: "update_playbook" as CreatorCampaignPlaybookRealignAction,
        recommended: recommendedAction === "update_playbook",
        title: "Update the playbook from what is actually working",
        note: isHealthy
          ? "Health and current signal suggest the newer operating pattern may be reusable enough to save back into the playbook."
          : "Choose this only if the drift is intentional and repeated enough that the saved playbook is now behind the current strategy.",
        targetRoute: "/drinks/creator-dashboard#campaign-playbook-profiles",
      },
      {
        action: "keep_new_direction" as CreatorCampaignPlaybookRealignAction,
        recommended: recommendedAction === "keep_new_direction",
        title: severity === "aligned" ? "Keep the current campaign direction" : "Keep the newer direction for now",
        note: severity === "aligned"
          ? "No meaningful drift is showing, so there is no need to force a playbook correction right now."
          : isHealthy
            ? "The campaign is showing enough healthy signal that you may want to let the new direction run before rewriting strategy."
            : "If the shift was intentional, keep it lightweight and watch the next readiness, health, and conversion signals before changing the playbook.",
        targetRoute: campaign.slug ? `/drinks/campaigns/${encodeURIComponent(campaign.slug)}` : "/drinks/creator-dashboard#campaigns",
      },
    ];

    const summary = buildCreatorCampaignPlaybookDriftSummary({
      driftScore,
      severity,
      mismatchCount: mismatches.length,
      recommendation: recommendedAction,
    });

    return [{
      campaignId: campaign.id,
      campaignName: campaign.name,
      campaignSlug: campaign.slug,
      campaignRoute: `/drinks/campaigns/${encodeURIComponent(campaign.slug)}`,
      state: getCreatorCampaignState(campaign),
      playbookId: profile.id,
      playbookName: profile.name,
      playbookDescription: profile.description ?? null,
      playbookAppliedAt: campaign.playbookAppliedAt?.toISOString() ?? null,
      isPlaybookApplied: true,
      playbookLineage: {
        parentPlaybook: lineageParent ? {
          id: lineageParent.id,
          name: lineageParent.name,
          versionLabel: lineageParent.versionLabel ?? null,
        } : null,
        sourceCampaign: lineageSourceCampaign ? {
          id: lineageSourceCampaign.id,
          name: lineageSourceCampaign.name,
          slug: lineageSourceCampaign.slug,
          route: `/drinks/campaigns/${encodeURIComponent(lineageSourceCampaign.slug)}`,
        } : null,
        derivedFromType: serializedProfile.derivedFromType,
        versionLabel: serializedProfile.versionLabel,
        basedOnLabel: lineageParent
          ? `Forked from ${lineageParent.name}${lineageParent.versionLabel ? ` (${lineageParent.versionLabel})` : ""}`
          : lineageSourceCampaign
            ? `Based on campaign ${lineageSourceCampaign.name}`
            : null,
      },
      severity,
      severityLabel: playbookDriftSeverityLabel(severity),
      severityVariant: playbookDriftSeverityVariant(severity),
      driftScore,
      mismatchCount: mismatches.length,
      alignmentCount: alignedSignals.length,
      summary,
      mismatches: mismatches.map((item) => ({
        key: item.key,
        label: item.label,
        detail: item.detail,
        weight: item.weight,
      })),
      alignedSignals,
      currentDirection: {
        visibility: campaign.visibility as CreatorCampaignVisibility,
        rolloutMode: (campaign.rolloutMode as CreatorCampaignRolloutMode | null) ?? "public_first",
        startsWithAudience: (campaign.startsWithAudience as CreatorCampaignRolloutAudience | null) ?? null,
        inferredCtaDirection,
        followerUnlockDelayHours: actualFollowerDelay,
        publicUnlockDelayHours: actualPublicDelay,
        recentExperimentTypes,
        bestAudienceFit: audienceFitItem?.bestAudienceFit ?? null,
        bestAudienceFitConfidence: audienceFitItem?.bestAudienceFitConfidence ?? "none",
      },
      savedPlaybookDirection: {
        visibilityStrategy: serializedProfile.visibilityStrategy,
        rolloutMode: serializedProfile.rolloutMode,
        startsWithAudience: serializedProfile.startsWithAudience,
        preferredCtaDirection: serializedProfile.preferredCtaDirection,
        recommendedFollowerUnlockDelayHours: serializedProfile.recommendedFollowerUnlockDelayHours,
        recommendedPublicUnlockDelayHours: serializedProfile.recommendedPublicUnlockDelayHours,
        preferredAudienceFit: serializedProfile.preferredAudienceFit,
        preferredExperimentTypes: serializedProfile.preferredExperimentTypes,
      },
      realignRecommendation: {
        action: recommendedAction,
        actionLabel: playbookRealignActionLabel(recommendedAction),
        confidence: severity === "misaligned" || (severity === "drifted" && (isHealthy || isAtRisk)) ? "high" : severity === "watch" ? "medium" : "low",
        reason: decisions.find((item) => item.recommended)?.note ?? null,
      },
      suggestedDecisions: decisions,
      outcomeContext: {
        playbookScorecardLabel: profileOutcome?.scorecardLabel ?? null,
        playbookOutcomeLabel: profileOutcome?.scorecardLabel ? playbookOutcomeStrengthLabel(profileOutcome.scorecardLabel as CreatorCampaignPlaybookScorecardLabel) : null,
        strongestUseCase: typeof profileOutcome?.strongestUseCase === "string" ? profileOutcome.strongestUseCase : null,
        confidenceNote: typeof profileOutcome?.confidenceNote === "string" ? profileOutcome.confidenceNote : null,
        appliedCount: typeof profileOutcome?.appliedCount === "number" ? profileOutcome.appliedCount : 0,
        healthState: healthItem?.healthState ?? null,
        healthScore: healthItem?.healthScore ?? null,
        readinessScore: readinessAverage,
      },
    }];
  });

  const summary = {
    appliedCampaignCount: items.length,
    driftedCount: items.filter((item) => ["drifted", "misaligned"].includes(String((item as { severity: string }).severity))).length,
    misalignedCount: items.filter((item) => String((item as { severity: string }).severity) === "misaligned").length,
    recommendedRealignCount: items.filter((item) => String((item as { realignRecommendation: { action: string } }).realignRecommendation.action) === "realign_campaign").length,
  };

  return {
    items: [...items].sort((a, b) => {
      const rank = (value: CreatorCampaignPlaybookDriftSeverity) => value === "misaligned" ? 4 : value === "drifted" ? 3 : value === "watch" ? 2 : 1;
      return rank((b as { severity: CreatorCampaignPlaybookDriftSeverity }).severity) - rank((a as { severity: CreatorCampaignPlaybookDriftSeverity }).severity)
        || ((b as { driftScore: number }).driftScore - (a as { driftScore: number }).driftScore)
        || String((a as { campaignName: string }).campaignName).localeCompare(String((b as { campaignName: string }).campaignName));
    }),
    summary,
    attributionNotes: [
      "Playbook drift stays creator-private and only evaluates campaigns where a saved playbook is still explicitly applied.",
      "This route stays intentionally lightweight: it compares current campaign strategy fields plus existing audience-fit, CTA, experiment, readiness, health, and playbook outcome layers already in ChefSire.",
      "Drift is directional, not a giant config diff. ChefSire is only checking the strategy surfaces that meaningfully change a campaign's playbook posture.",
      "Realign suggestions do not auto-change campaigns or playbooks. They are lightweight guidance on whether to realign the campaign, update the playbook, or keep the newer direction.",
    ],
    generatedAt: new Date().toISOString(),
  };
}

function healthStateRank(state: CreatorCampaignHealthState | null | undefined) {
  switch (state) {
    case "thriving":
      return 2;
    case "healthy":
      return 1;
    case "completed":
      return 1;
    case "watch":
      return -1;
    case "at_risk":
      return -2;
    default:
      return 0;
  }
}

function diffHoursBetween(start: Date | null | undefined, end: Date | null | undefined) {
  if (!start || !end) return null;
  const diffMs = end.getTime() - start.getTime();
  if (!Number.isFinite(diffMs) || diffMs <= 0) return null;
  return Math.max(1, Math.round(diffMs / (60 * 60 * 1000)));
}

function inferPreferredCtaDirectionFromVariants(
  variants: CreatorCampaignCtaVariantRecord[],
): CreatorCampaignPlaybookCtaDirection | null {
  if (!variants.length) return null;
  const counts = new Map<CreatorCampaignPlaybookCtaDirection, number>();
  for (const variant of variants) {
    const mapped: CreatorCampaignPlaybookCtaDirection =
      variant.ctaTargetType === "membership"
        ? "membership"
        : variant.ctaTargetType === "rsvp"
          ? "rsvp"
          : variant.ctaTargetType === "drop"
            ? "drop"
            : variant.ctaTargetType === "collection"
              ? "purchase"
              : "follow";
    counts.set(mapped, (counts.get(mapped) ?? 0) + (variant.isActive ? 2 : 1));
  }
  const ranked = [...counts.entries()].sort((left, right) => right[1] - left[1]);
  if (!ranked[0]) return null;
  if (ranked.length > 1 && ranked[0][1] === ranked[1][1]) return "mixed";
  return ranked[0][0];
}

async function buildCreatorCampaignPlaybookProfileFromCampaign(input: {
  creatorUserId: string;
  campaign: CreatorCampaignRecord;
  name?: string | null;
  description?: string | null;
  notes?: string | null;
  parentPlaybookProfileId?: string | null;
  sourceCampaignId?: string | null;
  derivedFromType?: CreatorCampaignPlaybookDerivedFromType | null;
  versionLabel?: string | null;
}) {
  if (!db) throw new Error("Database unavailable");

  const { creatorUserId, campaign } = input;
  const [variants, experiments] = await Promise.all([
    loadCreatorCampaignVariantsByCampaignIds([campaign.id]).then((map) => map.get(campaign.id) ?? []),
    db
      .select()
      .from(creatorCampaignExperiments)
      .where(eq(creatorCampaignExperiments.campaignId, campaign.id))
      .orderBy(desc(creatorCampaignExperiments.updatedAt), desc(creatorCampaignExperiments.createdAt))
      .limit(6),
  ]);

  const startsAt = campaign.startsAt ?? campaign.createdAt ?? null;
  const preferredExperimentTypes = uniqueStringList([
    ...experiments.map((item) => item.experimentType),
  ], 5).filter((value): value is CreatorCampaignExperimentType => creatorCampaignExperimentTypeSchema.safeParse(value).success);

  const generatedNotes = uniqueStringList([
    input.notes?.trim() || null,
    campaign.rolloutNotes?.trim() || null,
  ], 6).join(" ");

  return insertCreatorCampaignPlaybookProfileSchema.parse({
    creatorUserId,
    parentPlaybookProfileId: input.parentPlaybookProfileId ?? null,
    sourceCampaignId: input.sourceCampaignId ?? campaign.id,
    derivedFromType: input.derivedFromType ?? (input.parentPlaybookProfileId ? "playbook" : "campaign"),
    versionLabel: input.versionLabel ?? null,
    name: input.name?.trim() || `${campaign.name} Strategy`,
    description: input.description?.trim() || campaign.description || `Reusable strategy preset based on ${campaign.name}.`,
    visibilityStrategy: campaign.visibility,
    rolloutMode: (campaign.rolloutMode as CreatorCampaignRolloutMode | null) ?? "public_first",
    startsWithAudience: (campaign.startsWithAudience as CreatorCampaignRolloutAudience | null) ?? null,
    recommendedFollowerUnlockDelayHours: diffHoursBetween(startsAt, campaign.unlockFollowersAt),
    recommendedPublicUnlockDelayHours: diffHoursBetween(startsAt, campaign.unlockPublicAt),
    preferredCtaDirection: inferPreferredCtaDirectionFromVariants(variants) ?? null,
    preferredExperimentTypes,
    preferredAudienceFit: inferPreferredAudienceFitFromCampaign(campaign),
    notes: generatedNotes || null,
  });
}

async function buildNextPlaybookVersionLabel(input: {
  creatorUserId: string;
  parentPlaybookProfileId?: string | null;
  requestedVersionLabel?: string | null;
}) {
  if (input.requestedVersionLabel?.trim()) return input.requestedVersionLabel.trim();
  if (!input.parentPlaybookProfileId || !db) return null;

  const siblingRows = await db
    .select({ count: sql<number>`count(*)::int` })
    .from(creatorCampaignPlaybookProfiles)
    .where(and(
      eq(creatorCampaignPlaybookProfiles.creatorUserId, input.creatorUserId),
      eq(creatorCampaignPlaybookProfiles.parentPlaybookProfileId, input.parentPlaybookProfileId),
    ));

  const nextVersionNumber = Number(siblingRows[0]?.count ?? 0) + 2;
  return `v${nextVersionNumber}`;
}

async function applyCreatorCampaignPlaybookProfileToCampaign(input: {
  profile: CreatorCampaignPlaybookProfileRecord;
  campaign: CreatorCampaignRecord;
  actorUserId: string;
}) {
  if (!db) throw new Error("Database unavailable");

  const profile = input.profile;
  const campaign = input.campaign;
  const anchor = campaign.startsAt ?? campaign.createdAt ?? new Date();
  const nextFollowerUnlock = profile.recommendedFollowerUnlockDelayHours
    ? new Date(anchor.getTime() + profile.recommendedFollowerUnlockDelayHours * 60 * 60 * 1000)
    : null;
  const nextPublicUnlock = profile.recommendedPublicUnlockDelayHours
    ? new Date(anchor.getTime() + profile.recommendedPublicUnlockDelayHours * 60 * 60 * 1000)
    : null;
  const mergedNotes = uniqueStringList([
    campaign.rolloutNotes?.trim() || null,
    profile.notes?.trim() || null,
    profile.preferredCtaDirection ? `Suggested CTA direction: ${profile.preferredCtaDirection.replaceAll("_", " ")}.` : null,
  ], 4).join(" ");
  const appliedAt = new Date();

  const updatedRows = await db
    .update(creatorCampaigns)
    .set({
      visibility: (profile.visibilityStrategy as CreatorCampaignVisibility | null) ?? campaign.visibility,
      rolloutMode: (profile.rolloutMode as CreatorCampaignRolloutMode | null) ?? campaign.rolloutMode,
      startsWithAudience: normalizeCreatorCampaignPlaybookProfileStartsWithAudience(profile.startsWithAudience) ?? campaign.startsWithAudience,
      unlockFollowersAt: nextFollowerUnlock,
      unlockPublicAt: nextPublicUnlock,
      rolloutNotes: mergedNotes || null,
      appliedPlaybookProfileId: profile.id,
      playbookAppliedAt: appliedAt,
      updatedAt: new Date(),
    })
    .where(eq(creatorCampaigns.id, campaign.id))
    .returning();

  const nextCampaign = updatedRows[0];
  if (!nextCampaign) throw new Error("Failed to apply playbook profile.");

  await maybeCreateCampaignRolloutConfiguredEvent({
    previous: campaign,
    next: nextCampaign,
    actorUserId: input.actorUserId,
  });

  return nextCampaign;
}

function formatPlaybookAudienceLabel(value: CreatorCampaignRolloutAudience | CreatorCampaignVisibility | null | undefined) {
  if (value === "members") return "members";
  if (value === "followers") return "followers";
  return "public";
}

function formatPlaybookCtaDirectionLabel(value: CreatorCampaignPlaybookCtaDirection | null | undefined) {
  if (!value) return "mixed";
  return value.replaceAll("_", " ");
}

function buildCreatorCampaignPlaybookOnboardingSummary(items: Array<{ key: string; status: CreatorCampaignPlaybookOnboardingItemStatus }>) {
  const warningCount = items.filter((item) => item.status === "warning").length;
  const completeCount = items.filter((item) => item.status === "complete").length;
  const remainingItems = items.filter((item) => item.status !== "complete");
  return {
    totalCount: items.length,
    completeCount,
    warningCount,
    remainingCount: remainingItems.length,
    completedKeys: items.filter((item) => item.status === "complete").map((item) => item.key),
    nextRecommendedKey: remainingItems[0]?.key ?? null,
  };
}

async function loadCreatorCampaignPlaybookOnboarding(campaign: CreatorCampaignRecord, creatorUserId: string) {
  if (!db) throw new Error("Database unavailable");

  const [detail, readinessCollection, appliedProfileRows, pinnedRows] = await Promise.all([
    loadCreatorCampaignDetail(campaign, creatorUserId),
    loadCreatorCampaignLaunchReadiness(creatorUserId, campaign.id),
    campaign.appliedPlaybookProfileId
      ? db
          .select()
          .from(creatorCampaignPlaybookProfiles)
          .where(and(
            eq(creatorCampaignPlaybookProfiles.id, campaign.appliedPlaybookProfileId),
            eq(creatorCampaignPlaybookProfiles.creatorUserId, creatorUserId),
          ))
          .limit(1)
      : Promise.resolve([] as CreatorCampaignPlaybookProfileRecord[]),
    db
      .select({
        id: creatorCampaigns.id,
        name: creatorCampaigns.name,
        slug: creatorCampaigns.slug,
        isPinned: creatorCampaigns.isPinned,
      })
      .from(creatorCampaigns)
      .where(and(eq(creatorCampaigns.creatorUserId, creatorUserId), eq(creatorCampaigns.isPinned, true)))
      .limit(1),
  ]);

  const readiness = readinessCollection.items[0] ?? null;
  const profile = appliedProfileRows[0] ?? null;
  const serializedProfile = profile ? serializeCreatorCampaignPlaybookProfile(profile) : null;
  const rollout = detail.campaign.rollout ?? deriveCreatorCampaignRollout(campaign, new Date());
  const linkedDrops = detail.linkedContent.drops;
  const linkedPromos = detail.linkedContent.promos;
  const linkedPosts = detail.linkedContent.posts;
  const linkedCollections = detail.linkedContent.collections;
  const linkedRoadmap = detail.linkedContent.roadmap;
  const publicUpdatesCount = linkedPosts.filter((post) => post.visibility === "public").length
    + linkedRoadmap.filter((item) => item.visibility === "public").length
    + linkedDrops.filter((drop) => drop.visibility === "public").length;
  const memberOnlyCollectionCount = linkedCollections.filter((collection) => collection.accessType === "membership_only").length;
  const hasMemberDrop = linkedDrops.some((drop) => drop.visibility === "members");
  const hasAnyVariant = Boolean(detail.activeVariant) || detail.variants.length > 0;
  const checkByKey = new Map((readiness?.checks ?? []).map((check) => [check.key, check]));
  const pinnedCampaign = pinnedRows[0] ?? null;
  const memberFocused = detail.campaign.visibility === "members"
    || rollout.startsWithAudience === "members"
    || rollout.currentAudience === "members"
    || rollout.nextAudience === "members"
    || serializedProfile?.preferredAudienceFit === "members"
    || serializedProfile?.visibilityStrategy === "members";
  const wantsRsvpSurface = serializedProfile?.preferredCtaDirection === "rsvp"
    || serializedProfile?.preferredCtaDirection === "drop"
    || serializedProfile?.preferredExperimentTypes.includes("push_rsvp")
    || linkedDrops.length > 0;
  const wantsPromoSurface = serializedProfile?.preferredExperimentTypes.includes("launch_promo")
    || serializedProfile?.preferredCtaDirection === "purchase"
    || linkedPromos.length > 0;
  const needsPublicFacingTouchpoint = rollout.nextAudience === "public" || detail.campaign.visibility === "public";

  const items: Array<{
    key: string;
    label: string;
    status: CreatorCampaignPlaybookOnboardingItemStatus;
    note: string;
    targetRoute: string | null;
  }> = [];

  const pushItem = (
    key: string,
    label: string,
    status: CreatorCampaignPlaybookOnboardingItemStatus,
    note: string,
    targetRoute: string | null,
  ) => {
    items.push({ key, label, status, note, targetRoute });
  };

  const rolloutMatchesProfile = serializedProfile
    ? campaign.rolloutMode === serializedProfile.rolloutMode
      && (!serializedProfile.startsWithAudience || (campaign.startsWithAudience ?? null) === serializedProfile.startsWithAudience)
    : true;
  pushItem(
    "confirm_rollout_mode",
    "Confirm rollout mode",
    checkByKey.get("rollout_timing")?.status === "fail"
      ? "warning"
      : rolloutMatchesProfile
        ? "complete"
        : serializedProfile
          ? "ready"
          : "complete",
    checkByKey.get("rollout_timing")?.status === "fail"
      ? checkByKey.get("rollout_timing")?.note ?? "The staged rollout still needs a valid unlock setup."
      : serializedProfile
        ? `Playbook points to ${serializedProfile.rolloutMode.replaceAll("_", " ")}${serializedProfile.startsWithAudience ? ` starting with ${serializedProfile.startsWithAudience}` : ""}.`
        : `Campaign is already set to ${campaign.rolloutMode.replaceAll("_", " ")} rollout mode.`,
    "/drinks/creator-dashboard#campaigns",
  );

  const hasUnlockTiming = campaign.rolloutMode !== "staged"
    || (Boolean(rollout.unlockFollowersAt) || Boolean(rollout.unlockPublicAt) || !rollout.isRolloutActive);
  pushItem(
    "confirm_unlock_timing",
    "Confirm unlock timing",
    checkByKey.get("rollout_timing")?.status === "fail"
      ? "warning"
      : hasUnlockTiming
        ? "complete"
        : serializedProfile?.recommendedFollowerUnlockDelayHours || serializedProfile?.recommendedPublicUnlockDelayHours
          ? "ready"
          : "todo",
    checkByKey.get("rollout_timing")?.status === "fail"
      ? checkByKey.get("rollout_timing")?.note ?? "Add the missing follower/public unlock time."
      : campaign.rolloutMode !== "staged"
        ? `This campaign uses ${campaign.rolloutMode.replaceAll("_", " ")}, so extra staged timing is optional.`
        : rollout.nextUnlockAt
          ? `Next unlock is already scheduled for ${campaignReadinessWindowLabel(rollout.nextUnlockAt, "the configured window")}.`
          : serializedProfile?.recommendedFollowerUnlockDelayHours || serializedProfile?.recommendedPublicUnlockDelayHours
            ? `Playbook suggests follower/public unlock delays of ${serializedProfile.recommendedFollowerUnlockDelayHours ?? 0}h and ${serializedProfile.recommendedPublicUnlockDelayHours ?? 0}h from campaign start.`
            : "Set the next staged unlock window if this campaign should widen later.",
    "/drinks/creator-dashboard#campaigns",
  );

  pushItem(
    "add_cta_variant",
    "Add CTA variant",
    hasAnyVariant
      ? "complete"
      : serializedProfile?.preferredCtaDirection
        ? "ready"
        : checkByKey.get("cta_path")?.status === "fail"
          ? "warning"
          : "todo",
    hasAnyVariant
      ? `${detail.variants.length} CTA variant${detail.variants.length === 1 ? " is" : "s are"} already configured.`
      : serializedProfile?.preferredCtaDirection
        ? `Playbook leans ${formatPlaybookCtaDirectionLabel(serializedProfile.preferredCtaDirection)}, so a focused CTA variant would make that ask explicit.`
        : checkByKey.get("cta_path")?.note ?? "Add one CTA variant if you want a sharper ask than the default linked destination.",
    "/drinks/creator-dashboard#campaigns",
  );

  if (wantsRsvpSurface || linkedDrops.length > 0) {
    pushItem(
      "add_linked_drop",
      "Add linked drop",
      linkedDrops.length > 0
        ? "complete"
        : checkByKey.get("launch_support")?.status === "warning"
          ? "ready"
          : "todo",
      linkedDrops.length > 0
        ? `${linkedDrops.length} linked drop${linkedDrops.length === 1 ? " gives" : "s give"} the campaign an RSVP / Notify Me destination.`
        : serializedProfile?.preferredCtaDirection === "drop" || serializedProfile?.preferredCtaDirection === "rsvp"
          ? "This playbook is better with a linked drop so the next audience has a concrete launch moment."
          : checkByKey.get("launch_support")?.note ?? "Add a linked drop when this campaign needs a concrete next beat.",
      "/drinks/creator-dashboard#drops",
    );
  }

  pushItem(
    "add_creator_update",
    "Add creator update/post",
    checkByKey.get("recent_update")?.status === "pass"
      ? "complete"
      : linkedPosts.length > 0 || linkedRoadmap.length > 0
        ? "ready"
        : wantsRsvpSurface || wantsPromoSurface || linkedDrops.length > 0
          ? "ready"
          : "todo",
    checkByKey.get("recent_update")?.status === "pass"
      ? checkByKey.get("recent_update")?.note ?? "A recent campaign update is already linked."
      : linkedPosts.length > 0 || linkedRoadmap.length > 0
        ? "There is already some campaign storytelling linked, but a fresh update would make the next step clearer."
        : "A short creator update keeps the playbook strategy visible without turning this into a bigger workflow.",
    "/drinks/creator-dashboard#posts",
  );

  if (memberFocused) {
    pushItem(
      "add_member_only_asset",
      "Add member-only asset",
      memberOnlyCollectionCount > 0 || hasMemberDrop
        ? "complete"
        : checkByKey.get("member_destination")?.status === "fail"
          ? "warning"
          : "ready",
      memberOnlyCollectionCount > 0 || hasMemberDrop
        ? "A member-only collection or members-only drop is already linked."
        : checkByKey.get("member_destination")?.note ?? "This playbook leans member-focused, so add one member-only destination.",
      "/drinks/creator-dashboard#membership",
    );
  }

  if (wantsPromoSurface || wantsRsvpSurface) {
    const hasSupportSurface = linkedPromos.length > 0 || linkedDrops.length > 0;
    pushItem(
      "add_promo_or_rsvp_surface",
      "Add promo or RSVP surface",
      hasSupportSurface
        ? "complete"
        : wantsPromoSurface || wantsRsvpSurface
          ? "ready"
          : "todo",
      hasSupportSurface
        ? linkedPromos.length > 0
          ? `${linkedPromos.length} promo${linkedPromos.length === 1 ? " is" : "s are"} already linked for this campaign.`
          : `${linkedDrops.length} linked drop${linkedDrops.length === 1 ? " already provides" : "s already provide"} an RSVP path.`
        : wantsPromoSurface && wantsRsvpSurface
          ? "This playbook suggests either a lightweight promo or an RSVP-friendly surface before the next wider push."
          : wantsPromoSurface
            ? "This playbook suggests a lightweight promo surface to support conversion."
            : "This playbook suggests making RSVP / Notify Me more explicit before the next campaign step.",
      wantsPromoSurface ? "/drinks/creator-dashboard#promotions" : "/drinks/creator-dashboard#drops",
    );
  }

  pushItem(
    "review_pinned_spotlight",
    "Review pinned spotlight choice",
    detail.campaign.isPinned
      ? "complete"
      : needsPublicFacingTouchpoint
        ? "ready"
        : "todo",
    detail.campaign.isPinned
      ? "This campaign is already the pinned spotlight."
      : pinnedCampaign
        ? `${pinnedCampaign.name} is pinned right now, so decide whether this campaign should replace it for the next launch beat.`
        : "No pinned spotlight is set yet; near-launch campaigns are easier to find with one lightweight spotlight choice.",
    "/drinks/creator-dashboard#campaigns",
  );

  pushItem(
    "review_launch_readiness",
    "Review launch readiness",
    readiness?.readinessState === "ready"
      ? "complete"
      : readiness?.readinessState === "almost_ready"
        ? "ready"
        : readiness?.readinessState === "missing_key_items" || readiness?.readinessState === "blocked"
          ? "warning"
          : "todo",
    readiness
      ? readiness.nextLaunchStep
        ?? readiness.recommendedFixes[0]
        ?? readiness.warnings[0]
        ?? readiness.blockers[0]
        ?? `Readiness is currently ${readiness.readinessState.replaceAll("_", " ")}.`
      : "Readiness has not been derived for this campaign yet.",
    "/drinks/creator-dashboard#campaign-launch-readiness",
  );

  const orderedItems = items.sort((left, right) => {
    const rank = (value: CreatorCampaignPlaybookOnboardingItemStatus) => {
      switch (value) {
        case "warning":
          return 0;
        case "todo":
          return 1;
        case "ready":
          return 2;
        default:
          return 3;
      }
    };
    return rank(left.status) - rank(right.status) || left.label.localeCompare(right.label);
  });

  return {
    campaignId: campaign.id,
    campaignName: campaign.name,
    campaignSlug: campaign.slug,
    campaignRoute: detail.campaign.route,
    isPlaybookApplied: Boolean(campaign.appliedPlaybookProfileId),
    appliedPlaybookProfileId: campaign.appliedPlaybookProfileId ?? null,
    playbookAppliedAt: campaign.playbookAppliedAt?.toISOString() ?? null,
    profile: serializedProfile,
    checklist: orderedItems,
    summary: buildCreatorCampaignPlaybookOnboardingSummary(orderedItems),
    readinessState: readiness?.readinessState ?? null,
    readinessRoute: "/drinks/creator-dashboard#campaign-launch-readiness",
    attributionNotes: [
      "Playbook onboarding stays intentionally lightweight: it only derives the next campaign setup steps from the campaign's saved playbook link plus existing rollout, CTA, linked content, pinned spotlight, and readiness signals.",
      "This is not a new workflow engine or task system. Items are recomputed at read time so creators only see the next practical gaps after a playbook is applied.",
      "Checklist items map back to existing drinks-platform surfaces like campaigns, drops, posts, promotions, membership, and launch readiness instead of introducing a new setup product.",
    ],
    generatedAt: new Date().toISOString(),
  };
}

function fitScoreLabel(score: number): CreatorCampaignPlaybookFitLabel {
  if (score >= 75) return "strong_match";
  if (score >= 45) return "partial_match";
  return "weak_match";
}

function fitScoreRecommendation(input: {
  fitScore: number;
  mismatchesCount: number;
}): CreatorCampaignPlaybookFitRecommendation {
  if (input.fitScore >= 82 && input.mismatchesCount <= 1) return "apply_as_is";
  if (input.fitScore >= 55) return "apply_with_adjustments";
  return "loose_inspiration";
}

function normalizePlaybookDelayFit(actualHours: number | null, recommendedHours: number | null, toleranceHours: number) {
  if (actualHours === null || recommendedHours === null) return null;
  const diff = Math.abs(actualHours - recommendedHours);
  if (diff <= toleranceHours) return "strong";
  if (diff <= toleranceHours * 2) return "partial";
  return "weak";
}

function countMatchingExperimentTypes(
  profile: CreatorCampaignPlaybookProfileRecord,
  experiments: CreatorCampaignExperimentRecord[],
) {
  const preferred = Array.isArray(profile.preferredExperimentTypes)
    ? profile.preferredExperimentTypes
        .map((value) => String(value))
        .filter((value): value is CreatorCampaignExperimentType => creatorCampaignExperimentTypeSchema.safeParse(value).success)
    : [];
  if (!preferred.length) return { preferred, overlap: [] as CreatorCampaignExperimentType[] };
  const current = new Set(experiments.map((item) => item.experimentType));
  return {
    preferred,
    overlap: preferred.filter((value) => current.has(value)),
  };
}

async function loadCreatorCampaignPlaybookFitCollection(creatorUserId: string, campaignId?: string | null) {
  if (!db) throw new Error("Database unavailable");

  const campaigns = await db
    .select()
    .from(creatorCampaigns)
    .where(and(
      eq(creatorCampaigns.creatorUserId, creatorUserId),
      campaignId ? eq(creatorCampaigns.id, campaignId) : sql`true`,
    ))
    .orderBy(desc(creatorCampaigns.updatedAt), desc(creatorCampaigns.createdAt))
    .limit(campaignId ? 1 : 40);

  if (!campaigns.length) {
    return {
      items: [] as Array<Record<string, unknown>>,
      profiles: [] as ReturnType<typeof serializeCreatorCampaignPlaybookProfile>[],
      attributionNotes: [
        "Playbook fit only compares this creator's own saved playbook profiles against this creator's own campaigns.",
        "No playbook fit is available yet because there are no creator-owned campaigns to compare.",
      ],
      generatedAt: new Date().toISOString(),
    };
  }

  const [profiles, audienceFit, variantsByCampaignId, experimentRows] = await Promise.all([
    db
      .select()
      .from(creatorCampaignPlaybookProfiles)
      .where(eq(creatorCampaignPlaybookProfiles.creatorUserId, creatorUserId))
      .orderBy(desc(creatorCampaignPlaybookProfiles.updatedAt), desc(creatorCampaignPlaybookProfiles.createdAt)),
    loadCreatorCampaignAudienceFit(creatorUserId),
    loadCreatorCampaignVariantsByCampaignIds(campaigns.map((entry: CreatorCampaignRecord) => entry.id)),
    db
      .select()
      .from(creatorCampaignExperiments)
      .where(inArray(creatorCampaignExperiments.campaignId, campaigns.map((entry: CreatorCampaignRecord) => entry.id)))
      .orderBy(desc(creatorCampaignExperiments.updatedAt), desc(creatorCampaignExperiments.createdAt)),
  ]);

  const audienceFitByCampaignId = new Map<string, Awaited<ReturnType<typeof loadCreatorCampaignAudienceFit>>["items"][number]>(
    audienceFit.items.map((item: Awaited<ReturnType<typeof loadCreatorCampaignAudienceFit>>["items"][number]) => [item.campaignId, item] as const),
  );
  const experimentsByCampaignId = new Map<string, CreatorCampaignExperimentRecord[]>();
  for (const row of experimentRows) {
    const current = experimentsByCampaignId.get(row.campaignId) ?? [];
    current.push(row);
    experimentsByCampaignId.set(row.campaignId, current);
  }

  const items = campaigns.map((campaign: CreatorCampaignRecord) => {
    const campaignAudienceFit = audienceFitByCampaignId.get(campaign.id) ?? null;
    const campaignVariants = variantsByCampaignId.get(campaign.id) ?? [];
    const campaignExperiments = experimentsByCampaignId.get(campaign.id) ?? [];
    const inferredCtaDirection = inferPreferredCtaDirectionFromVariants(campaignVariants);
    const campaignVisibility = (campaign.visibility as CreatorCampaignVisibility | null) ?? "public";
    const campaignStartsWithAudience = (campaign.startsWithAudience as CreatorCampaignRolloutAudience | null) ?? null;
    const campaignRolloutMode = (campaign.rolloutMode as CreatorCampaignRolloutMode | null) ?? "public_first";
    const startsAt = campaign.startsAt ?? campaign.createdAt ?? null;
    const actualFollowerDelay = diffHoursBetween(startsAt, campaign.unlockFollowersAt);
    const actualPublicDelay = diffHoursBetween(startsAt, campaign.unlockPublicAt);

    const matches = profiles.map((profile: CreatorCampaignPlaybookProfileRecord) => {
      const profileVisibility = (profile.visibilityStrategy as CreatorCampaignVisibility | null) ?? null;
      const profileStartsWithAudience = normalizeCreatorCampaignPlaybookProfileStartsWithAudience(profile.startsWithAudience);
      const profilePreferredAudienceFit = normalizeCreatorCampaignPlaybookPreferredAudienceFit(profile.preferredAudienceFit);
      const profilePreferredCtaDirection = (profile.preferredCtaDirection as CreatorCampaignPlaybookCtaDirection | null) ?? null;
      let earned = 0;
      let possible = 0;
      const whyItFits: string[] = [];
      const mismatches: string[] = [];
      const suggestedAdjustments: string[] = [];

      if (profileVisibility) {
        possible += 18;
        if (profileVisibility === campaignVisibility) {
          earned += 18;
          whyItFits.push(`Visibility matches the playbook's ${formatPlaybookAudienceLabel(profileVisibility)} emphasis.`);
        } else {
          mismatches.push(`Saved visibility expects ${formatPlaybookAudienceLabel(profileVisibility)}, but this campaign is ${formatPlaybookAudienceLabel(campaignVisibility)}.`);
          suggestedAdjustments.push(`If you apply this playbook, review campaign visibility before publishing changes.`);
        }
      }

      possible += 18;
      if (profile.rolloutMode === campaignRolloutMode) {
        earned += 18;
        whyItFits.push(`Rollout mode aligns on ${profile.rolloutMode.replaceAll("_", " ")}.`);
      } else {
        mismatches.push(`Rollout mode differs: playbook is ${profile.rolloutMode.replaceAll("_", " ")}, campaign is ${campaignRolloutMode.replaceAll("_", " ")}.`);
        suggestedAdjustments.push(`Adjust rollout mode if you want this strategy to shape unlock sequencing too.`);
      }

      if (profileStartsWithAudience) {
        possible += 10;
        if (campaignStartsWithAudience === profileStartsWithAudience) {
          earned += 10;
          whyItFits.push(`Starting audience matches at ${formatPlaybookAudienceLabel(profileStartsWithAudience)}.`);
        } else if (!campaignStartsWithAudience && campaignVisibility === profileStartsWithAudience) {
          earned += 5;
          whyItFits.push(`Campaign visibility already leans toward the playbook's ${formatPlaybookAudienceLabel(profileStartsWithAudience)} starting audience.`);
        } else {
          mismatches.push(`Playbook starts with ${formatPlaybookAudienceLabel(profileStartsWithAudience)}, but this campaign starts with ${formatPlaybookAudienceLabel(campaignStartsWithAudience ?? campaignVisibility)}.`);
          suggestedAdjustments.push(`Review which audience should unlock first before applying this playbook literally.`);
        }
      }

      if (profilePreferredAudienceFit) {
        possible += 16;
        if (campaignAudienceFit?.bestAudienceFit === profilePreferredAudienceFit) {
          earned += 16;
          whyItFits.push(`Audience-fit signal points to ${formatPlaybookAudienceLabel(profilePreferredAudienceFit)} for this campaign too.`);
        } else if (!campaignAudienceFit?.bestAudienceFit && campaignVisibility === profilePreferredAudienceFit) {
          earned += 8;
          whyItFits.push(`There is no strong audience-fit history yet, but campaign visibility already leans ${formatPlaybookAudienceLabel(profilePreferredAudienceFit)}.`);
        } else {
          mismatches.push(
            campaignAudienceFit?.bestAudienceFit
              ? `Campaign audience-fit signal leans ${formatPlaybookAudienceLabel(campaignAudienceFit.bestAudienceFit as CreatorCampaignRolloutAudience)}, not ${formatPlaybookAudienceLabel(profilePreferredAudienceFit)}.`
              : `Audience-fit signal is still thin, so the playbook's ${formatPlaybookAudienceLabel(profilePreferredAudienceFit)} preference is not strongly confirmed yet.`,
          );
          suggestedAdjustments.push(`Use this playbook as guidance for tone or rollout, but double-check audience emphasis first.`);
        }
      }

      if (profile.recommendedFollowerUnlockDelayHours !== null) {
        possible += 7;
        const fit = normalizePlaybookDelayFit(actualFollowerDelay, profile.recommendedFollowerUnlockDelayHours, 12);
        if (fit === "strong") {
          earned += 7;
          whyItFits.push(`Follower unlock timing is close to the playbook's ${profile.recommendedFollowerUnlockDelayHours}h pattern.`);
        } else if (fit === "partial") {
          earned += 4;
          whyItFits.push(`Follower unlock timing is in the same general range as the playbook.`);
        } else {
          mismatches.push(
            actualFollowerDelay === null
              ? `Playbook expects a follower unlock window, but this campaign does not have one yet.`
              : `Follower unlock timing is ${actualFollowerDelay}h here vs ${profile.recommendedFollowerUnlockDelayHours}h in the playbook.`,
          );
          suggestedAdjustments.push(`Tighten follower unlock timing if you want a closer match.`);
        }
      }

      if (profile.recommendedPublicUnlockDelayHours !== null) {
        possible += 7;
        const fit = normalizePlaybookDelayFit(actualPublicDelay, profile.recommendedPublicUnlockDelayHours, 18);
        if (fit === "strong") {
          earned += 7;
          whyItFits.push(`Public unlock timing lines up with the playbook's ${profile.recommendedPublicUnlockDelayHours}h pattern.`);
        } else if (fit === "partial") {
          earned += 4;
          whyItFits.push(`Public unlock timing is directionally similar to the playbook.`);
        } else {
          mismatches.push(
            actualPublicDelay === null
              ? `Playbook expects a public unlock delay, but this campaign does not have one yet.`
              : `Public unlock timing is ${actualPublicDelay}h here vs ${profile.recommendedPublicUnlockDelayHours}h in the playbook.`,
          );
          suggestedAdjustments.push(`Adjust public unlock timing if you want to apply this playbook more literally.`);
        }
      }

      if (profilePreferredCtaDirection) {
        possible += 14;
        if (inferredCtaDirection === profilePreferredCtaDirection) {
          earned += 14;
          whyItFits.push(`CTA direction matches on ${formatPlaybookCtaDirectionLabel(profilePreferredCtaDirection)}.`);
        } else if (profilePreferredCtaDirection === "mixed" && inferredCtaDirection) {
          earned += 8;
          whyItFits.push(`This campaign already mixes CTA styles, which fits a more flexible playbook.`);
        } else if (inferredCtaDirection === "mixed" && profilePreferredCtaDirection !== null) {
          earned += 6;
          whyItFits.push(`The campaign uses mixed CTA paths, so the playbook's ${formatPlaybookCtaDirectionLabel(profilePreferredCtaDirection)} direction can still guide the primary ask.`);
        } else {
          mismatches.push(
            inferredCtaDirection
              ? `CTA focus leans ${formatPlaybookCtaDirectionLabel(inferredCtaDirection)}, not ${formatPlaybookCtaDirectionLabel(profilePreferredCtaDirection)}.`
              : `No clear CTA direction is configured yet to confirm the playbook's ${formatPlaybookCtaDirectionLabel(profilePreferredCtaDirection)} preference.`,
          );
          suggestedAdjustments.push(`Review the active CTA before applying this playbook as-is.`);
        }
      }

      const experimentOverlap = countMatchingExperimentTypes(profile, campaignExperiments);
      if (experimentOverlap.preferred.length > 0) {
        possible += 10;
        if (experimentOverlap.overlap.length > 0) {
          const earnedExperimentScore = Math.min(10, Math.max(4, Math.round((experimentOverlap.overlap.length / experimentOverlap.preferred.length) * 10)));
          earned += earnedExperimentScore;
          whyItFits.push(`Experiment preference overlap: ${experimentOverlap.overlap.slice(0, 2).map((value) => value.replaceAll("_", " ")).join(", ")}.`);
        } else {
          mismatches.push(`Current experiment mix does not overlap with this playbook's preferred fix patterns yet.`);
          suggestedAdjustments.push(`Treat the playbook as a strategic nudge unless you also want to adopt its experiment pattern.`);
        }
      }

      const fitScore = possible > 0 ? Math.round((earned / possible) * 100) : 0;
      const fitLabel = fitScoreLabel(fitScore);
      const recommendation = fitScoreRecommendation({
        fitScore,
        mismatchesCount: mismatches.length,
      });

      return {
        playbookId: profile.id,
        playbookName: profile.name,
        playbookDescription: profile.description ?? null,
        fitScore,
        fitLabel,
        recommendation,
        whyItFits: whyItFits.slice(0, 4),
        mismatches: mismatches.slice(0, 4),
        suggestedAdjustments: suggestedAdjustments.slice(0, 4),
        comparedSignals: {
          visibilityStrategy: profile.visibilityStrategy ?? null,
          rolloutMode: profile.rolloutMode,
          startsWithAudience: normalizeCreatorCampaignPlaybookProfileStartsWithAudience(profile.startsWithAudience),
          preferredAudienceFit: normalizeCreatorCampaignPlaybookPreferredAudienceFit(profile.preferredAudienceFit),
          preferredCtaDirection: profile.preferredCtaDirection ?? null,
          preferredExperimentTypes: experimentOverlap.preferred,
        },
      };
    }).sort((a: { fitScore: number; playbookName: string }, b: { fitScore: number; playbookName: string }) => b.fitScore - a.fitScore || a.playbookName.localeCompare(b.playbookName));

    const bestMatch = matches[0] ?? null;
    const runnerUp = matches[1] ?? null;

    return {
      campaignId: campaign.id,
      campaignName: campaign.name,
      campaignSlug: campaign.slug,
      campaignRoute: `/drinks/campaigns/${encodeURIComponent(campaign.slug)}`,
      visibility: campaignVisibility,
      state: getCreatorCampaignState(campaign),
      bestMatch,
      runnerUp,
      matches,
      audienceFit: campaignAudienceFit
        ? {
          bestAudienceFit: campaignAudienceFit.bestAudienceFit,
          bestAudienceFitConfidence: campaignAudienceFit.bestAudienceFitConfidence,
          bestAudienceFitReason: campaignAudienceFit.bestAudienceFitReason,
        }
        : null,
      inferredCtaDirection,
      actualFollowerUnlockDelayHours: actualFollowerDelay,
      actualPublicUnlockDelayHours: actualPublicDelay,
    };
  });

  const outcomes = await loadCreatorCampaignPlaybookOutcomeCollection(creatorUserId);
  const outcomeByPlaybookId = new Map(
    outcomes.items.map((item) => [
      String((item as { playbookId: string }).playbookId),
      item as {
        playbookId: string;
        appliedCount: number;
        scorecardLabel: CreatorCampaignPlaybookScorecardLabel;
        confidenceNote: string | null;
      },
    ] as const),
  );

  const itemsWithOutcomeContext = items.map((item) => ({
    ...item,
    bestMatch: item.bestMatch
      ? {
          ...item.bestMatch,
          historicalOutcomeLabel: outcomeByPlaybookId.get(item.bestMatch.playbookId)
            ? playbookOutcomeStrengthLabel(outcomeByPlaybookId.get(item.bestMatch.playbookId)!.scorecardLabel)
            : null,
          historicalOutcomeConfidenceNote: outcomeByPlaybookId.get(item.bestMatch.playbookId)?.confidenceNote ?? null,
          historicalOutcomeAppliedCount: outcomeByPlaybookId.get(item.bestMatch.playbookId)?.appliedCount ?? 0,
        }
      : null,
    runnerUp: item.runnerUp
      ? {
          ...item.runnerUp,
          historicalOutcomeLabel: outcomeByPlaybookId.get(item.runnerUp.playbookId)
            ? playbookOutcomeStrengthLabel(outcomeByPlaybookId.get(item.runnerUp.playbookId)!.scorecardLabel)
            : null,
          historicalOutcomeConfidenceNote: outcomeByPlaybookId.get(item.runnerUp.playbookId)?.confidenceNote ?? null,
          historicalOutcomeAppliedCount: outcomeByPlaybookId.get(item.runnerUp.playbookId)?.appliedCount ?? 0,
        }
      : null,
    matches: item.matches.map((match) => ({
      ...match,
      historicalOutcomeLabel: outcomeByPlaybookId.get(match.playbookId)
        ? playbookOutcomeStrengthLabel(outcomeByPlaybookId.get(match.playbookId)!.scorecardLabel)
        : null,
      historicalOutcomeConfidenceNote: outcomeByPlaybookId.get(match.playbookId)?.confidenceNote ?? null,
      historicalOutcomeAppliedCount: outcomeByPlaybookId.get(match.playbookId)?.appliedCount ?? 0,
    })),
  }));

  return {
    items: itemsWithOutcomeContext,
    profiles: profiles.map(serializeCreatorCampaignPlaybookProfile),
    attributionNotes: [
      "Playbook fit is intentionally rules-based and lightweight. It compares only campaign fields and saved playbook profile fields already stored in ChefSire.",
      "This is not a recommendation engine and it does not use hidden ML scoring, external creator clusters, or cross-creator strategy borrowing.",
      "Templates and clone/reuse stay separate: playbook fit only answers which saved strategy preset looks closest to this campaign right now.",
      "Rollout advisor and timing advisor stay separate too: playbook fit checks alignment with a saved preset, rather than generating a new advisor thesis from scratch.",
    ],
    generatedAt: new Date().toISOString(),
  };
}

async function loadCreatorCampaignPlaybookOutcomeCollection(creatorUserId: string) {
  if (!db) throw new Error("Database unavailable");

  const [profiles, campaigns, performance, health, readiness, bottlenecks] = await Promise.all([
    db
      .select()
      .from(creatorCampaignPlaybookProfiles)
      .where(eq(creatorCampaignPlaybookProfiles.creatorUserId, creatorUserId))
      .orderBy(desc(creatorCampaignPlaybookProfiles.updatedAt), desc(creatorCampaignPlaybookProfiles.createdAt)),
    db
      .select()
      .from(creatorCampaigns)
      .where(eq(creatorCampaigns.creatorUserId, creatorUserId))
      .orderBy(desc(creatorCampaigns.updatedAt), desc(creatorCampaigns.createdAt))
      .limit(160),
    loadCreatorCampaignPerformanceSnapshots(creatorUserId),
    loadCreatorCampaignHealth(creatorUserId),
    loadCreatorCampaignLaunchReadiness(creatorUserId),
    loadCreatorCampaignFunnelBottlenecks(creatorUserId),
  ]);

  if (!profiles.length) {
    return {
      items: [] as Array<Record<string, unknown>>,
      strongestPlaybooks: [] as Array<Record<string, unknown>>,
      weakestPlaybooks: [] as Array<Record<string, unknown>>,
      attributionNotes: [
        "Playbook outcomes stay creator-private and only summarize this creator's own campaigns where a saved playbook was explicitly applied.",
        "No saved playbook profiles exist yet, so there is no strategy scorecard to summarize.",
      ],
      generatedAt: new Date().toISOString(),
    };
  }

  const appliedCampaigns = campaigns.filter((campaign) => Boolean(campaign.appliedPlaybookProfileId));
  if (!appliedCampaigns.length) {
    const emptyItems = profiles.map((profile) => ({
      playbookId: profile.id,
      playbookName: profile.name,
      playbookDescription: profile.description ?? null,
      appliedCount: 0,
      appliedCampaignCount: 0,
      campaignsUsingIt: [] as Array<Record<string, unknown>>,
      activeCampaignCount: 0,
      archivedCampaignCount: 0,
      averageFollowerOutcome: null,
      averageFollowerGain: null,
      averageRsvpOutcome: null,
      averageRsvpLift: null,
      averageClickOutcome: null,
      averageClickPerformance: null,
      averageApproxPurchaseOutcome: null,
      averageApproxPurchasePerformance: null,
      averageApproxMembershipOutcome: null,
      averageApproxMembershipPerformance: null,
      averageGoalCompletionRate: null,
      averageReadinessScore: null,
      averageHealthStateImprovement: null,
      averageBottleneckReduction: null,
      strongestUseCase: "Apply this playbook to at least one campaign to start a lightweight scorecard.",
      scorecardLabel: "promising" as CreatorCampaignPlaybookScorecardLabel,
      confidenceNote: "No campaign has been explicitly linked to this playbook yet, so ChefSire is not inferring strategy outcomes.",
      summary: "No applied-history signal yet.",
      strongestCampaignExample: null,
      weakestCampaignExample: null,
    }));

    return {
      items: emptyItems,
      strongestPlaybooks: [],
      weakestPlaybooks: [],
      attributionNotes: [
        "Playbook outcomes stay creator-private and only summarize this creator's own campaigns where a saved playbook was explicitly applied.",
        "This route stays intentionally lightweight: it uses the campaign → playbook link plus existing follower, RSVP, click, purchase, membership, readiness, health, and bottleneck signals already in ChefSire.",
        "Outcome fields are directional and approximate. They show what happened after a playbook was applied, not strict causality.",
      ],
      generatedAt: new Date().toISOString(),
    };
  }

  const campaignIds = appliedCampaigns.map((campaign) => campaign.id);
  const linkMap = await loadCreatorCampaignLinksByCampaignIds(campaignIds);
  const dropIds = [...new Set(appliedCampaigns.flatMap((campaign) => (
    (linkMap.get(campaign.id) ?? []).filter((link) => link.targetType === "drop").map((link) => link.targetId)
  )))];
  const collectionIds = [...new Set(appliedCampaigns.flatMap((campaign) => (
    (linkMap.get(campaign.id) ?? []).filter((link) => link.targetType === "collection").map((link) => link.targetId)
  )))];

  const [goalRows, followRows, dropEventRows, rsvpRows, purchaseRows, membershipRows] = await Promise.all([
    db
      .select()
      .from(creatorCampaignGoals)
      .where(inArray(creatorCampaignGoals.campaignId, campaignIds))
      .orderBy(desc(creatorCampaignGoals.updatedAt), asc(creatorCampaignGoals.createdAt)),
    db.select({
      campaignId: creatorCampaignFollows.campaignId,
      createdAt: creatorCampaignFollows.createdAt,
    }).from(creatorCampaignFollows).where(inArray(creatorCampaignFollows.campaignId, campaignIds)).orderBy(asc(creatorCampaignFollows.createdAt)),
    dropIds.length
      ? db.select({
          dropId: creatorDropEvents.dropId,
          eventType: creatorDropEvents.eventType,
          createdAt: creatorDropEvents.createdAt,
        }).from(creatorDropEvents).where(inArray(creatorDropEvents.dropId, dropIds)).orderBy(asc(creatorDropEvents.createdAt))
      : Promise.resolve([] as Array<{ dropId: string; eventType: string; createdAt: Date }>),
    dropIds.length
      ? db.select({
          dropId: creatorDropRsvps.dropId,
          createdAt: creatorDropRsvps.createdAt,
        }).from(creatorDropRsvps).where(inArray(creatorDropRsvps.dropId, dropIds)).orderBy(asc(creatorDropRsvps.createdAt))
      : Promise.resolve([] as Array<{ dropId: string; createdAt: Date }>),
    collectionIds.length
      ? db.select({
          collectionId: drinkCollectionPurchases.collectionId,
          createdAt: drinkCollectionPurchases.createdAt,
          status: drinkCollectionPurchases.status,
        }).from(drinkCollectionPurchases).where(inArray(drinkCollectionPurchases.collectionId, collectionIds)).orderBy(asc(drinkCollectionPurchases.createdAt))
      : Promise.resolve([] as Array<{ collectionId: string; createdAt: Date; status: string }>),
    db.select({
      createdAt: creatorMemberships.createdAt,
      status: creatorMemberships.status,
    }).from(creatorMemberships).where(eq(creatorMemberships.creatorUserId, creatorUserId)).orderBy(asc(creatorMemberships.createdAt)),
  ]);

  const performanceByCampaignId = new Map(performance.items.map((item) => [item.campaignId, item]));
  const healthByCampaignId = new Map(health.items.map((item) => [item.campaignId, item]));
  const readinessByCampaignId = new Map<string, Array<typeof readiness.items[number]>>();
  for (const item of readiness.items) {
    const current = readinessByCampaignId.get(item.campaignId) ?? [];
    current.push(item);
    readinessByCampaignId.set(item.campaignId, current);
  }
  const bottleneckByCampaignId = new Map(bottlenecks.items.map((item) => [item.campaignId, item]));

  const goalsByCampaignId = new Map<string, CreatorCampaignGoalRecord[]>();
  for (const row of goalRows) {
    const current = goalsByCampaignId.get(row.campaignId) ?? [];
    current.push(row);
    goalsByCampaignId.set(row.campaignId, current);
  }

  const followRowsByCampaignId = new Map<string, Array<{ createdAt: Date }>>();
  for (const row of followRows) {
    const current = followRowsByCampaignId.get(row.campaignId) ?? [];
    current.push({ createdAt: row.createdAt });
    followRowsByCampaignId.set(row.campaignId, current);
  }

  const dropEventRowsByDropId = new Map<string, Array<{ eventType: string; createdAt: Date }>>();
  for (const row of dropEventRows) {
    const current = dropEventRowsByDropId.get(row.dropId) ?? [];
    current.push({ eventType: row.eventType, createdAt: row.createdAt });
    dropEventRowsByDropId.set(row.dropId, current);
  }

  const rsvpRowsByDropId = new Map<string, Array<{ createdAt: Date }>>();
  for (const row of rsvpRows) {
    const current = rsvpRowsByDropId.get(row.dropId) ?? [];
    current.push({ createdAt: row.createdAt });
    rsvpRowsByDropId.set(row.dropId, current);
  }

  const purchaseRowsByCollectionId = new Map<string, Array<{ createdAt: Date; status: string }>>();
  for (const row of purchaseRows) {
    const current = purchaseRowsByCollectionId.get(row.collectionId) ?? [];
    current.push({ createdAt: row.createdAt, status: row.status });
    purchaseRowsByCollectionId.set(row.collectionId, current);
  }

  const activeMembershipRows = membershipRows.filter((row) => row.status === "active");

  const campaignsByProfileId = new Map<string, CreatorCampaignRecord[]>();
  for (const campaign of appliedCampaigns) {
    const profileId = campaign.appliedPlaybookProfileId;
    if (!profileId) continue;
    const current = campaignsByProfileId.get(profileId) ?? [];
    current.push(campaign);
    campaignsByProfileId.set(profileId, current);
  }

  const items = profiles.map((profile) => {
    const profileCampaigns = campaignsByProfileId.get(profile.id) ?? [];
    const campaignSummaries = profileCampaigns.map((campaign) => {
      const analytics = performanceByCampaignId.get(campaign.id) ?? null;
      const healthItem = healthByCampaignId.get(campaign.id) ?? null;
      const readinessItems = readinessByCampaignId.get(campaign.id) ?? [];
      const bottleneckItem = bottleneckByCampaignId.get(campaign.id) ?? null;
      const goals = (goalsByCampaignId.get(campaign.id) ?? []).map((goal) => serializeCreatorCampaignGoal(goal, analytics));
      const windowStart = campaign.startsAt ?? campaign.createdAt;
      const appliedAt = campaign.playbookAppliedAt ?? campaign.updatedAt ?? campaign.createdAt;
      const links = linkMap.get(campaign.id) ?? [];
      const dropLinkIds = links.filter((link) => link.targetType === "drop").map((link) => link.targetId);
      const collectionLinkIds = links.filter((link) => link.targetType === "collection").map((link) => link.targetId);

      const countSinceApplied = (rows: Array<{ createdAt: Date }>) => rows.filter((row) => row.createdAt >= appliedAt && isDateWithinCampaignAnalyticsWindow(row.createdAt, campaign)).length;
      const countBeforeApplied = (rows: Array<{ createdAt: Date }>) => rows.filter((row) => row.createdAt >= windowStart && row.createdAt < appliedAt && isDateWithinCampaignAnalyticsWindow(row.createdAt, campaign)).length;

      const followRowsForCampaign = followRowsByCampaignId.get(campaign.id) ?? [];
      const rsvpRowsForCampaign = dropLinkIds.flatMap((dropId) => rsvpRowsByDropId.get(dropId) ?? []);
      const clickRowsForCampaign = dropLinkIds.flatMap((dropId) => (dropEventRowsByDropId.get(dropId) ?? []).filter((row) => row.eventType === "click_drop_target"));
      const viewRowsForCampaign = dropLinkIds.flatMap((dropId) => (dropEventRowsByDropId.get(dropId) ?? []).filter((row) => row.eventType === "view_drop"));
      const purchaseRowsForCampaign = collectionLinkIds.flatMap((collectionId) => (purchaseRowsByCollectionId.get(collectionId) ?? []).filter((row) => row.status === "completed"));
      const membershipRowsForCampaign = analytics?.membershipsFromCampaignNote
        ? activeMembershipRows.filter((row) => isDateWithinCampaignAnalyticsWindow(row.createdAt, campaign))
        : [];

      const beforeFollowers = countBeforeApplied(followRowsForCampaign);
      const afterFollowers = countSinceApplied(followRowsForCampaign);
      const beforeRsvps = countBeforeApplied(rsvpRowsForCampaign);
      const afterRsvps = countSinceApplied(rsvpRowsForCampaign);
      const beforeClicks = countBeforeApplied(clickRowsForCampaign);
      const afterClicks = countSinceApplied(clickRowsForCampaign);
      const beforeViews = countBeforeApplied(viewRowsForCampaign);
      const afterViews = countSinceApplied(viewRowsForCampaign);
      const beforePurchases = countBeforeApplied(purchaseRowsForCampaign);
      const afterPurchases = countSinceApplied(purchaseRowsForCampaign);
      const beforeMemberships = countBeforeApplied(membershipRowsForCampaign);
      const afterMemberships = countSinceApplied(membershipRowsForCampaign);
      const beforeLeakage = beforeViews > 0 ? roundRate(100 - ((Math.max(beforePurchases, beforeMemberships) / beforeViews) * 100)) : null;
      const afterLeakage = afterViews > 0 ? roundRate(100 - ((Math.max(afterPurchases, afterMemberships) / afterViews) * 100)) : null;
      const bottleneckReduction = beforeLeakage !== null && afterLeakage !== null ? roundPlaybookMetric(beforeLeakage - afterLeakage) : null;
      const averageReadinessScore = readinessItems.length
        ? roundPlaybookMetric(readinessItems.reduce((sum, item) => sum + item.readinessScore, 0) / readinessItems.length)
        : null;
      const averageGoalCompletionRate = goals.length
        ? roundPlaybookMetric(goals.reduce((sum, goal) => sum + goal.percentComplete, 0) / goals.length)
        : null;
      const healthImprovement = healthItem
        ? roundPlaybookMetric(
          healthStateRank(healthItem.healthState)
          + (healthItem.recentFollowers > healthItem.previousFollowers ? 0.3 : healthItem.recentFollowers < healthItem.previousFollowers ? -0.3 : 0)
          + (healthItem.recentRsvps > healthItem.previousRsvps ? 0.3 : healthItem.recentRsvps < healthItem.previousRsvps ? -0.3 : 0)
          + (healthItem.recentClicks > healthItem.previousClicks ? 0.2 : healthItem.recentClicks < healthItem.previousClicks ? -0.2 : 0)
          + (healthItem.recentPurchases > healthItem.previousPurchases ? 0.4 : healthItem.recentPurchases < healthItem.previousPurchases ? -0.4 : 0)
          + (healthItem.recentMemberships > healthItem.previousMemberships ? 0.4 : healthItem.recentMemberships < healthItem.previousMemberships ? -0.4 : 0),
        )
        : null;

      const weightedOutcomeScore = roundPlaybookMetric(
        (afterFollowers - beforeFollowers)
        + (afterRsvps - beforeRsvps) * 2
        + (afterClicks - beforeClicks) * 3
        + (afterPurchases - beforePurchases) * 5
        + (afterMemberships - beforeMemberships) * 6,
      ) ?? 0;

      return {
        campaignId: campaign.id,
        campaignName: campaign.name,
        campaignSlug: campaign.slug,
        campaignRoute: `/drinks/campaigns/${encodeURIComponent(campaign.slug)}`,
        state: getCreatorCampaignState(campaign),
        visibility: campaign.visibility as CreatorCampaignVisibility,
        appliedAt: appliedAt.toISOString(),
        followerOutcome: afterFollowers - beforeFollowers,
        rsvpOutcome: afterRsvps - beforeRsvps,
        clickOutcome: afterClicks - beforeClicks,
        approxPurchaseOutcome: afterPurchases - beforePurchases,
        approxMembershipOutcome: afterMemberships - beforeMemberships,
        goalCompletionRate: averageGoalCompletionRate,
        readinessScore: averageReadinessScore,
        healthState: healthItem?.healthState ?? null,
        healthScore: healthItem?.healthScore ?? null,
        healthStateImprovement: healthImprovement,
        bottleneckReduction,
        currentLeakage: bottleneckItem?.overallLeakageFromViews ?? null,
        weightedOutcomeScore,
        notes: [
          `Counts compare campaign signal after ${new Date(appliedAt).toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" })} against signal earlier in the same campaign window.`,
          analytics?.purchasesFromLinkedCollectionsNote ?? null,
          analytics?.membershipsFromCampaignNote ?? null,
        ].filter((value): value is string => Boolean(value)),
      };
    });

    const appliedCount = campaignSummaries.length;
    const activeCampaignCount = campaignSummaries.filter((item) => item.state === "active" || item.state === "upcoming").length;
    const archivedCampaignCount = campaignSummaries.filter((item) => item.state === "past").length;
    const averageOutcomeScore = appliedCount
      ? (campaignSummaries.reduce((sum, item) => sum + item.weightedOutcomeScore, 0) / appliedCount)
      : 0;
    const scorecardLabel = playbookScorecardLabel({ averageOutcomeScore, appliedCount });
    const strongestCampaignExample = [...campaignSummaries].sort((a, b) => b.weightedOutcomeScore - a.weightedOutcomeScore || a.campaignName.localeCompare(b.campaignName))[0] ?? null;
    const weakestCampaignExample = [...campaignSummaries].sort((a, b) => a.weightedOutcomeScore - b.weightedOutcomeScore || a.campaignName.localeCompare(b.campaignName))[0] ?? null;

    const average = (selector: (item: typeof campaignSummaries[number]) => number | null) => {
      const values = campaignSummaries.map(selector).filter((value): value is number => typeof value === "number" && Number.isFinite(value));
      if (!values.length) return null;
      return roundPlaybookMetric(values.reduce((sum, value) => sum + value, 0) / values.length);
    };

    const visibilityCounts = campaignSummaries.reduce<Record<CreatorCampaignVisibility, number>>((acc, item) => {
      acc[item.visibility] += 1;
      return acc;
    }, { public: 0, followers: 0, members: 0 });
    const dominantVisibility = (Object.entries(visibilityCounts).sort((a, b) => b[1] - a[1])[0]?.[0] ?? "public") as CreatorCampaignVisibility;
    const averageFollowerOutcome = average((item) => item.followerOutcome);
    const averageRsvpOutcome = average((item) => item.rsvpOutcome);
    const averageClickOutcome = average((item) => item.clickOutcome);
    const averageApproxPurchaseOutcome = average((item) => item.approxPurchaseOutcome);
    const averageApproxMembershipOutcome = average((item) => item.approxMembershipOutcome);
    const strongestUseCase = appliedCount === 0
      ? "Apply this playbook to at least one campaign to start learning what it is actually good at."
      : averageApproxMembershipOutcome && averageApproxMembershipOutcome > Math.max(averageFollowerOutcome ?? 0, averageRsvpOutcome ?? 0)
        ? "This playbook tends to look best on member-first or membership-forward campaigns."
        : averageApproxPurchaseOutcome && averageApproxPurchaseOutcome > Math.max(averageFollowerOutcome ?? 0, averageRsvpOutcome ?? 0)
          ? "This playbook looks most useful on conversion-oriented launches with linked collections."
          : averageRsvpOutcome && averageRsvpOutcome > Math.max(averageFollowerOutcome ?? 0, averageClickOutcome ?? 0)
            ? "This playbook tends to work best when the campaign's main job is RSVP interest."
            : dominantVisibility === "members"
              ? "This playbook is showing its clearest signal on member-first campaigns."
              : dominantVisibility === "followers"
                ? "This playbook currently looks strongest on follower-first campaigns."
                : "This playbook is currently strongest on broader public launches.";

    const summaryParts = [
      strongestUseCase,
      appliedCount <= 1
        ? "Promising, but the history is still limited."
        : averageApproxPurchaseOutcome !== null && averageApproxPurchaseOutcome <= 0 && (averageFollowerOutcome ?? 0) > 0
          ? "Follower growth looks stronger than conversion so far."
          : averageApproxPurchaseOutcome !== null && averageApproxPurchaseOutcome > 0 && (averageFollowerOutcome ?? 0) <= 0
            ? "Conversion looks stronger than top-of-funnel growth so far."
            : null,
    ].filter((value): value is string => Boolean(value));

    return {
      playbookId: profile.id,
      playbookName: profile.name,
      playbookDescription: profile.description ?? null,
      appliedCount,
      appliedCampaignCount: appliedCount,
      campaignsUsingIt: campaignSummaries.map((item) => ({
        campaignId: item.campaignId,
        campaignName: item.campaignName,
        campaignSlug: item.campaignSlug,
        campaignRoute: item.campaignRoute,
        state: item.state,
        appliedAt: item.appliedAt,
      })),
      activeCampaignCount,
      archivedCampaignCount,
      averageFollowerOutcome,
      averageFollowerGain: averageFollowerOutcome,
      averageRsvpOutcome,
      averageRsvpLift: averageRsvpOutcome,
      averageClickOutcome,
      averageClickPerformance: averageClickOutcome,
      averageApproxPurchaseOutcome,
      averageApproxPurchasePerformance: averageApproxPurchaseOutcome,
      averageApproxMembershipOutcome,
      averageApproxMembershipPerformance: averageApproxMembershipOutcome,
      averageGoalCompletionRate: average((item) => item.goalCompletionRate),
      averageReadinessScore: average((item) => item.readinessScore),
      averageHealthStateImprovement: average((item) => item.healthStateImprovement),
      averageBottleneckReduction: average((item) => item.bottleneckReduction),
      strongestUseCase,
      summary: summaryParts.join(" "),
      confidenceNote: appliedCount === 0
        ? "No applied playbook history yet."
        : appliedCount === 1
          ? "One applied campaign only — read this as directional learning, not a proven strategy."
          : "Directional only: ChefSire compares the same campaign before vs. after playbook application plus current creator-private health/readiness context. It does not claim strict causality.",
      strongestCampaignExample,
      weakestCampaignExample,
      scorecardLabel,
    };
  });

  const ranked = [...items]
    .filter((item) => item.appliedCount > 0)
    .sort((a, b) => {
      const rank = (value: CreatorCampaignPlaybookScorecardLabel) => value === "strong" ? 4 : value === "promising" ? 3 : value === "mixed" ? 2 : 1;
      return rank(b.scorecardLabel) - rank(a.scorecardLabel)
        || ((b.strongestCampaignExample?.weightedOutcomeScore ?? -999) - (a.strongestCampaignExample?.weightedOutcomeScore ?? -999))
        || a.playbookName.localeCompare(b.playbookName);
    });

  return {
    items,
    strongestPlaybooks: ranked.filter((item) => item.scorecardLabel === "strong" || item.scorecardLabel === "promising").slice(0, 3),
    weakestPlaybooks: [...ranked].reverse().filter((item) => item.scorecardLabel === "weak" || item.scorecardLabel === "mixed").slice(0, 3),
    attributionNotes: [
      "Playbook outcomes stay creator-private and only summarize this creator's own campaigns where a saved playbook was explicitly applied.",
      "This route stays intentionally lightweight: it uses the campaign → playbook link plus existing follower, RSVP, click, purchase, membership, readiness, health, and bottleneck signals already in ChefSire.",
      "Outcome fields are directional and approximate. They compare what happened after a playbook was applied against earlier signal in the same campaign window or current creator-private status layers.",
      "Playbook profiles stay distinct from playbook fit, templates/clone, rollout advisors, and the experiment library: this layer only reports how saved strategy presets have performed once applied.",
    ],
    generatedAt: new Date().toISOString(),
  };
}

async function instantiateCampaignFromTemplate(input: {
  creatorUserId: string;
  blueprint: CreatorCampaignTemplateBlueprint;
  newName?: string | null;
  newSlug?: string | null;
  resetDates?: boolean;
  copyLinkedDrafts?: boolean;
  copyCtaVariants?: boolean;
}) {
  if (!db) throw new Error("Database unavailable");

  const resetDates = input.resetDates ?? input.blueprint.defaults.resetDates;
  const copyLinkedDrafts = input.copyLinkedDrafts ?? input.blueprint.defaults.copyLinkedDrafts;
  const copyCtaVariants = input.copyCtaVariants ?? input.blueprint.defaults.copyCtaVariants;

  const baseName = input.newName?.trim() || `${input.blueprint.campaign.name} Draft`;
  const slug = await ensureUniqueCreatorCampaignSlug(
    input.newSlug?.trim() || baseName,
  );

  const insertedCampaignRows = await db.insert(creatorCampaigns).values(insertCreatorCampaignSchema.parse({
    creatorUserId: input.creatorUserId,
    slug,
    name: baseName,
    description: input.blueprint.campaign.description,
    visibility: input.blueprint.campaign.visibility,
    startsAt: resetDates || !input.blueprint.campaign.startsAt ? null : new Date(input.blueprint.campaign.startsAt),
    endsAt: resetDates || !input.blueprint.campaign.endsAt ? null : new Date(input.blueprint.campaign.endsAt),
    isActive: false,
  })).returning();
  const campaign = insertedCampaignRows[0];
  if (!campaign) throw new Error("Failed to create campaign from template.");

  const nextLinks: Array<{ targetType: CreatorCampaignTargetType; targetId: string; sortOrder: number }> = [];

  for (const link of input.blueprint.links) {
    if (!["collection", "promo", "challenge"].includes(link.targetType)) {
      continue;
    }
    nextLinks.push({
      targetType: link.targetType,
      targetId: link.targetId,
      sortOrder: nextLinks.length,
    });
  }

  if (copyLinkedDrafts) {
    for (const drop of input.blueprint.linkedDrafts.drops) {
      const scheduledFor = resetDates ? new Date(Date.now() + 7 * 24 * 60 * 60 * 1000) : (drop.scheduledFor ? new Date(drop.scheduledFor) : new Date(Date.now() + 7 * 24 * 60 * 60 * 1000));
      await validateCreatorDropLinkedEntities({
        creatorUserId: input.creatorUserId,
        visibility: drop.visibility,
        dropType: drop.dropType,
        linkedCollectionId: drop.linkedCollectionId,
        linkedChallengeId: drop.linkedChallengeId,
        linkedPromotionId: drop.linkedPromotionId,
      });
      const inserted = await db.insert(creatorDrops).values(insertCreatorDropSchema.parse({
        creatorUserId: input.creatorUserId,
        title: `${drop.title} (Draft)`,
        description: drop.description,
        dropType: drop.dropType,
        visibility: drop.visibility,
        scheduledFor,
        linkedCollectionId: drop.linkedCollectionId,
        linkedChallengeId: drop.linkedChallengeId,
        linkedPromotionId: drop.linkedPromotionId,
        recapNotes: drop.recapNotes,
        isPublished: false,
      })).returning();
      if (inserted[0]) {
        nextLinks.push({ targetType: "drop", targetId: inserted[0].id, sortOrder: nextLinks.length });
      }
    }

    for (const post of input.blueprint.linkedDrafts.posts) {
      await validateCreatorPostLinkedEntities({
        creatorUserId: input.creatorUserId,
        visibility: post.visibility,
        linkedCollectionId: post.linkedCollectionId,
        linkedChallengeId: post.linkedChallengeId,
      });
      const inserted = await db.insert(creatorPosts).values({
        creatorUserId: input.creatorUserId,
        title: `${post.title} (Draft)`,
        body: post.body,
        postType: post.postType,
        visibility: post.visibility,
        linkedCollectionId: post.linkedCollectionId,
        linkedChallengeId: post.linkedChallengeId,
        updatedAt: new Date(),
      }).returning();
      if (inserted[0]) {
        nextLinks.push({ targetType: "post", targetId: inserted[0].id, sortOrder: nextLinks.length });
      }
    }

    for (const item of input.blueprint.linkedDrafts.roadmap) {
      await validateCreatorRoadmapLinkedEntities({
        creatorUserId: input.creatorUserId,
        itemType: item.itemType,
        visibility: item.visibility,
        linkedCollectionId: item.linkedCollectionId,
        linkedChallengeId: item.linkedChallengeId,
      });
      const inserted = await db.insert(creatorRoadmapItems).values(insertCreatorRoadmapItemSchema.parse({
        creatorUserId: input.creatorUserId,
        title: `${item.title} (Draft)`,
        description: item.description,
        itemType: item.itemType,
        visibility: item.visibility,
        linkedCollectionId: item.linkedCollectionId,
        linkedChallengeId: item.linkedChallengeId,
        scheduledFor: resetDates ? null : (item.scheduledFor ? new Date(item.scheduledFor) : null),
        releasedAt: null,
        status: "upcoming",
      })).returning();
      if (inserted[0]) {
        nextLinks.push({ targetType: "roadmap", targetId: inserted[0].id, sortOrder: nextLinks.length });
      }
    }
  }

  await replaceCreatorCampaignLinks(campaign.id, nextLinks);

  if (copyCtaVariants) {
    const variants = input.blueprint.variants.slice(0, 6);
    for (let index = 0; index < variants.length; index += 1) {
      const variant = variants[index];
      await db.insert(creatorCampaignCtaVariants).values(insertCreatorCampaignCtaVariantSchema.parse({
        campaignId: campaign.id,
        label: variant.label,
        headline: variant.headline,
        subheadline: variant.subheadline,
        ctaText: variant.ctaText,
        ctaTargetType: variant.ctaTargetType,
        isActive: index === 0 ? true : Boolean(variant.isActive && !variants.slice(0, index).some((item) => item.isActive)),
      }));
    }
  }

  return campaign;
}
function creatorRoadmapAudienceLabel(item: Pick<CreatorRoadmapRecord, "creatorUserId" | "visibility">, viewerId?: string | null) {
  if (viewerId && item.creatorUserId === viewerId) return "You";
  if (item.visibility === "members") return "Members";
  if (item.visibility === "followers") return "Followers";
  return "Public";
}

function roadmapSortDate(item: Pick<CreatorRoadmapRecord, "status" | "scheduledFor" | "releasedAt" | "updatedAt" | "createdAt">) {
  if (item.status === "upcoming") {
    return item.scheduledFor ?? item.updatedAt ?? item.createdAt;
  }
  return item.releasedAt ?? item.updatedAt ?? item.createdAt;
}

function sortCreatorRoadmapItems(items: CreatorRoadmapRecord[]) {
  const statusPriority: Record<CreatorRoadmapStatus, number> = {
    live: 0,
    upcoming: 1,
    archived: 2,
  };

  return [...items].sort((a, b) => {
    const aStatus = a.status as CreatorRoadmapStatus;
    const bStatus = b.status as CreatorRoadmapStatus;
    if (statusPriority[aStatus] !== statusPriority[bStatus]) {
      return statusPriority[aStatus] - statusPriority[bStatus];
    }

    const aDate = roadmapSortDate(a).getTime();
    const bDate = roadmapSortDate(b).getTime();

    if (aStatus === "upcoming") {
      return aDate - bDate;
    }

    return bDate - aDate;
  });
}

async function validateCreatorPostLinkedEntities(input: {
  creatorUserId: string;
  visibility?: CreatorPostVisibility | null;
  linkedCollectionId?: string | null;
  linkedChallengeId?: string | null;
}) {
  if (!db) throw new Error("Database unavailable");

  if (input.linkedCollectionId) {
    const collectionRows = await db
      .select({ id: drinkCollections.id, isPublic: drinkCollections.isPublic })
      .from(drinkCollections)
      .where(and(eq(drinkCollections.id, input.linkedCollectionId), eq(drinkCollections.userId, input.creatorUserId)))
      .limit(1);

    if (!collectionRows[0]) {
      throw new Error("Linked collection must belong to the creator.");
    }
    if (!collectionRows[0].isPublic && input.visibility !== "members") {
      throw new Error("Non-public collections can only be linked from member-visible posts.");
    }
  }

  if (input.linkedChallengeId) {
    const challengeRows = await db
      .select({ id: drinkChallenges.id })
      .from(drinkChallenges)
      .where(eq(drinkChallenges.id, input.linkedChallengeId))
      .limit(1);

    if (!challengeRows[0]) {
      throw new Error("Linked challenge was not found.");
    }
  }
}

async function validateCreatorDropLinkedEntities(input: {
  creatorUserId: string;
  visibility?: CreatorDropVisibility | null;
  dropType?: CreatorDropType | null;
  linkedCollectionId?: string | null;
  linkedChallengeId?: string | null;
  linkedPromotionId?: string | null;
}) {
  if (!db) throw new Error("Database unavailable");

  if (input.linkedCollectionId) {
    const collectionRows = await db
      .select({
        id: drinkCollections.id,
        isPublic: drinkCollections.isPublic,
        accessType: drinkCollections.accessType,
      })
      .from(drinkCollections)
      .where(and(eq(drinkCollections.id, input.linkedCollectionId), eq(drinkCollections.userId, input.creatorUserId)))
      .limit(1);

    const linkedCollection = collectionRows[0];
    if (!linkedCollection) {
      throw new Error("Linked collection must belong to the creator.");
    }
    if ((linkedCollection.accessType === "membership_only" || !linkedCollection.isPublic) && input.visibility !== "members") {
      throw new Error("Member-only collections can only be linked from member-visible drops.");
    }
  }

  if (input.linkedChallengeId) {
    const challengeRows = await db
      .select({ id: drinkChallenges.id })
      .from(drinkChallenges)
      .where(eq(drinkChallenges.id, input.linkedChallengeId))
      .limit(1);

    if (!challengeRows[0]) {
      throw new Error("Linked challenge was not found.");
    }
  }

  if (input.linkedPromotionId) {
    const promotionRows = await db
      .select({
        id: drinkCollectionPromotions.id,
        creatorUserId: drinkCollectionPromotions.creatorUserId,
        collectionId: drinkCollectionPromotions.collectionId,
      })
      .from(drinkCollectionPromotions)
      .where(eq(drinkCollectionPromotions.id, input.linkedPromotionId))
      .limit(1);

    const promotion = promotionRows[0];
    if (!promotion || promotion.creatorUserId !== input.creatorUserId) {
      throw new Error("Linked promotion must belong to the creator.");
    }
    if (input.linkedCollectionId && promotion.collectionId !== input.linkedCollectionId) {
      throw new Error("Linked promotion must match the linked collection.");
    }
  }

  if (input.dropType === "promo_launch" && !input.linkedPromotionId) {
    throw new Error("Promo launch drops should link to a promotion.");
  }

  if (input.dropType === "member_drop" && input.visibility !== "members") {
    throw new Error("Member drops must use members visibility.");
  }
}

async function validateCreatorRoadmapLinkedEntities(input: {
  creatorUserId: string;
  itemType?: CreatorRoadmapItemType | null;
  visibility?: CreatorRoadmapVisibility | null;
  linkedCollectionId?: string | null;
  linkedChallengeId?: string | null;
}) {
  if (!db) throw new Error("Database unavailable");

  if (input.linkedCollectionId) {
    const collectionRows = await db
      .select({ id: drinkCollections.id })
      .from(drinkCollections)
      .where(and(eq(drinkCollections.id, input.linkedCollectionId), eq(drinkCollections.userId, input.creatorUserId)))
      .limit(1);

    if (!collectionRows[0]) {
      throw new Error("Linked collection must belong to the creator.");
    }
  }

  if (input.linkedChallengeId) {
    const challengeRows = await db
      .select({ id: drinkChallenges.id })
      .from(drinkChallenges)
      .where(eq(drinkChallenges.id, input.linkedChallengeId))
      .limit(1);

    if (!challengeRows[0]) {
      throw new Error("Linked challenge was not found.");
    }
  }

  if (input.itemType === "member_drop" && input.visibility !== "members") {
    throw new Error("Member drop roadmap items must use members visibility.");
  }
}

async function loadCreatorPostLinkedMaps(posts: CreatorPostRecord[]) {
  if (!db || posts.length === 0) {
    return {
      creatorMap: new Map<string, Awaited<ReturnType<typeof loadUserBasicProfile>>>(),
      collectionMap: new Map<string, typeof drinkCollections.$inferSelect>(),
      challengeMap: new Map<string, typeof drinkChallenges.$inferSelect>(),
      collaborationMap: new Map<string, CreatorCollaborationRecord>(),
      collaborationProfileMap: new Map<string, { id: string; username: string | null; avatar: string | null }>(),
    };
  }

  const creatorIds = [...new Set(posts.map((post) => post.creatorUserId).filter(Boolean))];
  const collectionIds = [...new Set(posts.map((post) => post.linkedCollectionId).filter((value): value is string => Boolean(value)))];
  const challengeIds = [...new Set(posts.map((post) => post.linkedChallengeId).filter((value): value is string => Boolean(value)))];

  const [creatorRows, collectionRows, challengeRows] = await Promise.all([
    creatorIds.length === 0
      ? Promise.resolve([] as Array<{ id: string; username: string | null; avatar: string | null }>)
      : db
        .select({ id: users.id, username: users.username, avatar: users.avatar })
        .from(users)
        .where(inArray(users.id, creatorIds)),
    collectionIds.length === 0
      ? Promise.resolve([] as Array<typeof drinkCollections.$inferSelect>)
      : db.select().from(drinkCollections).where(inArray(drinkCollections.id, collectionIds)),
    challengeIds.length === 0
      ? Promise.resolve([] as Array<typeof drinkChallenges.$inferSelect>)
      : db.select().from(drinkChallenges).where(inArray(drinkChallenges.id, challengeIds)),
  ]);
  const collaborationMap = await loadAcceptedCollaborationsForTargets(
    posts.map((post) => ({ collaborationType: "post" as const, targetId: post.id })),
  );
  const collaborationProfileMap = await loadCreatorProfilesMap(
    [...collaborationMap.values()].flatMap((row) => [row.ownerCreatorUserId, row.collaboratorUserId]),
  );

  return {
    creatorMap: new Map(creatorRows.map((row) => [row.id, row])),
    collectionMap: new Map(collectionRows.map((row) => [row.id, row])),
    challengeMap: new Map(challengeRows.map((row) => [row.id, row])),
    collaborationMap,
    collaborationProfileMap,
  };
}

