function toMilestoneDate(value?: Date | null) {
  return value ? value.toISOString() : null;
}

function buildCampaignGoalProgress(goalType: CreatorCampaignGoalType, analytics: CreatorCampaignAnalyticsItem): CreatorCampaignGoalProgress {
  switch (goalType) {
    case "followers":
      return {
        currentValue: analytics.followerCount,
        percentComplete: 0,
        isComplete: false,
        metricLabel: "Campaign followers",
        metricNote: "Direct: counts explicit campaign follows.",
      };
    case "rsvps":
      return {
        currentValue: analytics.totalDropRsvps,
        percentComplete: 0,
        isComplete: false,
        metricLabel: "Linked drop RSVPs",
        metricNote: "Direct: rolls up linked drop RSVP / Notify Me activity.",
      };
    case "clicks":
      return {
        currentValue: analytics.totalDropClicks,
        percentComplete: 0,
        isComplete: false,
        metricLabel: "Linked drop clicks",
        metricNote: "Direct: click-throughs from linked drop analytics.",
      };
    case "purchases":
      return {
        currentValue: analytics.purchasesFromLinkedCollections,
        percentComplete: 0,
        isComplete: false,
        metricLabel: "Linked collection purchases",
        metricNote: analytics.purchasesFromLinkedCollectionsNote,
      };
    case "membership_conversions":
      return {
        currentValue: analytics.membershipsFromCampaign,
        percentComplete: 0,
        isComplete: false,
        metricLabel: "Membership conversions",
        metricNote: analytics.membershipsFromCampaignNote,
      };
    case "linked_drop_views":
      return {
        currentValue: analytics.totalDropViews,
        percentComplete: 0,
        isComplete: false,
        metricLabel: "Linked drop views",
        metricNote: "Directional: rolls up existing linked drop view events.",
      };
    default:
      return {
        currentValue: 0,
        percentComplete: 0,
        isComplete: false,
        metricLabel: "Progress",
        metricNote: null,
      };
  }
}

function serializeCreatorCampaignGoal(
  goal: CreatorCampaignGoalRecord,
  analytics: CreatorCampaignAnalyticsItem | null,
): SerializedCreatorCampaignGoal {
  const baseProgress = analytics
    ? buildCampaignGoalProgress(goal.goalType as CreatorCampaignGoalType, analytics)
    : {
        currentValue: 0,
        percentComplete: 0,
        isComplete: false,
        metricLabel: "Progress",
        metricNote: null,
      };
  const targetValue = Number(goal.targetValue ?? 0);
  const percentComplete = targetValue > 0
    ? Math.min(100, Math.round((baseProgress.currentValue / targetValue) * 1000) / 10)
    : 0;
  const isComplete = targetValue > 0 && baseProgress.currentValue >= targetValue;

  return {
    id: goal.id,
    campaignId: goal.campaignId,
    goalType: goal.goalType as CreatorCampaignGoalType,
    targetValue,
    label: goal.label ?? null,
    createdAt: goal.createdAt.toISOString(),
    updatedAt: goal.updatedAt.toISOString(),
    currentValue: baseProgress.currentValue,
    percentComplete,
    isComplete,
    metricLabel: baseProgress.metricLabel,
    metricNote: baseProgress.metricNote,
  };
}

function findNthAchievementDate<T extends { createdAt: Date }>(rows: T[], target: number) {
  if (rows.length < target || target <= 0) return null;
  return rows[target - 1]?.createdAt ?? null;
}

function isDateWithinRange(value: Date, startsAt: Date, endsAt: Date) {
  return value >= startsAt && value <= endsAt;
}

function campaignWasActiveWithinRange(
  campaign: Pick<CreatorCampaignRecord, "startsAt" | "endsAt" | "createdAt" | "isActive">,
  startsAt: Date,
  endsAt: Date,
) {
  if (!campaign.isActive) return false;
  const campaignStartsAt = campaign.startsAt ?? campaign.createdAt;
  const campaignEndsAt = campaign.endsAt ?? endsAt;
  return campaignStartsAt <= endsAt && campaignEndsAt >= startsAt;
}

function buildCreatorCampaignMilestones(input: {
  campaign: CreatorCampaignRecord;
  links: CreatorCampaignLinkRecord[];
  isMemberFocusedCampaign: boolean;
  followerCount: number;
  followRows: Array<{ createdAt: Date }>;
  dropRows: Array<Pick<CreatorDropRecord, "id" | "dropType" | "isPublished" | "scheduledFor">>;
  totalDropRsvps: number;
  rsvpRows: Array<{ createdAt: Date }>;
  totalDropClicks: number;
  clickRows: Array<{ createdAt: Date }>;
  purchasesFromLinkedCollections: number;
  purchaseRows: Array<{ createdAt: Date }>;
  membershipsFromCampaign: number;
  membershipRows: Array<{ createdAt: Date }>;
}) {
  const now = new Date();
  const state = getCreatorCampaignState(input.campaign, now);
  const launchedAt = input.campaign.startsAt && input.campaign.startsAt <= now
    ? input.campaign.startsAt
    : state !== "upcoming"
      ? input.campaign.createdAt
      : null;
  const sortedLiveDrops = input.dropRows
    .filter((drop) => drop.isPublished && drop.scheduledFor <= now)
    .sort((a, b) => a.scheduledFor.getTime() - b.scheduledFor.getTime());
  const firstDropLiveAt = sortedLiveDrops[0]?.scheduledFor ?? null;
  const firstCollectionLinkedAt = input.links
    .filter((link) => link.targetType === "collection")
    .sort((a, b) => a.createdAt.getTime() - b.createdAt.getTime())[0]?.createdAt ?? null;
  const memberCampaignLaunchAt = input.isMemberFocusedCampaign && state !== "upcoming"
    ? launchedAt ?? input.campaign.createdAt
    : null;

  const milestones: CreatorCampaignMilestone[] = [
    {
      type: "campaign_live",
      label: state === "active" ? "Live now" : "Campaign launched",
      shortLabel: state === "active" ? "Live now" : "Launched",
      description: "The campaign has started and is actively part of the creator story arc.",
      achieved: Boolean(launchedAt),
      achievedAt: toMilestoneDate(launchedAt),
      isPublic: true,
      currentValue: null,
      targetValue: null,
    },
    {
      type: "first_drop_live",
      label: "First drop live",
      shortLabel: "Drop live",
      description: "At least one linked drop has gone live inside this campaign.",
      achieved: Boolean(firstDropLiveAt),
      achievedAt: toMilestoneDate(firstDropLiveAt),
      isPublic: true,
      currentValue: Number(sortedLiveDrops.length),
      targetValue: 1,
    },
    {
      type: "first_collection_linked",
      label: "Collection linked",
      shortLabel: "Collection linked",
      description: "The campaign has a linked collection for followers to explore or purchase.",
      achieved: Boolean(firstCollectionLinkedAt),
      achievedAt: toMilestoneDate(firstCollectionLinkedAt),
      isPublic: true,
      currentValue: input.links.filter((link) => link.targetType === "collection").length,
      targetValue: 1,
    },
    {
      type: "first_sale_from_campaign",
      label: "First campaign sale",
      shortLabel: "First sale",
      description: "A linked collection has recorded its first completed purchase during the campaign window.",
      achieved: input.purchasesFromLinkedCollections > 0,
      achievedAt: toMilestoneDate(input.purchaseRows[0]?.createdAt ?? null),
      isPublic: true,
      currentValue: input.purchasesFromLinkedCollections,
      targetValue: 1,
    },
    {
      type: "first_membership_conversion",
      label: "First membership conversion",
      shortLabel: "First member",
      description: "The campaign has driven its first membership conversion proxy.",
      achieved: input.membershipsFromCampaign > 0,
      achievedAt: toMilestoneDate(input.membershipRows[0]?.createdAt ?? null),
      isPublic: false,
      currentValue: input.membershipsFromCampaign,
      targetValue: 1,
    },
    {
      type: "member_campaign_launched",
      label: "Member campaign launched",
      shortLabel: "Member campaign",
      description: "This campaign includes member-focused access or member drops.",
      achieved: Boolean(memberCampaignLaunchAt),
      achievedAt: toMilestoneDate(memberCampaignLaunchAt),
      isPublic: false,
      currentValue: null,
      targetValue: null,
    },
    ...([10, 50, 100] as const).map((target) => ({
      type: `campaign_followers_${target}` as const,
      label: `${target} campaign followers`,
      shortLabel: `${target} followers`,
      description: `Followers are explicitly subscribing to this campaign story arc.`,
      achieved: input.followerCount >= target,
      achievedAt: toMilestoneDate(findNthAchievementDate(input.followRows, target)),
      isPublic: true,
      currentValue: input.followerCount,
      targetValue: target,
    })),
    ...([10, 50] as const).map((target) => ({
      type: `campaign_rsvps_${target}` as const,
      label: `${target} RSVP interest`,
      shortLabel: `${target} RSVPs`,
      description: `Linked drops have collected ${target}+ RSVPs or Notify Me signups.`,
      achieved: input.totalDropRsvps >= target,
      achievedAt: toMilestoneDate(findNthAchievementDate(input.rsvpRows, target)),
      isPublic: true,
      currentValue: input.totalDropRsvps,
      targetValue: target,
    })),
    {
      type: "campaign_clicks_100",
      label: "100 click-throughs",
      shortLabel: "100 clicks",
      description: "Linked drops have generated 100 or more click-through events.",
      achieved: input.totalDropClicks >= 100,
      achievedAt: toMilestoneDate(findNthAchievementDate(input.clickRows, 100)),
      isPublic: false,
      currentValue: input.totalDropClicks,
      targetValue: 100,
    },
  ];

  return milestones;
}

async function loadCreatorCampaignPerformanceSnapshots(creatorUserId: string) {
  if (!db) throw new Error("Database unavailable");

  const campaigns = await db
    .select()
    .from(creatorCampaigns)
    .where(eq(creatorCampaigns.creatorUserId, creatorUserId))
    .orderBy(desc(creatorCampaigns.updatedAt))
    .limit(120);

  if (campaigns.length === 0) {
    return {
      summary: {
        totalCampaigns: 0,
        activeCampaigns: 0,
        totalCampaignFollowers: 0,
        totalCampaignDropRsvps: 0,
        totalCampaignClicks: 0,
        totalCampaignPurchases: 0,
        totalCampaignMembershipConversions: 0,
      } satisfies CreatorCampaignAnalyticsSummary,
      items: [] as CreatorCampaignAnalyticsItem[],
      attributionNotes: [
        "Campaign follower counts come from explicit campaign follows.",
        "Drop RSVP, view, and click metrics roll up linked drop analytics that already exist elsewhere in the creator dashboard.",
        "Purchases from linked collections are approximate and count completed purchases made during the campaign window.",
        "Membership conversions are approximate and only shown for member-focused campaigns that have member visibility, member drops, or members-only collections.",
        "Milestones are derived from existing campaign analytics so creators get momentum badges without managing another system.",
        "Campaign engagement score is a lightweight weighted score for comparison, not a payout or attribution metric.",
      ],
      generatedAt: new Date().toISOString(),
    };
  }

  const campaignIds = campaigns.map((campaign) => campaign.id);
  const [linkMap, followerCountMap, followRows, membershipRows] = await Promise.all([
    loadCreatorCampaignLinksByCampaignIds(campaignIds),
    loadCampaignFollowerCountMap(campaignIds),
    db.select({
      campaignId: creatorCampaignFollows.campaignId,
      createdAt: creatorCampaignFollows.createdAt,
    }).from(creatorCampaignFollows).where(inArray(creatorCampaignFollows.campaignId, campaignIds)).orderBy(asc(creatorCampaignFollows.createdAt)),
    db.select({
      createdAt: creatorMemberships.createdAt,
      status: creatorMemberships.status,
    }).from(creatorMemberships).where(eq(creatorMemberships.creatorUserId, creatorUserId)).orderBy(asc(creatorMemberships.createdAt)),
  ]);

  const dropIds = [...new Set(
    campaigns.flatMap((campaign) => (linkMap.get(campaign.id) ?? [])
      .filter((link) => link.targetType === "drop")
      .map((link) => link.targetId)),
  )];
  const collectionIds = [...new Set(
    campaigns.flatMap((campaign) => (linkMap.get(campaign.id) ?? [])
      .filter((link) => link.targetType === "collection")
      .map((link) => link.targetId)),
  )];

  const [dropRows, collectionRows, eventRows, eventActivityRows, rsvpCountRows, rsvpActivityRows, purchaseRows] = await Promise.all([
    dropIds.length
      ? db.select({
          id: creatorDrops.id,
          dropType: creatorDrops.dropType,
          isPublished: creatorDrops.isPublished,
          scheduledFor: creatorDrops.scheduledFor,
        }).from(creatorDrops).where(inArray(creatorDrops.id, dropIds))
      : Promise.resolve([] as Array<Pick<CreatorDropRecord, "id" | "dropType" | "isPublished" | "scheduledFor">>),
    collectionIds.length
      ? db.select({
          id: drinkCollections.id,
          accessType: drinkCollections.accessType,
        }).from(drinkCollections).where(inArray(drinkCollections.id, collectionIds))
      : Promise.resolve([] as Array<{ id: string; accessType: string | null }>),
    dropIds.length
      ? db.select({
          dropId: creatorDropEvents.dropId,
          eventType: creatorDropEvents.eventType,
          count: sql<number>`count(*)::int`,
        }).from(creatorDropEvents).where(inArray(creatorDropEvents.dropId, dropIds)).groupBy(creatorDropEvents.dropId, creatorDropEvents.eventType)
      : Promise.resolve([] as Array<{ dropId: string; eventType: string; count: number }>),
    dropIds.length
      ? db.select({
          dropId: creatorDropEvents.dropId,
          eventType: creatorDropEvents.eventType,
          createdAt: creatorDropEvents.createdAt,
        }).from(creatorDropEvents).where(inArray(creatorDropEvents.dropId, dropIds)).orderBy(asc(creatorDropEvents.createdAt))
      : Promise.resolve([] as Array<{ dropId: string; eventType: string; createdAt: Date }>),
    dropIds.length
      ? db.select({
          dropId: creatorDropRsvps.dropId,
          count: sql<number>`count(*)::int`,
        }).from(creatorDropRsvps).where(inArray(creatorDropRsvps.dropId, dropIds)).groupBy(creatorDropRsvps.dropId)
      : Promise.resolve([] as Array<{ dropId: string; count: number }>),
    dropIds.length
      ? db.select({
          dropId: creatorDropRsvps.dropId,
          createdAt: creatorDropRsvps.createdAt,
        }).from(creatorDropRsvps).where(inArray(creatorDropRsvps.dropId, dropIds)).orderBy(asc(creatorDropRsvps.createdAt))
      : Promise.resolve([] as Array<{ dropId: string; createdAt: Date }>),
    collectionIds.length
      ? db.select({
          collectionId: drinkCollectionPurchases.collectionId,
          createdAt: drinkCollectionPurchases.createdAt,
          status: drinkCollectionPurchases.status,
        }).from(drinkCollectionPurchases).where(inArray(drinkCollectionPurchases.collectionId, collectionIds)).orderBy(asc(drinkCollectionPurchases.createdAt))
      : Promise.resolve([] as Array<{ collectionId: string; createdAt: Date; status: string }>),
  ]);

  const dropMap = new Map(dropRows.map((row) => [row.id, row]));
  const collectionMap = new Map(collectionRows.map((row) => [row.id, row]));
  const rsvpCountMap = new Map(rsvpCountRows.map((row) => [row.dropId, Number(row.count ?? 0)]));
  const eventCountMap = new Map<string, { views: number; clicks: number }>();
  for (const row of eventRows) {
    const current = eventCountMap.get(row.dropId) ?? { views: 0, clicks: 0 };
    if (row.eventType === "view_drop") current.views = Number(row.count ?? 0);
    if (row.eventType === "click_drop_target") current.clicks = Number(row.count ?? 0);
    eventCountMap.set(row.dropId, current);
  }

  const purchaseRowsByCollectionId = new Map<string, Array<{ createdAt: Date; status: string }>>();
  for (const purchase of purchaseRows) {
    const current = purchaseRowsByCollectionId.get(purchase.collectionId) ?? [];
    current.push({ createdAt: purchase.createdAt, status: purchase.status });
    purchaseRowsByCollectionId.set(purchase.collectionId, current);
  }

  const followRowsByCampaignId = new Map<string, Array<{ createdAt: Date }>>();
  for (const follow of followRows) {
    const current = followRowsByCampaignId.get(follow.campaignId) ?? [];
    current.push({ createdAt: follow.createdAt });
    followRowsByCampaignId.set(follow.campaignId, current);
  }

  const rsvpRowsByDropId = new Map<string, Array<{ createdAt: Date }>>();
  for (const rsvp of rsvpActivityRows) {
    const current = rsvpRowsByDropId.get(rsvp.dropId) ?? [];
    current.push({ createdAt: rsvp.createdAt });
    rsvpRowsByDropId.set(rsvp.dropId, current);
  }

  const clickRowsByDropId = new Map<string, Array<{ createdAt: Date }>>();
  for (const event of eventActivityRows) {
    if (event.eventType !== "click_drop_target") continue;
    const current = clickRowsByDropId.get(event.dropId) ?? [];
    current.push({ createdAt: event.createdAt });
    clickRowsByDropId.set(event.dropId, current);
  }

  const items = campaigns.map((campaign) => {
    const links = linkMap.get(campaign.id) ?? [];
    const dropLinkIds = links.filter((link) => link.targetType === "drop").map((link) => link.targetId);
    const collectionLinkIds = links.filter((link) => link.targetType === "collection").map((link) => link.targetId);
    const followerCount = followerCountMap.get(campaign.id) ?? 0;
    const totalDropRsvps = dropLinkIds.reduce((sum, dropId) => sum + (rsvpCountMap.get(dropId) ?? 0), 0);
    const totalDropViews = dropLinkIds.reduce((sum, dropId) => sum + (eventCountMap.get(dropId)?.views ?? 0), 0);
    const totalDropClicks = dropLinkIds.reduce((sum, dropId) => sum + (eventCountMap.get(dropId)?.clicks ?? 0), 0);
    const purchasesFromLinkedCollections = collectionLinkIds.reduce((sum, collectionId) => {
      const count = (purchaseRowsByCollectionId.get(collectionId) ?? []).filter((purchase) => (
        purchase.status === "completed" && isDateWithinCampaignAnalyticsWindow(purchase.createdAt, campaign)
      )).length;
      return sum + count;
    }, 0);
    const isMemberFocusedCampaign = campaign.visibility === "members"
      || dropLinkIds.some((dropId) => (dropMap.get(dropId)?.dropType ?? "") === "member_drop")
      || collectionLinkIds.some((collectionId) => (collectionMap.get(collectionId)?.accessType ?? "") === "membership_only");
    const membershipActivityRows = isMemberFocusedCampaign
      ? membershipRows.filter((membership) => isDateWithinCampaignAnalyticsWindow(membership.createdAt, campaign))
      : [];
    const membershipsFromCampaign = membershipActivityRows.length;
    const campaignEngagementScore = Math.round(
      followerCount
      + totalDropRsvps * 2
      + totalDropClicks * 3
      + purchasesFromLinkedCollections * 5
      + membershipsFromCampaign * 6
      + totalDropViews * 0.25
      + links.filter((link) => link.targetType === "post").length
    );

    const purchaseActivityRows = collectionLinkIds.flatMap((collectionId) => (
      purchaseRowsByCollectionId.get(collectionId) ?? []
    )).filter((purchase) => (
      purchase.status === "completed" && isDateWithinCampaignAnalyticsWindow(purchase.createdAt, campaign)
    )).sort((a, b) => a.createdAt.getTime() - b.createdAt.getTime());

    const campaignRsvpRows = dropLinkIds.flatMap((dropId) => rsvpRowsByDropId.get(dropId) ?? [])
      .sort((a, b) => a.createdAt.getTime() - b.createdAt.getTime());

    const milestones = buildCreatorCampaignMilestones({
      campaign,
      links,
      isMemberFocusedCampaign,
      followerCount,
      followRows: followRowsByCampaignId.get(campaign.id) ?? [],
      dropRows: dropLinkIds.map((dropId) => dropMap.get(dropId)).filter((drop): drop is Pick<CreatorDropRecord, "id" | "dropType" | "isPublished" | "scheduledFor"> => Boolean(drop)),
      totalDropRsvps,
      rsvpRows: campaignRsvpRows,
      totalDropClicks,
      clickRows: dropLinkIds.flatMap((dropId) => clickRowsByDropId.get(dropId) ?? [])
        .sort((a, b) => a.createdAt.getTime() - b.createdAt.getTime()),
      purchasesFromLinkedCollections,
      purchaseRows: purchaseActivityRows,
      membershipsFromCampaign,
      membershipRows: membershipActivityRows,
    });

    return {
      campaignId: campaign.id,
      slug: campaign.slug,
      name: campaign.name,
      visibility: campaign.visibility as CreatorCampaignVisibility,
      isActive: Boolean(campaign.isActive),
      startsAt: campaign.startsAt ? campaign.startsAt.toISOString() : null,
      endsAt: campaign.endsAt ? campaign.endsAt.toISOString() : null,
      followerCount,
      linkedDropsCount: dropLinkIds.length,
      linkedPostsCount: links.filter((link) => link.targetType === "post").length,
      linkedCollectionsCount: collectionLinkIds.length,
      linkedChallengesCount: links.filter((link) => link.targetType === "challenge").length,
      totalDropRsvps,
      totalDropViews,
      totalDropClicks,
      purchasesFromLinkedCollections,
      purchasesFromLinkedCollectionsNote: collectionLinkIds.length
        ? "Approximate: counts completed linked-collection purchases inside the campaign window."
        : null,
      membershipsFromCampaign,
      membershipsFromCampaignNote: isMemberFocusedCampaign
        ? "Approximate: counts memberships that started during this campaign window for member-focused campaign content."
        : null,
      campaignEngagementScore,
      campaignEngagementScoreNote: "Weighted comparison score using followers, RSVP interest, click-throughs, and approximate conversions.",
      milestones,
    } satisfies CreatorCampaignAnalyticsItem;
  });

  return {
    summary: {
      totalCampaigns: items.length,
      activeCampaigns: campaigns.filter((campaign) => getCreatorCampaignState(campaign) === "active").length,
      totalCampaignFollowers: items.reduce((sum, item) => sum + item.followerCount, 0),
      totalCampaignDropRsvps: items.reduce((sum, item) => sum + item.totalDropRsvps, 0),
      totalCampaignClicks: items.reduce((sum, item) => sum + item.totalDropClicks, 0),
      totalCampaignPurchases: items.reduce((sum, item) => sum + item.purchasesFromLinkedCollections, 0),
      totalCampaignMembershipConversions: items.reduce((sum, item) => sum + item.membershipsFromCampaign, 0),
    } satisfies CreatorCampaignAnalyticsSummary,
    items,
    attributionNotes: [
      "Campaign follower counts come from explicit campaign follows.",
      "Drop RSVP, view, and click metrics roll up linked drop analytics that already exist elsewhere in the creator dashboard.",
      "Purchases from linked collections are approximate and count completed purchases made during the campaign window.",
      "Membership conversions are approximate and only shown for member-focused campaigns that have member visibility, member drops, or members-only collections.",
      "Milestones are derived from existing campaign follows, linked drop RSVPs, click activity, and conversion proxies.",
      "Campaign engagement score is a lightweight weighted score for comparison, not a payout or attribution metric.",
    ],
    generatedAt: new Date().toISOString(),
  };
}

function getCreatorCampaignAnalyticsWindow(campaign: Pick<CreatorCampaignRecord, "startsAt" | "endsAt" | "createdAt">) {
  return {
    startsAt: campaign.startsAt ?? campaign.createdAt,
    endsAt: campaign.endsAt ?? new Date(),
  };
}

function isDateWithinCampaignAnalyticsWindow(value: Date, campaign: Pick<CreatorCampaignRecord, "startsAt" | "endsAt" | "createdAt">) {
  const window = getCreatorCampaignAnalyticsWindow(campaign);
  return value >= window.startsAt && value <= window.endsAt;
}

async function loadCreatorFollowerRelationshipRows(creatorUserId: string) {
  if (!db) throw new Error("Database unavailable");
  return db
    .select({
      userId: follows.followerId,
      createdAt: follows.createdAt,
    })
    .from(follows)
    .where(eq(follows.followingId, creatorUserId))
    .orderBy(asc(follows.createdAt));
}

function groupCreatedAtRowsByUserId<T extends { userId: string | null | undefined; createdAt: Date }>(rows: T[]) {
  const grouped = new Map<string, Date[]>();
  for (const row of rows) {
    const userId = typeof row.userId === "string" ? row.userId.trim() : "";
    if (!userId) continue;
    const current = grouped.get(userId) ?? [];
    current.push(row.createdAt);
    grouped.set(userId, current);
  }
  for (const dates of grouped.values()) {
    dates.sort((a, b) => a.getTime() - b.getTime());
  }
  return grouped;
}

function groupMembershipRowsByUserId(rows: CreatorMembershipRecord[]) {
  const grouped = new Map<string, CreatorMembershipRecord[]>();
  for (const row of rows) {
    const userId = typeof row.userId === "string" ? row.userId.trim() : "";
    if (!userId) continue;
    const current = grouped.get(userId) ?? [];
    current.push(row);
    grouped.set(userId, current);
  }
  for (const memberships of grouped.values()) {
    memberships.sort((a, b) => a.createdAt.getTime() - b.createdAt.getTime());
  }
  return grouped;
}

function classifyCreatorAudienceSegmentAt(input: {
  userId: string | null | undefined;
  occurredAt: Date;
  creatorFollowMap: Map<string, Date[]>;
  creatorMembershipMap: Map<string, CreatorMembershipRecord[]>;
}): CreatorCampaignAudienceSegment {
  const userId = typeof input.userId === "string" ? input.userId.trim() : "";
  if (!userId) return "public";

  const memberships = input.creatorMembershipMap.get(userId) ?? [];
  if (memberships.some((membership) => membership.createdAt <= input.occurredAt && isCreatorMembershipActiveRecord(membership, input.occurredAt))) {
    return "members";
  }

  const followDates = input.creatorFollowMap.get(userId) ?? [];
  if (followDates.some((createdAt) => createdAt <= input.occurredAt)) {
    return "followers";
  }

  return "public";
}

function classifyMembershipConversionAudienceSegment(input: {
  userId: string | null | undefined;
  occurredAt: Date;
  creatorFollowMap: Map<string, Date[]>;
}): CreatorCampaignAudienceSegment {
  const userId = typeof input.userId === "string" ? input.userId.trim() : "";
  if (!userId) return "public";
  const followDates = input.creatorFollowMap.get(userId) ?? [];
  return followDates.some((createdAt) => createdAt < input.occurredAt) ? "followers" : "public";
}

function createEmptyAudienceFitSegment(audience: CreatorCampaignAudienceSegment): CreatorCampaignAudienceFitSegmentSummary {
  return {
    audience,
    campaignFollows: 0,
    dropRsvps: 0,
    dropViews: 0,
    dropClicks: 0,
    purchases: 0,
    memberships: 0,
    weightedScore: 0,
    weightedScoreNote: "Weighted score favors explicit follow, RSVP, click, purchase, and membership signals over passive views.",
  };
}

function finalizeAudienceFitSegment(segment: CreatorCampaignAudienceFitSegmentSummary) {
  segment.weightedScore = Math.round(
    segment.campaignFollows * 4
    + segment.dropRsvps * 3
    + segment.dropClicks * 3
    + segment.purchases * 5
    + segment.memberships * 6
    + segment.dropViews * 0.25
  );
  return segment;
}

function formatAudienceSegmentLabel(audience: CreatorCampaignAudienceSegment) {
  switch (audience) {
    case "followers":
      return "follower audience";
    case "members":
      return "member audience";
    case "public":
    default:
      return "public audience";
  }
}

function buildAudienceFitReason(input: {
  bestSegment: CreatorCampaignAudienceFitSegmentSummary;
  nextSegment: CreatorCampaignAudienceFitSegmentSummary | null;
}): { confidence: CreatorCampaignAudienceFitConfidence; reason: string | null } {
  if (input.bestSegment.weightedScore <= 0) {
    return {
      confidence: "none",
      reason: "No segment has enough current signal yet — this reads as too early to call honestly.",
    };
  }

  const margin = input.nextSegment ? input.bestSegment.weightedScore - input.nextSegment.weightedScore : input.bestSegment.weightedScore;
  const confidence: CreatorCampaignAudienceFitConfidence = margin >= 12
    ? "high"
    : margin >= 5
      ? "medium"
      : "low";

  const strongestSignals = [
    input.bestSegment.memberships > 0 ? `${input.bestSegment.memberships} memberships` : null,
    input.bestSegment.purchases > 0 ? `${input.bestSegment.purchases} purchases` : null,
    input.bestSegment.dropClicks > 0 ? `${input.bestSegment.dropClicks} clicks` : null,
    input.bestSegment.dropRsvps > 0 ? `${input.bestSegment.dropRsvps} RSVPs` : null,
    input.bestSegment.campaignFollows > 0 ? `${input.bestSegment.campaignFollows} campaign follows` : null,
    input.bestSegment.dropViews > 0 ? `${input.bestSegment.dropViews} views` : null,
  ].filter((value): value is string => Boolean(value)).slice(0, 2);

  const leadText = input.nextSegment && input.nextSegment.weightedScore > 0
    ? ` It is ahead of ${formatAudienceSegmentLabel(input.nextSegment.audience)} signals by ${margin} score points.`
    : "";

  return {
    confidence,
    reason: `${formatAudienceSegmentLabel(input.bestSegment.audience).replace(/^./, (value) => value.toUpperCase())} is leading right now from ${strongestSignals.join(" + ") || "the strongest available engagement mix"}.${leadText}`,
  };
}

async function loadCreatorCampaignAudienceFit(creatorUserId: string) {
  if (!db) throw new Error("Database unavailable");

  const [campaigns, performance, creatorFollowRows, creatorMembershipRows] = await Promise.all([
    db
      .select()
      .from(creatorCampaigns)
      .where(eq(creatorCampaigns.creatorUserId, creatorUserId))
      .orderBy(desc(creatorCampaigns.updatedAt))
      .limit(120),
    loadCreatorCampaignPerformanceSnapshots(creatorUserId),
    loadCreatorFollowerRelationshipRows(creatorUserId),
    db
      .select()
      .from(creatorMemberships)
      .where(eq(creatorMemberships.creatorUserId, creatorUserId))
      .orderBy(asc(creatorMemberships.createdAt)),
  ]);

  if (!campaigns.length) {
    return {
      summary: {
        totalCampaigns: 0,
        activeCampaigns: 0,
        publicBestFitCount: 0,
        followerBestFitCount: 0,
        memberBestFitCount: 0,
        noClearFitCount: 0,
        bestPublicCampaign: null,
        bestFollowerCampaign: null,
        bestMemberCampaign: null,
      } satisfies CreatorCampaignAudienceFitSummary,
      items: [] as CreatorCampaignAudienceFitItem[],
      attributionNotes: [
        "Audience fit uses only the platform-native audiences you already have: public, followers, and members.",
        "No campaigns exist yet for this creator, so there is no audience fit signal to summarize.",
      ],
      generatedAt: new Date().toISOString(),
    };
  }

  const campaignIds = campaigns.map((campaign) => campaign.id);
  const linkMap = await loadCreatorCampaignLinksByCampaignIds(campaignIds);
  const creatorFollowMap = groupCreatedAtRowsByUserId(creatorFollowRows);
  const creatorMembershipMap = groupMembershipRowsByUserId(creatorMembershipRows);
  const performanceByCampaignId = new Map(performance.items.map((item) => [item.campaignId, item]));

  const campaignFollowRows = await db
    .select({
      campaignId: creatorCampaignFollows.campaignId,
      userId: creatorCampaignFollows.userId,
      createdAt: creatorCampaignFollows.createdAt,
    })
    .from(creatorCampaignFollows)
    .where(inArray(creatorCampaignFollows.campaignId, campaignIds))
    .orderBy(asc(creatorCampaignFollows.createdAt));

  const dropIds = [...new Set(
    campaigns.flatMap((campaign) => (linkMap.get(campaign.id) ?? [])
      .filter((link) => link.targetType === "drop")
      .map((link) => link.targetId)),
  )];
  const collectionIds = [...new Set(
    campaigns.flatMap((campaign) => (linkMap.get(campaign.id) ?? [])
      .filter((link) => link.targetType === "collection")
      .map((link) => link.targetId)),
  )];

  const [dropRsvpRows, dropEventRows, purchaseRows] = await Promise.all([
    dropIds.length
      ? db.select({
          dropId: creatorDropRsvps.dropId,
          userId: creatorDropRsvps.userId,
          createdAt: creatorDropRsvps.createdAt,
        }).from(creatorDropRsvps).where(inArray(creatorDropRsvps.dropId, dropIds)).orderBy(asc(creatorDropRsvps.createdAt))
      : Promise.resolve([] as Array<{ dropId: string; userId: string; createdAt: Date }>),
    dropIds.length
      ? db.select({
          dropId: creatorDropEvents.dropId,
          eventType: creatorDropEvents.eventType,
          userId: creatorDropEvents.userId,
          createdAt: creatorDropEvents.createdAt,
        }).from(creatorDropEvents).where(inArray(creatorDropEvents.dropId, dropIds)).orderBy(asc(creatorDropEvents.createdAt))
      : Promise.resolve([] as Array<{ dropId: string; eventType: CreatorDropEventType; userId: string | null; createdAt: Date }>),
    collectionIds.length
      ? db.select({
          collectionId: drinkCollectionPurchases.collectionId,
          userId: drinkCollectionPurchases.userId,
          createdAt: drinkCollectionPurchases.createdAt,
          status: drinkCollectionPurchases.status,
        }).from(drinkCollectionPurchases).where(inArray(drinkCollectionPurchases.collectionId, collectionIds)).orderBy(asc(drinkCollectionPurchases.createdAt))
      : Promise.resolve([] as Array<{ collectionId: string; userId: string; createdAt: Date; status: string }>),
  ]);

  const campaignIdsByDropId = new Map<string, string[]>();
  const campaignIdsByCollectionId = new Map<string, string[]>();
  for (const campaign of campaigns) {
    const links = linkMap.get(campaign.id) ?? [];
    for (const link of links) {
      if (link.targetType === "drop") {
        const current = campaignIdsByDropId.get(link.targetId) ?? [];
        current.push(campaign.id);
        campaignIdsByDropId.set(link.targetId, current);
      }
      if (link.targetType === "collection") {
        const current = campaignIdsByCollectionId.get(link.targetId) ?? [];
        current.push(campaign.id);
        campaignIdsByCollectionId.set(link.targetId, current);
      }
    }
  }

  const segmentMaps = new Map<string, Map<CreatorCampaignAudienceSegment, CreatorCampaignAudienceFitSegmentSummary>>();
  const ensureSegment = (campaignId: string, audience: CreatorCampaignAudienceSegment) => {
    const existing = segmentMaps.get(campaignId) ?? new Map<CreatorCampaignAudienceSegment, CreatorCampaignAudienceFitSegmentSummary>();
    if (!segmentMaps.has(campaignId)) segmentMaps.set(campaignId, existing);
    const segment = existing.get(audience) ?? createEmptyAudienceFitSegment(audience);
    if (!existing.has(audience)) existing.set(audience, segment);
    return segment;
  };

  for (const campaign of campaigns) {
    ensureSegment(campaign.id, "public");
    ensureSegment(campaign.id, "followers");
    ensureSegment(campaign.id, "members");
  }

  for (const row of campaignFollowRows) {
    const audience = classifyCreatorAudienceSegmentAt({
      userId: row.userId,
      occurredAt: row.createdAt,
      creatorFollowMap,
      creatorMembershipMap,
    });
    ensureSegment(row.campaignId, audience).campaignFollows += 1;
  }

  for (const row of dropRsvpRows) {
    const campaignIdsForDrop = campaignIdsByDropId.get(row.dropId) ?? [];
    if (!campaignIdsForDrop.length) continue;
    const audience = classifyCreatorAudienceSegmentAt({
      userId: row.userId,
      occurredAt: row.createdAt,
      creatorFollowMap,
      creatorMembershipMap,
    });
    for (const campaignId of campaignIdsForDrop) {
      ensureSegment(campaignId, audience).dropRsvps += 1;
    }
  }

  for (const row of dropEventRows) {
    const campaignIdsForDrop = campaignIdsByDropId.get(row.dropId) ?? [];
    if (!campaignIdsForDrop.length) continue;
    const audience = classifyCreatorAudienceSegmentAt({
      userId: row.userId,
      occurredAt: row.createdAt,
      creatorFollowMap,
      creatorMembershipMap,
    });
    for (const campaignId of campaignIdsForDrop) {
      const segment = ensureSegment(campaignId, audience);
      if (row.eventType === "view_drop") segment.dropViews += 1;
      if (row.eventType === "click_drop_target") segment.dropClicks += 1;
    }
  }

  for (const row of purchaseRows) {
    if (row.status !== "completed") continue;
    const campaignIdsForCollection = campaignIdsByCollectionId.get(row.collectionId) ?? [];
    if (!campaignIdsForCollection.length) continue;
    const audience = classifyCreatorAudienceSegmentAt({
      userId: row.userId,
      occurredAt: row.createdAt,
      creatorFollowMap,
      creatorMembershipMap,
    });
    for (const campaignId of campaignIdsForCollection) {
      const campaign = campaigns.find((entry) => entry.id === campaignId);
      if (!campaign || !isDateWithinCampaignAnalyticsWindow(row.createdAt, campaign)) continue;
      ensureSegment(campaignId, audience).purchases += 1;
    }
  }

  for (const membership of creatorMembershipRows) {
    const audience = classifyMembershipConversionAudienceSegment({
      userId: membership.userId,
      occurredAt: membership.createdAt,
      creatorFollowMap,
    });
    for (const campaign of campaigns) {
      if (!isDateWithinCampaignAnalyticsWindow(membership.createdAt, campaign)) continue;
      const analytics = performanceByCampaignId.get(campaign.id);
      if (!analytics?.membershipsFromCampaignNote) continue;
      ensureSegment(campaign.id, audience).memberships += 1;
    }
  }

  const items = campaigns.map((campaign) => {
    const route = `/drinks/campaigns/${encodeURIComponent(campaign.slug)}`;
    const segments = ["public", "followers", "members"].map((audience) => finalizeAudienceFitSegment({ ...ensureSegment(campaign.id, audience as CreatorCampaignAudienceSegment) }));
    const sorted = [...segments].sort((a, b) => b.weightedScore - a.weightedScore || b.memberships - a.memberships || b.purchases - a.purchases || b.dropClicks - a.dropClicks || b.dropRsvps - a.dropRsvps);
    const bestSegment = sorted[0] ?? null;
    const nextSegment = sorted[1] ?? null;
    const { confidence, reason } = bestSegment
      ? buildAudienceFitReason({ bestSegment, nextSegment })
      : { confidence: "none" as CreatorCampaignAudienceFitConfidence, reason: null };
    const bestAudienceFit = bestSegment && bestSegment.weightedScore > 0 ? bestSegment.audience : null;
    const analytics = performanceByCampaignId.get(campaign.id);
    const topSignals = [
      bestSegment && bestSegment.campaignFollows > 0 ? `${bestSegment.campaignFollows} follows from ${formatAudienceSegmentLabel(bestSegment.audience)}` : null,
      bestSegment && bestSegment.dropRsvps > 0 ? `${bestSegment.dropRsvps} RSVPs from ${formatAudienceSegmentLabel(bestSegment.audience)}` : null,
      bestSegment && bestSegment.dropClicks > 0 ? `${bestSegment.dropClicks} clicks from ${formatAudienceSegmentLabel(bestSegment.audience)}` : null,
      bestSegment && bestSegment.purchases > 0 ? `${bestSegment.purchases} purchases from ${formatAudienceSegmentLabel(bestSegment.audience)}` : null,
      bestSegment && bestSegment.memberships > 0 ? `${bestSegment.memberships} memberships started by ${formatAudienceSegmentLabel(bestSegment.audience === "public" ? "public" : bestSegment.audience)}` : null,
    ].filter((value): value is string => Boolean(value)).slice(0, 3);

    return {
      campaignId: campaign.id,
      slug: campaign.slug,
      name: campaign.name,
      route,
      visibility: campaign.visibility as CreatorCampaignVisibility,
      state: getCreatorCampaignState(campaign),
      bestAudienceFit,
      bestAudienceFitConfidence: confidence,
      bestAudienceFitReason: reason,
      audienceSegments: segments,
      topSignals,
      notes: [
        "Audience segments are only public, followers, and members — no hidden micro-segments or exported ad audiences are used here.",
        "Anonymous drop traffic is counted as public because the platform cannot tie it to a follow or membership relationship.",
        "Follower and member labels use the creator relationship visible in product data at the time of the event when ChefSire can infer it.",
        analytics?.purchasesFromLinkedCollectionsNote ?? null,
        analytics?.membershipsFromCampaignNote ? "Membership starts are still approximate conversion proxies and are bucketed by pre-membership relationship when possible." : null,
      ].filter((value): value is string => Boolean(value)),
    } satisfies CreatorCampaignAudienceFitItem;
  }).sort((a, b) => {
    const scoreA = a.audienceSegments.find((segment) => segment.audience === a.bestAudienceFit)?.weightedScore ?? 0;
    const scoreB = b.audienceSegments.find((segment) => segment.audience === b.bestAudienceFit)?.weightedScore ?? 0;
    return scoreB - scoreA || a.name.localeCompare(b.name);
  });

  const bestBySegment = (audience: CreatorCampaignAudienceSegment) => {
    const best = items
      .map((item) => ({ item, segment: item.audienceSegments.find((entry) => entry.audience === audience) ?? null }))
      .filter((entry): entry is { item: CreatorCampaignAudienceFitItem; segment: CreatorCampaignAudienceFitSegmentSummary } => Boolean(entry.segment && entry.segment.weightedScore > 0))
      .sort((a, b) => b.segment.weightedScore - a.segment.weightedScore || a.item.name.localeCompare(b.item.name))[0];
    return best ? {
      campaignId: best.item.campaignId,
      name: best.item.name,
      slug: best.item.slug,
      route: best.item.route,
      weightedScore: best.segment.weightedScore,
    } : null;
  };

  return {
    summary: {
      totalCampaigns: items.length,
      activeCampaigns: items.filter((item) => item.state === "active").length,
      publicBestFitCount: items.filter((item) => item.bestAudienceFit === "public").length,
      followerBestFitCount: items.filter((item) => item.bestAudienceFit === "followers").length,
      memberBestFitCount: items.filter((item) => item.bestAudienceFit === "members").length,
      noClearFitCount: items.filter((item) => !item.bestAudienceFit).length,
      bestPublicCampaign: bestBySegment("public"),
      bestFollowerCampaign: bestBySegment("followers"),
      bestMemberCampaign: bestBySegment("members"),
    } satisfies CreatorCampaignAudienceFitSummary,
    items,
    attributionNotes: [
      "Audience fit stays inside existing drinks-platform audiences only: public, followers, and members.",
      "Segments are mutually exclusive inside this summary: member overrides follower, follower overrides public, and anonymous traffic rolls into public.",
      "Follower and member buckets use relationship timing when the platform can infer it from creator follows or membership records, but they are still lightweight creator insights rather than a full attribution warehouse.",
      "Purchases and memberships remain approximate anywhere the underlying campaign analytics are already approximate.",
      "Best audience fit is a weighted comparison signal to help creators learn which audience is responding most, not a delivery guarantee or targeting engine.",
    ],
    generatedAt: new Date().toISOString(),
  };
}

async function loadCreatorCampaignAnalytics(creatorUserId: string) {
  return loadCreatorCampaignPerformanceSnapshots(creatorUserId);
}

function roundRate(value: number) {
  return Math.round(value * 1000) / 10;
}

function campaignFunnelStepLabel(step: CreatorCampaignFunnelStepKey) {
  switch (step) {
    case "views":
      return "Views";
    case "clicks":
      return "Clicks";
    case "follows":
      return "Follows";
    case "rsvps":
      return "RSVPs";
    case "purchases":
      return "Purchases";
    case "memberships":
      return "Memberships";
    default:
      return "Step";
  }
}

function campaignFunnelStepDescription(step: CreatorCampaignFunnelStepKey) {
  switch (step) {
    case "views":
      return "Linked drop views already tracked on the drinks platform.";
    case "clicks":
      return "Linked drop click-throughs.";
    case "follows":
      return "Explicit campaign follows.";
    case "rsvps":
      return "Linked drop RSVPs / Notify Me signups.";
    case "purchases":
      return "Approximate linked collection purchases inside the campaign window.";
    case "memberships":
      return "Approximate campaign-window membership starts for member-focused campaigns.";
    default:
      return "Campaign funnel signal.";
  }
}

function buildCreatorCampaignFunnelStep(input: {
  key: CreatorCampaignFunnelStepKey;
  count: number;
  note?: string | null;
}) {
  return {
    key: input.key,
    label: campaignFunnelStepLabel(input.key),
    count: input.count,
    description: campaignFunnelStepDescription(input.key),
    note: input.note ?? null,
  } satisfies CreatorCampaignFunnelStep;
}

function buildCreatorCampaignFunnelTransition(input: {
  from: CreatorCampaignFunnelStep;
  to: CreatorCampaignFunnelStep;
}) {
  const retainedCount = Math.min(input.from.count, input.to.count);
  const leakedCount = Math.max(input.from.count - input.to.count, 0);
  const expansionCount = Math.max(input.to.count - input.from.count, 0);
  const retentionRate = input.from.count > 0 ? roundRate((retainedCount / input.from.count) * 100) : null;
  const leakageRate = input.from.count > 0 ? roundRate((leakedCount / input.from.count) * 100) : null;

  let severity: CreatorCampaignFunnelTransitionSeverity = "healthy";
  let headline = `${input.from.label} are holding into ${input.to.label.toLowerCase()}.`;
  let reason = `${retainedCount} of ${input.from.count} ${input.from.label.toLowerCase()} progressed to ${input.to.label.toLowerCase()}.`;
  let suggestedFocus = `Keep the current ${input.from.label.toLowerCase()} → ${input.to.label.toLowerCase()} handoff.`;

  if (input.from.count < 10) {
    severity = "insufficient_signal";
    headline = `Too little ${input.from.label.toLowerCase()} signal to judge ${input.to.label.toLowerCase()} leakage honestly yet.`;
    reason = `Only ${input.from.count} ${input.from.label.toLowerCase()} are in this step, so ChefSire keeps this transition diagnostic light for now.`;
    suggestedFocus = `Wait for more ${input.from.label.toLowerCase()} volume before treating this as a real bottleneck.`;
  } else if (expansionCount > 0) {
    severity = "alternate_path";
    headline = `${input.to.label} are outpacing ${input.from.label.toLowerCase()} signal.`;
    reason = `${input.to.count} ${input.to.label.toLowerCase()} exceed ${input.from.count} ${input.from.label.toLowerCase()}, which usually means people are entering later in the funnel through another native path.`;
    suggestedFocus = `Treat ${input.to.label.toLowerCase()} as an alternate entry path instead of a leak from ${input.from.label.toLowerCase()}.`;
  } else if ((retentionRate ?? 0) < 8 || retainedCount === 0) {
    severity = "critical";
    headline = `${input.from.label} are dropping hard before ${input.to.label.toLowerCase()}.`;
    reason = `${leakedCount} of ${input.from.count} ${input.from.label.toLowerCase()} are not reaching ${input.to.label.toLowerCase()} (${leakageRate}% leakage).`;
    suggestedFocus = `Tighten the ${input.from.label.toLowerCase()} → ${input.to.label.toLowerCase()} handoff next.`;
  } else if ((retentionRate ?? 0) < 20) {
    severity = "high";
    headline = `${input.from.label} are leaking meaningfully before ${input.to.label.toLowerCase()}.`;
    reason = `${leakedCount} of ${input.from.count} ${input.from.label.toLowerCase()} fall out before ${input.to.label.toLowerCase()} (${leakageRate}% leakage).`;
    suggestedFocus = `This looks like the clearest place to improve momentum right now.`;
  } else if ((retentionRate ?? 0) < 40) {
    severity = "watch";
    headline = `${input.from.label} are softening before ${input.to.label.toLowerCase()}.`;
    reason = `${retainedCount} of ${input.from.count} ${input.from.label.toLowerCase()} are carrying forward (${retentionRate}% retention).`;
    suggestedFocus = `Worth monitoring if this transition stays soft across more campaigns or more volume.`;
  }

  return {
    fromStep: input.from.key,
    toStep: input.to.key,
    fromLabel: input.from.label,
    toLabel: input.to.label,
    fromCount: input.from.count,
    toCount: input.to.count,
    retainedCount,
    leakedCount,
    expansionCount,
    retentionRate,
    leakageRate,
    severity,
    headline,
    reason,
    suggestedFocus,
  } satisfies CreatorCampaignFunnelTransition;
}

function averageFunnelTransitionRate(items: CreatorCampaignFunnelBottleneckItem[], fromStep: CreatorCampaignFunnelStepKey, toStep: CreatorCampaignFunnelStepKey) {
  const rates = items
    .flatMap((item) => item.transitions)
    .filter((transition) => transition.fromStep === fromStep && transition.toStep === toStep && typeof transition.retentionRate === "number")
    .map((transition) => transition.retentionRate as number);
  if (!rates.length) return null;
  return roundRate(rates.reduce((sum, value) => sum + value, 0) / rates.length);
}

async function loadCreatorCampaignFunnelBottlenecks(creatorUserId: string, campaignId?: string | null) {
  if (!db) throw new Error("Database unavailable");

  const [campaigns, performance] = await Promise.all([
    db
      .select()
      .from(creatorCampaigns)
      .where(eq(creatorCampaigns.creatorUserId, creatorUserId))
      .orderBy(desc(creatorCampaigns.updatedAt))
      .limit(120),
    loadCreatorCampaignPerformanceSnapshots(creatorUserId),
  ]);

  const filteredCampaigns = campaignId
    ? campaigns.filter((campaign) => campaign.id === campaignId)
    : campaigns;

  const performanceByCampaignId = new Map(performance.items.map((item) => [item.campaignId, item]));

  const items = filteredCampaigns.map((campaign) => {
    const analytics = performanceByCampaignId.get(campaign.id);
    if (!analytics) return null;

    const memberFocused = Boolean(analytics.membershipsFromCampaignNote);
    const steps = [
      buildCreatorCampaignFunnelStep({ key: "views", count: analytics.totalDropViews, note: "Drop landing and campaign-linked view signal only — no external warehouse joins." }),
      buildCreatorCampaignFunnelStep({ key: "clicks", count: analytics.totalDropClicks }),
      buildCreatorCampaignFunnelStep({ key: "follows", count: analytics.followerCount, note: "Campaign follows can happen without a prior tracked click if people follow from a native campaign surface." }),
      buildCreatorCampaignFunnelStep({ key: "rsvps", count: analytics.totalDropRsvps, note: analytics.linkedDropsCount > 0 ? null : "No linked drops yet, so RSVP signal may stay at zero until a drop exists." }),
      buildCreatorCampaignFunnelStep({ key: "purchases", count: analytics.purchasesFromLinkedCollections, note: analytics.purchasesFromLinkedCollectionsNote }),
      buildCreatorCampaignFunnelStep({ key: "memberships", count: analytics.membershipsFromCampaign, note: memberFocused ? analytics.membershipsFromCampaignNote : "This campaign is not currently member-focused, so memberships are expected to be light or zero." }),
    ] satisfies CreatorCampaignFunnelStep[];

    const transitions = steps.slice(0, -1).map((step, index) => buildCreatorCampaignFunnelTransition({
      from: step,
      to: steps[index + 1]!,
    }));

    const topBottlenecks = transitions
      .filter((transition) => transition.severity === "critical" || transition.severity === "high" || transition.severity === "watch")
      .sort((a, b) => {
        const severityRank = (value: CreatorCampaignFunnelTransitionSeverity) => {
          switch (value) {
            case "critical":
              return 4;
            case "high":
              return 3;
            case "watch":
              return 2;
            case "healthy":
              return 1;
            default:
              return 0;
          }
        };
        return severityRank(b.severity) - severityRank(a.severity)
          || (b.leakageRate ?? -1) - (a.leakageRate ?? -1)
          || b.leakedCount - a.leakedCount;
      })
      .slice(0, 3);

    const strongestStep = [...steps].sort((a, b) => b.count - a.count || a.label.localeCompare(b.label))[0] ?? null;
    const deepestNonZeroStep = [...steps].reverse().find((step) => step.count > 0)?.key ?? null;
    const overallConversionRateFromViews = steps[0] && steps[0].count > 0
      ? roundRate((Math.max(analytics.purchasesFromLinkedCollections, analytics.membershipsFromCampaign) / steps[0].count) * 100)
      : null;
    const overallLeakageFromViews = overallConversionRateFromViews === null ? null : roundRate(100 - overallConversionRateFromViews);

    return {
      campaignId: campaign.id,
      slug: campaign.slug,
      name: campaign.name,
      route: `/drinks/campaigns/${encodeURIComponent(campaign.slug)}`,
      visibility: campaign.visibility as CreatorCampaignVisibility,
      state: getCreatorCampaignState(campaign),
      linkedDropsCount: analytics.linkedDropsCount,
      linkedCollectionsCount: analytics.linkedCollectionsCount,
      memberFocused,
      steps,
      transitions,
      topBottlenecks,
      strongestStep,
      deepestNonZeroStep,
      overallConversionRateFromViews,
      overallLeakageFromViews,
      notes: [
        "This funnel is intentionally lightweight and uses only signals ChefSire already tracks for campaigns.",
        "Views, clicks, and RSVPs come from linked drops; follows come from campaign follows; purchases and memberships stay approximate and creator-private.",
        analytics.purchasesFromLinkedCollectionsNote,
        memberFocused ? analytics.membershipsFromCampaignNote : "Memberships can outpace purchases for some member-first campaigns because they are a parallel native conversion path, not always a post-purchase step.",
      ].filter((value): value is string => Boolean(value)),
    } satisfies CreatorCampaignFunnelBottleneckItem;
  }).filter((item): item is CreatorCampaignFunnelBottleneckItem => Boolean(item));

  const weakTransitionCounts = new Map<string, { fromStep: CreatorCampaignFunnelStepKey; toStep: CreatorCampaignFunnelStepKey; label: string; affectedCampaigns: number }>();
  for (const item of items) {
    const uniqueWeak = new Set(
      item.topBottlenecks
        .filter((transition) => transition.severity === "critical" || transition.severity === "high" || transition.severity === "watch")
        .map((transition) => `${transition.fromStep}:${transition.toStep}`),
    );
    for (const key of uniqueWeak) {
      const [fromStep, toStep] = key.split(":") as [CreatorCampaignFunnelStepKey, CreatorCampaignFunnelStepKey];
      const current = weakTransitionCounts.get(key) ?? {
        fromStep,
        toStep,
        label: `${campaignFunnelStepLabel(fromStep)} → ${campaignFunnelStepLabel(toStep)}`,
        affectedCampaigns: 0,
      };
      current.affectedCampaigns += 1;
      weakTransitionCounts.set(key, current);
    }
  }

  const mostCommonWeakTransition = [...weakTransitionCounts.values()]
    .sort((a, b) => b.affectedCampaigns - a.affectedCampaigns || a.label.localeCompare(b.label))[0] ?? null;

  return {
    summary: {
      totalCampaigns: items.length,
      activeCampaigns: items.filter((item) => item.state === "active").length,
      campaignsWithMeaningfulViewSignal: items.filter((item) => (item.steps.find((step) => step.key === "views")?.count ?? 0) >= 10).length,
      campaignsWithBottlenecks: items.filter((item) => item.topBottlenecks.length > 0).length,
      criticalBottlenecks: items.flatMap((item) => item.topBottlenecks).filter((transition) => transition.severity === "critical").length,
      highBottlenecks: items.flatMap((item) => item.topBottlenecks).filter((transition) => transition.severity === "high").length,
      watchBottlenecks: items.flatMap((item) => item.topBottlenecks).filter((transition) => transition.severity === "watch").length,
      averageViewToClickRate: averageFunnelTransitionRate(items, "views", "clicks"),
      averageClickToFollowRate: averageFunnelTransitionRate(items, "clicks", "follows"),
      averageFollowToRsvpRate: averageFunnelTransitionRate(items, "follows", "rsvps"),
      averageRsvpToPurchaseRate: averageFunnelTransitionRate(items, "rsvps", "purchases"),
      averagePurchaseToMembershipRate: averageFunnelTransitionRate(items, "purchases", "memberships"),
      mostCommonWeakTransition,
    } satisfies CreatorCampaignFunnelBottleneckSummary,
    items,
    attributionNotes: [
      "Campaign funnel bottlenecks stay drinks-platform-native and only connect signals already tracked in the creator dashboard.",
      "This is a diagnostic layer, not a warehouse model: it compares step-to-step retention and leakage across views, clicks, follows, RSVPs, purchases, and memberships.",
      "Follower, RSVP, click, purchase, and membership counts all remain creator-private on this route.",
      "Purchases and memberships remain clearly labeled approximations anywhere the underlying campaign analytics are already approximate.",
      "Some later steps can exceed earlier steps because campaigns can be entered from different native surfaces; those cases are labeled as alternate paths instead of leakage.",
    ],
    generatedAt: new Date().toISOString(),
  };
}

