function campaignRolloutStageLabel(audience: CreatorCampaignRolloutAudience) {
  switch (audience) {
    case "members":
      return "Member stage";
    case "followers":
      return "Follower stage";
    case "public":
    default:
      return "Public stage";
  }
}

function emptyCreatorCampaignRolloutStageAnalytics(
  audience: CreatorCampaignRolloutAudience,
): CreatorCampaignRolloutStageAnalytics {
  return {
    audience,
    label: campaignRolloutStageLabel(audience),
    views: 0,
    clicks: 0,
    rsvps: 0,
  };
}

function getCampaignRolloutStageAt(
  campaign: Pick<CreatorCampaignRecord, "visibility" | "startsAt" | "endsAt" | "isActive" | "createdAt" | "rolloutMode" | "startsWithAudience" | "unlockFollowersAt" | "unlockPublicAt" | "rolloutNotes" | "isRolloutActive" | "isRolloutPaused" | "rolloutPausedAt">,
  occurredAt: Date,
) {
  const rollout = deriveCreatorCampaignRollout(campaign, occurredAt);
  return rollout.currentAudience;
}

function rolloutStageWeightedEngagement(stage: CreatorCampaignRolloutStageAnalytics) {
  return stage.rsvps * 4 + stage.clicks * 3 + stage.views;
}

function stageRecapWeightedSignal(input: {
  views: number;
  clicks: number;
  rsvps: number;
  approximatePurchases: number | null;
  approximateMemberships: number | null;
}) {
  return (
    input.views
    + (input.clicks * 3)
    + (input.rsvps * 4)
    + ((input.approximatePurchases ?? 0) * 6)
    + ((input.approximateMemberships ?? 0) * 6)
  );
}

function stageDurationHoursBetween(startAt: Date | null, endAt: Date | null) {
  if (!startAt || !endAt) return null;
  const milliseconds = endAt.getTime() - startAt.getTime();
  if (milliseconds <= 0) return 0;
  return Math.round((milliseconds / (1000 * 60 * 60)) * 10) / 10;
}

function isDateWithinStageWindow(value: Date, startAt: Date | null, endAt: Date | null) {
  if (!startAt || value < startAt) return false;
  if (endAt && value > endAt) return false;
  return true;
}

function stageLabelForSummary(audience: CreatorCampaignRolloutAudience) {
  if (audience === "members") return "Member stage";
  if (audience === "followers") return "Follower stage";
  return "Public stage";
}

function buildCampaignStageRecapPrimaryOutcome(input: {
  stage: {
    audience: CreatorCampaignRolloutAudience;
    views: number;
    clicks: number;
    rsvps: number;
    approximatePurchases: number | null;
    approximateMemberships: number | null;
  };
  totals: {
    views: number;
    clicks: number;
    rsvps: number;
    approximatePurchases: number;
    approximateMemberships: number;
  };
}) {
  const { stage, totals } = input;
  if ((stage.approximateMemberships ?? 0) > 0 && (stage.approximateMemberships ?? 0) >= Math.max(1, totals.approximateMemberships)) {
    return "Approximate membership signal";
  }
  if ((stage.approximatePurchases ?? 0) > 0 && (stage.approximatePurchases ?? 0) >= Math.max(1, totals.approximatePurchases)) {
    return "Approximate purchase signal";
  }
  if (stage.rsvps > 0 && stage.rsvps >= Math.max(1, totals.rsvps / 2)) {
    return "RSVP lift";
  }
  if (stage.clicks > 0 && stage.clicks >= Math.max(1, totals.clicks / 2)) {
    return "Click momentum";
  }
  if (stage.views > 0 && stage.views >= Math.max(1, totals.views / 2)) {
    return "Reach expansion";
  }
  return "Light signal";
}

function buildCampaignStageRecapSummary(input: {
  stage: {
    audience: CreatorCampaignRolloutAudience;
    views: number;
    clicks: number;
    rsvps: number;
    approximatePurchases: number | null;
    approximateMemberships: number | null;
    stageDurationHours: number | null;
    hasEnded: boolean;
  };
  previousStage?: {
    views: number;
    clicks: number;
    rsvps: number;
    approximatePurchases: number | null;
    approximateMemberships: number | null;
  } | null;
  totals: {
    views: number;
    clicks: number;
    rsvps: number;
    approximatePurchases: number;
    approximateMemberships: number;
  };
  strongestAudience: CreatorCampaignRolloutAudience | null;
  averageSignalPerHour: number | null;
}) {
  const { stage, previousStage, totals, strongestAudience, averageSignalPerHour } = input;
  const label = stageLabelForSummary(stage.audience);
  const stageSignal = stageRecapWeightedSignal(stage);
  const previousSignal = previousStage ? stageRecapWeightedSignal(previousStage) : 0;
  const durationHours = Math.max(stage.stageDurationHours ?? 0, 1);
  const signalPerHour = stageSignal / durationHours;

  if (
    stage.audience === "members"
    && strongestAudience === "members"
    && stage.clicks + stage.rsvps > 0
    && stage.views > 0
  ) {
    return "Member stage drove the strongest early conversion.";
  }

  if (
    stage.audience === "followers"
    && previousStage
    && stage.views > previousStage.views
    && stage.rsvps <= previousStage.rsvps
    && stage.hasEnded
  ) {
    return "Follower stage expanded reach but added limited RSVP lift.";
  }

  if (stage.audience === "public" && stage.clicks > 0 && stage.clicks >= Math.max(1, Math.ceil(totals.clicks * 0.5))) {
    return "Public stage generated the majority of clicks.";
  }

  if (
    stage.stageDurationHours !== null
    && stage.stageDurationHours > 0
    && stage.stageDurationHours <= 24
    && stageSignal > 0
    && averageSignalPerHour !== null
    && signalPerHour >= averageSignalPerHour * 1.2
  ) {
    return "This stage was short but effective.";
  }

  if (
    previousStage
    && previousSignal > 0
    && stageSignal <= previousSignal * 0.5
    && stage.rsvps <= previousStage.rsvps
    && stage.clicks <= previousStage.clicks
  ) {
    return "This stage added little incremental momentum.";
  }

  if ((stage.approximatePurchases ?? 0) > 0) {
    return `${label} lined up the clearest approximate purchase signal.`;
  }

  if ((stage.approximateMemberships ?? 0) > 0) {
    return `${label} aligned with the clearest approximate membership signal.`;
  }

  if (stage.rsvps > 0 && stage.rsvps >= Math.max(1, totals.rsvps / 2)) {
    return `${label} created the strongest RSVP lift in this rollout.`;
  }

  if (stage.views > 0 && stage.views >= Math.max(1, totals.views / 2)) {
    return `${label} delivered the broadest reach in this rollout.`;
  }

  return stageSignal > 0
    ? `${label} added measurable momentum without dominating the full rollout.`
    : `${label} unlocked, but signal stayed light.`;
}

function buildCampaignStageRecapNextStepHint(input: {
  stage: {
    audience: CreatorCampaignRolloutAudience;
    views: number;
    clicks: number;
    rsvps: number;
    approximatePurchases: number | null;
    approximateMemberships: number | null;
    hasEnded: boolean;
    isCurrentStage: boolean;
  };
  nextStageAudience: CreatorCampaignRolloutAudience | null;
  previousStage?: {
    views: number;
    clicks: number;
    rsvps: number;
  } | null;
}) {
  const { stage, nextStageAudience, previousStage } = input;

  if (stage.isCurrentStage && !stage.hasEnded) {
    return "Still live — this review will firm up once the next unlock happens or the campaign closes.";
  }

  if ((stage.approximatePurchases ?? 0) > 0 || (stage.approximateMemberships ?? 0) > 0) {
    return nextStageAudience
      ? `Carry this message into the ${stageLabelForSummary(nextStageAudience).toLowerCase()} while intent is still warm.`
      : "Use this result as a recap benchmark before planning the next campaign.";
  }

  if (stage.views > Math.max(1, stage.clicks * 4) && stage.rsvps <= Math.max(1, Math.floor(stage.clicks / 3))) {
    return nextStageAudience
      ? `The next unlock should sharpen the RSVP ask, because this ${stageLabelForSummary(stage.audience).toLowerCase()} mostly expanded reach.`
      : "Treat this as a reach-heavy recap and pair it with a stronger CTA next time.";
  }

  if (previousStage && stage.clicks + stage.rsvps < previousStage.clicks + previousStage.rsvps) {
    return nextStageAudience
      ? "Refresh the headline or linked drop before widening access again."
      : "This stage cooled off versus the prior unlock, so note the creative drop-off in the recap.";
  }

  return nextStageAudience
    ? `Keep the strongest creative elements moving into the ${stageLabelForSummary(nextStageAudience).toLowerCase()}.`
    : "Archive this stage review as a timing-based lesson for the next rollout.";
}

function buildCreatorCampaignRolloutInsights(input: {
  stages: CreatorCampaignRolloutStageAnalytics[];
  visibility: CreatorCampaignVisibility;
  approximatePurchasesAfterFollowerUnlock: number | null;
  approximatePurchasesAfterPublicUnlock: number | null;
  approximateMembershipsAfterMemberFirstRollout: number | null;
}) {
  const insights: string[] = [];
  const stageByAudience = new Map(input.stages.map((stage) => [stage.audience, stage]));
  const rankedStages = [...input.stages]
    .sort((a, b) => rolloutStageWeightedEngagement(b) - rolloutStageWeightedEngagement(a) || b.clicks - a.clicks || b.views - a.views);
  const strongestStage = rankedStages[0] ?? null;
  const membersStage = stageByAudience.get("members") ?? emptyCreatorCampaignRolloutStageAnalytics("members");
  const followersStage = stageByAudience.get("followers") ?? emptyCreatorCampaignRolloutStageAnalytics("followers");
  const publicStage = stageByAudience.get("public") ?? emptyCreatorCampaignRolloutStageAnalytics("public");

  if (strongestStage && rolloutStageWeightedEngagement(strongestStage) > 0) {
    if (strongestStage.audience === "public") {
      insights.push("Most engagement happened after public unlock.");
    } else if (strongestStage.audience === "members") {
      insights.push("Member-stage engagement outperformed follower/public stages.");
    } else if (strongestStage.audience === "followers") {
      insights.push("Follower-stage activity led the rollout before wider access opened.");
    }
  }

  if (followersStage.views > membersStage.views && followersStage.clicks + followersStage.rsvps <= Math.max(1, membersStage.clicks + membersStage.rsvps)) {
    insights.push("Follower unlock increased reach but not conversion.");
  }

  if (membersStage.clicks + membersStage.rsvps > 0 && publicStage.views > 0) {
    const memberConversionRate = (membersStage.clicks + membersStage.rsvps) / Math.max(1, membersStage.views);
    const publicConversionRate = (publicStage.clicks + publicStage.rsvps) / Math.max(1, publicStage.views);
    if (memberConversionRate > publicConversionRate * 1.25) {
      insights.push("Early member access generated stronger conversions.");
    }
  }

  if (input.visibility === "public" && publicStage.clicks + publicStage.rsvps > (membersStage.clicks + membersStage.rsvps + followersStage.clicks + followersStage.rsvps)) {
    insights.push("This campaign may not need a long staged rollout next time.");
  }

  if ((input.approximatePurchasesAfterPublicUnlock ?? 0) > (input.approximatePurchasesAfterFollowerUnlock ?? 0)) {
    insights.push("Approximate purchase activity skewed later, after public unlock.");
  }

  if ((input.approximateMembershipsAfterMemberFirstRollout ?? 0) > 0 && membersStage.rsvps + membersStage.clicks > 0) {
    insights.push("Member-first access coincided with approximate membership conversion signal.");
  }

  return insights.slice(0, 4);
}

async function loadCreatorCampaignRolloutAnalytics(creatorUserId: string, campaignId?: string | null) {
  if (!db) throw new Error("Database unavailable");

  const campaignRows = await db
    .select()
    .from(creatorCampaigns)
    .where(campaignId
      ? and(eq(creatorCampaigns.creatorUserId, creatorUserId), eq(creatorCampaigns.id, campaignId))
      : eq(creatorCampaigns.creatorUserId, creatorUserId))
    .orderBy(desc(creatorCampaigns.updatedAt))
    .limit(campaignId ? 1 : 120);

  if (!campaignRows.length) {
    return {
      summary: {
        totalCampaigns: 0,
        campaignsWithRolloutConfig: 0,
        campaignsWithSequencedRollout: 0,
        activeSequencedRollouts: 0,
        totalStageViews: 0,
        totalStageClicks: 0,
        totalStageRsvps: 0,
      } satisfies CreatorCampaignRolloutAnalyticsSummary,
      items: [] as CreatorCampaignRolloutAnalyticsItem[],
      attributionNotes: [
        "Rollout analytics classify timing against rollout unlock boundaries, not perfect causal exposure.",
        "No creator campaigns exist yet for this view, so there is no rollout stage activity to summarize.",
      ],
      generatedAt: new Date().toISOString(),
    };
  }

  const campaignsById = new Map(campaignRows.map((campaign) => [campaign.id, campaign]));
  const campaignIds = campaignRows.map((campaign) => campaign.id);
  const linkMap = await loadCreatorCampaignLinksByCampaignIds(campaignIds);

  const dropIds = [...new Set(
    campaignRows.flatMap((campaign) => (linkMap.get(campaign.id) ?? [])
      .filter((link) => link.targetType === "drop")
      .map((link) => link.targetId)),
  )];
  const collectionIds = [...new Set(
    campaignRows.flatMap((campaign) => (linkMap.get(campaign.id) ?? [])
      .filter((link) => link.targetType === "collection")
      .map((link) => link.targetId)),
  )];

  const [surfaceEventRows, dropEventRows, rsvpRows, purchaseRows, membershipRows] = await Promise.all([
    db.select({
      campaignId: creatorCampaignSurfaceEvents.campaignId,
      eventType: creatorCampaignSurfaceEvents.eventType,
      createdAt: creatorCampaignSurfaceEvents.createdAt,
    }).from(creatorCampaignSurfaceEvents).where(inArray(creatorCampaignSurfaceEvents.campaignId, campaignIds)).orderBy(asc(creatorCampaignSurfaceEvents.createdAt)),
    dropIds.length
      ? db.select({
          dropId: creatorDropEvents.dropId,
          eventType: creatorDropEvents.eventType,
          createdAt: creatorDropEvents.createdAt,
        }).from(creatorDropEvents).where(inArray(creatorDropEvents.dropId, dropIds)).orderBy(asc(creatorDropEvents.createdAt))
      : Promise.resolve([] as Array<{ dropId: string; eventType: string; createdAt: Date }>),
    dropIds.length
      ? db.select({
          dropId: creatorDropRsvps.dropId,
          createdAt: creatorDropRsvps.createdAt,
        }).from(creatorDropRsvps).where(inArray(creatorDropRsvps.dropId, dropIds)).orderBy(asc(creatorDropRsvps.createdAt))
      : Promise.resolve([] as Array<{ dropId: string; createdAt: Date }>),
    collectionIds.length
      ? db.select({
          collectionId: drinkCollectionPurchases.collectionId,
          createdAt: drinkCollectionPurchases.createdAt,
          status: drinkCollectionPurchases.status,
        }).from(drinkCollectionPurchases).where(inArray(drinkCollectionPurchases.collectionId, collectionIds)).orderBy(asc(drinkCollectionPurchases.createdAt))
      : Promise.resolve([] as Array<{ collectionId: string; createdAt: Date; status: string }>),
    db.select({
      createdAt: creatorMemberships.createdAt,
    }).from(creatorMemberships).where(eq(creatorMemberships.creatorUserId, creatorUserId)).orderBy(asc(creatorMemberships.createdAt)),
  ]);

  const campaignIdsByDropId = new Map<string, string[]>();
  const campaignIdsByCollectionId = new Map<string, string[]>();
  for (const campaign of campaignRows) {
    for (const link of linkMap.get(campaign.id) ?? []) {
      if (link.targetType === "drop") {
        const current = campaignIdsByDropId.get(link.targetId) ?? [];
        current.push(campaign.id);
        campaignIdsByDropId.set(link.targetId, current);
      }
      if (link.targetType === "collection") {
        const current = campaignIdsByCollectionId.get(link.targetId) ?? [];
        current.push(campaign.id);
        campaignIdsByCollectionId.set(link.targetId, current);
      }
    }
  }

  const stageMapByCampaignId = new Map<string, Map<CreatorCampaignRolloutAudience, CreatorCampaignRolloutStageAnalytics>>();
  const ensureStage = (campaignIdValue: string, audience: CreatorCampaignRolloutAudience) => {
    const current = stageMapByCampaignId.get(campaignIdValue) ?? new Map<CreatorCampaignRolloutAudience, CreatorCampaignRolloutStageAnalytics>();
    if (!stageMapByCampaignId.has(campaignIdValue)) stageMapByCampaignId.set(campaignIdValue, current);
    const stage = current.get(audience) ?? emptyCreatorCampaignRolloutStageAnalytics(audience);
    if (!current.has(audience)) current.set(audience, stage);
    return stage;
  };

  for (const campaign of campaignRows) {
    ensureStage(campaign.id, "members");
    ensureStage(campaign.id, "followers");
    ensureStage(campaign.id, "public");
  }

  for (const row of surfaceEventRows) {
    const campaign = campaignsById.get(row.campaignId);
    if (!campaign || !isDateWithinCampaignAnalyticsWindow(row.createdAt, campaign)) continue;
    const stage = ensureStage(row.campaignId, getCampaignRolloutStageAt(campaign, row.createdAt));
    if (row.eventType === "view_campaign") stage.views += 1;
    if (row.eventType === "click_campaign") stage.clicks += 1;
  }

  for (const row of dropEventRows) {
    const campaignIdsForDrop = campaignIdsByDropId.get(row.dropId) ?? [];
    for (const campaignIdValue of campaignIdsForDrop) {
      const campaign = campaignsById.get(campaignIdValue);
      if (!campaign || !isDateWithinCampaignAnalyticsWindow(row.createdAt, campaign)) continue;
      const stage = ensureStage(campaignIdValue, getCampaignRolloutStageAt(campaign, row.createdAt));
      if (row.eventType === "view_drop") stage.views += 1;
      if (row.eventType === "click_drop_target") stage.clicks += 1;
    }
  }

  for (const row of rsvpRows) {
    const campaignIdsForDrop = campaignIdsByDropId.get(row.dropId) ?? [];
    for (const campaignIdValue of campaignIdsForDrop) {
      const campaign = campaignsById.get(campaignIdValue);
      if (!campaign || !isDateWithinCampaignAnalyticsWindow(row.createdAt, campaign)) continue;
      ensureStage(campaignIdValue, getCampaignRolloutStageAt(campaign, row.createdAt)).rsvps += 1;
    }
  }

  const items = campaignRows.map((campaign) => {
    const rollout = deriveCreatorCampaignRollout(campaign);
    const hasSequencedRollout = Boolean(campaign.isRolloutActive && rollout.timeline.length > 1);
    const stages = ["members", "followers", "public"].map((audience) => ({
      ...ensureStage(campaign.id, audience as CreatorCampaignRolloutAudience),
    }));
    const stageByAudience = new Map(stages.map((stage) => [stage.audience, stage]));
    const followersUnlockAt = campaign.unlockFollowersAt && campaign.unlockFollowersAt <= new Date()
      ? campaign.unlockFollowersAt.toISOString()
      : null;
    const publicUnlockAt = campaign.unlockPublicAt && campaign.unlockPublicAt <= new Date()
      ? campaign.unlockPublicAt.toISOString()
      : null;
    const campaignCollectionIds = (linkMap.get(campaign.id) ?? [])
      .filter((link) => link.targetType === "collection")
      .map((link) => link.targetId);
    const approximatePurchasesAfterFollowerUnlock = campaign.unlockFollowersAt
      ? purchaseRows.filter((row) => (
        row.status === "completed"
        && campaignCollectionIds.includes(row.collectionId)
        && row.createdAt >= campaign.unlockFollowersAt!
        && isDateWithinCampaignAnalyticsWindow(row.createdAt, campaign)
      )).length
      : null;
    const approximatePurchasesAfterPublicUnlock = campaign.unlockPublicAt
      ? purchaseRows.filter((row) => (
        row.status === "completed"
        && campaignCollectionIds.includes(row.collectionId)
        && row.createdAt >= campaign.unlockPublicAt!
        && isDateWithinCampaignAnalyticsWindow(row.createdAt, campaign)
      )).length
      : null;
    const memberFirstStageEndsAt = campaign.unlockFollowersAt
      ?? campaign.unlockPublicAt
      ?? campaign.endsAt
      ?? new Date();
    const approximateMembershipsAfterMemberFirstRollout = rollout.startsWithAudience === "members"
      ? membershipRows.filter((row) => (
        row.createdAt >= getCreatorCampaignAnalyticsWindow(campaign).startsAt
        && row.createdAt <= memberFirstStageEndsAt
        && isDateWithinCampaignAnalyticsWindow(row.createdAt, campaign)
      )).length
      : null;
    const insights = buildCreatorCampaignRolloutInsights({
      stages,
      visibility: campaign.visibility as CreatorCampaignVisibility,
      approximatePurchasesAfterFollowerUnlock,
      approximatePurchasesAfterPublicUnlock,
      approximateMembershipsAfterMemberFirstRollout,
    });

    return {
      campaignId: campaign.id,
      slug: campaign.slug,
      name: campaign.name,
      route: `/drinks/campaigns/${encodeURIComponent(campaign.slug)}`,
      visibility: campaign.visibility as CreatorCampaignVisibility,
      state: getCreatorCampaignState(campaign),
      hasRolloutConfig: Boolean(campaign.isRolloutActive || campaign.rolloutMode !== "public_first" || campaign.unlockFollowersAt || campaign.unlockPublicAt || campaign.startsWithAudience),
      hasSequencedRollout,
      rolloutMode: rollout.rolloutMode,
      currentRolloutState: rollout.state,
      startsWithAudience: rollout.startsWithAudience,
      unlockFollowersAt: rollout.unlockFollowersAt,
      unlockPublicAt: rollout.unlockPublicAt,
      currentAudience: rollout.currentAudience,
      nextAudience: rollout.nextAudience,
      membersStageViews: stageByAudience.get("members")?.views ?? 0,
      followersStageViews: stageByAudience.get("followers")?.views ?? 0,
      publicStageViews: stageByAudience.get("public")?.views ?? 0,
      membersStageClicks: stageByAudience.get("members")?.clicks ?? 0,
      followersStageClicks: stageByAudience.get("followers")?.clicks ?? 0,
      publicStageClicks: stageByAudience.get("public")?.clicks ?? 0,
      membersStageRsvps: stageByAudience.get("members")?.rsvps ?? 0,
      followersStageRsvps: stageByAudience.get("followers")?.rsvps ?? 0,
      publicStageRsvps: stageByAudience.get("public")?.rsvps ?? 0,
      followersUnlockedAt,
      publicUnlockedAt,
      approximatePurchasesAfterFollowerUnlock,
      approximatePurchasesAfterPublicUnlock,
      approximateMembershipsAfterMemberFirstRollout,
      stagePerformance: stages,
      insights,
    } satisfies CreatorCampaignRolloutAnalyticsItem;
  });

  return {
    summary: {
      totalCampaigns: items.length,
      campaignsWithRolloutConfig: items.filter((item) => item.hasRolloutConfig).length,
      campaignsWithSequencedRollout: items.filter((item) => item.hasSequencedRollout).length,
      activeSequencedRollouts: items.filter((item) => item.hasSequencedRollout && item.currentRolloutState !== "completed" && item.state !== "past").length,
      totalStageViews: items.reduce((sum, item) => sum + item.membersStageViews + item.followersStageViews + item.publicStageViews, 0),
      totalStageClicks: items.reduce((sum, item) => sum + item.membersStageClicks + item.followersStageClicks + item.publicStageClicks, 0),
      totalStageRsvps: items.reduce((sum, item) => sum + item.membersStageRsvps + item.followersStageRsvps + item.publicStageRsvps, 0),
    } satisfies CreatorCampaignRolloutAnalyticsSummary,
    items,
    attributionNotes: [
      "Rollout analytics classify campaign-stage activity by timestamp relative to configured rollout unlock boundaries.",
      "Views and clicks reuse existing direct campaign surface events plus linked drop view/click events already tracked elsewhere in the drinks platform.",
      "RSVPs reuse linked drop RSVP timing and are bucketed into the rollout stage that was live when the RSVP happened.",
      "Purchases and memberships remain clearly labeled approximations and should be read as timing-based rollout signals rather than exact causality.",
      "Rollout mode, rollout state, rollout analytics, audience fit, and surface attribution stay separate on purpose.",
    ],
    generatedAt: new Date().toISOString(),
  };
}

async function loadCreatorCampaignStageRecaps(creatorUserId: string, campaignId?: string | null) {
  if (!db) throw new Error("Database unavailable");

  const rolloutAnalytics = await loadCreatorCampaignRolloutAnalytics(creatorUserId, campaignId);
  const rolloutItems = rolloutAnalytics.items.filter((item) => item.hasSequencedRollout);
  if (!rolloutItems.length) {
    return {
      summary: {
        totalCampaigns: campaignId ? 1 : rolloutAnalytics.items.length,
        campaignsWithRecaps: 0,
        totalStageRecaps: 0,
        completedStageRecaps: 0,
      } satisfies CreatorCampaignStageRecapSummary,
      items: [] as CreatorCampaignStageRecapCampaignItem[],
      attributionNotes: [
        "Stage recaps stay lightweight: they reuse rollout timing, rollout analytics, linked purchase proxies, and membership proxies that already exist.",
        "No sequenced rollout has unlocked enough stages yet to produce an honest stage recap here.",
      ],
      generatedAt: new Date().toISOString(),
    };
  }

  const campaignIds = rolloutItems.map((item) => item.campaignId);
  const campaignRows = await db
    .select()
    .from(creatorCampaigns)
    .where(campaignId
      ? and(eq(creatorCampaigns.creatorUserId, creatorUserId), eq(creatorCampaigns.id, campaignId))
      : and(eq(creatorCampaigns.creatorUserId, creatorUserId), inArray(creatorCampaigns.id, campaignIds)))
    .orderBy(desc(creatorCampaigns.updatedAt))
    .limit(campaignId ? 1 : 120);

  const campaignById = new Map(campaignRows.map((campaign) => [campaign.id, campaign]));
  const linkMap = await loadCreatorCampaignLinksByCampaignIds(campaignIds);
  const collectionIds = [...new Set(
    campaignIds.flatMap((campaignIdValue) => (linkMap.get(campaignIdValue) ?? [])
      .filter((link) => link.targetType === "collection")
      .map((link) => link.targetId)),
  )];

  const [purchaseRows, membershipRows] = await Promise.all([
    collectionIds.length
      ? db.select({
          collectionId: drinkCollectionPurchases.collectionId,
          createdAt: drinkCollectionPurchases.createdAt,
          status: drinkCollectionPurchases.status,
        }).from(drinkCollectionPurchases).where(inArray(drinkCollectionPurchases.collectionId, collectionIds)).orderBy(asc(drinkCollectionPurchases.createdAt))
      : Promise.resolve([] as Array<{ collectionId: string; createdAt: Date; status: string }>),
    db.select({
      createdAt: creatorMemberships.createdAt,
      status: creatorMemberships.status,
    }).from(creatorMemberships).where(eq(creatorMemberships.creatorUserId, creatorUserId)).orderBy(asc(creatorMemberships.createdAt)),
  ]);

  const items = rolloutItems.map((rolloutItem) => {
    const campaign = campaignById.get(rolloutItem.campaignId);
    if (!campaign) return null;

    const rollout = deriveCreatorCampaignRollout(campaign);
    const window = getCreatorCampaignAnalyticsWindow(campaign);
    const timeline = rollout.timeline.map((step, index) => {
      const stepStartAt = step.unlockAt ? new Date(step.unlockAt) : (index === 0 ? window.startsAt : null);
      const nextStep = rollout.timeline[index + 1] ?? null;
      const nextStepStartAt = nextStep?.unlockAt ? new Date(nextStep.unlockAt) : null;
      const isCurrentStage = step.audience === rollout.currentAudience;
      const stageEndedAt = nextStepStartAt
        ?? (getCreatorCampaignState(campaign) === "past" ? window.endsAt : null);
      return {
        audience: step.audience,
        stageStartedAt: stepStartAt,
        stageEndedAt,
        stageDurationHours: stageDurationHoursBetween(stepStartAt, stageEndedAt),
        isCurrentStage,
        hasEnded: Boolean(stageEndedAt && stageEndedAt.getTime() <= Date.now()),
      };
    });

    const campaignCollectionIds = (linkMap.get(campaign.id) ?? [])
      .filter((link) => link.targetType === "collection")
      .map((link) => link.targetId);
    const stageMetricsByAudience = new Map(rolloutItem.stagePerformance.map((stage) => [stage.audience, stage]));

    const recapDrafts = timeline.map((stageWindow) => {
      const stageMetrics = stageMetricsByAudience.get(stageWindow.audience) ?? emptyCreatorCampaignRolloutStageAnalytics(stageWindow.audience);
      const approximatePurchases = purchaseRows.filter((row) => (
        row.status === "completed"
        && campaignCollectionIds.includes(row.collectionId)
        && isDateWithinCampaignAnalyticsWindow(row.createdAt, campaign)
        && isDateWithinStageWindow(row.createdAt, stageWindow.stageStartedAt, stageWindow.stageEndedAt)
      )).length;
      const approximateMemberships = membershipRows.filter((row) => (
        row.status === "active"
        && isDateWithinCampaignAnalyticsWindow(row.createdAt, campaign)
        && isDateWithinStageWindow(row.createdAt, stageWindow.stageStartedAt, stageWindow.stageEndedAt)
      )).length;

      return {
        audience: stageWindow.audience,
        stageStartedAt: stageWindow.stageStartedAt,
        stageEndedAt: stageWindow.stageEndedAt,
        stageDurationHours: stageWindow.stageDurationHours,
        isCurrentStage: stageWindow.isCurrentStage,
        hasEnded: stageWindow.hasEnded,
        views: stageMetrics.views,
        clicks: stageMetrics.clicks,
        rsvps: stageMetrics.rsvps,
        approximatePurchases,
        approximateMemberships: rollout.startsWithAudience === "members" || stageWindow.audience === "members"
          ? approximateMemberships
          : 0,
      };
    });

    const totals = recapDrafts.reduce((accumulator, stage) => ({
      views: accumulator.views + stage.views,
      clicks: accumulator.clicks + stage.clicks,
      rsvps: accumulator.rsvps + stage.rsvps,
      approximatePurchases: accumulator.approximatePurchases + (stage.approximatePurchases ?? 0),
      approximateMemberships: accumulator.approximateMemberships + (stage.approximateMemberships ?? 0),
    }), {
      views: 0,
      clicks: 0,
      rsvps: 0,
      approximatePurchases: 0,
      approximateMemberships: 0,
    });

    const strongestStage = [...recapDrafts]
      .sort((a, b) => stageRecapWeightedSignal(b) - stageRecapWeightedSignal(a))
      [0] ?? null;
    const maxSignal = Math.max(...recapDrafts.map((stage) => stageRecapWeightedSignal(stage)), 0);
    const averageSignalPerHour = recapDrafts.length
      ? recapDrafts.reduce((sum, stage) => sum + (stageRecapWeightedSignal(stage) / Math.max(stage.stageDurationHours ?? 1, 1)), 0) / recapDrafts.length
      : null;

    const recaps = recapDrafts.map((stage, index) => {
      const previousStage = recapDrafts[index - 1] ?? null;
      const nextStage = recapDrafts[index + 1] ?? null;
      const stageSignal = stageRecapWeightedSignal(stage);
      return {
        campaignId: campaign.id,
        campaignName: campaign.name,
        campaignSlug: campaign.slug,
        campaignRoute: `/drinks/campaigns/${encodeURIComponent(campaign.slug)}`,
        stageName: stage.audience,
        stageLabel: stageLabelForSummary(stage.audience),
        stageStartedAt: stage.stageStartedAt ? stage.stageStartedAt.toISOString() : null,
        stageEndedAt: stage.stageEndedAt ? stage.stageEndedAt.toISOString() : null,
        stageDurationHours: stage.stageDurationHours,
        views: stage.views,
        clicks: stage.clicks,
        rsvps: stage.rsvps,
        approximatePurchases: stage.approximatePurchases,
        approximateMemberships: stage.approximateMemberships,
        primaryOutcome: buildCampaignStageRecapPrimaryOutcome({
          stage,
          totals,
        }),
        stageSummary: buildCampaignStageRecapSummary({
          stage,
          previousStage,
          totals,
          strongestAudience: strongestStage?.audience ?? null,
          averageSignalPerHour,
        }),
        stageScore: maxSignal > 0 ? Math.round((stageSignal / maxSignal) * 100) : null,
        nextStepHint: buildCampaignStageRecapNextStepHint({
          stage,
          nextStageAudience: nextStage?.audience ?? null,
          previousStage,
        }),
        isCurrentStage: stage.isCurrentStage,
        hasEnded: stage.hasEnded,
      } satisfies CreatorCampaignStageRecap;
    });

    return {
      campaignId: campaign.id,
      campaignName: campaign.name,
      campaignSlug: campaign.slug,
      campaignRoute: `/drinks/campaigns/${encodeURIComponent(campaign.slug)}`,
      rolloutMode: rollout.rolloutMode,
      currentRolloutState: rollout.state,
      hasSequencedRollout: rolloutItem.hasSequencedRollout,
      recaps,
    } satisfies CreatorCampaignStageRecapCampaignItem;
  }).filter(Boolean) as CreatorCampaignStageRecapCampaignItem[];

  return {
    summary: {
      totalCampaigns: rolloutAnalytics.items.length,
      campaignsWithRecaps: items.length,
      totalStageRecaps: items.reduce((sum, item) => sum + item.recaps.length, 0),
      completedStageRecaps: items.reduce((sum, item) => sum + item.recaps.filter((recap) => recap.hasEnded).length, 0),
    } satisfies CreatorCampaignStageRecapSummary,
    items,
    attributionNotes: [
      "Stage recaps reuse rollout timing, rollout analytics, timeline unlock boundaries, linked purchase proxies, and membership proxies that already exist.",
      "Views, clicks, and RSVPs are assigned to stages by timestamp relative to unlock windows, then summarized into concise outcome reviews.",
      "Approximate purchases and memberships are timing-based proxies within each stage window, not exact causal attribution.",
    ],
    generatedAt: new Date().toISOString(),
  };
}

function safeRolloutStageRate(stage: CreatorCampaignRolloutStageAnalytics) {
  return (stage.clicks + stage.rsvps) / Math.max(1, stage.views);
}

function rolloutAdvisorConfidenceFromSignals(totalSignal: number, margin: number, audienceFitConfidence?: CreatorCampaignAudienceFitConfidence | null): CreatorCampaignAudienceFitConfidence {
  if (totalSignal >= 45 && margin >= 10) return "high";
  if (totalSignal >= 20 && margin >= 5) return "medium";
  if (totalSignal > 0) return audienceFitConfidence === "high" ? "medium" : "low";
  return audienceFitConfidence ?? "none";
}

function formatRolloutModeLabel(mode: CreatorCampaignRolloutMode) {
  switch (mode) {
    case "members_first":
      return "members first";
    case "followers_first":
      return "followers first";
    case "staged":
      return "staged rollout";
    case "public_first":
    default:
      return "public first";
  }
}

function formatRolloutAudienceLabel(audience: CreatorCampaignRolloutAudience | null) {
  switch (audience) {
    case "members":
      return "members";
    case "followers":
      return "followers";
    case "public":
      return "public";
    default:
      return "no single audience";
  }
}

function pluralizeRolloutCampaign(count: number) {
  return `${count} campaign${count === 1 ? "" : "s"}`;
}

async function loadCreatorCampaignRolloutAdvisor(creatorUserId: string) {
  if (!db) throw new Error("Database unavailable");

  const [
    campaignRows,
    analytics,
    rolloutAnalytics,
    audienceFit,
    health,
    benchmarks,
  ] = await Promise.all([
    db.select().from(creatorCampaigns).where(eq(creatorCampaigns.creatorUserId, creatorUserId)).orderBy(desc(creatorCampaigns.updatedAt)).limit(120),
    loadCreatorCampaignAnalytics(creatorUserId),
    loadCreatorCampaignRolloutAnalytics(creatorUserId),
    loadCreatorCampaignAudienceFit(creatorUserId),
    loadCreatorCampaignHealth(creatorUserId),
    loadCreatorCampaignBenchmarks(creatorUserId),
  ]);

  if (!campaignRows.length) {
    return {
      summary: {
        totalCampaigns: 0,
        campaignsWithRecommendations: 0,
        memberFirstRecommendations: 0,
        followerFirstRecommendations: 0,
        publicFirstRecommendations: 0,
        stagedRecommendations: 0,
      } satisfies CreatorCampaignRolloutAdvisorSummary,
      creatorInsights: [] as CreatorCampaignRolloutAdvisorInsight[],
      items: [] as CreatorCampaignRolloutAdvisorItem[],
      attributionNotes: [
        "Rollout advisor is rules-based and uses the rollout, audience-fit, benchmark, health, goal, purchase, and membership signals already tracked in the drinks platform.",
        "No creator campaigns exist yet, so there is no rollout sequence history to summarize.",
      ],
      generatedAt: new Date().toISOString(),
    };
  }

  const campaignIds = campaignRows.map((campaign) => campaign.id);
  const linkMap = await loadCreatorCampaignLinksByCampaignIds(campaignIds);
  const collectionIds = [...new Set(
    campaignRows.flatMap((campaign) => (linkMap.get(campaign.id) ?? [])
      .filter((link) => link.targetType === "collection")
      .map((link) => link.targetId)),
  )];
  const collectionRows = collectionIds.length
    ? await db.select({ id: drinkCollections.id, accessType: drinkCollections.accessType }).from(drinkCollections).where(inArray(drinkCollections.id, collectionIds))
    : [];
  const collectionAccessMap = new Map(collectionRows.map((row) => [row.id, row.accessType]));

  const analyticsByCampaignId = new Map(analytics.items.map((item) => [item.campaignId, item]));
  const rolloutByCampaignId = new Map(rolloutAnalytics.items.map((item) => [item.campaignId, item]));
  const audienceFitByCampaignId = new Map(audienceFit.items.map((item) => [item.campaignId, item]));
  const healthByCampaignId = new Map(health.items.map((item) => [item.campaignId, item]));
  const benchmarkByCampaignId = new Map(benchmarks.items.map((item) => [item.campaignId, item]));

  const items = campaignRows.map((campaign) => {
    const analyticsItem = analyticsByCampaignId.get(campaign.id) ?? null;
    const rolloutItem = rolloutByCampaignId.get(campaign.id) ?? null;
    const audienceFitItem = audienceFitByCampaignId.get(campaign.id) ?? null;
    const healthItem = healthByCampaignId.get(campaign.id) ?? null;
    const benchmarkItem = benchmarkByCampaignId.get(campaign.id) ?? null;
    const collectionLinks = (linkMap.get(campaign.id) ?? []).filter((link) => link.targetType === "collection");
    const memberOnlyCollectionsCount = collectionLinks.filter((link) => collectionAccessMap.get(link.targetId) === "membership_only").length;

    const stageMap = new Map((rolloutItem?.stagePerformance ?? []).map((stage) => [stage.audience, stage]));
    const membersStage = stageMap.get("members") ?? emptyCreatorCampaignRolloutStageAnalytics("members");
    const followersStage = stageMap.get("followers") ?? emptyCreatorCampaignRolloutStageAnalytics("followers");
    const publicStage = stageMap.get("public") ?? emptyCreatorCampaignRolloutStageAnalytics("public");
    const rankedStages = [membersStage, followersStage, publicStage]
      .map((stage) => ({ ...stage, weighted: rolloutStageWeightedEngagement(stage), rate: safeRolloutStageRate(stage) }))
      .sort((a, b) => b.weighted - a.weighted || b.rate - a.rate);
    const strongestStage = rankedStages[0] ?? null;
    const secondStage = rankedStages[1] ?? null;
    const totalStageSignal = rankedStages.reduce((sum, stage) => sum + stage.weighted, 0);
    const signalMargin = Math.max(0, (strongestStage?.weighted ?? 0) - (secondStage?.weighted ?? 0));
    const audienceFitWinner = audienceFitItem?.bestAudienceFit ?? null;
    const membersWeighted = rolloutStageWeightedEngagement(membersStage);
    const followersWeighted = rolloutStageWeightedEngagement(followersStage);
    const publicWeighted = rolloutStageWeightedEngagement(publicStage);
    const memberSignalStrong = (
      (membersWeighted >= Math.max(followersWeighted, publicWeighted) * 1.2 && membersWeighted >= 6)
      || ((rolloutItem?.approximateMembershipsAfterMemberFirstRollout ?? 0) > 0 && membersStage.clicks + membersStage.rsvps > 0)
      || (audienceFitWinner === "members" && audienceFitItem?.bestAudienceFitConfidence === "high")
    );
    const followerSignalStrong = (
      audienceFitWinner === "followers"
      && followersWeighted >= Math.max(membersWeighted, publicWeighted)
      && followersWeighted >= 6
    );
    const publicSignalStrong = (
      (publicWeighted >= Math.max(membersWeighted, followersWeighted) * 1.2 && publicWeighted >= 6)
      || ((rolloutItem?.approximatePurchasesAfterPublicUnlock ?? 0) > (rolloutItem?.approximatePurchasesAfterFollowerUnlock ?? 0))
      || (audienceFitWinner === "public" && audienceFitItem?.bestAudienceFitConfidence !== "none")
    );
    const weakFollowerStage = followersStage.views >= 3 && followersStage.clicks + followersStage.rsvps <= Math.max(1, Math.round((publicStage.clicks + publicStage.rsvps) * 0.35));
    const weakMemberStage = membersStage.views >= 3 && membersStage.clicks + membersStage.rsvps <= Math.max(1, Math.round((publicStage.clicks + publicStage.rsvps) * 0.3));
    const multipleMeaningfulStages = rankedStages.filter((stage) => stage.weighted >= Math.max(4, Math.round(totalStageSignal * 0.18))).length >= 2;
    const rsvpHeavyCampaign = (analyticsItem?.totalDropRsvps ?? 0) >= Math.max(5, Math.round((analyticsItem?.followerCount ?? 0) * 0.2));
    const confidence = rolloutAdvisorConfidenceFromSignals(totalStageSignal, signalMargin, audienceFitItem?.bestAudienceFitConfidence ?? null);

    let recommendationType: CreatorCampaignRolloutAdvisorRecommendationType;
    let recommendedNextRolloutMode: CreatorCampaignRolloutMode;
    let title: string;
    let message: string;
    const rationaleParts: string[] = [];

    if (memberSignalStrong && campaign.visibility !== "members" && memberOnlyCollectionsCount > 0 && campaign.rolloutMode !== "members_first" && campaign.rolloutMode !== "staged") {
      recommendationType = "add_member_phase";
      recommendedNextRolloutMode = "staged";
      title = "Add a member phase before wider access";
      message = "Your member signal is strong enough that a short member window should lead the next launch before followers or public unlocks.";
      rationaleParts.push(`Member-stage engagement led this campaign with ${membersStage.views} views, ${membersStage.clicks} clicks, and ${membersStage.rsvps} RSVPs.`);
    } else if (memberSignalStrong && campaign.rolloutMode === "members_first" && (weakFollowerStage || publicWeighted < membersWeighted * 0.65)) {
      recommendationType = "extend_member_window";
      recommendedNextRolloutMode = "members_first";
      title = "Keep members-first and give the member window more room";
      message = "Members are doing the heavy lifting early, so the next launch should keep the same sequence but avoid widening access too quickly.";
      rationaleParts.push(`Member-stage conversion rate was ${roundPercent(safeRolloutStageRate(membersStage) * 100)}% versus ${roundPercent(safeRolloutStageRate(publicStage) * 100)}% in public.`);
    } else if (memberSignalStrong && campaign.rolloutMode === "members_first") {
      recommendationType = "keep_members_first";
      recommendedNextRolloutMode = "members_first";
      title = "Keep the members-first sequence";
      message = "Your current member-first sequence already matches where this campaign is converting best.";
      rationaleParts.push(`Member-stage weighted signal (${rolloutStageWeightedEngagement(membersStage)}) outperformed later stages.`);
    } else if (followerSignalStrong && campaign.rolloutMode === "followers_first" && publicWeighted < followersWeighted * 0.7) {
      recommendationType = "extend_follower_window";
      recommendedNextRolloutMode = "followers_first";
      title = "Keep followers-first and extend the follower window";
      message = "Follower access appears to be the best middle ground for this campaign, so the next launch should stay follower-led a bit longer before widening.";
      rationaleParts.push(`Follower-stage engagement score (${rolloutStageWeightedEngagement(followersStage)}) stayed ahead of public-stage signal.`);
    } else if (followerSignalStrong && campaign.rolloutMode === "followers_first") {
      recommendationType = "keep_followers_first";
      recommendedNextRolloutMode = "followers_first";
      title = "Keep the followers-first sequence";
      message = "This campaign lands best with followers, so the current sequence looks like the right lightweight default.";
      rationaleParts.push(audienceFitItem?.bestAudienceFitReason ?? "Follower-fit signals are leading inside your own campaign data.");
    } else if (campaign.rolloutMode === "staged" && publicSignalStrong && (weakMemberStage || weakFollowerStage || healthItem?.goalsBehind)) {
      recommendationType = "shorten_staged_rollout";
      recommendedNextRolloutMode = "public_first";
      title = "Shorten the staged rollout next time";
      message = "This staged launch widened more slowly than the response curve needed, so the next campaign should reach public earlier.";
      rationaleParts.push(`Public-stage weighted signal (${rolloutStageWeightedEngagement(publicStage)}) overtook earlier stages by ${signalMargin} points.`);
    } else if (publicSignalStrong && campaign.rolloutMode === "staged") {
      recommendationType = "go_public_earlier";
      recommendedNextRolloutMode = "staged";
      title = "Use the same staged structure, but go public earlier";
      message = "Your public unlock is where this campaign accelerated, so keep the sequence lightweight and move the final unlock up next time.";
      rationaleParts.push(`Approximate purchases after public unlock (${rolloutItem?.approximatePurchasesAfterPublicUnlock ?? 0}) beat the follower-stage proxy (${rolloutItem?.approximatePurchasesAfterFollowerUnlock ?? 0}).`);
    } else if (publicSignalStrong && weakMemberStage && memberOnlyCollectionsCount === 0 && (analyticsItem?.membershipsFromCampaign ?? 0) === 0 && campaign.rolloutMode !== "public_first") {
      recommendationType = "skip_member_phase";
      recommendedNextRolloutMode = "public_first";
      title = "Skip the member phase for the next launch";
      message = "This campaign did not show enough member-only lift to justify holding it back before public access.";
      rationaleParts.push(`Member-stage response stayed light while public reached ${publicStage.views} views and ${publicStage.clicks + publicStage.rsvps} higher-intent actions.`);
    } else if (publicSignalStrong && weakFollowerStage && campaign.rolloutMode !== "public_first") {
      recommendationType = "skip_follower_phase";
      recommendedNextRolloutMode = "public_first";
      title = "Skip the follower phase next time";
      message = "Followers added reach, but not enough extra lift to justify a separate middle stage for this campaign.";
      rationaleParts.push(`Follower-stage response stayed softer than public after unlock.`);
    } else if (campaign.rolloutMode !== "staged" && multipleMeaningfulStages && rsvpHeavyCampaign && campaign.visibility === "public") {
      recommendationType = "use_staged_rollout_next_time";
      recommendedNextRolloutMode = "staged";
      title = "Use a staged rollout next time";
      message = "This campaign had enough step-by-step lift that a member/follower/public sequence should be worth testing on the next launch.";
      rationaleParts.push(`At least ${rankedStages.filter((stage) => stage.weighted >= Math.max(4, Math.round(totalStageSignal * 0.18))).length} rollout stages produced meaningful engagement.`);
    } else if (publicSignalStrong && campaign.rolloutMode === "public_first") {
      recommendationType = "keep_public_first";
      recommendedNextRolloutMode = "public_first";
      title = "Keep the public-first launch";
      message = "This campaign appears broad enough that leading with public access is still the most practical sequence.";
      rationaleParts.push(audienceFitItem?.bestAudienceFitReason ?? "Public-stage response is the clearest winner in your own launch data.");
    } else if (memberSignalStrong && campaign.rolloutMode !== "members_first") {
      recommendationType = "add_member_phase";
      recommendedNextRolloutMode = campaign.visibility === "public" ? "staged" : "members_first";
      title = "Start narrower with members before the wider launch";
      message = "This campaign is showing enough member intent that a member phase should be part of the next rollout.";
      rationaleParts.push(`Approximate membership signal during the member window: ${rolloutItem?.approximateMembershipsAfterMemberFirstRollout ?? analyticsItem?.membershipsFromCampaign ?? 0}.`);
    } else if (followerSignalStrong && campaign.rolloutMode !== "followers_first") {
      recommendationType = "keep_followers_first";
      recommendedNextRolloutMode = "followers_first";
      title = "Lead with followers on the next launch";
      message = "Follower response is the best current sequence signal for this campaign, so start there rather than going fully public immediately.";
      rationaleParts.push(audienceFitItem?.bestAudienceFitReason ?? "Follower-stage signal currently leads your audience mix.");
    } else {
      const fallback = buildCampaignRolloutSuggestion({
        campaign: { visibility: campaign.visibility },
        audienceFit: audienceFitItem
          ? {
            bestAudienceFit: audienceFitItem.bestAudienceFit as CreatorCampaignRolloutAudience | null,
            bestAudienceFitConfidence: audienceFitItem.bestAudienceFitConfidence,
            bestAudienceFitReason: audienceFitItem.bestAudienceFitReason,
          }
          : null,
      });
      recommendedNextRolloutMode = fallback.suggestedMode;
      recommendationType = fallback.suggestedMode === "members_first"
        ? "keep_members_first"
        : fallback.suggestedMode === "followers_first"
          ? "keep_followers_first"
          : "keep_public_first";
      title = `Keep ${formatRolloutModeLabel(fallback.suggestedMode)}`;
      message = "There is not enough rollout-stage history to recommend a more complex change yet, so this stays close to the audience fit signal already visible in your dashboard.";
      rationaleParts.push(fallback.reason ?? "Audience-fit signal is the clearest honest read so far.");
    }

    if (healthItem?.goalsBehind) {
      rationaleParts.push(`${healthItem.goalsBehind} goal${healthItem.goalsBehind === 1 ? " is" : "s are"} currently behind pace, so the next rollout should avoid unnecessary delay.`);
    } else if (healthItem?.goalsOnTrack) {
      rationaleParts.push(`${healthItem.goalsOnTrack} goal${healthItem.goalsOnTrack === 1 ? " is" : "s are"} already on track.`);
    }

    const rationaleChips = [
      strongestStage?.weighted ? `Strongest stage: ${campaignRolloutStageLabel(strongestStage.audience)}` : null,
      audienceFitWinner ? `${formatRolloutAudienceLabel(audienceFitWinner)} fit` : "No clear fit yet",
      memberOnlyCollectionsCount > 0 ? `${memberOnlyCollectionsCount} member-only collection${memberOnlyCollectionsCount === 1 ? "" : "s"}` : null,
      (analyticsItem?.membershipsFromCampaign ?? 0) > 0 ? `${analyticsItem?.membershipsFromCampaign ?? 0} approx. memberships` : null,
      (analyticsItem?.purchasesFromLinkedCollections ?? 0) > 0 ? `${analyticsItem?.purchasesFromLinkedCollections ?? 0} approx. purchases` : null,
      healthItem?.healthState ? `Health: ${healthItem.healthState.replace("_", " ")}` : null,
      benchmarkItem?.benchmarkLabels[0] ?? null,
    ].filter((value): value is string => Boolean(value)).slice(0, 5);

    return {
      campaignId: campaign.id,
      campaignName: campaign.name,
      route: `/drinks/campaigns/${encodeURIComponent(campaign.slug)}`,
      currentRolloutMode: (campaign.rolloutMode as CreatorCampaignRolloutMode) ?? "public_first",
      recommendedNextRolloutMode,
      recommendationType,
      title,
      message,
      rationale: rationaleParts.join(" "),
      confidence,
      rationaleChips,
      currentAudienceFit: audienceFitWinner as CreatorCampaignRolloutAudience | null,
      currentAudienceFitConfidence: audienceFitItem?.bestAudienceFitConfidence ?? "none",
      healthState: healthItem?.healthState ?? null,
      benchmarkLabels: benchmarkItem?.benchmarkLabels ?? [],
      memberOnlyCollectionsCount,
      goalsOnTrack: healthItem?.goalsOnTrack ?? 0,
      goalsBehind: healthItem?.goalsBehind ?? 0,
      strongestStage: strongestStage?.audience ?? null,
      totalStageSignal,
    } satisfies CreatorCampaignRolloutAdvisorItem;
  }).sort((a, b) => {
    const stateRank = (campaignId: string) => {
      const campaign = campaignRows.find((entry) => entry.id === campaignId);
      return campaign ? (getCreatorCampaignState(campaign) === "active" ? 2 : getCreatorCampaignState(campaign) === "upcoming" ? 1 : 0) : 0;
    };
    const confidenceRank = (value: CreatorCampaignAudienceFitConfidence) => value === "high" ? 3 : value === "medium" ? 2 : value === "low" ? 1 : 0;
    return stateRank(b.campaignId) - stateRank(a.campaignId)
      || confidenceRank(b.confidence) - confidenceRank(a.confidence)
      || b.totalStageSignal - a.totalStageSignal
      || a.campaignName.localeCompare(b.campaignName);
  });

  const creatorInsights: CreatorCampaignRolloutAdvisorInsight[] = [];
  const publicLed = items.filter((item) => ["keep_public_first", "go_public_earlier", "skip_member_phase", "skip_follower_phase", "shorten_staged_rollout"].includes(item.recommendationType));
  const followerLed = items.filter((item) => ["keep_followers_first", "extend_follower_window"].includes(item.recommendationType));
  const followerUnderperforming = items.filter((item) => item.recommendationType === "skip_follower_phase");
  const memberOnlyWinners = items.filter((item) => item.memberOnlyCollectionsCount > 0 && ["keep_members_first", "extend_member_window", "add_member_phase"].includes(item.recommendationType));
  const rsvpHeavyStaged = items.filter((item) => item.recommendationType === "use_staged_rollout_next_time" || item.recommendationType === "extend_member_window" || item.recommendationType === "extend_follower_window");

  if (memberOnlyWinners.length) {
    creatorInsights.push({
      key: "member_only_strength",
      title: "Member-first is strongest when your campaign links member-only access",
      message: `Inside your own portfolio, ${pluralizeRolloutCampaign(memberOnlyWinners.length)} with member-only collection hooks leaned toward a member-led rollout recommendation rather than a fully public launch.`,
      confidence: memberOnlyWinners.length >= 2 ? "high" : "medium",
      evidence: memberOnlyWinners.slice(0, 3).map((item) => `${item.campaignName}: ${item.memberOnlyCollectionsCount} member-only collection link${item.memberOnlyCollectionsCount === 1 ? "" : "s"} and ${item.recommendationType.replaceAll("_", " ")}.`),
    });
  }

  if (publicLed.length) {
    const strongestPublic = [...publicLed].sort((a, b) => b.totalStageSignal - a.totalStageSignal)[0];
    if (strongestPublic) {
      creatorInsights.push({
        key: "public_strength",
        title: "Broad-reach launches are your clearest public-first fit",
        message: `${strongestPublic.campaignName} is your strongest current public-leaning example, and similar campaigns are consistently pointing toward public-first or earlier public unlocks.`,
        confidence: publicLed.length >= 2 ? "medium" : strongestPublic.confidence,
        evidence: publicLed.slice(0, 3).map((item) => `${item.campaignName}: ${item.recommendationType.replaceAll("_", " ")} with ${Math.round(item.totalStageSignal)} total stage signal.`),
      });
    }
  }

  if (followerUnderperforming.length && followerLed.length <= followerUnderperforming.length) {
    creatorInsights.push({
      key: "follower_underperforming",
      title: "Follower-only middle stages are often too soft for you",
      message: `Follower-first or follower-middle sequencing appears weaker in ${pluralizeRolloutCampaign(followerUnderperforming.length)} of your campaigns, so it looks best reserved for launches that already show clear follower-fit.`,
      confidence: followerUnderperforming.length >= 2 ? "medium" : "low",
      evidence: followerUnderperforming.slice(0, 3).map((item) => `${item.campaignName}: ${item.rationaleChips.find((chip) => chip.includes("Strongest stage")) ?? "Follower stage stayed weaker than the winning stage."}`),
    });
  }

  if (rsvpHeavyStaged.length) {
    creatorInsights.push({
      key: "staged_when_rsvp_heavy",
      title: "Staged rollouts look best when launch intent is already building",
      message: `Your own rollout history suggests staged sequencing is most useful on campaigns that already carry meaningful RSVP or early-intent signal, rather than on every launch by default.`,
      confidence: rsvpHeavyStaged.length >= 2 ? "medium" : "low",
      evidence: rsvpHeavyStaged.slice(0, 3).map((item) => `${item.campaignName}: ${item.recommendationType.replaceAll("_", " ")}.`),
    });
  }

  const summary = {
    totalCampaigns: items.length,
    campaignsWithRecommendations: items.length,
    memberFirstRecommendations: items.filter((item) => item.recommendedNextRolloutMode === "members_first").length,
    followerFirstRecommendations: items.filter((item) => item.recommendedNextRolloutMode === "followers_first").length,
    publicFirstRecommendations: items.filter((item) => item.recommendedNextRolloutMode === "public_first").length,
    stagedRecommendations: items.filter((item) => item.recommendedNextRolloutMode === "staged").length,
  } satisfies CreatorCampaignRolloutAdvisorSummary;

  return {
    summary,
    creatorInsights: creatorInsights.slice(0, 4),
    items,
    attributionNotes: [
      "Rollout advisor is creator-private, rules-based guidance built from existing rollout timing, audience fit, campaign performance, health/watchlist, benchmark, goal, purchase, and membership proxy signals.",
      "Recommendations stay grounded in this creator's own campaigns only. They do not claim a platform-wide truth or hidden AI certainty.",
      "Rollout mode, rollout analytics, audience fit, campaign lifecycle, and campaign health stay separate on purpose: this layer only suggests which sequence may fit the next launch.",
      "Purchase and membership evidence stays approximate anywhere the underlying campaign analytics are approximate.",
    ],
    generatedAt: new Date().toISOString(),
  };
}

function timingAdvisorConfidence(totalSignal: number, evidenceCount: number) {
  if (totalSignal >= 40 && evidenceCount >= 2) return "high" satisfies CreatorCampaignAudienceFitConfidence;
  if (totalSignal >= 16) return "medium" satisfies CreatorCampaignAudienceFitConfidence;
  if (totalSignal > 0) return "low" satisfies CreatorCampaignAudienceFitConfidence;
  return "none" satisfies CreatorCampaignAudienceFitConfidence;
}

function differenceInTimingDays(from: Date | null | undefined, to: Date | null | undefined) {
  if (!from || !to) return null;
  return Math.max(0, Math.round((to.getTime() - from.getTime()) / (24 * 60 * 60 * 1000)));
}

function formatTimingDelay(value: number | null, fallback: string) {
  if (value === null) return fallback;
  if (value <= 0) return "same day";
  if (value === 1) return "1 day after launch";
  return `${value} days after launch`;
}

function addDays(value: Date, days: number) {
  return new Date(value.getTime() + days * 24 * 60 * 60 * 1000);
}

type CampaignTimingSignal = {
  createdAt: Date;
  weight: number;
};

function countTimingSignalInRange(rows: CampaignTimingSignal[], startsAt: Date, endsAt: Date) {
  return rows.reduce((sum, row) => (
    row.createdAt >= startsAt && row.createdAt < endsAt
      ? sum + row.weight
      : sum
  ), 0);
}

function formatTimingRecommendationTypeLabel(value: CreatorCampaignTimingAdvisorRecommendationType) {
  switch (value) {
    case "start_earlier":
      return "Start earlier";
    case "start_later":
      return "Start later";
    case "shorten_member_window":
      return "Shorten member window";
    case "extend_member_window":
      return "Extend member window";
    case "shorten_follower_window":
      return "Shorten follower window";
    case "extend_follower_window":
      return "Extend follower window";
    case "accelerate_public_unlock":
      return "Accelerate public unlock";
    case "delay_public_unlock":
      return "Delay public unlock";
    case "use_short_burst_launch":
      return "Use short burst launch";
    case "use_longer_staged_rollout":
      return "Use longer staged rollout";
    case "keep_current_timing":
    default:
      return "Keep current timing";
  }
}

async function loadCreatorCampaignTimingAdvisor(creatorUserId: string, campaignId?: string | null) {
  if (!db) throw new Error("Database unavailable");

  const [
    campaigns,
    rolloutAnalytics,
    weeklyDigest,
    retrospectives,
    benchmarks,
    health,
  ] = await Promise.all([
    db
      .select()
      .from(creatorCampaigns)
      .where(campaignId
        ? and(eq(creatorCampaigns.creatorUserId, creatorUserId), eq(creatorCampaigns.id, campaignId))
        : eq(creatorCampaigns.creatorUserId, creatorUserId))
      .orderBy(desc(creatorCampaigns.updatedAt))
      .limit(campaignId ? 1 : 120),
    loadCreatorCampaignRolloutAnalytics(creatorUserId, campaignId ?? null),
    loadCreatorCampaignWeeklyDigest(creatorUserId),
    loadCreatorCampaignRetrospectives(creatorUserId),
    loadCreatorCampaignBenchmarks(creatorUserId),
    loadCreatorCampaignHealth(creatorUserId),
  ]);

  if (!campaigns.length) {
    return {
      summary: {
        totalCampaigns: 0,
        campaignsWithRecommendations: 0,
        shorterWindowRecommendations: 0,
        longerWindowRecommendations: 0,
        earlierPublicUnlockRecommendations: 0,
        shortBurstRecommendations: 0,
        keepCurrentTimingCount: 0,
      } satisfies CreatorCampaignTimingAdvisorSummary,
      creatorInsights: [] as CreatorCampaignTimingAdvisorInsight[],
      items: [] as CreatorCampaignTimingAdvisorItem[],
      attributionNotes: [
        "Timing advisor is creator-private, lightweight, and rules-based. It only reads signals that already exist in rollout analytics, weekly digest, retrospectives, benchmarks, health, follows, RSVPs, views, clicks, and approximate conversion proxies.",
        "No creator campaigns exist yet, so there is no launch timing history to summarize honestly.",
      ],
      generatedAt: new Date().toISOString(),
    };
  }

  const campaignIds = campaigns.map((campaign) => campaign.id);
  const linkMap = await loadCreatorCampaignLinksByCampaignIds(campaignIds);
  const dropIds = [...new Set(
    campaigns.flatMap((campaign) => (linkMap.get(campaign.id) ?? [])
      .filter((link) => link.targetType === "drop")
      .map((link) => link.targetId)),
  )];
  const collectionIds = [...new Set(
    campaigns.flatMap((campaign) => (linkMap.get(campaign.id) ?? [])
      .filter((link) => link.targetType === "collection")
      .map((link) => link.targetId)),
  )];

  const [campaignFollowRows, surfaceEventRows, dropEventRows, rsvpRows, purchaseRows] = await Promise.all([
    db.select({
      campaignId: creatorCampaignFollows.campaignId,
      createdAt: creatorCampaignFollows.createdAt,
    }).from(creatorCampaignFollows).where(inArray(creatorCampaignFollows.campaignId, campaignIds)).orderBy(asc(creatorCampaignFollows.createdAt)),
    db.select({
      campaignId: creatorCampaignSurfaceEvents.campaignId,
      eventType: creatorCampaignSurfaceEvents.eventType,
      createdAt: creatorCampaignSurfaceEvents.createdAt,
    }).from(creatorCampaignSurfaceEvents).where(inArray(creatorCampaignSurfaceEvents.campaignId, campaignIds)).orderBy(asc(creatorCampaignSurfaceEvents.createdAt)),
    dropIds.length
      ? db.select({
          dropId: creatorDropEvents.dropId,
          eventType: creatorDropEvents.eventType,
          createdAt: creatorDropEvents.createdAt,
        }).from(creatorDropEvents).where(inArray(creatorDropEvents.dropId, dropIds)).orderBy(asc(creatorDropEvents.createdAt))
      : Promise.resolve([] as Array<{ dropId: string; eventType: CreatorDropEventType; createdAt: Date }>),
    dropIds.length
      ? db.select({
          dropId: creatorDropRsvps.dropId,
          createdAt: creatorDropRsvps.createdAt,
        }).from(creatorDropRsvps).where(inArray(creatorDropRsvps.dropId, dropIds)).orderBy(asc(creatorDropRsvps.createdAt))
      : Promise.resolve([] as Array<{ dropId: string; createdAt: Date }>),
    collectionIds.length
      ? db.select({
          collectionId: drinkCollectionPurchases.collectionId,
          createdAt: drinkCollectionPurchases.createdAt,
          status: drinkCollectionPurchases.status,
        }).from(drinkCollectionPurchases).where(inArray(drinkCollectionPurchases.collectionId, collectionIds)).orderBy(asc(drinkCollectionPurchases.createdAt))
      : Promise.resolve([] as Array<{ collectionId: string; createdAt: Date; status: string }>),
  ]);

  const campaignIdsByDropId = new Map<string, string[]>();
  const campaignIdsByCollectionId = new Map<string, string[]>();
  for (const campaign of campaigns) {
    for (const link of linkMap.get(campaign.id) ?? []) {
      if (link.targetType === "drop") {
        const current = campaignIdsByDropId.get(link.targetId) ?? [];
        current.push(campaign.id);
        campaignIdsByDropId.set(link.targetId, current);
      }
      if (link.targetType === "collection") {
        const current = campaignIdsByCollectionId.get(link.targetId) ?? [];
        current.push(campaign.id);
        campaignIdsByCollectionId.set(link.targetId, current);
      }
    }
  }

  const signalsByCampaignId = new Map<string, CampaignTimingSignal[]>();
  const pushSignal = (campaignIdValue: string, signal: CampaignTimingSignal) => {
    const current = signalsByCampaignId.get(campaignIdValue) ?? [];
    current.push(signal);
    if (!signalsByCampaignId.has(campaignIdValue)) signalsByCampaignId.set(campaignIdValue, current);
  };

  for (const row of campaignFollowRows) {
    pushSignal(row.campaignId, { createdAt: row.createdAt, weight: 4 });
  }
  for (const row of surfaceEventRows) {
    if (row.eventType === "view_campaign") pushSignal(row.campaignId, { createdAt: row.createdAt, weight: 1 });
    if (row.eventType === "click_campaign") pushSignal(row.campaignId, { createdAt: row.createdAt, weight: 3 });
  }
  for (const row of dropEventRows) {
    for (const campaignIdValue of campaignIdsByDropId.get(row.dropId) ?? []) {
      if (row.eventType === "view_drop") pushSignal(campaignIdValue, { createdAt: row.createdAt, weight: 1 });
      if (row.eventType === "click_drop_target") pushSignal(campaignIdValue, { createdAt: row.createdAt, weight: 3 });
    }
  }
  for (const row of rsvpRows) {
    for (const campaignIdValue of campaignIdsByDropId.get(row.dropId) ?? []) {
      pushSignal(campaignIdValue, { createdAt: row.createdAt, weight: 4 });
    }
  }
  for (const row of purchaseRows) {
    if (row.status !== "completed") continue;
    for (const campaignIdValue of campaignIdsByCollectionId.get(row.collectionId) ?? []) {
      pushSignal(campaignIdValue, { createdAt: row.createdAt, weight: 5 });
    }
  }

  const rolloutByCampaignId = new Map(rolloutAnalytics.items.map((item) => [item.campaignId, item]));
  const digestByCampaignId = new Map(weeklyDigest.items.map((item) => [item.campaignId, item]));
  const retrospectiveByCampaignId = new Map(retrospectives.items.map((item) => [item.campaignId, item]));
  const benchmarkByCampaignId = new Map(benchmarks.items.map((item) => [item.campaignId, item]));
  const healthByCampaignId = new Map(health.items.map((item) => [item.campaignId, item]));

  const items = campaigns.map((campaign) => {
    const route = `/drinks/campaigns/${encodeURIComponent(campaign.slug)}`;
    const rolloutItem = rolloutByCampaignId.get(campaign.id) ?? null;
    const digestItem = digestByCampaignId.get(campaign.id) ?? null;
    const retrospective = retrospectiveByCampaignId.get(campaign.id) ?? null;
    const benchmark = benchmarkByCampaignId.get(campaign.id) ?? null;
    const healthItem = healthByCampaignId.get(campaign.id) ?? null;
    const launchAt = campaign.startsAt ?? campaign.createdAt;
    const campaignEndAt = campaign.endsAt ?? new Date();
    const followerUnlockDelay = differenceInTimingDays(launchAt, campaign.unlockFollowersAt);
    const publicUnlockDelay = differenceInTimingDays(launchAt, campaign.unlockPublicAt);
    const signals = (signalsByCampaignId.get(campaign.id) ?? []).filter((signal) => isDateWithinCampaignAnalyticsWindow(signal.createdAt, campaign));
    const totalTimingSignal = signals.reduce((sum, signal) => sum + signal.weight, 0);
    const first48hSignal = countTimingSignalInRange(signals, launchAt, addDays(launchAt, 2));
    const first7dSignal = countTimingSignalInRange(signals, launchAt, addDays(launchAt, 7));
    const after7dSignal = countTimingSignalInRange(signals, addDays(launchAt, 7), addDays(campaignEndAt, 1));
    const followerPhaseStart = campaign.unlockFollowersAt;
    const followerPhaseEnd = campaign.unlockPublicAt ?? campaignEndAt;
    const publicPhaseStart = campaign.unlockPublicAt ?? (campaign.rolloutMode === "public_first" ? launchAt : null);
    const memberPhaseEnd = campaign.unlockFollowersAt ?? campaign.unlockPublicAt ?? campaignEndAt;
    const memberEarlySignal = rolloutItem?.startsWithAudience === "members"
      ? countTimingSignalInRange(signals, launchAt, addDays(launchAt, 2))
      : 0;
    const memberTotalSignal = rolloutItem?.startsWithAudience === "members"
      ? countTimingSignalInRange(signals, launchAt, addDays(memberPhaseEnd, 1))
      : 0;
    const followerEarlySignal = followerPhaseStart
      ? countTimingSignalInRange(signals, followerPhaseStart, addDays(followerPhaseStart, 2))
      : 0;
    const followerLateSignal = followerPhaseStart
      ? countTimingSignalInRange(signals, addDays(followerPhaseStart, 2), addDays(followerPhaseEnd, 1))
      : 0;
    const publicEarlySignal = publicPhaseStart
      ? countTimingSignalInRange(signals, publicPhaseStart, addDays(publicPhaseStart, 2))
      : 0;
    const publicLateSignal = publicPhaseStart
      ? countTimingSignalInRange(signals, addDays(publicPhaseStart, 2), addDays(campaignEndAt, 1))
      : 0;

    const stageMap = new Map((rolloutItem?.stagePerformance ?? []).map((stage) => [stage.audience, stage]));
    const membersStage = stageMap.get("members") ?? emptyCreatorCampaignRolloutStageAnalytics("members");
    const followersStage = stageMap.get("followers") ?? emptyCreatorCampaignRolloutStageAnalytics("followers");
    const publicStage = stageMap.get("public") ?? emptyCreatorCampaignRolloutStageAnalytics("public");
    const membersWeighted = rolloutStageWeightedEngagement(membersStage);
    const followersWeighted = rolloutStageWeightedEngagement(followersStage);
    const publicWeighted = rolloutStageWeightedEngagement(publicStage);
    const strongestStage = [
      { audience: "members" as const, weighted: membersWeighted },
      { audience: "followers" as const, weighted: followersWeighted },
      { audience: "public" as const, weighted: publicWeighted },
    ].sort((a, b) => b.weighted - a.weighted)[0];
    const approxPurchaseSignal = (rolloutItem?.approximatePurchasesAfterPublicUnlock ?? 0) + (rolloutItem?.approximatePurchasesAfterFollowerUnlock ?? 0);
    const approxMembershipSignal = rolloutItem?.approximateMembershipsAfterMemberFirstRollout ?? benchmark?.membershipsFromCampaign ?? 0;
    const hasMemberWindow = rolloutItem?.startsWithAudience === "members" && memberPhaseEnd > launchAt;
    const followerWindowUseful = followersWeighted >= Math.max(6, Math.round(publicWeighted * 0.8));
    const followerWindowWeak = followersStage.views >= 3 && followersWeighted <= Math.max(2, Math.round(publicWeighted * 0.4));
    const publicEarlyBurst = publicEarlySignal >= Math.max(8, publicLateSignal * 1.25);
    const launchFrontLoaded = totalTimingSignal > 0 && first7dSignal >= Math.max(8, Math.round(totalTimingSignal * 0.7));
    const laterLift = after7dSignal >= Math.max(8, first7dSignal * 0.45);
    const multiStageSignal = [membersWeighted, followersWeighted, publicWeighted].filter((value) => value >= Math.max(4, Math.round(totalTimingSignal * 0.18))).length >= 2;
    const recommendationSignals: string[] = [];

    let timingRecommendationType: CreatorCampaignTimingAdvisorRecommendationType = "keep_current_timing";
    let title = "Keep the current launch timing";
    let message = "Your current timing still reads as a reasonable lightweight default for the next pass.";
    let suggestedFollowerUnlockDelay = followerUnlockDelay;
    let suggestedPublicUnlockDelay = publicUnlockDelay;
    let suggestedStartTiming = launchFrontLoaded
      ? "Start the visible push 1–2 days before the main drop, then move quickly through the unlocks."
      : "Start the campaign 3–5 days before the main drop so the early stages have time to collect signal.";

    if (hasMemberWindow && memberTotalSignal >= Math.max(publicEarlySignal + publicLateSignal, followersWeighted) * 1.15 && (approxMembershipSignal > 0 || membersStage.clicks + membersStage.rsvps > 0) && (followerUnlockDelay ?? 0) <= 2) {
      timingRecommendationType = "extend_member_window";
      suggestedFollowerUnlockDelay = Math.max(2, (followerUnlockDelay ?? 0) + 1);
      suggestedPublicUnlockDelay = Math.max(suggestedFollowerUnlockDelay ?? 0, (publicUnlockDelay ?? suggestedFollowerUnlockDelay ?? 0) + 1);
      suggestedStartTiming = "Start 4–6 days before the main drop so members get a real head start before wider access.";
      title = "Give the member window more room";
      message = "Member-stage response is doing enough work that the next launch should keep members exclusive a little longer before follower or public unlocks.";
      recommendationSignals.push(`Member-stage weighted signal ${membersWeighted} beat follower/public timing signal.`);
      if (approxMembershipSignal > 0) recommendationSignals.push(`${approxMembershipSignal} approximate membership conversions appeared during the member-first window.`);
    } else if (hasMemberWindow && memberTotalSignal > 0 && memberEarlySignal >= Math.max(6, Math.round(memberTotalSignal * 0.75)) && (followerUnlockDelay ?? 0) >= 3) {
      timingRecommendationType = "shorten_member_window";
      suggestedFollowerUnlockDelay = Math.max(1, (followerUnlockDelay ?? 0) - 1);
      suggestedPublicUnlockDelay = publicUnlockDelay !== null ? Math.max(suggestedFollowerUnlockDelay ?? 1, publicUnlockDelay - 1) : null;
      suggestedStartTiming = "Start 2–4 days before the main drop and let followers in sooner once the first member burst lands.";
      title = "Shorten the member-only hold";
      message = "Most of the member-stage lift happened quickly, so a shorter member window should preserve exclusivity without stalling the rest of the launch.";
      recommendationSignals.push(`About ${roundPercent((memberEarlySignal / Math.max(1, memberTotalSignal)) * 100)}% of member-stage timing signal landed in the first 48 hours.`);
    } else if (followerPhaseStart && followerWindowWeak && (publicUnlockDelay ?? 0) - (followerUnlockDelay ?? 0) >= 3) {
      timingRecommendationType = "shorten_follower_window";
      suggestedPublicUnlockDelay = Math.max((followerUnlockDelay ?? 0) + 1, (publicUnlockDelay ?? 0) - 1);
      suggestedStartTiming = "Start 2–3 days before the main drop and keep follower access brief before public unlock.";
      title = "Shorten the follower window";
      message = "Follower-stage reach did not create much extra lift on its own, so the next launch should move from followers to public faster.";
      recommendationSignals.push(`Follower-stage weighted signal ${followersWeighted} stayed soft versus public-stage ${publicWeighted}.`);
    } else if (followerPhaseStart && followerWindowUseful && followerLateSignal >= Math.max(6, followerEarlySignal * 1.1) && (publicUnlockDelay ?? 0) - (followerUnlockDelay ?? 0) <= 2) {
      timingRecommendationType = "extend_follower_window";
      suggestedPublicUnlockDelay = Math.max((publicUnlockDelay ?? 0) + 1, (followerUnlockDelay ?? 0) + 2);
      suggestedStartTiming = "Start 4–5 days before the main drop so follower access has time to compound before public unlock.";
      title = "Let the follower stage breathe a bit longer";
      message = "Follower activity kept building instead of peaking immediately, so the next launch should not rush into public access.";
      recommendationSignals.push(`Follower-stage timing signal kept growing after the first 48 hours (${followerLateSignal} late vs ${followerEarlySignal} early).`);
    } else if (campaign.unlockPublicAt && publicEarlyBurst && (publicUnlockDelay ?? 0) >= 3 && publicWeighted >= Math.max(membersWeighted, followersWeighted)) {
      timingRecommendationType = "accelerate_public_unlock";
      suggestedPublicUnlockDelay = Math.max(1, (publicUnlockDelay ?? 0) - 1);
      suggestedStartTiming = "Start 2–4 days before the main drop and move public unlock up once the early private stages have tested the message.";
      title = "Open public access sooner";
      message = "Public response appears to arrive fast once the campaign opens up, so the next launch should not wait as long before the public unlock.";
      recommendationSignals.push(`Public-stage timing signal hit quickly (${publicEarlySignal} in the first 48 hours after public unlock).`);
      if ((rolloutItem?.approximatePurchasesAfterPublicUnlock ?? 0) > 0) recommendationSignals.push(`${rolloutItem?.approximatePurchasesAfterPublicUnlock ?? 0} approximate purchases appeared after public unlock.`);
    } else if (campaign.unlockPublicAt && hasMemberWindow && memberTotalSignal >= Math.max(publicWeighted, followersWeighted) * 1.15 && approxMembershipSignal > 0 && (publicUnlockDelay ?? 0) <= 4) {
      timingRecommendationType = "delay_public_unlock";
      suggestedPublicUnlockDelay = Math.max((publicUnlockDelay ?? 0) + 1, (suggestedFollowerUnlockDelay ?? 0) + 1);
      suggestedStartTiming = "Start 4–6 days before the main drop so member/follower momentum has time to mature before the public phase.";
      title = "Delay the public unlock slightly";
      message = "This campaign looks strongest before it opens fully, so the next version should hold public access a bit longer to preserve the early-stage conversion window.";
      recommendationSignals.push(`Member-stage weighted signal ${membersWeighted} is currently stronger than public-stage ${publicWeighted}.`);
      recommendationSignals.push(`${approxMembershipSignal} approximate membership signal suggests the private window is doing useful work.`);
    } else if (launchFrontLoaded && !multiStageSignal && publicWeighted >= Math.max(membersWeighted, followersWeighted) && (benchmark?.campaignDurationDays ?? 0) >= 8) {
      timingRecommendationType = "use_short_burst_launch";
      suggestedFollowerUnlockDelay = followerUnlockDelay !== null ? Math.min(followerUnlockDelay, 1) : null;
      suggestedPublicUnlockDelay = publicUnlockDelay !== null ? Math.min(publicUnlockDelay, 2) : 1;
      suggestedStartTiming = "Start 1–2 days before the main drop and compress the whole launch into a short burst.";
      title = "Use a shorter burst launch next time";
      message = "Most of this campaign's signal landed early, so a compact launch window should fit better than a long staged arc.";
      recommendationSignals.push(`${roundPercent((first7dSignal / Math.max(1, totalTimingSignal)) * 100)}% of weighted timing signal landed in the first week.`);
      recommendationSignals.push(`The campaign still ran about ${benchmark?.campaignDurationDays ?? 0} days.`);
    } else if (multiStageSignal && laterLift && (benchmark?.campaignDurationDays ?? 0) <= 7) {
      timingRecommendationType = "use_longer_staged_rollout";
      suggestedFollowerUnlockDelay = followerUnlockDelay ?? 2;
      suggestedPublicUnlockDelay = publicUnlockDelay ?? 4;
      suggestedStartTiming = "Start 5–7 days before the main drop so each stage has enough room to produce signal.";
      title = "Give the rollout a little more runway";
      message = "Multiple stages are adding real lift here, so the next campaign should use a slightly longer staged window instead of collapsing everything together.";
      recommendationSignals.push(`Later timing signal stayed meaningful after day 7 (${after7dSignal}).`);
      recommendationSignals.push(`At least two rollout stages contributed meaningful engagement.`);
    } else if (after7dSignal >= Math.max(8, first48hSignal * 1.25) && (benchmark?.campaignDurationDays ?? 0) >= 7) {
      timingRecommendationType = "start_earlier";
      suggestedStartTiming = "Begin the campaign warm-up 5–7 days before the main drop so the audience has more time to build before the peak moment.";
      title = "Start warming this campaign up earlier";
      message = "This launch found more traction after the first burst, which suggests the next version should start its visible arc sooner rather than relying on a same-day spike.";
      recommendationSignals.push(`Post-launch signal after day 7 (${after7dSignal}) beat the first-48-hour burst (${first48hSignal}).`);
      if (digestItem) recommendationSignals.push(`${digestItem.newFollowersThisWeek} new follows and ${digestItem.newRsvpsThisWeek} new RSVPs landed in the latest digest window.`);
    } else if (launchFrontLoaded && (benchmark?.campaignDurationDays ?? 0) >= 10) {
      timingRecommendationType = "start_later";
      suggestedStartTiming = "Start closer to the main drop — about 1–3 days ahead — because this audience responds quickly once the campaign is visible.";
      title = "Start closer to the main launch moment";
      message = "This campaign did not need a long ramp: the strongest response arrived early, so the next version can wait longer before opening the arc.";
      recommendationSignals.push(`The first week carried most of the timing signal (${first7dSignal} of ${totalTimingSignal}).`);
    }

    const confidence = timingAdvisorConfidence(totalTimingSignal, recommendationSignals.length);
    const rationaleParts = [
      recommendationSignals[0] ?? null,
      digestItem ? `Weekly digest most recently showed ${digestItem.newFollowersThisWeek} follows, ${digestItem.newRsvpsThisWeek} RSVPs, ${digestItem.dropViewsThisWeek} linked drop views, and ${digestItem.dropClicksThisWeek} linked drop clicks.` : null,
      retrospective?.lessons[0]?.message ?? null,
      healthItem?.primaryStrength ? `Health strength: ${healthItem.primaryStrength}` : null,
      healthItem?.primaryConcern && timingRecommendationType !== "keep_current_timing" ? `Health concern: ${healthItem.primaryConcern}` : null,
      benchmark?.benchmarkLabels[0] ? `Benchmark context: ${benchmark.benchmarkLabels[0]}.` : null,
      approxPurchaseSignal > 0 ? `${approxPurchaseSignal} approximate purchase signal${approxPurchaseSignal === 1 ? "" : "s"} factored in where launch timing overlaps linked collection purchases.` : null,
      approxMembershipSignal > 0 ? `${approxMembershipSignal} approximate membership signal${approxMembershipSignal === 1 ? "" : "s"} factored in where member-first timing overlaps campaign conversion windows.` : null,
    ].filter((value): value is string => Boolean(value));

    const rationaleChips = [
      strongestStage?.weighted ? `Strongest stage: ${campaignRolloutStageLabel(strongestStage.audience)}` : null,
      followerUnlockDelay !== null ? `Follower unlock now: ${formatTimingDelay(followerUnlockDelay, "not used")}` : null,
      publicUnlockDelay !== null ? `Public unlock now: ${formatTimingDelay(publicUnlockDelay, "same day")}` : null,
      suggestedFollowerUnlockDelay !== null ? `Follower next: ${formatTimingDelay(suggestedFollowerUnlockDelay, "not used")}` : null,
      suggestedPublicUnlockDelay !== null ? `Public next: ${formatTimingDelay(suggestedPublicUnlockDelay, "same day")}` : null,
      healthItem?.healthState ? `Health: ${healthItem.healthState.replaceAll("_", " ")}` : null,
      benchmark?.benchmarkLabels[0] ?? null,
      digestItem?.wasActiveThisWeek ? "Active in weekly digest" : null,
      retrospective?.reuseCandidate ? "Retrospective says reusable" : null,
    ].filter((value): value is string => Boolean(value)).slice(0, 6);

    return {
      campaignId: campaign.id,
      campaignName: campaign.name,
      route,
      currentRolloutMode: (campaign.rolloutMode as CreatorCampaignRolloutMode) ?? "public_first",
      suggestedStartTiming,
      suggestedFollowerUnlockDelay,
      suggestedPublicUnlockDelay,
      timingRecommendationType,
      title,
      message,
      rationale: rationaleParts.join(" "),
      confidence,
      rationaleChips,
      strongestStage: strongestStage?.weighted ? strongestStage.audience : null,
      currentFollowerUnlockDelay: followerUnlockDelay,
      currentPublicUnlockDelay: publicUnlockDelay,
      totalTimingSignal,
      approximatePurchaseSignal: approxPurchaseSignal,
      approximateMembershipSignal: approxMembershipSignal,
    } satisfies CreatorCampaignTimingAdvisorItem;
  }).sort((a, b) => {
    const confidenceRank = (value: CreatorCampaignAudienceFitConfidence) => value === "high" ? 3 : value === "medium" ? 2 : value === "low" ? 1 : 0;
    return confidenceRank(b.confidence) - confidenceRank(a.confidence)
      || b.totalTimingSignal - a.totalTimingSignal
      || a.campaignName.localeCompare(b.campaignName);
  });

  const creatorInsights: CreatorCampaignTimingAdvisorInsight[] = [];
  const topItems = [...items].sort((a, b) => b.totalTimingSignal - a.totalTimingSignal).slice(0, Math.min(3, items.length));
  const shortBurstItems = items.filter((item) => ["use_short_burst_launch", "start_later", "accelerate_public_unlock", "shorten_follower_window", "shorten_member_window"].includes(item.timingRecommendationType));
  const longerWindowItems = items.filter((item) => ["use_longer_staged_rollout", "extend_member_window", "extend_follower_window", "delay_public_unlock", "start_earlier"].includes(item.timingRecommendationType));
  const memberWindowItems = items.filter((item) => ["extend_member_window", "delay_public_unlock"].includes(item.timingRecommendationType));
  const publicUnlockItems = items.filter((item) => item.suggestedPublicUnlockDelay !== null);
  const earlyPublicItems = items.filter((item) => ["accelerate_public_unlock", "use_short_burst_launch", "shorten_follower_window"].includes(item.timingRecommendationType));

  if (memberWindowItems.length) {
    creatorInsights.push({
      key: "member_window_strength",
      title: "Your member-led launches usually deserve a little protected time",
      message: `Across ${pluralizeRolloutCampaign(memberWindowItems.length)}, the strongest early signal showed up before the public phase, which points toward holding the private window a bit longer when member intent is real.`,
      confidence: memberWindowItems.length >= 2 ? "medium" : memberWindowItems[0]?.confidence ?? "low",
      evidence: memberWindowItems.slice(0, 3).map((item) => `${item.campaignName}: ${formatTimingRecommendationTypeLabel(item.timingRecommendationType)}.`),
    });
  }

  if (publicUnlockItems.length) {
    const delayValues = publicUnlockItems.map((item) => item.suggestedPublicUnlockDelay).filter((value): value is number => value !== null).sort((a, b) => a - b);
    const medianDelay = delayValues.length ? delayValues[Math.floor(delayValues.length / 2)] : null;
    if (medianDelay !== null) {
      creatorInsights.push({
        key: "public_unlock_window",
        title: "Public unlock usually matters within a tight window for you",
        message: `In your own campaign history, the next best public unlock usually lands around ${formatTimingDelay(medianDelay, "same day")}, rather than staying open-ended for a long time.`,
        confidence: delayValues.length >= 3 ? "medium" : "low",
        evidence: publicUnlockItems.slice(0, 3).map((item) => `${item.campaignName}: suggested public unlock ${formatTimingDelay(item.suggestedPublicUnlockDelay, "same day")}.`),
      });
    }
  }

  if (shortBurstItems.length > longerWindowItems.length && topItems.length) {
    creatorInsights.push({
      key: "short_burst_bias",
      title: "Short-burst launches look stronger than long arcs in your public-reach campaigns",
      message: `Your strongest timing examples lean toward compact launches that unlock quickly once interest appears, instead of stretching the arc longer than the response curve needs.`,
      confidence: shortBurstItems.length >= 2 ? "medium" : topItems[0]?.confidence ?? "low",
      evidence: topItems.map((item) => `${item.campaignName}: ${formatTimingRecommendationTypeLabel(item.timingRecommendationType)}.`),
    });
  } else if (longerWindowItems.length && longerWindowItems.length >= shortBurstItems.length) {
    creatorInsights.push({
      key: "longer_stage_bias",
      title: "Your stronger campaigns often need a little timing runway",
      message: `Several of your launches keep adding lift after the first burst, which suggests a short member/follower runway is often better than collapsing every stage into one day.`,
      confidence: longerWindowItems.length >= 2 ? "medium" : longerWindowItems[0]?.confidence ?? "low",
      evidence: longerWindowItems.slice(0, 3).map((item) => `${item.campaignName}: ${formatTimingRecommendationTypeLabel(item.timingRecommendationType)}.`),
    });
  }

  if (earlyPublicItems.length >= 2) {
    creatorInsights.push({
      key: "follower_window_softness",
      title: "Follower-stage timing can be too long for some of your broad-reach campaigns",
      message: `When follower-stage reach is mostly a bridge to public traffic, your data usually points toward widening access sooner instead of sitting in the middle stage too long.`,
      confidence: earlyPublicItems.length >= 3 ? "medium" : "low",
      evidence: earlyPublicItems.slice(0, 3).map((item) => `${item.campaignName}: ${item.rationaleChips.find((chip) => chip.startsWith("Public next")) ?? formatTimingRecommendationTypeLabel(item.timingRecommendationType)}.`),
    });
  }

  const summary = {
    totalCampaigns: items.length,
    campaignsWithRecommendations: items.length,
    shorterWindowRecommendations: items.filter((item) => ["shorten_member_window", "shorten_follower_window", "accelerate_public_unlock"].includes(item.timingRecommendationType)).length,
    longerWindowRecommendations: items.filter((item) => ["extend_member_window", "extend_follower_window", "delay_public_unlock", "use_longer_staged_rollout", "start_earlier"].includes(item.timingRecommendationType)).length,
    earlierPublicUnlockRecommendations: items.filter((item) => ["accelerate_public_unlock", "shorten_follower_window", "use_short_burst_launch"].includes(item.timingRecommendationType)).length,
    shortBurstRecommendations: items.filter((item) => ["use_short_burst_launch", "start_later"].includes(item.timingRecommendationType)).length,
    keepCurrentTimingCount: items.filter((item) => item.timingRecommendationType === "keep_current_timing").length,
  } satisfies CreatorCampaignTimingAdvisorSummary;

  return {
    summary,
    creatorInsights: creatorInsights.slice(0, 4),
    items,
    attributionNotes: [
      "Timing advisor stays separate from rollout mode and rollout advisor on purpose: rollout mode answers who unlocks first, while timing advisor answers how long each window should stay open next time.",
      "Recommendations are rules-based and grounded in this creator's own launch timing, follow, RSVP, view, click, benchmark, weekly digest, retrospective, health, and approximate conversion signals only.",
      "No new tracking system is introduced here; it re-reads timestamps and summaries the drinks platform already stores.",
      "Purchases and memberships remain clearly labeled approximations anywhere the underlying campaign analytics are already approximate.",
    ],
    generatedAt: new Date().toISOString(),
  };
}

function countRowsInRollingWindow(rows: Array<{ createdAt: Date }>, now: Date, days: number, campaign: Pick<CreatorCampaignRecord, "startsAt" | "endsAt" | "createdAt">) {
  const lowerBound = new Date(now.getTime() - (days * 24 * 60 * 60 * 1000));
  return rows.filter((row) => row.createdAt >= lowerBound && isDateWithinCampaignAnalyticsWindow(row.createdAt, campaign)).length;
}

function roundPercent(value: number) {
  return Math.round(value * 10) / 10;
}

function formatSpotlightPercent(value: number) {
  return `${roundPercent(value)}%`;
}

function buildSpotlightProxyScore(input: {
  recentFollowers: number;
  recentRsvps: number;
  recentClicks: number;
  recentPurchases: number;
  recentMemberships: number;
  totalViews: number;
  state: CreatorCampaignState;
}) {
  return Math.round(
    input.recentFollowers * 5
    + input.recentRsvps * 4
    + input.recentClicks * 3
    + input.recentPurchases * 5
    + input.recentMemberships * 6
    + input.totalViews * 0.15
    + (input.state === "active" ? 12 : input.state === "upcoming" ? 6 : 0)
  );
}

function buildSpotlightClickPotentialScore(input: {
  recentClicks: number;
  recentRsvps: number;
  totalClicks: number;
  totalViews: number;
}) {
  return Math.round(
    input.recentClicks * 4
    + input.recentRsvps * 3
    + input.totalClicks * 1.5
    + input.totalViews * 0.2
  );
}

function buildSpotlightConversionPotentialScore(input: {
  recentPurchases: number;
  recentMemberships: number;
  totalPurchases: number;
  totalMemberships: number;
}) {
  return Math.round(
    input.recentPurchases * 5
    + input.recentMemberships * 6
    + input.totalPurchases * 2
    + input.totalMemberships * 3
  );
}

async function loadPinnedCampaignSpotlightAnalytics(creatorUserId: string) {
  if (!db) throw new Error("Database unavailable");

  const [campaigns, performance] = await Promise.all([
    db.select().from(creatorCampaigns).where(eq(creatorCampaigns.creatorUserId, creatorUserId)).orderBy(desc(creatorCampaigns.updatedAt)).limit(120),
    loadCreatorCampaignPerformanceSnapshots(creatorUserId),
  ]);

  const performanceByCampaignId = new Map(performance.items.map((item) => [item.campaignId, item]));
  const pinnedCampaign = campaigns.find((campaign) => campaign.isPinned) ?? null;
  const now = new Date();
  const recentWindowDays = 14;

  if (campaigns.length === 0) {
    return {
      pinnedCampaign: null,
      candidates: [],
      rotationSuggestion: {
        key: "no_campaigns",
        headline: "No campaign spotlight yet",
        summary: "Create a campaign first, then spotlight analytics can compare your pinned slot against other active story arcs.",
        severity: "info",
        signals: [] as string[],
        suggestedCampaignId: null as string | null,
      },
      attributionNotes: [
        "Spotlight analytics are creator-private and stay separate from broader campaign analytics.",
        "No spotlight events or campaign candidates exist yet for this creator.",
      ],
      generatedAt: now.toISOString(),
    };
  }

  const campaignIds = campaigns.map((campaign) => campaign.id);
  const [linkMap, followRows, membershipRows, spotlightEventRows] = await Promise.all([
    loadCreatorCampaignLinksByCampaignIds(campaignIds),
    db.select({
      campaignId: creatorCampaignFollows.campaignId,
      userId: creatorCampaignFollows.userId,
      createdAt: creatorCampaignFollows.createdAt,
    }).from(creatorCampaignFollows).where(inArray(creatorCampaignFollows.campaignId, campaignIds)).orderBy(asc(creatorCampaignFollows.createdAt)),
    db.select({
      userId: creatorMemberships.userId,
      createdAt: creatorMemberships.createdAt,
      status: creatorMemberships.status,
    }).from(creatorMemberships).where(eq(creatorMemberships.creatorUserId, creatorUserId)).orderBy(asc(creatorMemberships.createdAt)),
    db.select().from(creatorCampaignSpotlightEvents).where(inArray(creatorCampaignSpotlightEvents.campaignId, campaignIds)).orderBy(asc(creatorCampaignSpotlightEvents.createdAt)),
  ]);

  const dropIds = [...new Set(
    campaigns.flatMap((campaign) => (linkMap.get(campaign.id) ?? [])
      .filter((link) => link.targetType === "drop")
      .map((link) => link.targetId)),
  )];
  const collectionIds = [...new Set(
    campaigns.flatMap((campaign) => (linkMap.get(campaign.id) ?? [])
      .filter((link) => link.targetType === "collection")
      .map((link) => link.targetId)),
  )];

  const [rsvpRows, purchaseRows] = await Promise.all([
    dropIds.length
      ? db.select({
          dropId: creatorDropRsvps.dropId,
          userId: creatorDropRsvps.userId,
          createdAt: creatorDropRsvps.createdAt,
        }).from(creatorDropRsvps).where(inArray(creatorDropRsvps.dropId, dropIds)).orderBy(asc(creatorDropRsvps.createdAt))
      : Promise.resolve([] as Array<{ dropId: string; userId: string; createdAt: Date }>),
    collectionIds.length
      ? db.select({
          collectionId: drinkCollectionPurchases.collectionId,
          userId: drinkCollectionPurchases.userId,
          createdAt: drinkCollectionPurchases.createdAt,
          status: drinkCollectionPurchases.status,
        }).from(drinkCollectionPurchases).where(inArray(drinkCollectionPurchases.collectionId, collectionIds)).orderBy(asc(drinkCollectionPurchases.createdAt))
      : Promise.resolve([] as Array<{ collectionId: string; userId: string; createdAt: Date; status: string }>),
  ]);

  const followRowsByCampaignId = new Map<string, Array<{ userId: string; createdAt: Date }>>();
  for (const row of followRows) {
    const current = followRowsByCampaignId.get(row.campaignId) ?? [];
    current.push({ userId: row.userId, createdAt: row.createdAt });
    followRowsByCampaignId.set(row.campaignId, current);
  }

  const linkedDropIdsByCampaignId = new Map<string, string[]>();
  const linkedCollectionIdsByCampaignId = new Map<string, string[]>();
  for (const campaign of campaigns) {
    const links = linkMap.get(campaign.id) ?? [];
    linkedDropIdsByCampaignId.set(campaign.id, links.filter((link) => link.targetType === "drop").map((link) => link.targetId));
    linkedCollectionIdsByCampaignId.set(campaign.id, links.filter((link) => link.targetType === "collection").map((link) => link.targetId));
  }

  const rsvpRowsByDropId = new Map<string, Array<{ userId: string; createdAt: Date }>>();
  for (const row of rsvpRows) {
    const current = rsvpRowsByDropId.get(row.dropId) ?? [];
    current.push({ userId: row.userId, createdAt: row.createdAt });
    rsvpRowsByDropId.set(row.dropId, current);
  }

  const purchaseRowsByCollectionId = new Map<string, Array<{ userId: string; createdAt: Date; status: string }>>();
  for (const row of purchaseRows) {
    const current = purchaseRowsByCollectionId.get(row.collectionId) ?? [];
    current.push({ userId: row.userId, createdAt: row.createdAt, status: row.status });
    purchaseRowsByCollectionId.set(row.collectionId, current);
  }

  const membershipRowsByUserId = new Map<string, Array<{ createdAt: Date; status: string }>>();
  for (const row of membershipRows) {
    const current = membershipRowsByUserId.get(row.userId) ?? [];
    current.push({ createdAt: row.createdAt, status: row.status });
    membershipRowsByUserId.set(row.userId, current);
  }

  const spotlightEventsByCampaignId = new Map<string, CreatorCampaignSpotlightEventRecord[]>();
  for (const row of spotlightEventRows) {
    const current = spotlightEventsByCampaignId.get(row.campaignId) ?? [];
    current.push(row);
    spotlightEventsByCampaignId.set(row.campaignId, current);
  }

  const comparisonItems = campaigns.map((campaign) => {
    const analytics = performanceByCampaignId.get(campaign.id);
    const state = getCreatorCampaignState(campaign, now);
    const followRowsForCampaign = followRowsByCampaignId.get(campaign.id) ?? [];
    const linkedDropIds = linkedDropIdsByCampaignId.get(campaign.id) ?? [];
    const linkedCollectionIds = linkedCollectionIdsByCampaignId.get(campaign.id) ?? [];
    const rsvpRowsForCampaign = linkedDropIds.flatMap((dropId) => rsvpRowsByDropId.get(dropId) ?? []);
    const purchaseRowsForCampaign = linkedCollectionIds.flatMap((collectionId) => purchaseRowsByCollectionId.get(collectionId) ?? [])
      .filter((row) => row.status === "completed");
    const membershipRowsForCampaign = membershipRows.filter((row) => (
      ["active", "canceled"].includes(row.status) && isDateWithinCampaignAnalyticsWindow(row.createdAt, campaign)
    ));
    const recentFollowers = countRowsInRollingWindow(followRowsForCampaign, now, recentWindowDays, campaign);
    const recentRsvps = countRowsInRollingWindow(rsvpRowsForCampaign, now, recentWindowDays, campaign);
    const recentPurchases = countRowsInRollingWindow(purchaseRowsForCampaign, now, recentWindowDays, campaign);
    const recentMemberships = countRowsInRollingWindow(membershipRowsForCampaign, now, recentWindowDays, campaign);
    const totalViews = analytics?.totalDropViews ?? 0;
    const totalClicks = analytics?.totalDropClicks ?? 0;
    const recentClicks = state === "past"
      ? 0
      : Math.min(totalClicks, Math.round(totalClicks * 0.5 + recentRsvps * 0.5));
    const memberFocused = campaign.visibility === "members" || (analytics?.membershipsFromCampaign ?? 0) > 0;
    const rotationScore = buildSpotlightProxyScore({
      recentFollowers,
      recentRsvps,
      recentClicks,
      recentPurchases,
      recentMemberships,
      totalViews,
      state,
    });
    const clickPotentialScore = buildSpotlightClickPotentialScore({
      recentClicks,
      recentRsvps,
      totalClicks,
      totalViews,
    });
    const conversionPotentialScore = buildSpotlightConversionPotentialScore({
      recentPurchases,
      recentMemberships,
      totalPurchases: analytics?.purchasesFromLinkedCollections ?? 0,
      totalMemberships: analytics?.membershipsFromCampaign ?? 0,
    });

    return {
      campaignId: campaign.id,
      name: campaign.name,
      slug: campaign.slug,
      route: `/drinks/campaigns/${encodeURIComponent(campaign.slug)}`,
      visibility: campaign.visibility as CreatorCampaignVisibility,
      state,
      isPinned: campaign.isPinned,
      memberFocused,
      followerMomentum: {
        recentFollowers,
        totalFollowers: analytics?.followerCount ?? 0,
      },
      clickPotential: {
        score: clickPotentialScore,
        recentClicks,
        totalClicks,
        totalViews,
      },
      conversionPotential: {
        score: conversionPotentialScore,
        recentPurchases,
        recentMemberships,
        totalPurchases: analytics?.purchasesFromLinkedCollections ?? 0,
        totalMemberships: analytics?.membershipsFromCampaign ?? 0,
      },
      engagementScore: analytics?.campaignEngagementScore ?? 0,
      rotationScore,
    };
  });

  const bestAlternative = comparisonItems
    .filter((item) => !item.isPinned && item.state !== "past")
    .sort((a, b) => b.rotationScore - a.rotationScore || b.clickPotential.score - a.clickPotential.score)[0] ?? null;

  const pinnedAnalytics = pinnedCampaign
    ? (() => {
        const analytics = performanceByCampaignId.get(pinnedCampaign.id);
        const events = spotlightEventsByCampaignId.get(pinnedCampaign.id) ?? [];
        const spotlightViews = events.filter((event) => event.eventType === "view_pinned_campaign").length;
        const spotlightClicks = events.filter((event) => event.eventType === "click_pinned_campaign").length;
        const spotlightCtr = spotlightViews > 0 ? roundPercent((spotlightClicks / spotlightViews) * 100) : 0;
        const linkedDropIds = linkedDropIdsByCampaignId.get(pinnedCampaign.id) ?? [];
        const clickEventsByUser = new Map<string, Date[]>();
        for (const event of events) {
          if (event.eventType !== "click_pinned_campaign" || !event.userId) continue;
          const current = clickEventsByUser.get(event.userId) ?? [];
          current.push(event.createdAt);
          clickEventsByUser.set(event.userId, current);
        }
        const followConversions = (followRowsByCampaignId.get(pinnedCampaign.id) ?? []).filter((row) => {
          const clicks = clickEventsByUser.get(row.userId) ?? [];
          return clicks.some((clickedAt) => clickedAt <= row.createdAt && isDateWithinCampaignAnalyticsWindow(row.createdAt, pinnedCampaign));
        }).length;
        const rsvpConversions = linkedDropIds.flatMap((dropId) => rsvpRowsByDropId.get(dropId) ?? []).filter((row) => {
          const clicks = clickEventsByUser.get(row.userId) ?? [];
          return clicks.some((clickedAt) => clickedAt <= row.createdAt && isDateWithinCampaignAnalyticsWindow(row.createdAt, pinnedCampaign));
        }).length;

        return {
          campaignId: pinnedCampaign.id,
          name: pinnedCampaign.name,
          slug: pinnedCampaign.slug,
          route: `/drinks/campaigns/${encodeURIComponent(pinnedCampaign.slug)}`,
          visibility: pinnedCampaign.visibility as CreatorCampaignVisibility,
          state: getCreatorCampaignState(pinnedCampaign, now),
          spotlightViews,
          spotlightClicks,
          spotlightClickThroughRate: spotlightCtr,
          spotlightCtrLabel: formatSpotlightPercent(spotlightCtr),
          followConversions,
          rsvpConversions,
          totalFollowers: analytics?.followerCount ?? 0,
          totalDropClicks: analytics?.totalDropClicks ?? 0,
          totalDropViews: analytics?.totalDropViews ?? 0,
          totalDropRsvps: analytics?.totalDropRsvps ?? 0,
          approximatePurchases: analytics?.purchasesFromLinkedCollections ?? 0,
          approximateMemberships: analytics?.membershipsFromCampaign ?? 0,
          spotlightSurfaces: Array.from(new Set(events.map((event) => event.surface))).sort(),
        };
      })()
    : null;

  const pinnedComparison = pinnedCampaign ? comparisonItems.find((item) => item.campaignId === pinnedCampaign.id) ?? null : null;
  const membershipAlternative = comparisonItems
    .filter((item) => !item.isPinned && item.state !== "past" && item.memberFocused)
    .sort((a, b) => b.conversionPotential.score - a.conversionPotential.score || b.rotationScore - a.rotationScore)[0] ?? null;

  const rotationSuggestion = (() => {
    if (!pinnedCampaign) {
      return {
        key: "pin_a_campaign",
        headline: bestAlternative ? "Pin a campaign to start measuring the spotlight slot" : "No active spotlight candidate yet",
        summary: bestAlternative
          ? `${bestAlternative.name} looks like the strongest first spotlight based on recent follows, clicks, and conversion proxies.`
          : "You do not have an active or upcoming alternative campaign to spotlight right now.",
        severity: "info" as const,
        signals: bestAlternative
          ? [
              `${bestAlternative.followerMomentum.recentFollowers} recent follower${bestAlternative.followerMomentum.recentFollowers === 1 ? "" : "s"}`,
              `${bestAlternative.clickPotential.totalClicks} linked click${bestAlternative.clickPotential.totalClicks === 1 ? "" : "s"}`,
            ]
          : [],
        suggestedCampaignId: bestAlternative?.campaignId ?? null,
      };
    }

    if (pinnedAnalytics && pinnedAnalytics.state === "past") {
      return {
        key: "rotate_after_campaign_end",
        headline: "Rotate after campaign end/archive",
        summary: bestAlternative
          ? `${pinnedAnalytics.name} has already ended. Keep the slot moving by switching to ${bestAlternative.name} or another active campaign.`
          : `${pinnedAnalytics.name} has already ended. Unpin it or replace it when your next campaign is ready.`,
        severity: "warning" as const,
        signals: [
          "Current pinned campaign is no longer active.",
          bestAlternative ? `${bestAlternative.name} is still ${bestAlternative.state}.` : "No alternative active campaign found yet.",
        ],
        suggestedCampaignId: bestAlternative?.campaignId ?? null,
      };
    }

    if (
      membershipAlternative
      && pinnedComparison
      && !pinnedComparison.memberFocused
      && membershipAlternative.conversionPotential.score > Math.max(8, pinnedComparison.conversionPotential.score * 1.25)
    ) {
      return {
        key: "rotate_to_membership_focused_campaign",
        headline: "Consider rotating to a membership-focused campaign",
        summary: `${membershipAlternative.name} is showing stronger membership or purchase momentum than the current spotlight.`,
        severity: "info" as const,
        signals: [
          `${membershipAlternative.conversionPotential.totalMemberships} approx. membership conversion${membershipAlternative.conversionPotential.totalMemberships === 1 ? "" : "s"}`,
          `${membershipAlternative.conversionPotential.totalPurchases} approx. linked purchase${membershipAlternative.conversionPotential.totalPurchases === 1 ? "" : "s"}`,
        ],
        suggestedCampaignId: membershipAlternative.campaignId,
      };
    }

    if (
      pinnedAnalytics
      && bestAlternative
      && pinnedComparison
      && pinnedAnalytics.spotlightViews >= 20
      && pinnedAnalytics.spotlightClickThroughRate <= 3
      && bestAlternative.rotationScore > Math.max(12, pinnedComparison.rotationScore * 1.2)
    ) {
      return {
        key: "pinned_campaign_underperforming",
        headline: "Pinned campaign is underperforming",
        summary: `${pinnedAnalytics.name} is getting seen, but it is not pulling enough spotlight clicks compared with ${bestAlternative.name}.`,
        severity: "warning" as const,
        signals: [
          `${pinnedAnalytics.spotlightViews} spotlight views`,
          `${pinnedAnalytics.spotlightCtrLabel} CTR`,
          `${bestAlternative.followerMomentum.recentFollowers} recent followers on ${bestAlternative.name}`,
        ],
        suggestedCampaignId: bestAlternative.campaignId,
      };
    }

    if (
      bestAlternative
      && pinnedComparison
      && bestAlternative.rotationScore > Math.max(12, pinnedComparison.rotationScore * 1.25)
    ) {
      return {
        key: "consider_rotating_to_active_campaign",
        headline: "Consider rotating to another active campaign",
        summary: `${bestAlternative.name} currently has stronger recent momentum than the pinned spotlight.`,
        severity: "info" as const,
        signals: [
          `${bestAlternative.followerMomentum.recentFollowers} recent followers`,
          `${bestAlternative.clickPotential.score} click-potential proxy score`,
        ],
        suggestedCampaignId: bestAlternative.campaignId,
      };
    }

    return {
      key: "keep_current_pinned_campaign",
      headline: "Pinned campaign is still the strongest spotlight choice",
      summary: pinnedAnalytics
        ? `${pinnedAnalytics.name} still looks like the best current place to start your creator story.`
        : "Your current spotlight is still the strongest option right now.",
      severity: "success" as const,
      signals: pinnedAnalytics
        ? [
            `${pinnedAnalytics.spotlightClicks} spotlight click${pinnedAnalytics.spotlightClicks === 1 ? "" : "s"}`,
            `${pinnedAnalytics.followConversions} follow conversion${pinnedAnalytics.followConversions === 1 ? "" : "s"} after spotlight clicks`,
          ]
        : [],
      suggestedCampaignId: null,
    };
  })();

  const candidates = comparisonItems
    .filter((item) => !item.isPinned)
    .sort((a, b) => b.rotationScore - a.rotationScore || b.clickPotential.score - a.clickPotential.score)
    .slice(0, 3)
    .map((item) => ({
      campaignId: item.campaignId,
      name: item.name,
      slug: item.slug,
      route: item.route,
      visibility: item.visibility,
      state: item.state,
      followerMomentum: item.followerMomentum,
      relativeClickPotential: {
        score: item.clickPotential.score,
        note: "Proxy-based from linked drop clicks, RSVP interest, and views.",
      },
      relativeMembershipPurchasePotential: {
        score: item.conversionPotential.score,
        totalPurchases: item.conversionPotential.totalPurchases,
        totalMemberships: item.conversionPotential.totalMemberships,
        note: "Proxy-based from linked collection purchases and member campaign conversions.",
      },
      whyConsider: [
        item.followerMomentum.recentFollowers > 0 ? `${item.followerMomentum.recentFollowers} recent followers` : null,
        item.clickPotential.totalClicks > 0 ? `${item.clickPotential.totalClicks} linked clicks` : null,
        item.conversionPotential.totalMemberships > 0 ? `${item.conversionPotential.totalMemberships} approx. memberships` : null,
        item.conversionPotential.totalPurchases > 0 ? `${item.conversionPotential.totalPurchases} approx. purchases` : null,
      ].filter((value): value is string => Boolean(value)),
    }));

  return {
    pinnedCampaign: pinnedAnalytics,
    candidates,
    rotationSuggestion,
    attributionNotes: [
      "Spotlight analytics measure the pinned slot itself, not the campaign's broader performance layer.",
      "Views and clicks are direct spotlight events from the public creator page spotlight and discover pinned-campaigns surface.",
      "Follow and RSVP conversions are proxy-based when a signed-in user clicks a pinned campaign and then follows or RSVPs during the campaign window.",
      "Candidate comparisons stay creator-private and use recent follower momentum plus proxy scores for click and membership/purchase potential.",
      "Rotation suggestions are lightweight rules only. Nothing auto-rotates.",
    ],
    generatedAt: now.toISOString(),
  };
}

async function loadCreatorCampaignSurfaceAttribution(creatorUserId: string) {
  if (!db) throw new Error("Database unavailable");

  const campaigns = await db
    .select()
    .from(creatorCampaigns)
    .where(eq(creatorCampaigns.creatorUserId, creatorUserId))
    .orderBy(desc(creatorCampaigns.updatedAt))
    .limit(120);

  const campaignIds = campaigns.map((campaign) => campaign.id);
  if (campaignIds.length === 0) {
    return {
      summary: {
        totalCampaigns: 0,
        trackedCampaigns: 0,
        totalViews: 0,
        totalClicks: 0,
        totalDirectFollows: 0,
        totalDirectRsvps: 0,
      },
      supportedSurfaces: CREATOR_CAMPAIGN_SURFACE_VALUES.map((surface) => ({
        key: surface,
        observationType: surface === "campaign_detail_page"
          ? "direct campaign page landings + CTA actions when no upstream entry point is known"
          : surface === "direct_or_unknown"
            ? "fallback when no attributable entry point was captured"
            : "directly observed entry-point impressions and opens",
      })),
      overallSurfaces: [] as Array<unknown>,
      topSurfaceInsights: [] as Array<{
        campaignId: string | null;
        campaignName: string | null;
        surface: CreatorCampaignSurface;
        headline: string;
        detail: string;
        metric: "views" | "clicks" | "follows" | "rsvps";
        value: number;
      }>,
      items: [] as Array<unknown>,
      attributionNotes: [
        "Surface attribution stays creator-private and only counts directly observed campaign surface events.",
        "No campaign surface events have been captured for this creator yet.",
      ],
      generatedAt: new Date().toISOString(),
    };
  }

  const rows = await db
    .select()
    .from(creatorCampaignSurfaceEvents)
    .where(inArray(creatorCampaignSurfaceEvents.campaignId, campaignIds))
    .orderBy(asc(creatorCampaignSurfaceEvents.createdAt));

  const campaignById = new Map(campaigns.map((campaign) => [campaign.id, campaign]));
  const items = campaigns.map((campaign) => {
    const route = `/drinks/campaigns/${encodeURIComponent(campaign.slug)}`;
    const surfaceMap = new Map<CreatorCampaignSurface, {
      surface: CreatorCampaignSurface;
      views: number;
      clicks: number;
      clickThroughRate: number | null;
      clickThroughRateLabel: string;
      directFollows: number;
      directRsvps: number;
      metricLabels: {
        views: "direct";
        clicks: "direct";
        follows: "direct";
        rsvps: "direct";
      };
    }>();

    for (const surface of CREATOR_CAMPAIGN_SURFACE_VALUES) {
      surfaceMap.set(surface, {
        surface,
        views: 0,
        clicks: 0,
        clickThroughRate: null,
        clickThroughRateLabel: "—",
        directFollows: 0,
        directRsvps: 0,
        metricLabels: { views: "direct", clicks: "direct", follows: "direct", rsvps: "direct" },
      });
    }

    return {
      campaignId: campaign.id,
      campaignName: campaign.name,
      slug: campaign.slug,
      route,
      visibility: campaign.visibility as CreatorCampaignVisibility,
      state: getCreatorCampaignState(campaign),
      surfaces: surfaceMap,
    };
  });
  const itemByCampaignId = new Map(items.map((item) => [item.campaignId, item]));

  for (const row of rows) {
    const item = itemByCampaignId.get(row.campaignId);
    const campaign = campaignById.get(row.campaignId);
    if (!item || !campaign) continue;
    const surface = resolveCreatorCampaignSurface(row.surface);
    const metrics = item.surfaces.get(surface);
    if (!metrics) continue;
    if (!isDateWithinCampaignAnalyticsWindow(row.createdAt, campaign)) continue;
    if (row.eventType === "view_campaign") metrics.views += 1;
    if (row.eventType === "click_campaign") metrics.clicks += 1;
    if (row.eventType === "follow_after_campaign_surface") metrics.directFollows += 1;
    if (row.eventType === "rsvp_after_campaign_surface") metrics.directRsvps += 1;
  }

  const serializedItems = items.map((item) => {
    const surfaces = [...item.surfaces.values()]
      .map((surface) => {
        const clickThroughRate = surface.views > 0 ? roundPercent((surface.clicks / surface.views) * 100) : null;
        return {
          ...surface,
          clickThroughRate,
          clickThroughRateLabel: clickThroughRate === null ? "—" : formatSpotlightPercent(clickThroughRate),
        };
      })
      .filter((surface) => surface.views > 0 || surface.clicks > 0 || surface.directFollows > 0 || surface.directRsvps > 0)
      .sort((a, b) => (
        (b.directFollows + b.directRsvps + b.clicks) - (a.directFollows + a.directRsvps + a.clicks)
        || b.views - a.views
        || a.surface.localeCompare(b.surface)
      ));

    const totals = surfaces.reduce((acc, surface) => {
      acc.views += surface.views;
      acc.clicks += surface.clicks;
      acc.directFollows += surface.directFollows;
      acc.directRsvps += surface.directRsvps;
      return acc;
    }, { views: 0, clicks: 0, directFollows: 0, directRsvps: 0 });

    const topSurface = surfaces[0] ?? null;

    return {
      campaignId: item.campaignId,
      campaignName: item.campaignName,
      slug: item.slug,
      route: item.route,
      visibility: item.visibility,
      state: item.state,
      totals,
      topSurface: topSurface
        ? {
          surface: topSurface.surface,
          headline: topSurface.directFollows > 0
            ? `${topSurface.surface.replaceAll("_", " ")} drives the most direct follows`
            : topSurface.directRsvps > 0
              ? `${topSurface.surface.replaceAll("_", " ")} is the strongest RSVP source`
              : topSurface.clicks > 0
                ? `${topSurface.surface.replaceAll("_", " ")} is currently the main click entry point`
                : `${topSurface.surface.replaceAll("_", " ")} is currently the main observed surface`,
        }
        : null,
      surfaces,
    };
  });

  const totalsBySurface = new Map<CreatorCampaignSurface, {
    surface: CreatorCampaignSurface;
    views: number;
    clicks: number;
    directFollows: number;
    directRsvps: number;
  }>();
  for (const surface of CREATOR_CAMPAIGN_SURFACE_VALUES) {
    totalsBySurface.set(surface, { surface, views: 0, clicks: 0, directFollows: 0, directRsvps: 0 });
  }
  for (const item of serializedItems) {
    for (const surface of item.surfaces) {
      const current = totalsBySurface.get(surface.surface);
      if (!current) continue;
      current.views += surface.views;
      current.clicks += surface.clicks;
      current.directFollows += surface.directFollows;
      current.directRsvps += surface.directRsvps;
    }
  }

  const topSurfaceInsights = [
    ...serializedItems.flatMap((item) => item.surfaces.map((surface) => ({ item, surface }))),
  ]
    .filter(({ surface }) => surface.views > 0 || surface.clicks > 0 || surface.directFollows > 0 || surface.directRsvps > 0)
    .map(({ item, surface }) => {
      const options = [
        { metric: "follows" as const, value: surface.directFollows, detail: `${surface.surface.replaceAll("_", " ")} generated ${surface.directFollows} directly observed follow${surface.directFollows === 1 ? "" : "s"}.` },
        { metric: "rsvps" as const, value: surface.directRsvps, detail: `${surface.surface.replaceAll("_", " ")} generated ${surface.directRsvps} directly observed RSVP${surface.directRsvps === 1 ? "" : "s"}.` },
        { metric: "clicks" as const, value: surface.clicks, detail: `${surface.surface.replaceAll("_", " ")} produced ${surface.clicks} direct campaign click${surface.clicks === 1 ? "" : "s"}${surface.clickThroughRateLabel !== "—" ? ` (${surface.clickThroughRateLabel} CTR).` : "."}` },
        { metric: "views" as const, value: surface.views, detail: `${surface.surface.replaceAll("_", " ")} produced ${surface.views} observed campaign view${surface.views === 1 ? "" : "s"}.` },
      ].sort((a, b) => b.value - a.value)[0];

      return {
        campaignId: item.campaignId,
        campaignName: item.campaignName,
        surface: surface.surface,
        headline: item.topSurface?.headline ?? `${surface.surface.replaceAll("_", " ")} is active`,
        detail: options.detail,
        metric: options.metric,
        value: options.value,
      };
    })
    .filter((item) => item.value > 0)
    .sort((a, b) => b.value - a.value || (a.campaignName ?? "").localeCompare(b.campaignName ?? ""))
    .slice(0, 6);

  const overallSurfaces = [...totalsBySurface.values()]
    .map((surface) => ({
      ...surface,
      clickThroughRate: surface.views > 0 ? roundPercent((surface.clicks / surface.views) * 100) : null,
      clickThroughRateLabel: surface.views > 0 ? formatSpotlightPercent(roundPercent((surface.clicks / surface.views) * 100)) : "—",
      followRateLabel: surface.clicks > 0 ? formatSpotlightPercent(roundPercent((surface.directFollows / surface.clicks) * 100)) : "—",
      rsvpRateLabel: surface.clicks > 0 ? formatSpotlightPercent(roundPercent((surface.directRsvps / surface.clicks) * 100)) : "—",
    }))
    .filter((surface) => surface.views > 0 || surface.clicks > 0 || surface.directFollows > 0 || surface.directRsvps > 0)
    .sort((a, b) => (
      (b.directFollows + b.directRsvps + b.clicks) - (a.directFollows + a.directRsvps + a.clicks)
      || b.views - a.views
      || a.surface.localeCompare(b.surface)
    ));

  return {
    summary: {
      totalCampaigns: campaigns.length,
      trackedCampaigns: serializedItems.filter((item) => item.surfaces.length > 0).length,
      totalViews: overallSurfaces.reduce((sum, surface) => sum + surface.views, 0),
      totalClicks: overallSurfaces.reduce((sum, surface) => sum + surface.clicks, 0),
      totalDirectFollows: overallSurfaces.reduce((sum, surface) => sum + surface.directFollows, 0),
      totalDirectRsvps: overallSurfaces.reduce((sum, surface) => sum + surface.directRsvps, 0),
    },
    supportedSurfaces: CREATOR_CAMPAIGN_SURFACE_VALUES.map((surface) => ({
      key: surface,
      observationType: surface === "creator_public_page"
        ? "direct creator-page campaign impressions and opens"
        : surface === "discover_pinned_campaigns"
          ? "direct discover pinned-campaign impressions and opens"
          : surface === "following_feed"
            ? "direct following-feed campaign impressions and opens"
            : surface === "alerts"
              ? "direct campaign-update alert impressions and opens"
              : surface === "campaign_detail_page"
                ? "direct detail-page landings and on-page CTA actions when no upstream entry point is known"
                : "fallback for unattributed actions or older traffic",
    })),
    topSurfaceInsights,
    items: serializedItems,
    overallSurfaces,
    attributionNotes: [
      "Views and clicks are direct, surface-specific events only where the drinks platform explicitly recorded a campaign impression or open.",
      "Direct follows and RSVPs are only credited when the action request carried a known campaign surface; otherwise they fall into direct_or_unknown.",
      "campaign_detail_page is reserved for direct landings or on-page activity without a clearer upstream surface. It is not a catch-all for every campaign visit.",
      "This layer stays separate from campaign analytics totals, pinned spotlight analytics, and spotlight rotation suggestions.",
      "No buyer identities, follower identities, or private member details are exposed here.",
    ],
    generatedAt: new Date().toISOString(),
  };
}

function buildCampaignBenchmarkSummaryItem(
  item: CreatorCampaignBenchmarkItem | null,
  value: number,
  label: string,
  note: string | null = null,
): CreatorCampaignBenchmarkSummaryItem | null {
  if (!item || value <= 0) return null;
  return {
    campaignId: item.campaignId,
    name: item.name,
    slug: item.slug,
    route: item.route,
    value,
    label,
    note,
  };
}

function averageCampaignBenchmarkMetric(items: CreatorCampaignBenchmarkItem[], selector: (item: CreatorCampaignBenchmarkItem) => number) {
  if (items.length === 0) return 0;
  return items.reduce((sum, item) => sum + selector(item), 0) / items.length;
}

function benchmarkPrimaryVariantMetric(metrics: ReturnType<typeof serializeCreatorCampaignVariant>["metrics"]) {
  const candidates = [
    {
      metricLabel: "approx. memberships",
      metricValue: metrics.approximateMemberships,
      score: metrics.approximateMemberships * 6,
      note: metrics.approximateMemberships > 0
        ? "Approximate memberships are credited when a clicked CTA is followed by a membership start during the campaign window."
        : null,
    },
    {
      metricLabel: "approx. purchases",
      metricValue: metrics.approximatePurchases,
      score: metrics.approximatePurchases * 5,
      note: metrics.approximatePurchases > 0
        ? "Approximate purchases are credited when a clicked CTA is followed by a linked collection purchase during the campaign window."
        : null,
    },
    { metricLabel: "RSVPs", metricValue: metrics.rsvps, score: metrics.rsvps * 4, note: null },
    { metricLabel: "follows", metricValue: metrics.follows, score: metrics.follows * 3, note: null },
    { metricLabel: "clicks", metricValue: metrics.clicks, score: metrics.clicks * 2, note: null },
    { metricLabel: "views", metricValue: metrics.views, score: metrics.views * 0.25, note: null },
  ].sort((a, b) => b.score - a.score || b.metricValue - a.metricValue);

  return candidates[0] ?? { metricLabel: "views", metricValue: 0, score: 0, note: null };
}

async function loadCreatorCampaignBenchmarks(creatorUserId: string) {
  if (!db) throw new Error("Database unavailable");

  const [performance, campaigns] = await Promise.all([
    loadCreatorCampaignPerformanceSnapshots(creatorUserId),
    db
      .select()
      .from(creatorCampaigns)
      .where(eq(creatorCampaigns.creatorUserId, creatorUserId))
      .orderBy(desc(creatorCampaigns.updatedAt))
      .limit(120),
  ]);

  if (campaigns.length === 0 || performance.items.length === 0) {
    return {
      summary: {
        totalCampaigns: 0,
        campaignsWithDrops: 0,
        memberFocusedCampaigns: 0,
        bestCampaignByFollowers: null,
        bestCampaignByRsvpInterest: null,
        bestCampaignByClickThroughs: null,
        bestCampaignByPurchases: null,
        bestCampaignByMemberships: null,
        bestCampaignByGoalCompletion: null,
        mostReusableCampaignCandidate: null,
      } satisfies CreatorCampaignBenchmarkSummary,
      items: [] as CreatorCampaignBenchmarkItem[],
      insights: [] as string[],
      attributionNotes: [
        "Benchmarks compare only this creator's own campaigns; nothing here is a platform-wide rank.",
        "Follower gain reflects campaign follows accumulated during each campaign window. In version one, that usually matches current follower count because unfollow history is not modeled separately.",
        "Purchases from linked collections and memberships from campaigns stay clearly labeled as approximate whenever attribution is proxy-based.",
        "Strongest CTA variants compare variants inside the creator's campaigns using existing CTA view, click, follow, RSVP, and proxy conversion signals.",
      ],
      generatedAt: performance.generatedAt,
    };
  }

  const campaignIds = campaigns.map((campaign) => campaign.id);
  const performanceByCampaignId = new Map(performance.items.map((item) => [item.campaignId, item]));
  const [goalRows, linkMap, variantsByCampaignId, followRows] = await Promise.all([
    db.select().from(creatorCampaignGoals).where(inArray(creatorCampaignGoals.campaignId, campaignIds)),
    loadCreatorCampaignLinksByCampaignIds(campaignIds),
    loadCreatorCampaignVariantsByCampaignIds(campaignIds),
    db.select({
      campaignId: creatorCampaignFollows.campaignId,
      createdAt: creatorCampaignFollows.createdAt,
    }).from(creatorCampaignFollows).where(inArray(creatorCampaignFollows.campaignId, campaignIds)).orderBy(asc(creatorCampaignFollows.createdAt)),
  ]);

  const goalRowsByCampaignId = new Map<string, CreatorCampaignGoalRecord[]>();
  for (const goal of goalRows) {
    const current = goalRowsByCampaignId.get(goal.campaignId) ?? [];
    current.push(goal);
    goalRowsByCampaignId.set(goal.campaignId, current);
  }

  const followRowsByCampaignId = new Map<string, Array<{ createdAt: Date }>>();
  for (const row of followRows) {
    const current = followRowsByCampaignId.get(row.campaignId) ?? [];
    current.push({ createdAt: row.createdAt });
    followRowsByCampaignId.set(row.campaignId, current);
  }

  const items: CreatorCampaignBenchmarkItem[] = [];
  for (const campaign of campaigns) {
    const analytics = performanceByCampaignId.get(campaign.id);
    if (!analytics) continue;

    const variantRows = variantsByCampaignId.get(campaign.id) ?? [];
    const variantMetrics = await loadCreatorCampaignVariantMetrics(campaign, variantRows);
    const strongestVariant = [...variantRows]
      .map((variant) => {
        const metrics = variantMetrics.get(variant.id) ?? {
          views: 0,
          clicks: 0,
          follows: 0,
          rsvps: 0,
          approximatePurchases: 0,
          approximateMemberships: 0,
        };
        const primaryMetric = benchmarkPrimaryVariantMetric(metrics);
        return {
          variantId: variant.id,
          label: variant.label,
          headline: variant.headline ?? null,
          ctaTargetType: variant.ctaTargetType as CreatorCampaignCtaTargetType,
          metricLabel: primaryMetric.metricLabel,
          metricValue: primaryMetric.metricValue,
          score: scoreRetrospectiveVariant(metrics),
          note: primaryMetric.note,
        } satisfies CreatorCampaignBenchmarkStrongestVariant;
      })
      .sort((a, b) => b.score - a.score || b.metricValue - a.metricValue)[0] ?? null;

    const goals = (goalRowsByCampaignId.get(campaign.id) ?? []).map((goal) => serializeCreatorCampaignGoal(goal, analytics));
    const goalsCompletedCount = goals.filter((goal) => goal.isComplete).length;
    const milestonesReachedCount = analytics.milestones.filter((milestone) => milestone.achieved).length;
    const durationStart = campaign.startsAt ?? campaign.createdAt;
    const durationEnd = campaign.endsAt ?? new Date();
    const campaignDurationDays = Math.max(1, Math.round((durationEnd.getTime() - durationStart.getTime()) / (24 * 60 * 60 * 1000)) || 1);
    const links = linkMap.get(campaign.id) ?? [];
    const memberFocused = analytics.visibility === "members"
      || analytics.membershipsFromCampaign > 0
      || links.some((link) => link.targetType === "collection" || link.targetType === "drop") && Boolean(analytics.membershipsFromCampaignNote);
    const followerGain = (followRowsByCampaignId.get(campaign.id) ?? []).filter((row) => (
      isDateWithinCampaignAnalyticsWindow(row.createdAt, campaign)
    )).length;
    const reusableTemplateCandidate = (
      campaign.isActive === false
      && (analytics.purchasesFromLinkedCollections >= 3 || analytics.membershipsFromCampaign >= 2 || analytics.campaignEngagementScore >= 120)
    );
    const reusableTemplateReason = reusableTemplateCandidate
      ? `Archived/internal winner inside your own portfolio: ${analytics.campaignEngagementScore} engagement score, ${analytics.totalDropRsvps} RSVPs, and ${analytics.purchasesFromLinkedCollections + analytics.membershipsFromCampaign} approximate conversions.`
      : null;

    items.push({
      campaignId: campaign.id,
      slug: campaign.slug,
      name: campaign.name,
      route: `/drinks/campaigns/${encodeURIComponent(campaign.slug)}`,
      visibility: campaign.visibility as CreatorCampaignVisibility,
      state: getCreatorCampaignState(campaign),
      followerCount: analytics.followerCount,
      followerGain,
      totalDropRsvps: analytics.totalDropRsvps,
      totalDropViews: analytics.totalDropViews,
      totalDropClicks: analytics.totalDropClicks,
      purchasesFromLinkedCollections: analytics.purchasesFromLinkedCollections,
      purchasesFromLinkedCollectionsNote: analytics.purchasesFromLinkedCollectionsNote,
      membershipsFromCampaign: analytics.membershipsFromCampaign,
      membershipsFromCampaignNote: analytics.membershipsFromCampaignNote,
      strongestCtaVariant: strongestVariant,
      milestonesReachedCount,
      goalsCompletedCount,
      campaignDurationDays,
      engagementScore: analytics.campaignEngagementScore,
      engagementScoreNote: analytics.campaignEngagementScoreNote,
      linkedDropsCount: analytics.linkedDropsCount,
      linkedCollectionsCount: analytics.linkedCollectionsCount,
      linkedPostsCount: analytics.linkedPostsCount,
      memberFocused,
      benchmarkLabels: [],
      reusableTemplateCandidate,
      reusableTemplateReason,
    });
  }

  const byFollowers = [...items].sort((a, b) => b.followerCount - a.followerCount || b.followerGain - a.followerGain)[0] ?? null;
  const byRsvps = [...items].sort((a, b) => b.totalDropRsvps - a.totalDropRsvps || b.totalDropClicks - a.totalDropClicks)[0] ?? null;
  const byClicks = [...items].sort((a, b) => b.totalDropClicks - a.totalDropClicks || b.totalDropViews - a.totalDropViews)[0] ?? null;
  const byPurchases = [...items].sort((a, b) => b.purchasesFromLinkedCollections - a.purchasesFromLinkedCollections || b.totalDropClicks - a.totalDropClicks)[0] ?? null;
  const byMemberships = [...items].sort((a, b) => b.membershipsFromCampaign - a.membershipsFromCampaign || b.engagementScore - a.engagementScore)[0] ?? null;
  const byGoals = [...items].sort((a, b) => b.goalsCompletedCount - a.goalsCompletedCount || b.milestonesReachedCount - a.milestonesReachedCount)[0] ?? null;
  const byReuse = [...items].filter((item) => item.reusableTemplateCandidate)
    .sort((a, b) => (
      (b.engagementScore + (b.purchasesFromLinkedCollections + b.membershipsFromCampaign) * 10)
      - (a.engagementScore + (a.purchasesFromLinkedCollections + a.membershipsFromCampaign) * 10)
    ))[0] ?? null;

  for (const item of items) {
    if (byFollowers && item.campaignId === byFollowers.campaignId && item.followerCount > 0) item.benchmarkLabels.push("Top follower campaign");
    if (byRsvps && item.campaignId === byRsvps.campaignId && item.totalDropRsvps > 0) item.benchmarkLabels.push("Best RSVP campaign");
    if (byPurchases && item.campaignId === byPurchases.campaignId && item.purchasesFromLinkedCollections > 0) item.benchmarkLabels.push("Best conversion campaign");
    if (byMemberships && item.campaignId === byMemberships.campaignId && item.membershipsFromCampaign > 0) item.benchmarkLabels.push("Best member campaign");
    if (byReuse && item.campaignId === byReuse.campaignId) item.benchmarkLabels.push("Strongest reusable template candidate");
  }

  const insights: string[] = [];
  const memberFocusedCampaigns = items.filter((item) => item.memberFocused);
  const oneOffCampaigns = items.filter((item) => !item.memberFocused && item.linkedCollectionsCount > 0);
  const memberFocusedAverage = averageCampaignBenchmarkMetric(memberFocusedCampaigns, (item) => item.membershipsFromCampaign + item.purchasesFromLinkedCollections);
  const oneOffAverage = averageCampaignBenchmarkMetric(oneOffCampaigns, (item) => item.membershipsFromCampaign + item.purchasesFromLinkedCollections);
  if (memberFocusedCampaigns.length > 0 && oneOffCampaigns.length > 0 && memberFocusedAverage > oneOffAverage * 1.15) {
    insights.push("Within your own portfolio, member-focused campaigns are converting better than one-off purchase campaigns.");
  }

  const withDrops = items.filter((item) => item.linkedDropsCount > 0);
  const withoutDrops = items.filter((item) => item.linkedDropsCount === 0);
  const withDropsAvg = averageCampaignBenchmarkMetric(withDrops, (item) => item.engagementScore);
  const withoutDropsAvg = averageCampaignBenchmarkMetric(withoutDrops, (item) => item.engagementScore);
  if (withDrops.length > 0 && withoutDrops.length > 0 && withDropsAvg > withoutDropsAvg * 1.15) {
    insights.push("Within your own campaigns, arcs with linked drops outperform arcs without drops on engagement score.");
  }

  const rsvpHeavy = items.filter((item) => item.totalDropRsvps >= Math.max(10, Math.round(item.followerCount * 0.25)));
  const lightRsvp = items.filter((item) => item.totalDropRsvps < Math.max(10, Math.round(item.followerCount * 0.25)));
  const rsvpHeavyClicks = averageCampaignBenchmarkMetric(rsvpHeavy, (item) => item.totalDropClicks);
  const lightRsvpClicks = averageCampaignBenchmarkMetric(lightRsvp, (item) => item.totalDropClicks);
  if (rsvpHeavy.length > 0 && lightRsvp.length > 0 && rsvpHeavyClicks > lightRsvpClicks * 1.15) {
    insights.push("RSVP-heavy campaigns in your portfolio tend to drive stronger click-through than lighter-intent arcs.");
  }

  if (byReuse?.reusableTemplateReason) {
    insights.push(`${byReuse.name} looks like your strongest archived candidate to clone or refresh: ${byReuse.reusableTemplateReason}`);
  }

  const summary = {
    totalCampaigns: items.length,
    campaignsWithDrops: withDrops.length,
    memberFocusedCampaigns: memberFocusedCampaigns.length,
    bestCampaignByFollowers: buildCampaignBenchmarkSummaryItem(byFollowers, byFollowers?.followerCount ?? 0, "campaign followers"),
    bestCampaignByRsvpInterest: buildCampaignBenchmarkSummaryItem(byRsvps, byRsvps?.totalDropRsvps ?? 0, "linked drop RSVPs"),
    bestCampaignByClickThroughs: buildCampaignBenchmarkSummaryItem(byClicks, byClicks?.totalDropClicks ?? 0, "linked drop clicks"),
    bestCampaignByPurchases: buildCampaignBenchmarkSummaryItem(byPurchases, byPurchases?.purchasesFromLinkedCollections ?? 0, "approx. linked purchases", "Approximate purchase proxy from linked collections."),
    bestCampaignByMemberships: buildCampaignBenchmarkSummaryItem(byMemberships, byMemberships?.membershipsFromCampaign ?? 0, "approx. memberships", "Approximate membership proxy from campaign-window membership starts."),
    bestCampaignByGoalCompletion: buildCampaignBenchmarkSummaryItem(byGoals, byGoals?.goalsCompletedCount ?? 0, "goals completed"),
    mostReusableCampaignCandidate: buildCampaignBenchmarkSummaryItem(byReuse, byReuse?.engagementScore ?? 0, "engagement score", byReuse?.reusableTemplateReason ?? null),
  } satisfies CreatorCampaignBenchmarkSummary;

  return {
    summary,
    items: items.sort((a, b) => (
      b.engagementScore - a.engagementScore
      || (b.purchasesFromLinkedCollections + b.membershipsFromCampaign) - (a.purchasesFromLinkedCollections + a.membershipsFromCampaign)
      || b.totalDropClicks - a.totalDropClicks
    )),
    insights,
    attributionNotes: [
      "Benchmarks compare only this creator's own campaigns; nothing here is a platform-wide rank.",
      "Follower gain reflects campaign follows accumulated during each campaign window. In version one, that usually matches current follower count because unfollow history is not modeled separately.",
      "Purchases from linked collections and memberships from campaigns stay clearly labeled as approximate whenever attribution is proxy-based.",
      "Strongest CTA variants compare variants inside the creator's campaigns using existing CTA view, click, follow, RSVP, and proxy conversion signals.",
      "Reusable-template flags are rules-based from engagement score, RSVP interest, and approximate conversions so creators get a lightweight comparison layer instead of a separate BI stack.",
    ],
    generatedAt: performance.generatedAt,
  };
}

function findGoalCompletionDate(rows: Array<{ createdAt: Date }>, targetValue: number, baselineCount = 0) {
  if (targetValue <= 0 || baselineCount >= targetValue) return null;
  const needed = targetValue - baselineCount;
  return rows[needed - 1]?.createdAt ?? null;
}

function campaignGoalCountsForDigest(input: {
  goalType: CreatorCampaignGoalType;
  campaign: CreatorCampaignRecord;
  followRows: Array<{ createdAt: Date }>;
  rsvpRows: Array<{ createdAt: Date }>;
  clickRows: Array<{ createdAt: Date }>;
  viewRows: Array<{ createdAt: Date }>;
  purchaseRows: Array<{ createdAt: Date; status: string }>;
  membershipRows: Array<{ createdAt: Date }>;
  digestStartsAt: Date;
  digestEndsAt: Date;
}) {
  const inCampaignWindow = <T extends { createdAt: Date }>(rows: T[]) => rows.filter((row) => (
    row.createdAt <= input.digestEndsAt && isDateWithinCampaignAnalyticsWindow(row.createdAt, input.campaign)
  ));
  const beforeDigestWindow = <T extends { createdAt: Date }>(rows: T[]) => inCampaignWindow(rows).filter((row) => row.createdAt < input.digestStartsAt);
  const withinDigestWindow = <T extends { createdAt: Date }>(rows: T[]) => inCampaignWindow(rows).filter((row) => (
    isDateWithinRange(row.createdAt, input.digestStartsAt, input.digestEndsAt)
  ));

  switch (input.goalType) {
    case "followers":
      return {
        currentValue: inCampaignWindow(input.followRows).length,
        baselineValue: beforeDigestWindow(input.followRows).length,
        weeklyRows: withinDigestWindow(input.followRows),
      };
    case "rsvps":
      return {
        currentValue: inCampaignWindow(input.rsvpRows).length,
        baselineValue: beforeDigestWindow(input.rsvpRows).length,
        weeklyRows: withinDigestWindow(input.rsvpRows),
      };
    case "clicks":
      return {
        currentValue: inCampaignWindow(input.clickRows).length,
        baselineValue: beforeDigestWindow(input.clickRows).length,
        weeklyRows: withinDigestWindow(input.clickRows),
      };
    case "linked_drop_views":
      return {
        currentValue: inCampaignWindow(input.viewRows).length,
        baselineValue: beforeDigestWindow(input.viewRows).length,
        weeklyRows: withinDigestWindow(input.viewRows),
      };
    case "purchases": {
      const purchaseRows = inCampaignWindow(input.purchaseRows.filter((row) => row.status === "completed"));
      return {
        currentValue: purchaseRows.length,
        baselineValue: purchaseRows.filter((row) => row.createdAt < input.digestStartsAt).length,
        weeklyRows: purchaseRows.filter((row) => isDateWithinRange(row.createdAt, input.digestStartsAt, input.digestEndsAt)),
      };
    }
    case "membership_conversions": {
      const membershipRows = inCampaignWindow(input.membershipRows);
      return {
        currentValue: membershipRows.length,
        baselineValue: membershipRows.filter((row) => row.createdAt < input.digestStartsAt).length,
        weeklyRows: membershipRows.filter((row) => isDateWithinRange(row.createdAt, input.digestStartsAt, input.digestEndsAt)),
      };
    }
    default:
      return {
        currentValue: 0,
        baselineValue: 0,
        weeklyRows: [] as Array<{ createdAt: Date }>,
      };
  }
}

async function loadCreatorCampaignWeeklyDigest(creatorUserId: string) {
  if (!db) throw new Error("Database unavailable");

  const digestEndsAt = new Date();
  const digestStartsAt = new Date(digestEndsAt.getTime() - (7 * 24 * 60 * 60 * 1000));

  const campaigns = await db
    .select()
    .from(creatorCampaigns)
    .where(eq(creatorCampaigns.creatorUserId, creatorUserId))
    .orderBy(desc(creatorCampaigns.updatedAt))
    .limit(120);

  if (campaigns.length === 0) {
    return {
      window: {
        startsAt: digestStartsAt.toISOString(),
        endsAt: digestEndsAt.toISOString(),
        days: 7,
      },
      summary: {
        campaignsIncluded: 0,
        activeCampaignsThisWeek: 0,
        newCampaignFollowersThisWeek: 0,
        newRsvpsThisWeek: 0,
        dropViewsThisWeek: 0,
        dropClicksThisWeek: 0,
        purchasesFromLinkedCollectionsThisWeek: 0,
        membershipConversionsThisWeek: 0,
        milestonesReachedThisWeek: 0,
        goalsCompletedThisWeek: 0,
      } satisfies CreatorCampaignWeeklyDigestSummary,
      items: [] as CreatorCampaignWeeklyDigestItem[],
      attributionNotes: [
        "Campaign followers and RSVPs are direct counts from explicit campaign follows and linked drop RSVP activity recorded in the last 7 days.",
        "Drop views and clicks reuse linked drop analytics that already exist elsewhere in the drinks creator dashboard.",
        "Linked collection purchases are approximate and count completed purchases on collections linked to the campaign during the last 7 days.",
        "Membership conversions are approximate and only shown for member-focused campaigns, using memberships started in the last 7 days.",
        "Goal completions are inferred when a campaign crossed a goal threshold during the last 7 days based on already-recorded campaign signals.",
      ],
      generatedAt: digestEndsAt.toISOString(),
    };
  }

  const campaignIds = campaigns.map((campaign) => campaign.id);
  const [linkMap, goalRows, followRows, membershipRows] = await Promise.all([
    loadCreatorCampaignLinksByCampaignIds(campaignIds),
    db.select().from(creatorCampaignGoals).where(inArray(creatorCampaignGoals.campaignId, campaignIds)).orderBy(desc(creatorCampaignGoals.updatedAt), asc(creatorCampaignGoals.createdAt)),
    db.select({
      campaignId: creatorCampaignFollows.campaignId,
      createdAt: creatorCampaignFollows.createdAt,
    }).from(creatorCampaignFollows).where(inArray(creatorCampaignFollows.campaignId, campaignIds)).orderBy(asc(creatorCampaignFollows.createdAt)),
    db.select({
      createdAt: creatorMemberships.createdAt,
      status: creatorMemberships.status,
    }).from(creatorMemberships).where(eq(creatorMemberships.creatorUserId, creatorUserId)).orderBy(asc(creatorMemberships.createdAt)),
  ]);

  const dropIds = [...new Set(
    campaigns.flatMap((campaign) => (linkMap.get(campaign.id) ?? [])
      .filter((link) => link.targetType === "drop")
      .map((link) => link.targetId)),
  )];
  const collectionIds = [...new Set(
    campaigns.flatMap((campaign) => (linkMap.get(campaign.id) ?? [])
      .filter((link) => link.targetType === "collection")
      .map((link) => link.targetId)),
  )];

  const [dropRows, collectionRows, eventRows, rsvpRows, purchaseRows] = await Promise.all([
    dropIds.length
      ? db.select({
          id: creatorDrops.id,
          dropType: creatorDrops.dropType,
          isPublished: creatorDrops.isPublished,
          scheduledFor: creatorDrops.scheduledFor,
        }).from(creatorDrops).where(inArray(creatorDrops.id, dropIds))
      : Promise.resolve([] as Array<Pick<CreatorDropRecord, "id" | "dropType" | "isPublished" | "scheduledFor">>),
    collectionIds.length
      ? db.select({
          id: drinkCollections.id,
          accessType: drinkCollections.accessType,
        }).from(drinkCollections).where(inArray(drinkCollections.id, collectionIds))
      : Promise.resolve([] as Array<{ id: string; accessType: string | null }>),
    dropIds.length
      ? db.select({
          dropId: creatorDropEvents.dropId,
          eventType: creatorDropEvents.eventType,
          createdAt: creatorDropEvents.createdAt,
        }).from(creatorDropEvents).where(inArray(creatorDropEvents.dropId, dropIds)).orderBy(asc(creatorDropEvents.createdAt))
      : Promise.resolve([] as Array<{ dropId: string; eventType: string; createdAt: Date }>),
    dropIds.length
      ? db.select({
          dropId: creatorDropRsvps.dropId,
          createdAt: creatorDropRsvps.createdAt,
        }).from(creatorDropRsvps).where(inArray(creatorDropRsvps.dropId, dropIds)).orderBy(asc(creatorDropRsvps.createdAt))
      : Promise.resolve([] as Array<{ dropId: string; createdAt: Date }>),
    collectionIds.length
      ? db.select({
          collectionId: drinkCollectionPurchases.collectionId,
          createdAt: drinkCollectionPurchases.createdAt,
          status: drinkCollectionPurchases.status,
        }).from(drinkCollectionPurchases).where(inArray(drinkCollectionPurchases.collectionId, collectionIds)).orderBy(asc(drinkCollectionPurchases.createdAt))
      : Promise.resolve([] as Array<{ collectionId: string; createdAt: Date; status: string }>),
  ]);

  const dropMap = new Map(dropRows.map((row) => [row.id, row]));
  const collectionMap = new Map(collectionRows.map((row) => [row.id, row]));

  const followRowsByCampaignId = new Map<string, Array<{ createdAt: Date }>>();
  for (const row of followRows) {
    const current = followRowsByCampaignId.get(row.campaignId) ?? [];
    current.push({ createdAt: row.createdAt });
    followRowsByCampaignId.set(row.campaignId, current);
  }

  const goalRowsByCampaignId = new Map<string, CreatorCampaignGoalRecord[]>();
  for (const goal of goalRows) {
    const current = goalRowsByCampaignId.get(goal.campaignId) ?? [];
    current.push(goal);
    goalRowsByCampaignId.set(goal.campaignId, current);
  }

  const rsvpRowsByDropId = new Map<string, Array<{ createdAt: Date }>>();
  for (const row of rsvpRows) {
    const current = rsvpRowsByDropId.get(row.dropId) ?? [];
    current.push({ createdAt: row.createdAt });
    rsvpRowsByDropId.set(row.dropId, current);
  }

  const eventRowsByDropId = new Map<string, {
    views: Array<{ createdAt: Date }>;
    clicks: Array<{ createdAt: Date }>;
  }>();
  for (const row of eventRows) {
    const current = eventRowsByDropId.get(row.dropId) ?? { views: [], clicks: [] };
    if (row.eventType === "view_drop") current.views.push({ createdAt: row.createdAt });
    if (row.eventType === "click_drop_target") current.clicks.push({ createdAt: row.createdAt });
    eventRowsByDropId.set(row.dropId, current);
  }

  const purchaseRowsByCollectionId = new Map<string, Array<{ createdAt: Date; status: string }>>();
  for (const row of purchaseRows) {
    const current = purchaseRowsByCollectionId.get(row.collectionId) ?? [];
    current.push({ createdAt: row.createdAt, status: row.status });
    purchaseRowsByCollectionId.set(row.collectionId, current);
  }

  const filteredMembershipRows = membershipRows.map((row) => ({ createdAt: row.createdAt, status: row.status }));

  const items = campaigns.map((campaign) => {
    const links = linkMap.get(campaign.id) ?? [];
    const dropLinkIds = links.filter((link) => link.targetType === "drop").map((link) => link.targetId);
    const collectionLinkIds = links.filter((link) => link.targetType === "collection").map((link) => link.targetId);
    const followActivityRows = followRowsByCampaignId.get(campaign.id) ?? [];
    const rsvpActivityRows = dropLinkIds.flatMap((dropId) => rsvpRowsByDropId.get(dropId) ?? [])
      .sort((a, b) => a.createdAt.getTime() - b.createdAt.getTime());
    const clickActivityRows = dropLinkIds.flatMap((dropId) => eventRowsByDropId.get(dropId)?.clicks ?? [])
      .sort((a, b) => a.createdAt.getTime() - b.createdAt.getTime());
    const viewActivityRows = dropLinkIds.flatMap((dropId) => eventRowsByDropId.get(dropId)?.views ?? [])
      .sort((a, b) => a.createdAt.getTime() - b.createdAt.getTime());
    const purchaseActivityRows = collectionLinkIds.flatMap((collectionId) => purchaseRowsByCollectionId.get(collectionId) ?? [])
      .sort((a, b) => a.createdAt.getTime() - b.createdAt.getTime());
    const isMemberFocusedCampaign = campaign.visibility === "members"
      || dropLinkIds.some((dropId) => (dropMap.get(dropId)?.dropType ?? "") === "member_drop")
      || collectionLinkIds.some((collectionId) => (collectionMap.get(collectionId)?.accessType ?? "") === "membership_only");
    const membershipActivityRows = isMemberFocusedCampaign
      ? filteredMembershipRows.filter((membership) => isDateWithinCampaignAnalyticsWindow(membership.createdAt, campaign))
          .map((membership) => ({ createdAt: membership.createdAt }))
      : [];

    const newFollowersThisWeek = followActivityRows.filter((row) => isDateWithinRange(row.createdAt, digestStartsAt, digestEndsAt)).length;
    const newRsvpsThisWeek = rsvpActivityRows.filter((row) => isDateWithinRange(row.createdAt, digestStartsAt, digestEndsAt)).length;
    const dropViewsThisWeek = viewActivityRows.filter((row) => isDateWithinRange(row.createdAt, digestStartsAt, digestEndsAt)).length;
    const dropClicksThisWeek = clickActivityRows.filter((row) => isDateWithinRange(row.createdAt, digestStartsAt, digestEndsAt)).length;
    const purchasesThisWeek = purchaseActivityRows.filter((row) => (
      row.status === "completed"
      && isDateWithinRange(row.createdAt, digestStartsAt, digestEndsAt)
      && isDateWithinCampaignAnalyticsWindow(row.createdAt, campaign)
    )).length;
    const membershipsThisWeek = membershipActivityRows.filter((row) => isDateWithinRange(row.createdAt, digestStartsAt, digestEndsAt)).length;

    const purchasesToDate = purchaseActivityRows.filter((row) => row.status === "completed" && isDateWithinCampaignAnalyticsWindow(row.createdAt, campaign))
      .map((row) => ({ createdAt: row.createdAt }));

    const milestonesReachedThisWeek = buildCreatorCampaignMilestones({
      campaign,
      links,
      isMemberFocusedCampaign,
      followerCount: followActivityRows.filter((row) => isDateWithinCampaignAnalyticsWindow(row.createdAt, campaign)).length,
      followRows: followActivityRows.filter((row) => isDateWithinCampaignAnalyticsWindow(row.createdAt, campaign)),
      dropRows: dropLinkIds.map((dropId) => dropMap.get(dropId)).filter((drop): drop is Pick<CreatorDropRecord, "id" | "dropType" | "isPublished" | "scheduledFor"> => Boolean(drop)),
      totalDropRsvps: rsvpActivityRows.filter((row) => isDateWithinCampaignAnalyticsWindow(row.createdAt, campaign)).length,
      rsvpRows: rsvpActivityRows.filter((row) => isDateWithinCampaignAnalyticsWindow(row.createdAt, campaign)),
      totalDropClicks: clickActivityRows.filter((row) => isDateWithinCampaignAnalyticsWindow(row.createdAt, campaign)).length,
      clickRows: clickActivityRows.filter((row) => isDateWithinCampaignAnalyticsWindow(row.createdAt, campaign)),
      purchasesFromLinkedCollections: purchasesToDate.length,
      purchaseRows: purchasesToDate,
      membershipsFromCampaign: membershipActivityRows.length,
      membershipRows: membershipActivityRows,
    }).filter((milestone) => (
      milestone.achieved
      && Boolean(milestone.achievedAt)
      && isDateWithinRange(new Date(milestone.achievedAt!), digestStartsAt, digestEndsAt)
    )).map((milestone) => ({
      type: milestone.type,
      label: milestone.label,
      achievedAt: milestone.achievedAt!,
      isPublic: milestone.isPublic,
    }));

    const goalsCompletedThisWeek = (goalRowsByCampaignId.get(campaign.id) ?? []).flatMap((goal) => {
      const goalProgress = campaignGoalCountsForDigest({
        goalType: goal.goalType as CreatorCampaignGoalType,
        campaign,
        followRows: followActivityRows,
        rsvpRows: rsvpActivityRows,
        clickRows: clickActivityRows,
        viewRows: viewActivityRows,
        purchaseRows: purchaseActivityRows,
        membershipRows: membershipActivityRows,
        digestStartsAt,
        digestEndsAt,
      });
      const targetValue = Number(goal.targetValue ?? 0);
      if (targetValue <= 0 || goalProgress.currentValue < targetValue || goalProgress.baselineValue >= targetValue) {
        return [];
      }
      const analyticsLikeItem = {
        campaignId: campaign.id,
        slug: campaign.slug,
        name: campaign.name,
        visibility: campaign.visibility as CreatorCampaignVisibility,
        isActive: Boolean(campaign.isActive),
        startsAt: campaign.startsAt ? campaign.startsAt.toISOString() : null,
        endsAt: campaign.endsAt ? campaign.endsAt.toISOString() : null,
        followerCount: followActivityRows.filter((row) => isDateWithinCampaignAnalyticsWindow(row.createdAt, campaign)).length,
        linkedDropsCount: dropLinkIds.length,
        linkedPostsCount: links.filter((link) => link.targetType === "post").length,
        linkedCollectionsCount: collectionLinkIds.length,
        linkedChallengesCount: links.filter((link) => link.targetType === "challenge").length,
        totalDropRsvps: rsvpActivityRows.filter((row) => isDateWithinCampaignAnalyticsWindow(row.createdAt, campaign)).length,
        totalDropViews: viewActivityRows.filter((row) => isDateWithinCampaignAnalyticsWindow(row.createdAt, campaign)).length,
        totalDropClicks: clickActivityRows.filter((row) => isDateWithinCampaignAnalyticsWindow(row.createdAt, campaign)).length,
        purchasesFromLinkedCollections: purchasesToDate.length,
        purchasesFromLinkedCollectionsNote: collectionLinkIds.length
          ? "Approximate: counts completed linked-collection purchases inside the campaign window."
          : null,
        membershipsFromCampaign: membershipActivityRows.length,
        membershipsFromCampaignNote: isMemberFocusedCampaign
          ? "Approximate: counts memberships that started during this campaign window for member-focused campaign content."
          : null,
        campaignEngagementScore: 0,
        campaignEngagementScoreNote: "",
        milestones: [],
      } satisfies CreatorCampaignAnalyticsItem;
      const progressMeta = buildCampaignGoalProgress(goal.goalType as CreatorCampaignGoalType, analyticsLikeItem);
      return [{
        id: goal.id,
        goalType: goal.goalType as CreatorCampaignGoalType,
        label: goal.label ?? progressMeta.metricLabel,
        targetValue,
        completedAt: findGoalCompletionDate(goalProgress.weeklyRows, targetValue, goalProgress.baselineValue)?.toISOString() ?? null,
        metricLabel: progressMeta.metricLabel,
        metricNote: progressMeta.metricNote,
      } satisfies CreatorCampaignWeeklyDigestGoal];
    });

    return {
      campaignId: campaign.id,
      slug: campaign.slug,
      name: campaign.name,
      route: `/drinks/campaigns/${encodeURIComponent(campaign.slug)}`,
      visibility: campaign.visibility as CreatorCampaignVisibility,
      state: getCreatorCampaignState(campaign),
      wasActiveThisWeek: campaignWasActiveWithinRange(campaign, digestStartsAt, digestEndsAt),
      newFollowersThisWeek,
      newRsvpsThisWeek,
      dropViewsThisWeek,
      dropClicksThisWeek,
      purchasesFromLinkedCollectionsThisWeek: purchasesThisWeek,
      purchasesFromLinkedCollectionsThisWeekNote: collectionLinkIds.length
        ? "Approximate: counts completed purchases on collections linked to this campaign during the last 7 days."
        : null,
      membershipConversionsThisWeek: membershipsThisWeek,
      membershipConversionsThisWeekNote: isMemberFocusedCampaign
        ? "Approximate: counts memberships started during the last 7 days while this campaign window was live."
        : null,
      milestonesReachedThisWeek,
      goalsCompletedThisWeek,
    } satisfies CreatorCampaignWeeklyDigestItem;
  }).filter((item) => (
    item.wasActiveThisWeek
    || item.newFollowersThisWeek > 0
    || item.newRsvpsThisWeek > 0
    || item.dropViewsThisWeek > 0
    || item.dropClicksThisWeek > 0
    || item.purchasesFromLinkedCollectionsThisWeek > 0
    || item.membershipConversionsThisWeek > 0
    || item.milestonesReachedThisWeek.length > 0
    || item.goalsCompletedThisWeek.length > 0
  )).sort((a, b) => {
    const aScore = (
      (a.wasActiveThisWeek ? 5000 : 0)
      + a.newFollowersThisWeek
      + a.newRsvpsThisWeek * 2
      + a.dropClicksThisWeek * 2
      + a.purchasesFromLinkedCollectionsThisWeek * 4
      + a.membershipConversionsThisWeek * 5
      + a.milestonesReachedThisWeek.length * 8
      + a.goalsCompletedThisWeek.length * 10
    );
    const bScore = (
      (b.wasActiveThisWeek ? 5000 : 0)
      + b.newFollowersThisWeek
      + b.newRsvpsThisWeek * 2
      + b.dropClicksThisWeek * 2
      + b.purchasesFromLinkedCollectionsThisWeek * 4
      + b.membershipConversionsThisWeek * 5
      + b.milestonesReachedThisWeek.length * 8
      + b.goalsCompletedThisWeek.length * 10
    );
    return bScore - aScore;
  });

  return {
    window: {
      startsAt: digestStartsAt.toISOString(),
      endsAt: digestEndsAt.toISOString(),
      days: 7,
    },
    summary: {
      campaignsIncluded: items.length,
      activeCampaignsThisWeek: items.filter((item) => item.wasActiveThisWeek).length,
      newCampaignFollowersThisWeek: items.reduce((sum, item) => sum + item.newFollowersThisWeek, 0),
      newRsvpsThisWeek: items.reduce((sum, item) => sum + item.newRsvpsThisWeek, 0),
      dropViewsThisWeek: items.reduce((sum, item) => sum + item.dropViewsThisWeek, 0),
      dropClicksThisWeek: items.reduce((sum, item) => sum + item.dropClicksThisWeek, 0),
      purchasesFromLinkedCollectionsThisWeek: items.reduce((sum, item) => sum + item.purchasesFromLinkedCollectionsThisWeek, 0),
      membershipConversionsThisWeek: items.reduce((sum, item) => sum + item.membershipConversionsThisWeek, 0),
      milestonesReachedThisWeek: items.reduce((sum, item) => sum + item.milestonesReachedThisWeek.length, 0),
      goalsCompletedThisWeek: items.reduce((sum, item) => sum + item.goalsCompletedThisWeek.length, 0),
    } satisfies CreatorCampaignWeeklyDigestSummary,
    items,
    attributionNotes: [
      "Campaign followers and RSVPs are direct counts from explicit campaign follows and linked drop RSVP activity recorded in the last 7 days.",
      "Drop views and clicks reuse linked drop analytics that already exist elsewhere in the drinks creator dashboard.",
      "Linked collection purchases are approximate and count completed purchases on collections linked to the campaign during the last 7 days.",
      "Membership conversions are approximate and only shown for member-focused campaigns, using memberships started in the last 7 days.",
      "Goal completions are inferred when a campaign crossed a goal threshold during the last 7 days based on already-recorded campaign signals.",
    ],
    generatedAt: digestEndsAt.toISOString(),
  };
}

function formatRetrospectiveSignalCount(label: string, value: number, approximate = false) {
  return `${value} ${label}${approximate ? " (approx.)" : ""}`;
}

function summarizeRetrospectivePrimaryMetric(input: {
  views: number;
  clicks: number;
  follows: number;
  rsvps: number;
  approximatePurchases: number;
  approximateMemberships: number;
}) {
  const metrics = [
    { label: "approx. memberships", value: input.approximateMemberships, weight: 8, approximate: true },
    { label: "approx. purchases", value: input.approximatePurchases, weight: 7, approximate: true },
    { label: "RSVPs", value: input.rsvps, weight: 6, approximate: false },
    { label: "follows", value: input.follows, weight: 5, approximate: false },
    { label: "clicks", value: input.clicks, weight: 4, approximate: false },
    { label: "views", value: input.views, weight: 1, approximate: false },
  ].filter((item) => item.value > 0);

  const best = metrics.sort((a, b) => (b.value * b.weight) - (a.value * a.weight))[0] ?? null;
  if (!best) {
    return { metricLabel: "No recorded lift yet", metricValue: 0, approximate: false };
  }
  return {
    metricLabel: best.label,
    metricValue: best.value,
    approximate: best.approximate,
  };
}

function scoreRetrospectiveVariant(metrics: ReturnType<typeof serializeCreatorCampaignVariant>["metrics"]) {
  return Math.round(
    metrics.views * 0.25
    + metrics.clicks * 2
    + metrics.follows * 3
    + metrics.rsvps * 4
    + metrics.approximatePurchases * 5
    + metrics.approximateMemberships * 6
  );
}

function scoreRetrospectiveAsset(input: {
  targetType: "drop" | "collection";
  views?: number;
  clicks?: number;
  rsvps?: number;
  purchases?: number;
}) {
  if (input.targetType === "collection") {
    return Math.round((input.purchases ?? 0) * 6);
  }

  return Math.round(
    (input.views ?? 0) * 0.25
    + (input.clicks ?? 0) * 3
    + (input.rsvps ?? 0) * 4
  );
}

function buildCampaignRetrospectiveInsights(input: {
  campaign: CreatorCampaignRecord;
  analytics: CreatorCampaignAnalyticsItem;
  milestonesReached: CreatorCampaignMilestone[];
  goalsCompleted: SerializedCreatorCampaignGoal[];
  goalsIncomplete: SerializedCreatorCampaignGoal[];
  strongestVariant: CreatorCampaignRetrospectiveVariant | null;
  bestAsset: CreatorCampaignRetrospectiveAsset | null;
  durationDays: number;
  memberFocused: boolean;
  reuseCandidate: boolean;
}) {
  const wins: CreatorCampaignRetrospectiveInsight[] = [];
  const misses: CreatorCampaignRetrospectiveInsight[] = [];
  const lessons: CreatorCampaignRetrospectiveInsight[] = [];
  const approximateConversions = input.analytics.purchasesFromLinkedCollections + input.analytics.membershipsFromCampaign;

  const pushUnique = (bucket: CreatorCampaignRetrospectiveInsight[], item: CreatorCampaignRetrospectiveInsight) => {
    if (!bucket.some((existing) => existing.title === item.title)) {
      bucket.push(item);
    }
  };

  if (input.analytics.followerCount >= 15) {
    pushUnique(wins, {
      kind: "win",
      title: "Strong audience lift",
      message: approximateConversions <= Math.max(1, Math.round(input.analytics.followerCount * 0.08))
        ? "This campaign generated strong follows but weak conversion."
        : "This campaign turned audience attention into meaningful follow growth.",
      supportingSignals: [
        `${input.analytics.followerCount} campaign followers`,
        formatRetrospectiveSignalCount("approx. conversions", approximateConversions, approximateConversions > 0),
      ],
    });
  }

  if (input.memberFocused && input.analytics.membershipsFromCampaign > input.analytics.purchasesFromLinkedCollections) {
    pushUnique(wins, {
      kind: "win",
      title: "Member-only content won this arc",
      message: "Member-only content outperformed one-off purchase content.",
      supportingSignals: [
        formatRetrospectiveSignalCount("memberships", input.analytics.membershipsFromCampaign, true),
        formatRetrospectiveSignalCount("purchases", input.analytics.purchasesFromLinkedCollections, true),
      ],
    });
  }

  if (input.goalsCompleted.length > 0) {
    pushUnique(wins, {
      kind: "win",
      title: "Goals were actually closed out",
      message: `${input.goalsCompleted.length} creator-set goal${input.goalsCompleted.length === 1 ? " was" : "s were"} completed before wrap-up.`,
      supportingSignals: input.goalsCompleted.slice(0, 3).map((goal) => `${goal.label?.trim() || goal.metricLabel}: ${goal.currentValue}/${goal.targetValue}`),
    });
  }

  if (input.analytics.followerCount >= 20 && approximateConversions <= 1 && input.analytics.totalDropClicks >= 10) {
    pushUnique(misses, {
      kind: "miss",
      title: "Interest did not convert cleanly",
      message: "This campaign generated strong follows but weak conversion.",
      supportingSignals: [
        `${input.analytics.followerCount} followers`,
        `${input.analytics.totalDropClicks} clicks`,
        formatRetrospectiveSignalCount("approx. conversions", approximateConversions, approximateConversions > 0),
      ],
    });
  }

  if (input.analytics.totalDropViews >= 40 && input.analytics.totalDropClicks <= Math.max(5, Math.round(input.analytics.totalDropViews * 0.08))) {
    pushUnique(misses, {
      kind: "miss",
      title: "Drop traffic was mostly passive",
      message: "People viewed linked drops, but the campaign story did not pull enough click-through intent.",
      supportingSignals: [
        `${input.analytics.totalDropViews} views`,
        `${input.analytics.totalDropClicks} clicks`,
      ],
    });
  }

  if (input.goalsIncomplete.length > 0) {
    const furthestGoal = [...input.goalsIncomplete].sort((a, b) => b.percentComplete - a.percentComplete)[0];
    if (furthestGoal) {
      pushUnique(misses, {
        kind: "miss",
        title: "One target still feels unfinished",
        message: `${furthestGoal.label?.trim() || furthestGoal.metricLabel} ended at ${furthestGoal.percentComplete}% of target.`,
        supportingSignals: [`${furthestGoal.currentValue}/${furthestGoal.targetValue} ${furthestGoal.metricLabel.toLowerCase()}`],
      });
    }
  }

  if (input.strongestVariant?.ctaTargetType === "rsvp" && input.strongestVariant.metricValue > 0) {
    pushUnique(lessons, {
      kind: "lesson",
      title: "RSVP framing was the clearest hook",
      message: "Your best-performing CTA variant emphasized RSVP.",
      supportingSignals: input.strongestVariant.supportingSignals.slice(0, 3),
    });
  }

  const followerMilestone = input.milestonesReached.find((milestone) => milestone.type === "campaign_followers_10" && milestone.achievedAt);
  if (followerMilestone?.achievedAt && input.durationDays >= 14) {
    const achievedAt = new Date(followerMilestone.achievedAt);
    const campaignStart = input.campaign.startsAt ?? input.campaign.createdAt;
    const daysToMilestone = Math.max(0, Math.round((achievedAt.getTime() - campaignStart.getTime()) / (24 * 60 * 60 * 1000)));
    if (daysToMilestone <= Math.max(2, Math.round(input.durationDays * 0.25)) && input.analytics.totalDropClicks < Math.max(12, input.analytics.followerCount)) {
      pushUnique(lessons, {
        kind: "lesson",
        title: "Momentum came early, then flattened",
        message: "This campaign hit follower milestones quickly but stalled after launch.",
        supportingSignals: [
          `${daysToMilestone} day${daysToMilestone === 1 ? "" : "s"} to first follower milestone`,
          `${input.analytics.totalDropClicks} linked clicks across ${input.durationDays} campaign days`,
        ],
      });
    }
  }

  if (input.bestAsset) {
    pushUnique(lessons, {
      kind: "lesson",
      title: "A reusable anchor emerged",
      message: input.bestAsset.targetType === "collection"
        ? "A linked collection was the strongest reusable conversion asset in this campaign."
        : "One linked drop clearly carried the campaign’s strongest response.",
      supportingSignals: input.bestAsset.supportingSignals.slice(0, 3),
    });
  }

  if (input.reuseCandidate) {
    pushUnique(lessons, {
      kind: "lesson",
      title: "Worth reusing",
      message: "This archived campaign may be worth cloning.",
      supportingSignals: [
        `${input.analytics.campaignEngagementScore} engagement score`,
        formatRetrospectiveSignalCount("approx. conversions", approximateConversions, approximateConversions > 0),
      ],
    });
  }

  return {
    wins: wins.slice(0, 3),
    misses: misses.slice(0, 3),
    lessons: lessons.slice(0, 3),
  };
}

async function loadCreatorCampaignRetrospectives(creatorUserId: string) {
  if (!db) throw new Error("Database unavailable");

  const campaigns = await db
    .select()
    .from(creatorCampaigns)
    .where(eq(creatorCampaigns.creatorUserId, creatorUserId))
    .orderBy(desc(creatorCampaigns.updatedAt))
    .limit(120);

  const completedCampaigns = campaigns.filter((campaign) => getCreatorCampaignState(campaign) === "past");
  if (completedCampaigns.length === 0) {
    return {
      summary: {
        totalRetrospectives: 0,
        completedCampaigns: 0,
        archivedCampaigns: 0,
        totalFollowerGain: 0,
        totalRsvpInterest: 0,
        totalApproximateConversions: 0,
        reuseCandidates: 0,
      } satisfies CreatorCampaignRetrospectiveSummary,
      items: [] as CreatorCampaignRetrospectiveItem[],
      attributionNotes: [
        "Retrospectives only surface campaigns whose state is already past, so analytics and weekly digest views stay separate from end-of-campaign wrap-up.",
        "Follower gain and RSVP interest are direct campaign signals. Purchases and membership conversions remain clearly labeled as approximate wherever the platform only has proxy attribution.",
        "Lessons are lightweight rules based on campaign follows, linked drop traffic, linked collection purchases, membership conversion proxies, goals, milestones, and CTA variant performance.",
      ],
      generatedAt: new Date().toISOString(),
    };
  }

  const performance = await loadCreatorCampaignPerformanceSnapshots(creatorUserId);
  const performanceByCampaignId = new Map(performance.items.map((item) => [item.campaignId, item]));
  const campaignIds = completedCampaigns.map((campaign) => campaign.id);

  const [linkMap, goalRows, followRows, variantsByCampaignId] = await Promise.all([
    loadCreatorCampaignLinksByCampaignIds(campaignIds),
    db.select().from(creatorCampaignGoals).where(inArray(creatorCampaignGoals.campaignId, campaignIds)).orderBy(desc(creatorCampaignGoals.updatedAt), asc(creatorCampaignGoals.createdAt)),
    db.select({
      campaignId: creatorCampaignFollows.campaignId,
      createdAt: creatorCampaignFollows.createdAt,
    }).from(creatorCampaignFollows).where(inArray(creatorCampaignFollows.campaignId, campaignIds)).orderBy(asc(creatorCampaignFollows.createdAt)),
    loadCreatorCampaignVariantsByCampaignIds(campaignIds),
  ]);

  const collectionIds = [...new Set(
    completedCampaigns.flatMap((campaign) => (linkMap.get(campaign.id) ?? [])
      .filter((link) => link.targetType === "collection")
      .map((link) => link.targetId)),
  )];
  const dropIds = [...new Set(
    completedCampaigns.flatMap((campaign) => (linkMap.get(campaign.id) ?? [])
      .filter((link) => link.targetType === "drop")
      .map((link) => link.targetId)),
  )];

  const [collectionRows, dropRows, purchaseRows, dropEventRows, dropRsvpRows] = await Promise.all([
    collectionIds.length
      ? db.select({ id: drinkCollections.id, name: drinkCollections.name, accessType: drinkCollections.accessType }).from(drinkCollections).where(inArray(drinkCollections.id, collectionIds))
      : Promise.resolve([] as Array<{ id: string; name: string; accessType: string | null }>),
    dropIds.length
      ? db.select({ id: creatorDrops.id, title: creatorDrops.title }).from(creatorDrops).where(inArray(creatorDrops.id, dropIds))
      : Promise.resolve([] as Array<{ id: string; title: string }>),
    collectionIds.length
      ? db.select({ collectionId: drinkCollectionPurchases.collectionId, createdAt: drinkCollectionPurchases.createdAt, status: drinkCollectionPurchases.status }).from(drinkCollectionPurchases).where(inArray(drinkCollectionPurchases.collectionId, collectionIds)).orderBy(asc(drinkCollectionPurchases.createdAt))
      : Promise.resolve([] as Array<{ collectionId: string; createdAt: Date; status: string }>),
    dropIds.length
      ? db.select({ dropId: creatorDropEvents.dropId, eventType: creatorDropEvents.eventType, createdAt: creatorDropEvents.createdAt }).from(creatorDropEvents).where(inArray(creatorDropEvents.dropId, dropIds)).orderBy(asc(creatorDropEvents.createdAt))
      : Promise.resolve([] as Array<{ dropId: string; eventType: string; createdAt: Date }>),
    dropIds.length
      ? db.select({ dropId: creatorDropRsvps.dropId, createdAt: creatorDropRsvps.createdAt }).from(creatorDropRsvps).where(inArray(creatorDropRsvps.dropId, dropIds)).orderBy(asc(creatorDropRsvps.createdAt))
      : Promise.resolve([] as Array<{ dropId: string; createdAt: Date }>),
  ]);

  const goalRowsByCampaignId = new Map<string, CreatorCampaignGoalRecord[]>();
  for (const goal of goalRows) {
    const current = goalRowsByCampaignId.get(goal.campaignId) ?? [];
    current.push(goal);
    goalRowsByCampaignId.set(goal.campaignId, current);
  }

  const followRowsByCampaignId = new Map<string, Array<{ createdAt: Date }>>();
  for (const row of followRows) {
    const current = followRowsByCampaignId.get(row.campaignId) ?? [];
    current.push({ createdAt: row.createdAt });
    followRowsByCampaignId.set(row.campaignId, current);
  }

  const purchaseRowsByCollectionId = new Map<string, Array<{ createdAt: Date; status: string }>>();
  for (const row of purchaseRows) {
    const current = purchaseRowsByCollectionId.get(row.collectionId) ?? [];
    current.push({ createdAt: row.createdAt, status: row.status });
    purchaseRowsByCollectionId.set(row.collectionId, current);
  }

  const dropEventsByDropId = new Map<string, { views: Array<{ createdAt: Date }>; clicks: Array<{ createdAt: Date }> }>();
  for (const row of dropEventRows) {
    const current = dropEventsByDropId.get(row.dropId) ?? { views: [], clicks: [] };
    if (row.eventType === "view_drop") current.views.push({ createdAt: row.createdAt });
    if (row.eventType === "click_drop_target") current.clicks.push({ createdAt: row.createdAt });
    dropEventsByDropId.set(row.dropId, current);
  }

  const rsvpRowsByDropId = new Map<string, Array<{ createdAt: Date }>>();
  for (const row of dropRsvpRows) {
    const current = rsvpRowsByDropId.get(row.dropId) ?? [];
    current.push({ createdAt: row.createdAt });
    rsvpRowsByDropId.set(row.dropId, current);
  }

  const collectionMap = new Map(collectionRows.map((row) => [row.id, row]));
  const dropMap = new Map(dropRows.map((row) => [row.id, row]));
  const items: CreatorCampaignRetrospectiveItem[] = [];

  for (const campaign of completedCampaigns) {
    const analytics = performanceByCampaignId.get(campaign.id);
    if (!analytics) continue;

    const links = linkMap.get(campaign.id) ?? [];
    const linkedDropIds = links.filter((link) => link.targetType === "drop").map((link) => link.targetId);
    const linkedCollectionIds = links.filter((link) => link.targetType === "collection").map((link) => link.targetId);
    const followerGain = (followRowsByCampaignId.get(campaign.id) ?? []).filter((row) => isDateWithinCampaignAnalyticsWindow(row.createdAt, campaign)).length;
    const goals = (goalRowsByCampaignId.get(campaign.id) ?? []).map((goal) => serializeCreatorCampaignGoal(goal, analytics));
    const completedGoals = goals.filter((goal) => goal.isComplete);
    const incompleteGoals = goals.filter((goal) => !goal.isComplete);
    const milestonesReached = analytics.milestones.filter((milestone) => milestone.achieved);

    const variantRows = variantsByCampaignId.get(campaign.id) ?? [];
    const variantMetrics = await loadCreatorCampaignVariantMetrics(campaign, variantRows);
    const strongestVariant = [...variantRows]
      .map((variant) => {
        const metrics = variantMetrics.get(variant.id) ?? {
          views: 0,
          clicks: 0,
          follows: 0,
          rsvps: 0,
          approximatePurchases: 0,
          approximateMemberships: 0,
        };
        const primaryMetric = summarizeRetrospectivePrimaryMetric(metrics);
        const supportingSignals = [
          `${metrics.views} views`,
          `${metrics.clicks} clicks`,
          `${metrics.follows} follows`,
          `${metrics.rsvps} RSVPs`,
          formatRetrospectiveSignalCount("purchases", metrics.approximatePurchases, metrics.approximatePurchases > 0),
          formatRetrospectiveSignalCount("memberships", metrics.approximateMemberships, metrics.approximateMemberships > 0),
        ].filter((signal) => !/^0 /.test(signal));

        return {
          variantId: variant.id,
          label: variant.label,
          headline: variant.headline ?? null,
          ctaTargetType: variant.ctaTargetType as CreatorCampaignCtaTargetType,
          score: scoreRetrospectiveVariant(metrics),
          metricLabel: primaryMetric.metricLabel,
          metricValue: primaryMetric.metricValue,
          supportingSignals,
          note: (metrics.approximatePurchases > 0 || metrics.approximateMemberships > 0)
            ? "Approximate purchases and memberships are credited when a signed-in user converted after clicking this CTA during the campaign window."
            : null,
        } satisfies CreatorCampaignRetrospectiveVariant;
      })
      .sort((a, b) => b.score - a.score)[0] ?? null;

    const assetCandidates: CreatorCampaignRetrospectiveAsset[] = [
      ...linkedDropIds.map((dropId) => {
        const drop = dropMap.get(dropId);
        const events = dropEventsByDropId.get(dropId) ?? { views: [], clicks: [] };
        const rsvpRowsForDrop = rsvpRowsByDropId.get(dropId) ?? [];
        const views = events.views.filter((row) => isDateWithinCampaignAnalyticsWindow(row.createdAt, campaign)).length;
        const clicks = events.clicks.filter((row) => isDateWithinCampaignAnalyticsWindow(row.createdAt, campaign)).length;
        const rsvps = rsvpRowsForDrop.filter((row) => isDateWithinCampaignAnalyticsWindow(row.createdAt, campaign)).length;
        const score = scoreRetrospectiveAsset({ targetType: "drop", views, clicks, rsvps });
        const primaryMetric = rsvps > 0 ? { label: "RSVPs", value: rsvps } : clicks > 0 ? { label: "clicks", value: clicks } : { label: "views", value: views };

        return {
          targetType: "drop" as const,
          targetId: dropId,
          title: drop?.title ?? "Linked drop",
          route: `/drinks/drops/${encodeURIComponent(dropId)}`,
          score,
          metricLabel: primaryMetric.label,
          metricValue: primaryMetric.value,
          supportingSignals: [`${views} views`, `${clicks} clicks`, `${rsvps} RSVPs`],
        };
      }),
      ...linkedCollectionIds.map((collectionId) => {
        const collection = collectionMap.get(collectionId);
        const purchases = (purchaseRowsByCollectionId.get(collectionId) ?? []).filter((row) => (
          row.status === "completed" && isDateWithinCampaignAnalyticsWindow(row.createdAt, campaign)
        )).length;
        const score = scoreRetrospectiveAsset({ targetType: "collection", purchases });
        return {
          targetType: "collection" as const,
          targetId: collectionId,
          title: collection?.name ?? "Linked collection",
          route: `/drinks/collections/${encodeURIComponent(collectionId)}`,
          score,
          metricLabel: "approx. purchases",
          metricValue: purchases,
          supportingSignals: [formatRetrospectiveSignalCount("purchases", purchases, true)],
        };
      }),
    ].filter((item) => item.score > 0 || item.metricValue > 0);

    const bestPerformingAsset = assetCandidates.sort((a, b) => b.score - a.score)[0] ?? null;
    const durationStart = campaign.startsAt ?? campaign.createdAt;
    const durationEnd = campaign.endsAt ?? campaign.updatedAt ?? new Date();
    const durationDays = Math.max(1, Math.round((durationEnd.getTime() - durationStart.getTime()) / (24 * 60 * 60 * 1000)) || 1);
    const linkedMemberOnlyCollectionsCount = linkedCollectionIds.filter((collectionId) => (collectionMap.get(collectionId)?.accessType ?? null) === "membership_only").length;
    const memberFocused = campaign.visibility === "members" || analytics.membershipsFromCampaign > 0 || linkedMemberOnlyCollectionsCount > 0;
    const reuseCandidate = analytics.purchasesFromLinkedCollections >= 3 || analytics.membershipsFromCampaign >= 3 || analytics.campaignEngagementScore >= 120;
    const reuseReason = reuseCandidate
      ? `Worth cloning: ${analytics.campaignEngagementScore} engagement score, ${analytics.purchasesFromLinkedCollections} linked purchases, and ${analytics.membershipsFromCampaign} membership conversions.`
      : null;
    const insights = buildCampaignRetrospectiveInsights({
      campaign,
      analytics: {
        ...analytics,
        followerCount: followerGain,
      },
      milestonesReached,
      goalsCompleted: completedGoals,
      goalsIncomplete: incompleteGoals,
      strongestVariant,
      bestAsset: bestPerformingAsset,
      durationDays,
      memberFocused,
      reuseCandidate,
    });

    items.push({
      campaignId: campaign.id,
      slug: campaign.slug,
      name: campaign.name,
      route: `/drinks/campaigns/${encodeURIComponent(campaign.slug)}`,
      visibility: campaign.visibility as CreatorCampaignVisibility,
      startsAt: campaign.startsAt ? campaign.startsAt.toISOString() : null,
      endsAt: campaign.endsAt ? campaign.endsAt.toISOString() : null,
      durationDays,
      endState: campaign.isActive ? "completed" : "archived",
      followerGain,
      totalRsvpInterest: analytics.totalDropRsvps,
      totalDropViews: analytics.totalDropViews,
      totalDropClicks: analytics.totalDropClicks,
      linkedCollectionPurchases: analytics.purchasesFromLinkedCollections,
      linkedCollectionPurchasesNote: analytics.purchasesFromLinkedCollectionsNote,
      membershipConversions: analytics.membershipsFromCampaign,
      membershipConversionsNote: analytics.membershipsFromCampaignNote,
      milestonesReached,
      goals: {
        completed: completedGoals,
        incomplete: incompleteGoals,
      },
      bestPerformingAsset,
      strongestVariant,
      wins: insights.wins,
      misses: insights.misses,
      lessons: insights.lessons,
      linkedCounts: {
        drops: linkedDropIds.length,
        collections: linkedCollectionIds.length,
        posts: links.filter((link) => link.targetType === "post").length,
        promos: links.filter((link) => link.targetType === "promo").length,
        roadmap: links.filter((link) => link.targetType === "roadmap").length,
        challenges: links.filter((link) => link.targetType === "challenge").length,
      },
      reuseCandidate,
      reuseReason,
    });
  }

  items.sort((a, b) => {
    const aTime = new Date(a.endsAt ?? a.startsAt ?? 0).getTime();
    const bTime = new Date(b.endsAt ?? b.startsAt ?? 0).getTime();
    return bTime - aTime;
  });

  return {
    summary: {
      totalRetrospectives: items.length,
      completedCampaigns: items.filter((item) => item.endState === "completed").length,
      archivedCampaigns: items.filter((item) => item.endState === "archived").length,
      totalFollowerGain: items.reduce((sum, item) => sum + item.followerGain, 0),
      totalRsvpInterest: items.reduce((sum, item) => sum + item.totalRsvpInterest, 0),
      totalApproximateConversions: items.reduce((sum, item) => sum + item.linkedCollectionPurchases + item.membershipConversions, 0),
      reuseCandidates: items.filter((item) => item.reuseCandidate).length,
    } satisfies CreatorCampaignRetrospectiveSummary,
    items,
    attributionNotes: [
      "Retrospectives only surface campaigns whose state is already past, so analytics and weekly digest views stay separate from end-of-campaign wrap-up.",
      "Follower gain and RSVP interest are direct campaign signals. Linked collection purchases and membership conversions are clearly labeled approximate whenever the platform only has proxy attribution.",
      "Lessons are rules-based from campaign follows, linked drop traffic, linked collection purchases, membership conversion proxies, goals, milestones, and CTA variant performance.",
    ],
    generatedAt: new Date().toISOString(),
  };
}

function recommendationPriorityRank(priority: CreatorCampaignRecommendationPriority) {
  switch (priority) {
    case "high":
      return 3;
    case "medium":
      return 2;
    case "low":
    default:
      return 1;
  }
}

function uniqueRecommendationKey(item: CreatorCampaignRecommendation) {
  return `${item.campaignId}:${item.recommendationType}`;
}

export async function loadCreatorCampaignRecommendations(creatorUserId: string) {
  if (!db) throw new Error("Database unavailable");

  const performance = await loadCreatorCampaignPerformanceSnapshots(creatorUserId);
  if (performance.items.length === 0) {
    return {
      summary: {
        totalCampaigns: 0,
        campaignsWithRecommendations: 0,
        totalRecommendations: 0,
      },
      items: [] as CreatorCampaignRecommendation[],
      attributionNotes: [
        "Recommendations are lightweight and rules-based, using the campaign analytics already tracked in the drinks platform.",
        "Goals stay creator-defined, milestones stay system-derived, and recommendations only suggest possible next moves.",
      ],
      generatedAt: performance.generatedAt,
    };
  }

  const campaigns = await db
    .select()
    .from(creatorCampaigns)
    .where(eq(creatorCampaigns.creatorUserId, creatorUserId))
    .orderBy(desc(creatorCampaigns.updatedAt))
    .limit(120);

  const campaignById = new Map(campaigns.map((campaign) => [campaign.id, campaign]));
  const campaignIds = campaigns.map((campaign) => campaign.id);
  const linkMap = await loadCreatorCampaignLinksByCampaignIds(campaignIds);
  const goalRows = campaignIds.length
    ? await db
      .select()
      .from(creatorCampaignGoals)
      .where(inArray(creatorCampaignGoals.campaignId, campaignIds))
      .orderBy(desc(creatorCampaignGoals.updatedAt), asc(creatorCampaignGoals.createdAt))
    : [];

  const collectionIds = [...new Set(
    campaigns.flatMap((campaign) => (linkMap.get(campaign.id) ?? [])
      .filter((link) => link.targetType === "collection")
      .map((link) => link.targetId)),
  )];
  const collections = collectionIds.length
    ? await db
      .select({
        id: drinkCollections.id,
        accessType: drinkCollections.accessType,
      })
      .from(drinkCollections)
      .where(inArray(drinkCollections.id, collectionIds))
    : [];
  const collectionMap = new Map(collections.map((collection) => [collection.id, collection]));

  const goalsByCampaignId = new Map<string, CreatorCampaignGoalRecord[]>();
  for (const goal of goalRows) {
    const current = goalsByCampaignId.get(goal.campaignId) ?? [];
    current.push(goal);
    goalsByCampaignId.set(goal.campaignId, current);
  }

  const recommendations: CreatorCampaignRecommendation[] = [];
  const seen = new Set<string>();

  const pushRecommendation = (item: CreatorCampaignRecommendation) => {
    const key = uniqueRecommendationKey(item);
    if (seen.has(key)) return;
    seen.add(key);
    recommendations.push(item);
  };

  for (const analytics of performance.items) {
    const campaign = campaignById.get(analytics.campaignId);
    if (!campaign) continue;

    const links = linkMap.get(campaign.id) ?? [];
    const state = getCreatorCampaignState(campaign);
    const route = `/drinks/campaigns/${encodeURIComponent(campaign.slug)}`;
    const linkedPromosCount = links.filter((link) => link.targetType === "promo").length;
    const linkedPostsCount = links.filter((link) => link.targetType === "post").length;
    const linkedRoadmapCount = links.filter((link) => link.targetType === "roadmap").length;
    const linkedMemberOnlyCollectionsCount = links.filter((link) => (
      link.targetType === "collection" && (collectionMap.get(link.targetId)?.accessType ?? null) === "membership_only"
    )).length;
    const memberFocused = analytics.visibility === "members" || analytics.membershipsFromCampaign > 0 || linkedMemberOnlyCollectionsCount > 0;
    const goals = (goalsByCampaignId.get(campaign.id) ?? []).map((goal) => serializeCreatorCampaignGoal(goal, analytics));
    const behindGoals = goals.filter((goal) => !goal.isComplete && goal.percentComplete < 60);
    const completeMilestones = analytics.milestones.filter((milestone) => milestone.achieved);
    const celebratableMilestone = [...completeMilestones]
      .sort((a, b) => {
        const aTime = a.achievedAt ? new Date(a.achievedAt).getTime() : 0;
        const bTime = b.achievedAt ? new Date(b.achievedAt).getTime() : 0;
        return bTime - aTime;
      })[0];
    const hasMeaningfulMomentum = analytics.followerCount >= 10 || analytics.totalDropRsvps >= 10 || analytics.purchasesFromLinkedCollections > 0;
    const clickToPurchaseRate = analytics.totalDropClicks > 0
      ? analytics.purchasesFromLinkedCollections / analytics.totalDropClicks
      : 0;

    if ((state === "active" || state === "upcoming") && analytics.followerCount >= 25 && analytics.linkedDropsCount < 1) {
      pushRecommendation({
        campaignId: campaign.id,
        campaignName: campaign.name,
        campaignSlug: campaign.slug,
        campaignRoute: route,
        campaignState: state,
        recommendationType: "add_drop",
        priority: analytics.followerCount >= 75 ? "high" : "medium",
        title: "Consider adding a drop",
        message: `This campaign already has ${analytics.followerCount} followers but no linked drops yet. A lightweight drop could give people a concrete next touchpoint.`,
        suggestedAction: "Add a linked drop or scheduled release moment",
        suggestedRoute: "/drinks/creator-dashboard#campaigns",
        supportingSignals: [
          `${analytics.followerCount} campaign followers`,
          `${analytics.linkedDropsCount} linked drops`,
        ],
      });
    }

    if ((state === "active" || state === "upcoming") && analytics.linkedDropsCount > 0 && analytics.followerCount >= 20 && analytics.totalDropRsvps < Math.max(5, Math.round(analytics.followerCount * 0.2))) {
      pushRecommendation({
        campaignId: campaign.id,
        campaignName: campaign.name,
        campaignSlug: campaign.slug,
        campaignRoute: route,
        campaignState: state,
        recommendationType: "push_rsvp",
        priority: "medium",
        title: "This campaign may benefit from a stronger RSVP push",
        message: `The campaign has ${analytics.followerCount} followers and ${analytics.linkedDropsCount} linked drop${analytics.linkedDropsCount === 1 ? "" : "s"}, but RSVP interest is still modest at ${analytics.totalDropRsvps}. A clearer RSVP hook could help convert passive interest into launch intent.`,
        suggestedAction: "Highlight RSVP / Notify Me in the next campaign touchpoint",
        suggestedRoute: route,
        supportingSignals: [
          `${analytics.followerCount} followers`,
          `${analytics.totalDropRsvps} total RSVPs`,
        ],
      });
    }

    if ((state === "active" || state === "upcoming") && analytics.totalDropClicks >= 20 && analytics.purchasesFromLinkedCollections === 0) {
      pushRecommendation({
        campaignId: campaign.id,
        campaignName: campaign.name,
        campaignSlug: campaign.slug,
        campaignRoute: route,
        campaignState: state,
        recommendationType: "improve_cta",
        priority: "high",
        title: "This campaign may benefit from a stronger CTA",
        message: `People are clicking through (${analytics.totalDropClicks} linked clicks), but those visits have not turned into purchases yet. A tighter CTA framing could better connect the story arc to the collection or drop outcome.`,
        suggestedAction: "Test a new CTA variant or sharpen the campaign framing",
        suggestedRoute: "/drinks/creator-dashboard#campaigns",
        supportingSignals: [
          `${analytics.totalDropClicks} linked clicks`,
          `${analytics.purchasesFromLinkedCollections} purchases`,
        ],
      });
    } else if ((state === "active" || state === "upcoming") && analytics.totalDropClicks >= 30 && clickToPurchaseRate > 0 && clickToPurchaseRate < 0.08) {
      pushRecommendation({
        campaignId: campaign.id,
        campaignName: campaign.name,
        campaignSlug: campaign.slug,
        campaignRoute: route,
        campaignState: state,
        recommendationType: "launch_promo",
        priority: linkedPromosCount === 0 ? "high" : "medium",
        title: linkedPromosCount === 0 ? "Consider pairing this campaign with a promo" : "A refreshed promo angle may help",
        message: `This campaign is generating attention (${analytics.totalDropClicks} clicks) but only ${analytics.purchasesFromLinkedCollections} purchase${analytics.purchasesFromLinkedCollections === 1 ? "" : "s"} so far. A lightweight promo or clearer conversion hook may help close the gap.`,
        suggestedAction: linkedPromosCount === 0 ? "Launch a simple promo tied to the campaign" : "Refresh the promo framing or offer",
        suggestedRoute: linkedPromosCount === 0 ? "/drinks/creator-dashboard#promotions" : route,
        supportingSignals: [
          `${analytics.totalDropClicks} linked clicks`,
          `${analytics.purchasesFromLinkedCollections} purchases`,
          `${linkedPromosCount} linked promos`,
        ],
      });
    }

    if (memberFocused && linkedMemberOnlyCollectionsCount === 0) {
      pushRecommendation({
        campaignId: campaign.id,
        campaignName: campaign.name,
        campaignSlug: campaign.slug,
        campaignRoute: route,
        campaignState: state,
        recommendationType: "add_member_only_collection",
        priority: "medium",
        title: "Consider linking a member-only collection",
        message: "This campaign already leans member-focused, but it does not yet link a member-only collection. Adding one could give the membership story a clearer destination.",
        suggestedAction: "Add or link a member-only collection",
        suggestedRoute: "/drinks/collections",
        supportingSignals: [
          `visibility: ${analytics.visibility}`,
          `${linkedMemberOnlyCollectionsCount} member-only collections linked`,
        ],
      });
    }

    if (memberFocused && analytics.followerCount >= 15 && analytics.membershipsFromCampaign < 3) {
      pushRecommendation({
        campaignId: campaign.id,
        campaignName: campaign.name,
        campaignSlug: campaign.slug,
        campaignRoute: route,
        campaignState: state,
        recommendationType: "promote_membership",
        priority: analytics.membershipsFromCampaign === 0 ? "high" : "medium",
        title: "This campaign could surface membership more clearly",
        message: `The campaign is attracting audience attention (${analytics.followerCount} followers) but only ${analytics.membershipsFromCampaign} membership conversion${analytics.membershipsFromCampaign === 1 ? "" : "s"} so far. A member-focused post or CTA may help clarify the value.`,
        suggestedAction: "Publish a member-value touchpoint or update the campaign CTA",
        suggestedRoute: "/drinks/creator-dashboard#membership",
        supportingSignals: [
          `${analytics.followerCount} followers`,
          `${analytics.membershipsFromCampaign} membership conversions`,
        ],
      });
    }

    if ((state === "active" || state === "upcoming") && hasMeaningfulMomentum && linkedPostsCount === 0) {
      pushRecommendation({
        campaignId: campaign.id,
        campaignName: campaign.name,
        campaignSlug: campaign.slug,
        campaignRoute: route,
        campaignState: state,
        recommendationType: "publish_update",
        priority: "medium",
        title: "A creator update could help this campaign stay visible",
        message: `This campaign has early momentum (${analytics.followerCount} followers, ${analytics.totalDropRsvps} RSVPs) but no linked campaign update yet. A short post could keep the story arc active without overbuilding the workflow.`,
        suggestedAction: "Publish a lightweight creator update",
        suggestedRoute: "/drinks/creator-dashboard#posts",
        supportingSignals: [
          `${linkedPostsCount} linked posts`,
          `${analytics.followerCount} followers`,
          `${analytics.totalDropRsvps} RSVPs`,
        ],
      });
    }

    if (celebratableMilestone && linkedPostsCount === 0) {
      pushRecommendation({
        campaignId: campaign.id,
        campaignName: campaign.name,
        campaignSlug: campaign.slug,
        campaignRoute: route,
        campaignState: state,
        recommendationType: "celebrate_milestone",
        priority: "medium",
        title: "You’ve hit a milestone — a creator post could help capitalize on it",
        message: `The campaign has already reached "${celebratableMilestone.shortLabel}". Sharing that momentum in a quick creator update may help carry the next wave of attention forward.`,
        suggestedAction: "Celebrate the milestone with a creator post or recap",
        suggestedRoute: "/drinks/creator-dashboard#posts",
        supportingSignals: [
          `Milestone: ${celebratableMilestone.shortLabel}`,
          `${completeMilestones.length} achieved milestones`,
        ],
      });
    }

    const topBehindGoal = [...behindGoals].sort((a, b) => a.percentComplete - b.percentComplete)[0];
    if (topBehindGoal) {
      const metricGap = Math.max(0, topBehindGoal.targetValue - topBehindGoal.currentValue);
      const goalAction = (() => {
        switch (topBehindGoal.goalType) {
          case "followers":
            return "Consider adding a campaign update or a new CTA hook to bring more followers into the arc.";
          case "rsvps":
            return "Consider emphasizing RSVP / Notify Me in the next drop touchpoint.";
          case "clicks":
            return "Consider refreshing the CTA or adding a more direct action prompt.";
          case "purchases":
            return "Consider pairing the campaign with a promo or clearer purchase framing.";
          case "membership_conversions":
            return "Consider making the member benefit more explicit in the campaign narrative.";
          case "linked_drop_views":
            return "Consider adding another linked drop or roadmap moment to create more traffic opportunities.";
          default:
            return "Consider making the next campaign action more explicit.";
        }
      })();

      pushRecommendation({
        campaignId: campaign.id,
        campaignName: campaign.name,
        campaignSlug: campaign.slug,
        campaignRoute: route,
        campaignState: state,
        recommendationType: topBehindGoal.goalType === "membership_conversions" ? "promote_membership" : "publish_update",
        priority: topBehindGoal.percentComplete < 25 ? "high" : "medium",
        title: `One goal looks behind pace: ${topBehindGoal.label?.trim() || topBehindGoal.metricLabel}`,
        message: `${topBehindGoal.currentValue} of ${topBehindGoal.targetValue} ${topBehindGoal.metricLabel.toLowerCase()} have landed so far (${topBehindGoal.percentComplete}%). ${goalAction}`,
        suggestedAction: topBehindGoal.goalType === "purchases"
          ? "Review CTA or promo options for this campaign"
          : topBehindGoal.goalType === "rsvps"
            ? "Add an RSVP-oriented touchpoint"
            : "Add a practical next campaign touchpoint",
        suggestedRoute: route,
        supportingSignals: [
          `${topBehindGoal.percentComplete}% of goal`,
          `${metricGap} remaining to target`,
        ],
      });
    }

    if (state === "past" && (analytics.purchasesFromLinkedCollections >= 3 || analytics.membershipsFromCampaign >= 3 || analytics.campaignEngagementScore >= 120)) {
      pushRecommendation({
        campaignId: campaign.id,
        campaignName: campaign.name,
        campaignSlug: campaign.slug,
        campaignRoute: route,
        campaignState: state,
        recommendationType: "clone_successful_campaign",
        priority: "medium",
        title: "This archived campaign looks reusable",
        message: `The campaign performed well enough to reuse: ${analytics.purchasesFromLinkedCollections} purchases, ${analytics.membershipsFromCampaign} membership conversions, and a ${analytics.campaignEngagementScore} engagement score. Cloning it could save setup time for a follow-up season.`,
        suggestedAction: "Clone the campaign and reset the dates for a new run",
        suggestedRoute: "/drinks/creator-dashboard#campaigns",
        supportingSignals: [
          `${analytics.purchasesFromLinkedCollections} purchases`,
          `${analytics.membershipsFromCampaign} memberships`,
          `${analytics.campaignEngagementScore} engagement score`,
        ],
      });
    } else if (state === "past" && analytics.campaignEngagementScore >= 30 && linkedRoadmapCount === 0) {
      pushRecommendation({
        campaignId: campaign.id,
        campaignName: campaign.name,
        campaignSlug: campaign.slug,
        campaignRoute: route,
        campaignState: state,
        recommendationType: "refresh_archived_campaign",
        priority: "low",
        title: "This archived campaign may be worth refreshing",
        message: "The campaign found some traction, but it currently ends without a fresh follow-up path. A refreshed archive recap, roadmap item, or new season could keep the idea alive.",
        suggestedAction: "Add a follow-up roadmap note or start a refreshed version",
        suggestedRoute: "/drinks/creator-dashboard#campaigns",
        supportingSignals: [
          `${analytics.campaignEngagementScore} engagement score`,
          `${linkedRoadmapCount} linked roadmap items`,
        ],
      });
    }
  }

  recommendations.sort((a, b) => {
    const priorityDiff = recommendationPriorityRank(b.priority) - recommendationPriorityRank(a.priority);
    if (priorityDiff !== 0) return priorityDiff;
    const aCampaign = performance.items.find((item) => item.campaignId === a.campaignId);
    const bCampaign = performance.items.find((item) => item.campaignId === b.campaignId);
    return Number(bCampaign?.campaignEngagementScore ?? 0) - Number(aCampaign?.campaignEngagementScore ?? 0);
  });

  return {
    summary: {
      totalCampaigns: performance.items.length,
      campaignsWithRecommendations: new Set(recommendations.map((item) => item.campaignId)).size,
      totalRecommendations: recommendations.length,
    },
    items: recommendations.slice(0, 18),
    attributionNotes: [
      "Recommendations are intentionally lightweight and rules-based, not generated by a large AI orchestration layer.",
      "Signals come from campaign follows, linked drop RSVP / click / view metrics, linked collection purchases, membership conversion proxies, goals progress, and campaign milestones.",
      "Goals remain creator-set targets. Milestones remain system-derived achievements. Recommendations simply suggest possible next moves.",
      "Purchase and membership recommendations stay approximate wherever the underlying campaign analytics are approximate.",
    ],
    generatedAt: new Date().toISOString(),
  };
}

function campaignLifecycleConfidenceLabel(score: number): CreatorCampaignLifecycleConfidence {
  if (score >= 80) return "high";
  if (score >= 55) return "medium";
  return "low";
}

function campaignLifecyclePhaseLabel(input: {
  state: CreatorCampaignState;
  action: CreatorCampaignLifecycleAction;
}) {
  if (input.state === "past" && (input.action === "clone_for_next_season" || input.action === "convert_to_template")) {
    return "evergreen_candidate" satisfies CreatorCampaignLifecyclePhase;
  }
  if (input.state === "past") return "archived" satisfies CreatorCampaignLifecyclePhase;
  if (input.action === "shift_to_membership") return "member_arc" satisfies CreatorCampaignLifecyclePhase;
  if (input.action === "launch_promo_push" || input.action === "refresh_cta") return "conversion_push" satisfies CreatorCampaignLifecyclePhase;
  if (input.action === "archive_campaign" || input.action === "close_with_recap") return "wrap_up" satisfies CreatorCampaignLifecyclePhase;
  if (input.state === "upcoming") return "warming_up" satisfies CreatorCampaignLifecyclePhase;
  return "momentum" satisfies CreatorCampaignLifecyclePhase;
}

export async function loadCreatorCampaignLifecycleSuggestions(creatorUserId: string) {
  if (!db) throw new Error("Database unavailable");

  const [campaigns, health, benchmarks, retrospectives, templateRows] = await Promise.all([
    db
      .select()
      .from(creatorCampaigns)
      .where(eq(creatorCampaigns.creatorUserId, creatorUserId))
      .orderBy(desc(creatorCampaigns.updatedAt))
      .limit(120),
    loadCreatorCampaignHealth(creatorUserId),
    loadCreatorCampaignBenchmarks(creatorUserId),
    loadCreatorCampaignRetrospectives(creatorUserId),
    db
      .select({
        sourceCampaignId: creatorCampaignTemplates.sourceCampaignId,
      })
      .from(creatorCampaignTemplates)
      .where(eq(creatorCampaignTemplates.creatorUserId, creatorUserId)),
  ]);

  if (campaigns.length === 0 || health.items.length === 0) {
    return {
      summary: {
        totalCampaigns: 0,
        activeCampaigns: 0,
        archivedCampaigns: 0,
        keepRunningCount: 0,
        phaseShiftCount: 0,
        archiveCount: 0,
        cloneOrTemplateCount: 0,
        membershipArcCount: 0,
      } satisfies CreatorCampaignLifecycleSummary,
      items: [] as CreatorCampaignLifecycleSuggestion[],
      attributionNotes: [
        "Lifecycle suggestions are a lightweight phase-change layer built from campaign state, momentum, conversions, goals, milestones, and archive signals already tracked in the drinks dashboard.",
        "This layer stays distinct from health, recommendations, recovery, and retrospectives: it only suggests what phase or lifecycle move appears most appropriate next.",
        "Suggestions are rules-based and directional rather than predictive certainty.",
      ],
      generatedAt: new Date().toISOString(),
    };
  }

  const healthByCampaignId = new Map(health.items.map((item) => [item.campaignId, item]));
  const benchmarkByCampaignId = new Map(benchmarks.items.map((item) => [item.campaignId, item]));
  const retrospectiveByCampaignId = new Map(retrospectives.items.map((item) => [item.campaignId, item]));
  const templateSourceIds = new Set(
    templateRows
      .map((row) => row.sourceCampaignId)
      .filter((value): value is string => Boolean(value)),
  );
  const now = new Date();

  const items: CreatorCampaignLifecycleSuggestion[] = [];

  for (const campaign of campaigns) {
    const healthItem = healthByCampaignId.get(campaign.id);
    if (!healthItem) continue;

    const benchmark = benchmarkByCampaignId.get(campaign.id) ?? null;
    const retrospective = retrospectiveByCampaignId.get(campaign.id) ?? null;
    const currentState = getCreatorCampaignState(campaign, now);
    const route = `/drinks/campaigns/${encodeURIComponent(campaign.slug)}`;
    const daysSinceActivity = activityAgeInDays(
      healthItem.recentActivityAt ? new Date(healthItem.recentActivityAt) : null,
      now,
    );
    const approximateConversions = (benchmark?.purchasesFromLinkedCollections ?? 0) + (benchmark?.membershipsFromCampaign ?? 0);
    const recentEngagement = healthItem.recentFollowers + healthItem.recentRsvps + healthItem.recentClicks;
    const strongMomentum = ["surging", "up"].includes(healthItem.followerMomentum)
      || ["surging", "up"].includes(healthItem.rsvpMomentum)
      || ["surging", "up"].includes(healthItem.clickMomentum);
    const weakConversion = healthItem.recentClicks >= 8 && healthItem.recentPurchases + healthItem.recentMemberships === 0;
    const memberHeavy = (benchmark?.membershipsFromCampaign ?? 0) >= Math.max(2, benchmark?.purchasesFromLinkedCollections ?? 0)
      || campaign.visibility === "members"
      || healthItem.recentMemberships >= Math.max(1, healthItem.recentPurchases);
    const archiveReady = currentState === "active"
      && (healthItem.healthState === "watch" || healthItem.healthState === "at_risk")
      && daysSinceActivity >= 14
      && (healthItem.completedGoalCount > 0 || healthItem.milestoneCount > 0 || recentEngagement <= 2);
    const strongArchivedCampaign = currentState === "past" && (
      benchmark?.reusableTemplateCandidate
      || retrospective?.reuseCandidate
      || approximateConversions >= 3
      || healthItem.completedGoalCount >= 2
      || healthItem.milestoneCount >= 3
      || (benchmark?.engagementScore ?? 0) >= 120
    );
    const needsRecap = currentState === "past" && !retrospective && healthItem.linkedPostsCount === 0;
    const needsDropExtension = currentState !== "past"
      && strongMomentum
      && healthItem.linkedDropsCount <= 1
      && (healthItem.recentRsvps >= 4 || (benchmark?.totalDropRsvps ?? 0) >= 10);
    const needsCtaRefresh = currentState !== "past"
      && healthItem.recentViews >= 10
      && healthItem.recentClicks <= Math.max(1, Math.floor(healthItem.recentViews * 0.12))
      && healthItem.recentPurchases + healthItem.recentMemberships <= 1;

    let suggestedLifecycleAction: CreatorCampaignLifecycleAction;
    let title: string;
    let message: string;
    let rationale: string;
    let supportingSignals: string[];
    let suggestedRoute: string | null;
    let confidenceScore = 50;

    if (currentState === "past" && strongArchivedCampaign && !templateSourceIds.has(campaign.id)) {
      suggestedLifecycleAction = "convert_to_template";
      title = "This archived campaign looks reusable as a template";
      message = "The campaign already proved out a repeatable arc, so saving it as a reusable template is likely more valuable than leaving it as a one-off.";
      rationale = "Archived performance, milestones, and completed goals suggest the arc can be reused without building a heavier automation system.";
      supportingSignals = [
        `${approximateConversions} approx. conversions`,
        `${healthItem.completedGoalCount} completed goals`,
        `${healthItem.milestoneCount} achieved milestones`,
      ];
      suggestedRoute = `/drinks/campaigns/${encodeURIComponent(campaign.slug)}`;
      confidenceScore = 87;
    } else if (currentState === "past" && strongArchivedCampaign) {
      suggestedLifecycleAction = "clone_for_next_season";
      title = "This archived campaign is a good candidate to relaunch";
      message = "The campaign finished with enough traction to justify a fresh seasonal run instead of starting from zero.";
      rationale = "Strong archived engagement or conversion signals make cloning the simplest next lifecycle move.";
      supportingSignals = [
        `${benchmark?.engagementScore ?? healthItem.healthScore} engagement score`,
        `${approximateConversions} approx. conversions`,
        templateSourceIds.has(campaign.id) ? "Template already exists" : "Archive has reusable signal",
      ];
      suggestedRoute = "/drinks/creator-dashboard#campaigns";
      confidenceScore = templateSourceIds.has(campaign.id) ? 84 : 72;
    } else if (needsRecap) {
      suggestedLifecycleAction = "close_with_recap";
      title = "Close this campaign with a quick recap";
      message = "The campaign appears mostly finished, but it still lacks a lightweight wrap-up for followers or members.";
      rationale = "A short recap closes the loop without turning the campaign into another long-running system.";
      supportingSignals = [
        `${healthItem.linkedPostsCount} linked recap-style posts`,
        `${healthItem.milestoneCount} achieved milestones`,
        `${Math.round(daysSinceActivity)} days since activity`,
      ];
      suggestedRoute = route;
      confidenceScore = 70;
    } else if (archiveReady) {
      suggestedLifecycleAction = "archive_campaign";
      title = "This campaign likely belongs in archive mode";
      message = "Recent activity has slowed enough that the campaign reads more like a finished arc than something that still needs weekly pushes.";
      rationale = "When momentum cools after meaningful progress, archiving cleanly keeps the dashboard focused and makes room for the next launch.";
      supportingSignals = [
        `${Math.round(daysSinceActivity)} days since activity`,
        `${healthItem.healthState.replaceAll("_", " ")} health state`,
        `${healthItem.completedGoalCount} completed goals`,
      ];
      suggestedRoute = route;
      confidenceScore = 78;
    } else if (memberHeavy && currentState !== "past") {
      suggestedLifecycleAction = "shift_to_membership";
      title = "This campaign is reading more like an ongoing member arc";
      message = "The strongest conversion signal here is membership-style behavior, so the next phase should probably lean into member value instead of another one-off push.";
      rationale = "Membership-heavy campaigns work better as ongoing access/content arcs than single launch spikes.";
      supportingSignals = [
        `${benchmark?.membershipsFromCampaign ?? 0} approx. memberships`,
        `${benchmark?.purchasesFromLinkedCollections ?? 0} approx. purchases`,
        `Visibility: ${campaign.visibility}`,
      ];
      suggestedRoute = "/drinks/creator-dashboard#membership";
      confidenceScore = campaign.visibility === "members" ? 88 : 76;
    } else if (weakConversion && healthItem.linkedPromosCount === 0) {
      suggestedLifecycleAction = "launch_promo_push";
      title = "Interest is there, but conversion may need a promo push";
      message = "People are clicking into this campaign, yet the linked conversion proxies are still light. A simple promo run could help close the gap.";
      rationale = "This is a lifecycle nudge toward a conversion phase, not a rescue plan or a broad recommendation set.";
      supportingSignals = [
        `${healthItem.recentClicks} recent clicks`,
        `${healthItem.recentPurchases + healthItem.recentMemberships} recent conversions`,
        `${healthItem.linkedPromosCount} linked promos`,
      ];
      suggestedRoute = "/drinks/creator-dashboard#promotions";
      confidenceScore = 74;
    } else if (needsCtaRefresh) {
      suggestedLifecycleAction = "refresh_cta";
      title = "The campaign likely needs a fresh CTA before a bigger push";
      message = "View activity is outpacing click-through, which suggests the campaign frame is visible but not compelling enough yet.";
      rationale = "Refreshing the CTA is a lighter phase shift than launching a promo or building a new campaign.";
      supportingSignals = [
        `${healthItem.recentViews} recent views`,
        `${healthItem.recentClicks} recent clicks`,
        `${healthItem.clickMomentum} click momentum`,
      ];
      suggestedRoute = route;
      confidenceScore = 68;
    } else if (needsDropExtension) {
      suggestedLifecycleAction = "add_phase_two_drop";
      title = "This campaign has room for a second-phase drop";
      message = "Momentum is healthy, and the campaign looks strong enough to support another drop or launch beat instead of tapering off now.";
      rationale = "Adding a phase-two drop extends an already-working arc without overcomplicating the platform.";
      supportingSignals = [
        `${healthItem.linkedDropsCount} linked drops`,
        `${healthItem.recentRsvps} recent RSVPs`,
        `${healthItem.followerMomentum} follower momentum`,
      ];
      suggestedRoute = "/drinks/creator-dashboard#drops";
      confidenceScore = 82;
    } else {
      suggestedLifecycleAction = "keep_running";
      title = "Keep pushing this campaign for now";
      message = "The campaign still has enough live momentum that the simplest next step is to keep running the current arc rather than forcing a phase change.";
      rationale = "Lifecycle suggestions stay intentionally conservative when the existing campaign state still looks viable.";
      supportingSignals = [
        `${healthItem.healthState.replaceAll("_", " ")} health`,
        `${recentEngagement} recent engagement actions`,
        `${benchmark?.engagementScore ?? healthItem.healthScore} engagement score`,
      ];
      suggestedRoute = route;
      confidenceScore = currentState === "active" && strongMomentum ? 77 : 58;
    }

    items.push({
      campaignId: campaign.id,
      campaignName: campaign.name,
      campaignSlug: campaign.slug,
      campaignRoute: route,
      currentState,
      inferredPhase: campaignLifecyclePhaseLabel({ state: currentState, action: suggestedLifecycleAction }),
      suggestedLifecycleAction,
      title,
      message,
      rationale,
      confidence: campaignLifecycleConfidenceLabel(confidenceScore),
      supportingSignals,
      suggestedRoute,
    });
  }

  const sorted = items.sort((a, b) => {
    const order: CreatorCampaignLifecycleAction[] = [
      "shift_to_membership",
      "add_phase_two_drop",
      "launch_promo_push",
      "refresh_cta",
      "archive_campaign",
      "close_with_recap",
      "clone_for_next_season",
      "convert_to_template",
      "keep_running",
    ];
    const confidenceWeight = (value: CreatorCampaignLifecycleConfidence) => value === "high" ? 3 : value === "medium" ? 2 : 1;
    return order.indexOf(a.suggestedLifecycleAction) - order.indexOf(b.suggestedLifecycleAction)
      || confidenceWeight(b.confidence) - confidenceWeight(a.confidence)
      || a.campaignName.localeCompare(b.campaignName);
  });

  return {
    summary: {
      totalCampaigns: sorted.length,
      activeCampaigns: sorted.filter((item) => item.currentState === "active").length,
      archivedCampaigns: sorted.filter((item) => item.currentState === "past").length,
      keepRunningCount: sorted.filter((item) => item.suggestedLifecycleAction === "keep_running").length,
      phaseShiftCount: sorted.filter((item) => ["add_phase_two_drop", "launch_promo_push", "refresh_cta", "close_with_recap"].includes(item.suggestedLifecycleAction)).length,
      archiveCount: sorted.filter((item) => item.suggestedLifecycleAction === "archive_campaign").length,
      cloneOrTemplateCount: sorted.filter((item) => ["clone_for_next_season", "convert_to_template"].includes(item.suggestedLifecycleAction)).length,
      membershipArcCount: sorted.filter((item) => item.suggestedLifecycleAction === "shift_to_membership").length,
    } satisfies CreatorCampaignLifecycleSummary,
    items: sorted,
    attributionNotes: [
      "Lifecycle suggestions are a phase-change layer, not a giant automation engine: they only suggest when to keep pushing, shift the arc, archive, clone, template, or wrap up.",
      "Health still answers how the campaign is doing now. Recommendations still surface general next-step ideas. Recovery plans still handle slipping campaigns. Retrospectives still summarize completed campaigns.",
      "Signals stay grounded in existing campaign state, follows, drop views / clicks / RSVPs, approximate purchases, approximate memberships, goals, milestones, and archived benchmark outcomes.",
    ],
    generatedAt: health.generatedAt,
  };
}

function campaignHealthMomentum(current: number, previous: number, strongThreshold: number) {
  if (current <= 0 && previous <= 0) return "quiet" satisfies CreatorCampaignHealthMomentum;
  if (current >= Math.max(strongThreshold, previous + Math.max(3, Math.round(previous * 0.5)))) {
    return "surging" satisfies CreatorCampaignHealthMomentum;
  }
  if (current > previous) return "up" satisfies CreatorCampaignHealthMomentum;
  if (current < previous) return "down" satisfies CreatorCampaignHealthMomentum;
  if (current > 0) return "flat" satisfies CreatorCampaignHealthMomentum;
  return "quiet" satisfies CreatorCampaignHealthMomentum;
}

function activityAgeInDays(value: Date | null, now = new Date()) {
  if (!value) return Number.POSITIVE_INFINITY;
  return Math.max(0, (now.getTime() - value.getTime()) / (24 * 60 * 60 * 1000));
}

function formatCampaignSignal(label: string, current: number, previous: number) {
  const delta = current - previous;
  if (previous <= 0) {
    return delta > 0 ? `${label} ${current} in the last 7 days.` : `${label} is quiet right now.`;
  }
  if (delta > 0) return `${label} is up (+${delta}) vs. the prior week.`;
  if (delta < 0) return `${label} is down (${delta}) vs. the prior week.`;
  return `${label} is flat week over week.`;
}

function countRowsWithinWindow<T extends { createdAt: Date }>(rows: T[], startsAt: Date, endsAt: Date) {
  return rows.filter((row) => isDateWithinRange(row.createdAt, startsAt, endsAt)).length;
}

function buildCampaignHealthGoalSummary(input: {
  campaign: CreatorCampaignRecord;
  goals: SerializedCreatorCampaignGoal[];
  now: Date;
}) {
  const state = getCreatorCampaignState(input.campaign, input.now);
  if (input.goals.length === 0) {
    return { goalsOnTrack: 0, goalsBehind: 0 };
  }

  if (state !== "active") {
    return {
      goalsOnTrack: input.goals.filter((goal) => goal.isComplete).length,
      goalsBehind: 0,
    };
  }

  const start = input.campaign.startsAt ?? input.campaign.createdAt;
  const end = input.campaign.endsAt;
  const elapsedRatio = end && end > start
    ? Math.min(1, Math.max(0, (input.now.getTime() - start.getTime()) / (end.getTime() - start.getTime())))
    : null;

  let goalsOnTrack = 0;
  let goalsBehind = 0;
  for (const goal of input.goals) {
    if (goal.isComplete) {
      goalsOnTrack += 1;
      continue;
    }
    if (elapsedRatio === null) {
      if (goal.percentComplete >= 35) goalsOnTrack += 1;
      continue;
    }

    const expectedPercent = Math.round(elapsedRatio * 100);
    if (elapsedRatio >= 0.2 && goal.percentComplete + 12 < expectedPercent) {
      goalsBehind += 1;
    } else {
      goalsOnTrack += 1;
    }
  }

  return { goalsOnTrack, goalsBehind };
}

export async function loadCreatorCampaignHealth(creatorUserId: string) {
  if (!db) throw new Error("Database unavailable");

  const now = new Date();
  const currentWindowEnd = now;
  const currentWindowStart = new Date(now.getTime() - (7 * 24 * 60 * 60 * 1000));
  const previousWindowStart = new Date(currentWindowStart.getTime() - (7 * 24 * 60 * 60 * 1000));
  const previousWindowEnd = currentWindowStart;

  const [performance, recommendations, campaigns] = await Promise.all([
    loadCreatorCampaignPerformanceSnapshots(creatorUserId),
    loadCreatorCampaignRecommendations(creatorUserId),
    db
      .select()
      .from(creatorCampaigns)
      .where(eq(creatorCampaigns.creatorUserId, creatorUserId))
      .orderBy(desc(creatorCampaigns.updatedAt))
      .limit(120),
  ]);

  if (campaigns.length === 0 || performance.items.length === 0) {
    return {
      summary: {
        totalCampaigns: 0,
        activeOrUpcomingCampaigns: 0,
        watchlistCount: 0,
        thrivingCount: 0,
        healthyCount: 0,
        watchCount: 0,
        atRiskCount: 0,
        completedCount: 0,
      } satisfies CreatorCampaignHealthSummary,
      items: [] as CreatorCampaignHealthItem[],
      watchlist: [] as CreatorCampaignHealthItem[],
      attributionNotes: [
        "Health is a lightweight current-status layer built from campaign signals the drinks platform already tracks.",
        "Recommendations stay separate: health describes current status, while recommendations suggest possible next moves.",
        "Archived and completed campaigns can still appear for context, but risk/watch scoring focuses on active and upcoming work.",
      ],
      generatedAt: now.toISOString(),
    };
  }

  const campaignIds = campaigns.map((campaign) => campaign.id);
  const performanceByCampaignId = new Map(performance.items.map((item) => [item.campaignId, item]));
  const recommendationsByCampaignId = new Map<string, CreatorCampaignRecommendation[]>();
  for (const item of recommendations.items) {
    const current = recommendationsByCampaignId.get(item.campaignId) ?? [];
    current.push(item);
    recommendationsByCampaignId.set(item.campaignId, current);
  }

  const [linkMap, goalRows, followRows, membershipRows] = await Promise.all([
    loadCreatorCampaignLinksByCampaignIds(campaignIds),
    db
      .select()
      .from(creatorCampaignGoals)
      .where(inArray(creatorCampaignGoals.campaignId, campaignIds))
      .orderBy(desc(creatorCampaignGoals.updatedAt), asc(creatorCampaignGoals.createdAt)),
    db.select({
      campaignId: creatorCampaignFollows.campaignId,
      createdAt: creatorCampaignFollows.createdAt,
    }).from(creatorCampaignFollows).where(inArray(creatorCampaignFollows.campaignId, campaignIds)).orderBy(asc(creatorCampaignFollows.createdAt)),
    db.select({
      createdAt: creatorMemberships.createdAt,
      status: creatorMemberships.status,
    }).from(creatorMemberships).where(eq(creatorMemberships.creatorUserId, creatorUserId)).orderBy(asc(creatorMemberships.createdAt)),
  ]);

  const goalsByCampaignId = new Map<string, CreatorCampaignGoalRecord[]>();
  for (const goal of goalRows) {
    const current = goalsByCampaignId.get(goal.campaignId) ?? [];
    current.push(goal);
    goalsByCampaignId.set(goal.campaignId, current);
  }

  const followRowsByCampaignId = new Map<string, Array<{ createdAt: Date }>>();
  for (const row of followRows) {
    const current = followRowsByCampaignId.get(row.campaignId) ?? [];
    current.push({ createdAt: row.createdAt });
    followRowsByCampaignId.set(row.campaignId, current);
  }

  const campaignDropIds = new Map<string, string[]>();
  const campaignCollectionIds = new Map<string, string[]>();
  const campaignPostIds = new Map<string, string[]>();
  const campaignRoadmapIds = new Map<string, string[]>();
  const campaignPromoIds = new Map<string, string[]>();
  const campaignChallengeIds = new Map<string, string[]>();
  for (const campaign of campaigns) {
    const links = linkMap.get(campaign.id) ?? [];
    campaignDropIds.set(campaign.id, links.filter((link) => link.targetType === "drop").map((link) => link.targetId));
    campaignCollectionIds.set(campaign.id, links.filter((link) => link.targetType === "collection").map((link) => link.targetId));
    campaignPostIds.set(campaign.id, links.filter((link) => link.targetType === "post").map((link) => link.targetId));
    campaignRoadmapIds.set(campaign.id, links.filter((link) => link.targetType === "roadmap").map((link) => link.targetId));
    campaignPromoIds.set(campaign.id, links.filter((link) => link.targetType === "promo").map((link) => link.targetId));
    campaignChallengeIds.set(campaign.id, links.filter((link) => link.targetType === "challenge").map((link) => link.targetId));
  }

  const dropIds = [...new Set([...campaignDropIds.values()].flat())];
  const collectionIds = [...new Set([...campaignCollectionIds.values()].flat())];
  const postIds = [...new Set([...campaignPostIds.values()].flat())];
  const roadmapIds = [...new Set([...campaignRoadmapIds.values()].flat())];
  const promoIds = [...new Set([...campaignPromoIds.values()].flat())];

  const [dropRows, postRows, roadmapRows, promoRows, dropEventRows, rsvpRows, purchaseRows] = await Promise.all([
    dropIds.length
      ? db.select({ id: creatorDrops.id, scheduledFor: creatorDrops.scheduledFor, createdAt: creatorDrops.createdAt, updatedAt: creatorDrops.updatedAt }).from(creatorDrops).where(inArray(creatorDrops.id, dropIds))
      : Promise.resolve([] as Array<{ id: string; scheduledFor: Date; createdAt: Date; updatedAt: Date }>),
    postIds.length
      ? db.select({ id: creatorPosts.id, createdAt: creatorPosts.createdAt, updatedAt: creatorPosts.updatedAt }).from(creatorPosts).where(inArray(creatorPosts.id, postIds))
      : Promise.resolve([] as Array<{ id: string; createdAt: Date; updatedAt: Date }>),
    roadmapIds.length
      ? db.select({ id: creatorRoadmapItems.id, createdAt: creatorRoadmapItems.createdAt, updatedAt: creatorRoadmapItems.updatedAt, scheduledFor: creatorRoadmapItems.scheduledFor, releasedAt: creatorRoadmapItems.releasedAt }).from(creatorRoadmapItems).where(inArray(creatorRoadmapItems.id, roadmapIds))
      : Promise.resolve([] as Array<{ id: string; createdAt: Date; updatedAt: Date; scheduledFor: Date | null; releasedAt: Date | null }>),
    promoIds.length
      ? db.select({ id: drinkCollectionPromotions.id, createdAt: drinkCollectionPromotions.createdAt, updatedAt: drinkCollectionPromotions.updatedAt, startsAt: drinkCollectionPromotions.startsAt, endsAt: drinkCollectionPromotions.endsAt }).from(drinkCollectionPromotions).where(inArray(drinkCollectionPromotions.id, promoIds))
      : Promise.resolve([] as Array<{ id: string; createdAt: Date; updatedAt: Date; startsAt: Date | null; endsAt: Date | null }>),
    dropIds.length
      ? db.select({ dropId: creatorDropEvents.dropId, eventType: creatorDropEvents.eventType, createdAt: creatorDropEvents.createdAt }).from(creatorDropEvents).where(inArray(creatorDropEvents.dropId, dropIds)).orderBy(asc(creatorDropEvents.createdAt))
      : Promise.resolve([] as Array<{ dropId: string; eventType: string; createdAt: Date }>),
    dropIds.length
      ? db.select({ dropId: creatorDropRsvps.dropId, createdAt: creatorDropRsvps.createdAt }).from(creatorDropRsvps).where(inArray(creatorDropRsvps.dropId, dropIds)).orderBy(asc(creatorDropRsvps.createdAt))
      : Promise.resolve([] as Array<{ dropId: string; createdAt: Date }>),
    collectionIds.length
      ? db.select({ collectionId: drinkCollectionPurchases.collectionId, createdAt: drinkCollectionPurchases.createdAt, status: drinkCollectionPurchases.status }).from(drinkCollectionPurchases).where(inArray(drinkCollectionPurchases.collectionId, collectionIds)).orderBy(asc(drinkCollectionPurchases.createdAt))
      : Promise.resolve([] as Array<{ collectionId: string; createdAt: Date; status: string }>),
  ]);

  const dropRowMap = new Map(dropRows.map((row) => [row.id, row]));
  const postRowMap = new Map(postRows.map((row) => [row.id, row]));
  const roadmapRowMap = new Map(roadmapRows.map((row) => [row.id, row]));
  const promoRowMap = new Map(promoRows.map((row) => [row.id, row]));

  const dropEventsByDropId = new Map<string, Array<{ eventType: string; createdAt: Date }>>();
  for (const row of dropEventRows) {
    const current = dropEventsByDropId.get(row.dropId) ?? [];
    current.push({ eventType: row.eventType, createdAt: row.createdAt });
    dropEventsByDropId.set(row.dropId, current);
  }

  const rsvpRowsByDropId = new Map<string, Array<{ createdAt: Date }>>();
  for (const row of rsvpRows) {
    const current = rsvpRowsByDropId.get(row.dropId) ?? [];
    current.push({ createdAt: row.createdAt });
    rsvpRowsByDropId.set(row.dropId, current);
  }

  const purchaseRowsByCollectionId = new Map<string, Array<{ createdAt: Date; status: string }>>();
  for (const row of purchaseRows) {
    const current = purchaseRowsByCollectionId.get(row.collectionId) ?? [];
    current.push({ createdAt: row.createdAt, status: row.status });
    purchaseRowsByCollectionId.set(row.collectionId, current);
  }

  const items: CreatorCampaignHealthItem[] = [];

  for (const campaign of campaigns) {
    const analytics = performanceByCampaignId.get(campaign.id);
    if (!analytics) continue;

    const state = getCreatorCampaignState(campaign, now);
    const route = `/drinks/campaigns/${encodeURIComponent(campaign.slug)}`;
    const dropLinkIds = campaignDropIds.get(campaign.id) ?? [];
    const collectionLinkIds = campaignCollectionIds.get(campaign.id) ?? [];
    const postLinkIds = campaignPostIds.get(campaign.id) ?? [];
    const roadmapLinkIds = campaignRoadmapIds.get(campaign.id) ?? [];
    const promoLinkIds = campaignPromoIds.get(campaign.id) ?? [];
    const challengeLinkIds = campaignChallengeIds.get(campaign.id) ?? [];

    const campaignFollowRows = (followRowsByCampaignId.get(campaign.id) ?? []).filter((row) => isDateWithinCampaignAnalyticsWindow(row.createdAt, campaign));
    const campaignRsvpRows = dropLinkIds
      .flatMap((dropId) => rsvpRowsByDropId.get(dropId) ?? [])
      .filter((row) => isDateWithinCampaignAnalyticsWindow(row.createdAt, campaign));
    const campaignClickRows = dropLinkIds
      .flatMap((dropId) => (dropEventsByDropId.get(dropId) ?? []).filter((row) => row.eventType === "click_drop_target"))
      .filter((row) => isDateWithinCampaignAnalyticsWindow(row.createdAt, campaign));
    const campaignViewRows = dropLinkIds
      .flatMap((dropId) => (dropEventsByDropId.get(dropId) ?? []).filter((row) => row.eventType === "view_drop"))
      .filter((row) => isDateWithinCampaignAnalyticsWindow(row.createdAt, campaign));
    const campaignPurchaseRows = collectionLinkIds
      .flatMap((collectionId) => purchaseRowsByCollectionId.get(collectionId) ?? [])
      .filter((row) => row.status === "completed" && isDateWithinCampaignAnalyticsWindow(row.createdAt, campaign));
    const campaignMembershipRows = analytics.membershipsFromCampaignNote
      ? membershipRows.filter((row) => row.status === "active" && isDateWithinCampaignAnalyticsWindow(row.createdAt, campaign))
      : [];

    const recentFollowers = countRowsWithinWindow(campaignFollowRows, currentWindowStart, currentWindowEnd);
    const previousFollowers = countRowsWithinWindow(campaignFollowRows, previousWindowStart, previousWindowEnd);
    const recentRsvps = countRowsWithinWindow(campaignRsvpRows, currentWindowStart, currentWindowEnd);
    const previousRsvps = countRowsWithinWindow(campaignRsvpRows, previousWindowStart, previousWindowEnd);
    const recentClicks = countRowsWithinWindow(campaignClickRows, currentWindowStart, currentWindowEnd);
    const previousClicks = countRowsWithinWindow(campaignClickRows, previousWindowStart, previousWindowEnd);
    const recentViews = countRowsWithinWindow(campaignViewRows, currentWindowStart, currentWindowEnd);
    const previousViews = countRowsWithinWindow(campaignViewRows, previousWindowStart, previousWindowEnd);
    const recentPurchases = countRowsWithinWindow(campaignPurchaseRows, currentWindowStart, currentWindowEnd);
    const previousPurchases = countRowsWithinWindow(campaignPurchaseRows, previousWindowStart, previousWindowEnd);
    const recentMemberships = countRowsWithinWindow(campaignMembershipRows, currentWindowStart, currentWindowEnd);
    const previousMemberships = countRowsWithinWindow(campaignMembershipRows, previousWindowStart, previousWindowEnd);

    const followerMomentum = campaignHealthMomentum(recentFollowers, previousFollowers, 6);
    const rsvpMomentum = campaignHealthMomentum(recentRsvps, previousRsvps, 5);
    const clickMomentum = campaignHealthMomentum(recentClicks, previousClicks, 8);
    const purchaseMomentum = campaignHealthMomentum(recentPurchases, previousPurchases, 2);
    const membershipMomentum = campaignHealthMomentum(recentMemberships, previousMemberships, 2);

    const goals = (goalsByCampaignId.get(campaign.id) ?? []).map((goal) => serializeCreatorCampaignGoal(goal, analytics));
    const completedGoalCount = goals.filter((goal) => goal.isComplete).length;
    const incompleteGoalCount = goals.length - completedGoalCount;
    const { goalsOnTrack, goalsBehind } = buildCampaignHealthGoalSummary({ campaign, goals, now });
    const milestoneCount = analytics.milestones.filter((milestone) => milestone.achieved).length;

    const recommendation = (recommendationsByCampaignId.get(campaign.id) ?? [])[0] ?? null;

    const candidateActivityDates: Array<Date | null | undefined> = [campaign.updatedAt, campaign.createdAt];
    for (const row of campaignFollowRows) candidateActivityDates.push(row.createdAt);
    for (const row of campaignRsvpRows) candidateActivityDates.push(row.createdAt);
    for (const row of campaignClickRows) candidateActivityDates.push(row.createdAt);
    for (const row of campaignViewRows) candidateActivityDates.push(row.createdAt);
    for (const row of campaignPurchaseRows) candidateActivityDates.push(row.createdAt);
    for (const row of campaignMembershipRows) candidateActivityDates.push(row.createdAt);
    for (const dropId of dropLinkIds) {
      const row = dropRowMap.get(dropId);
      candidateActivityDates.push(row?.updatedAt, row?.createdAt, row?.scheduledFor);
    }
    for (const postId of postLinkIds) {
      const row = postRowMap.get(postId);
      candidateActivityDates.push(row?.updatedAt, row?.createdAt);
    }
    for (const roadmapId of roadmapLinkIds) {
      const row = roadmapRowMap.get(roadmapId);
      candidateActivityDates.push(row?.updatedAt, row?.createdAt, row?.scheduledFor, row?.releasedAt);
    }
    for (const promoId of promoLinkIds) {
      const row = promoRowMap.get(promoId);
      candidateActivityDates.push(row?.updatedAt, row?.createdAt, row?.startsAt, row?.endsAt);
    }
    const recentActivityDate = candidateActivityDates
      .filter((value): value is Date => value instanceof Date)
      .sort((a, b) => b.getTime() - a.getTime())[0] ?? null;
    const recentActivityAt = recentActivityDate ? recentActivityDate.toISOString() : null;
    const activityAgeDays = activityAgeInDays(recentActivityDate, now);

    let score = state === "past" ? 75 : state === "active" ? 58 : 54;
    const strengthReasons: string[] = [];
    const watchReasons: string[] = [];

    if (state === "past") {
      score = 72 + Math.min(18, completedGoalCount * 4 + milestoneCount * 2 + Math.min(8, analytics.purchasesFromLinkedCollections + analytics.membershipsFromCampaign));
      if (analytics.purchasesFromLinkedCollections > 0 || analytics.membershipsFromCampaign > 0) {
        strengthReasons.push("Completed campaign generated conversion signals before wrap-up.");
      }
      if (completedGoalCount > 0) {
        strengthReasons.push(`${completedGoalCount} creator goal${completedGoalCount === 1 ? "" : "s"} completed before the campaign closed.`);
      }
    } else {
      if (followerMomentum === "surging" || followerMomentum === "up") {
        score += followerMomentum === "surging" ? 10 : 6;
        strengthReasons.push(formatCampaignSignal("Follower growth", recentFollowers, previousFollowers));
      } else if (followerMomentum === "down" && analytics.followerCount > 0) {
        score -= 8;
        watchReasons.push(formatCampaignSignal("Follower growth", recentFollowers, previousFollowers));
      }

      if (rsvpMomentum === "surging" || rsvpMomentum === "up") {
        score += rsvpMomentum === "surging" ? 10 : 6;
        strengthReasons.push(formatCampaignSignal("RSVP momentum", recentRsvps, previousRsvps));
      } else if (rsvpMomentum === "down" && analytics.totalDropRsvps > 0) {
        score -= 8;
        watchReasons.push(formatCampaignSignal("RSVP momentum", recentRsvps, previousRsvps));
      }

      if (clickMomentum === "surging" || clickMomentum === "up") {
        score += clickMomentum === "surging" ? 8 : 5;
        strengthReasons.push(formatCampaignSignal("Click momentum", recentClicks, previousClicks));
      } else if (clickMomentum === "down" && analytics.totalDropClicks > 0) {
        score -= 6;
      }

      if (recentPurchases > 0 || recentMemberships > 0) {
        score += 10;
        if (recentPurchases > 0) strengthReasons.push(`Approx. purchase activity landed ${recentPurchases} time${recentPurchases === 1 ? "" : "s"} this week.`);
        if (recentMemberships > 0) strengthReasons.push(`Approx. membership activity landed ${recentMemberships} time${recentMemberships === 1 ? "" : "s"} this week.`);
      }

      if (completedGoalCount > 0 || milestoneCount > 0) {
        score += Math.min(12, completedGoalCount * 4 + milestoneCount);
      }
      if (goalsOnTrack > 0) {
        score += Math.min(8, goalsOnTrack * 2);
        strengthReasons.push(goalsOnTrack === 1 ? "A creator goal is on track for the current campaign window." : `${goalsOnTrack} creator goals are on track for the current campaign window.`);
      }
      if (goalsBehind > 0) {
        score -= Math.min(16, goalsBehind * 6);
        watchReasons.push(goalsBehind === 1 ? "Goal progress is behind pace." : `${goalsBehind} goals are behind pace.`);
      }

      if (dropLinkIds.length + postLinkIds.length + collectionLinkIds.length >= 2) {
        score += 4;
      }
      if (dropLinkIds.length === 0 && state === "active" && analytics.followerCount >= 15) {
        score -= 8;
        watchReasons.push("Campaign interest exists, but no linked drop is giving followers a concrete launch moment yet.");
      }
      if (postLinkIds.length === 0 && roadmapLinkIds.length === 0 && promoLinkIds.length === 0 && activityAgeDays > 10) {
        score -= 10;
        watchReasons.push("No recent drops or updates are linked to this campaign.");
      }
      if (activityAgeDays > 21) {
        score -= 12;
        watchReasons.push("Campaign activity has gone quiet for more than three weeks.");
      } else if (activityAgeDays > 10) {
        score -= 6;
      }

      if (recentClicks >= 8 && recentPurchases === 0 && analytics.purchasesFromLinkedCollections === 0) {
        score -= 10;
        watchReasons.push("Strong clicks but weak conversion.");
      }
      if (analytics.totalDropViews >= 20 && analytics.totalDropClicks === 0) {
        score -= 5;
        watchReasons.push("Views are landing, but the campaign is not turning that attention into clicks yet.");
      }
      if (state === "upcoming" && (recentFollowers > 0 || recentRsvps > 0)) {
        score += 4;
        strengthReasons.push("Upcoming campaign is already collecting pre-launch interest.");
      }
    }

    score = Math.max(18, Math.min(96, Math.round(score)));

    const healthState: CreatorCampaignHealthState = state === "past"
      ? "completed"
      : score >= 78
        ? "thriving"
        : score >= 60
          ? "healthy"
          : score >= 42
            ? "watch"
            : "at_risk";

    const primaryStrength = strengthReasons[0] ?? null;
    const primaryConcern = watchReasons[0] ?? null;
    const isOnWatchlist = healthState === "watch" || healthState === "at_risk";

    items.push({
      campaignId: campaign.id,
      slug: campaign.slug,
      name: campaign.name,
      route,
      visibility: campaign.visibility as CreatorCampaignVisibility,
      status: state,
      healthState,
      healthScore: score,
      followerMomentum,
      rsvpMomentum,
      clickMomentum,
      purchaseMomentum,
      membershipMomentum,
      goalsOnTrack,
      goalsBehind,
      recentActivityAt,
      primaryConcern,
      primaryStrength,
      watchReasons: watchReasons.slice(0, 4),
      strengthReasons: strengthReasons.slice(0, 4),
      linkedDropsCount: dropLinkIds.length,
      linkedPostsCount: postLinkIds.length,
      linkedCollectionsCount: collectionLinkIds.length,
      linkedPromosCount: promoLinkIds.length,
      linkedRoadmapCount: roadmapLinkIds.length,
      linkedChallengesCount: challengeLinkIds.length,
      milestoneCount,
      completedGoalCount,
      incompleteGoalCount,
      recentFollowers,
      recentRsvps,
      recentClicks,
      recentPurchases,
      recentMemberships,
      recentViews,
      previousFollowers,
      previousRsvps,
      previousClicks,
      previousPurchases,
      previousMemberships,
      previousViews,
      recommendation: recommendation
        ? {
            recommendationType: recommendation.recommendationType,
            priority: recommendation.priority,
            title: recommendation.title,
            suggestedAction: recommendation.suggestedAction,
            suggestedRoute: recommendation.suggestedRoute,
          }
        : null,
      isOnWatchlist,
    });
  }

  const itemsSorted = [...items].sort((a, b) => {
    const watchRank = (item: CreatorCampaignHealthItem) => item.healthState === "at_risk" ? 4 : item.healthState === "watch" ? 3 : item.healthState === "thriving" ? 2 : item.healthState === "healthy" ? 1 : 0;
    const stateRank = (item: CreatorCampaignHealthItem) => item.status === "active" ? 2 : item.status === "upcoming" ? 1 : 0;
    return watchRank(b) - watchRank(a)
      || stateRank(b) - stateRank(a)
      || b.healthScore - a.healthScore
      || (b.recentActivityAt ? new Date(b.recentActivityAt).getTime() : 0) - (a.recentActivityAt ? new Date(a.recentActivityAt).getTime() : 0);
  });

  const watchlist = itemsSorted.filter((item) => item.isOnWatchlist).slice(0, 6);

  return {
    summary: {
      totalCampaigns: items.length,
      activeOrUpcomingCampaigns: items.filter((item) => item.status === "active" || item.status === "upcoming").length,
      watchlistCount: watchlist.length,
      thrivingCount: items.filter((item) => item.healthState === "thriving").length,
      healthyCount: items.filter((item) => item.healthState === "healthy").length,
      watchCount: items.filter((item) => item.healthState === "watch").length,
      atRiskCount: items.filter((item) => item.healthState === "at_risk").length,
      completedCount: items.filter((item) => item.healthState === "completed").length,
    } satisfies CreatorCampaignHealthSummary,
    items: itemsSorted,
    watchlist,
    attributionNotes: [
      "Health is rules-based and uses the campaign follows, linked drop RSVP/view/click activity, linked collection purchase proxies, membership proxies, goals, milestones, and linked surfaces already tracked in the drinks platform.",
      "Health is current status. Weekly digest is the last-7-days snapshot. Benchmarks compare campaigns against each other. Recommendations suggest next actions. Retrospectives stay end-of-campaign only.",
      "Archived/completed campaigns are marked completed so they remain visible for context without being treated as live risk items.",
      "Purchase and membership momentum stay approximate wherever the underlying analytics are approximate.",
    ],
    generatedAt: now.toISOString(),
  };
}


async function loadCreatorCampaignDetail(campaign: CreatorCampaignRecord, viewerId?: string | null) {
  if (!db) throw new Error("Database unavailable");

  const links = await db
    .select()
    .from(creatorCampaignLinks)
    .where(eq(creatorCampaignLinks.campaignId, campaign.id))
    .orderBy(asc(creatorCampaignLinks.sortOrder), asc(creatorCampaignLinks.createdAt));
  const variants = (await loadCreatorCampaignVariantsByCampaignIds([campaign.id])).get(campaign.id) ?? [];
  const variantMetrics = await loadCreatorCampaignVariantMetrics(campaign, variants);

  const collectionIds = [...new Set(links.filter((link) => link.targetType === "collection").map((link) => link.targetId))];
  const dropIds = [...new Set(links.filter((link) => link.targetType === "drop").map((link) => link.targetId))];
  const promoIds = [...new Set(links.filter((link) => link.targetType === "promo").map((link) => link.targetId))];
  const challengeIds = [...new Set(links.filter((link) => link.targetType === "challenge").map((link) => link.targetId))];
  const postIds = [...new Set(links.filter((link) => link.targetType === "post").map((link) => link.targetId))];
  const roadmapIds = [...new Set(links.filter((link) => link.targetType === "roadmap").map((link) => link.targetId))];

  const [
    creatorMap,
    followedCreatorIds,
    memberCreatorIds,
    collectionAccessMap,
    collectionRows,
    dropRows,
    promoRows,
    challengeRows,
    postRows,
    roadmapRows,
  ] = await Promise.all([
    loadCreatorProfilesMap([campaign.creatorUserId]),
    loadFollowedCreatorIdsForUser(viewerId),
    loadActiveMembershipCreatorIdsForUser(viewerId),
    loadCollectionAccessMapForUser(viewerId),
    collectionIds.length ? db.select().from(drinkCollections).where(inArray(drinkCollections.id, collectionIds)) : Promise.resolve([] as Array<typeof drinkCollections.$inferSelect>),
    dropIds.length ? db.select().from(creatorDrops).where(inArray(creatorDrops.id, dropIds)) : Promise.resolve([] as CreatorDropRecord[]),
    promoIds.length ? db.select().from(drinkCollectionPromotions).where(inArray(drinkCollectionPromotions.id, promoIds)) : Promise.resolve([] as Array<typeof drinkCollectionPromotions.$inferSelect>),
    challengeIds.length ? db.select().from(drinkChallenges).where(inArray(drinkChallenges.id, challengeIds)) : Promise.resolve([] as Array<typeof drinkChallenges.$inferSelect>),
    postIds.length ? db.select().from(creatorPosts).where(inArray(creatorPosts.id, postIds)) : Promise.resolve([] as CreatorPostRecord[]),
    roadmapIds.length ? db.select().from(creatorRoadmapItems).where(inArray(creatorRoadmapItems.id, roadmapIds)) : Promise.resolve([] as CreatorRoadmapRecord[]),
  ]);

  const collectionMap = new Map(collectionRows.map((row) => [row.id, row]));
  const dropMap = new Map(dropRows.map((row) => [row.id, row]));
  const promoMap = new Map(promoRows.map((row) => [row.id, row]));
  const challengeMap = new Map(challengeRows.map((row) => [row.id, row]));
  const postMap = new Map(postRows.map((row) => [row.id, row]));
  const roadmapMap = new Map(roadmapRows.map((row) => [row.id, row]));

  const visibleDrops = dropRows.filter((drop) => canViewerSeeCreatorDrop({
    drop,
    viewerId,
    followedCreatorIds,
    memberCreatorIds,
    includeArchived: true,
  }));
  const visiblePosts = postRows.filter((post) => canViewerSeeCreatorPost({ post, viewerId, followedCreatorIds, memberCreatorIds }));
  const visibleRoadmap = sortCreatorRoadmapItems(roadmapRows.filter((item) => canViewerSeeCreatorRoadmapItem({
    item,
    viewerId,
    followedCreatorIds,
    memberCreatorIds,
  })));

  const [dropLinkedMaps, dropRsvpMaps, postLinkedMaps, roadmapLinkedMaps] = await Promise.all([
    loadCreatorDropLinkedMaps(visibleDrops),
    loadCreatorDropRsvpMaps(visibleDrops, viewerId),
    loadCreatorPostLinkedMaps(visiblePosts),
    loadCreatorRoadmapLinkedMaps(visibleRoadmap),
  ]);

  const visibleCollections = links
    .filter((link) => link.targetType === "collection")
    .map((link) => collectionMap.get(link.targetId))
    .filter((collection): collection is typeof drinkCollections.$inferSelect => {
      if (!collection) return false;
      if (viewerId && collection.userId === viewerId) return true;
      const grants = collectionAccessMap.get(collection.id);
      if (collection.accessType === "membership_only" && !grants?.has("membership")) return false;
      if (!collection.isPublic && !grants?.size) return false;
      return true;
    });

  const visiblePromos = links
    .filter((link) => link.targetType === "promo")
    .map((link) => promoMap.get(link.targetId))
    .filter((promotion): promotion is typeof drinkCollectionPromotions.$inferSelect => {
      if (!promotion) return false;
      const linkedCollection = collectionMap.get(promotion.collectionId);
      if (!linkedCollection) return false;
      if (viewerId && linkedCollection.userId === viewerId) return true;
      const grants = collectionAccessMap.get(linkedCollection.id);
      if (linkedCollection.accessType === "membership_only" && !grants?.has("membership")) return false;
      if (!linkedCollection.isPublic && !grants?.size) return false;
      return true;
    })
    .map((promotion) => ({
      id: promotion.id,
      code: promotion.code,
      collectionId: promotion.collectionId,
      collectionName: collectionMap.get(promotion.collectionId)?.name ?? "Collection",
      createdAt: promotion.createdAt ? promotion.createdAt.toISOString() : null,
      startsAt: promotion.startsAt ? promotion.startsAt.toISOString() : null,
      endsAt: promotion.endsAt ? promotion.endsAt.toISOString() : null,
      isActive: Boolean(promotion.isActive),
      route: `/drinks/collections/${encodeURIComponent(promotion.collectionId)}`,
    }));

  const followerCountMap = await loadCampaignFollowerCountMap([campaign.id]);
  const followedCampaignIds = await loadFollowedCampaignIdsForUser(viewerId);
  const activeVariantRecord = variants.find((variant) => variant.isActive) ?? null;

  const detail = {
    campaign: serializeCreatorCampaign(campaign, {
      viewerId,
      creator: creatorMap.get(campaign.creatorUserId) ?? null,
      followerCount: followerCountMap.get(campaign.id) ?? 0,
      isFollowing: followedCampaignIds.has(campaign.id),
      counts: links.reduce((acc, link) => {
        const key = link.targetType as CreatorCampaignTargetType;
        acc[key] = Number(acc[key] ?? 0) + 1;
        return acc;
      }, {} as Partial<Record<CreatorCampaignTargetType, number>>),
    }),
    activeVariant: activeVariantRecord ? serializeCreatorCampaignVariant(activeVariantRecord, variantMetrics.get(activeVariantRecord.id)) : null,
    variants: variants.map((variant) => serializeCreatorCampaignVariant(variant, variantMetrics.get(variant.id))),
    variantAttributionNotes: [
      "Views and CTA clicks count tracked interactions with the active campaign CTA block.",
      "Follows and RSVPs only increment when the action is taken from the tracked campaign CTA flow.",
      "Purchases and memberships are approximate proxies based on a prior CTA click from the same signed-in user during the campaign window.",
    ],
    linkedContent: {
      collections: visibleCollections.map((collection) => ({
        id: collection.id,
        name: collection.name,
        description: collection.description ?? null,
        accessType: collectionAccessTypeForRow(collection),
        isPublic: Boolean(collection.isPublic),
        route: `/drinks/collections/${encodeURIComponent(collection.id)}`,
      })),
      drops: visibleDrops.map((drop) => serializeCreatorDrop(drop, {
        viewerId,
        creator: dropLinkedMaps.creatorMap.get(drop.creatorUserId) ?? null,
        linkedCollection: drop.linkedCollectionId ? dropLinkedMaps.collectionMap.get(drop.linkedCollectionId) ?? null : null,
        linkedChallenge: drop.linkedChallengeId ? dropLinkedMaps.challengeMap.get(drop.linkedChallengeId) ?? null : null,
        linkedPromotion: drop.linkedPromotionId ? dropLinkedMaps.promotionMap.get(drop.linkedPromotionId) ?? null : null,
        acceptedCollaboration: serializeAcceptedCollaboration(dropLinkedMaps.collaborationMap.get(`drop:${drop.id}`) ?? null, dropLinkedMaps.collaborationProfileMap),
        rsvpCount: dropRsvpMaps.rsvpCountMap.get(drop.id) ?? 0,
        isRsvped: dropRsvpMaps.viewerRsvpSet.has(drop.id),
      })),
      promos: visiblePromos,
      challenges: links
        .filter((link) => link.targetType === "challenge")
        .map((link) => challengeMap.get(link.targetId))
        .filter((challenge): challenge is typeof drinkChallenges.$inferSelect => Boolean(challenge))
        .map((challenge) => ({
          id: challenge.id,
          slug: challenge.slug,
          title: challenge.title,
          route: `/drinks/challenges/${encodeURIComponent(challenge.slug)}`,
        })),
      posts: visiblePosts.map((post) => serializeCreatorPost(post, {
        viewerId,
        creator: postLinkedMaps.creatorMap.get(post.creatorUserId) ?? null,
        linkedCollection: post.linkedCollectionId ? postLinkedMaps.collectionMap.get(post.linkedCollectionId) ?? null : null,
        linkedChallenge: post.linkedChallengeId ? postLinkedMaps.challengeMap.get(post.linkedChallengeId) ?? null : null,
        acceptedCollaboration: serializeAcceptedCollaboration(postLinkedMaps.collaborationMap.get(`post:${post.id}`) ?? null, postLinkedMaps.collaborationProfileMap),
      })),
      roadmap: visibleRoadmap.map((item) => serializeCreatorRoadmapItem(item, {
        viewerId,
        creator: roadmapLinkedMaps.creatorMap.get(item.creatorUserId) ?? null,
        linkedCollection: item.linkedCollectionId ? roadmapLinkedMaps.collectionMap.get(item.linkedCollectionId) ?? null : null,
        linkedChallenge: item.linkedChallengeId ? roadmapLinkedMaps.challengeMap.get(item.linkedChallengeId) ?? null : null,
        acceptedCollaboration: serializeAcceptedCollaboration(roadmapLinkedMaps.collaborationMap.get(`roadmap:${item.id}`) ?? null, roadmapLinkedMaps.collaborationProfileMap),
      })),
    },
  };

  return detail;
}

type CreatorCampaignUpdateItem = {
  id: string;
  targetType: "drop" | "post" | "roadmap" | "promo";
  label: string;
  title: string;
  description: string | null;
  timestamp: string | null;
  route: string;
};

function buildCreatorCampaignUpdateItems(detail: Awaited<ReturnType<typeof loadCreatorCampaignDetail>>) {
  const updates: CreatorCampaignUpdateItem[] = [
    ...detail.linkedContent.drops.map((drop) => ({
      id: `drop:${drop.id}`,
      targetType: "drop" as const,
      label: drop.status === "live" ? "Drop live" : drop.status === "upcoming" ? "Drop scheduled" : "Drop replay",
      title: drop.title,
      description: drop.description ?? drop.recapNotes ?? null,
      timestamp: drop.scheduledFor ?? drop.updatedAt ?? drop.createdAt,
      route: drop.detailRoute,
    })),
    ...detail.linkedContent.posts.map((post) => ({
      id: `post:${post.id}`,
      targetType: "post" as const,
      label: post.postType === "member_only" ? "Member post" : "Campaign post",
      title: post.title,
      description: post.body ?? null,
      timestamp: post.updatedAt ?? post.createdAt,
      route: post.linkedCollection?.route ?? post.linkedChallenge?.route ?? detail.campaign.route,
    })),
    ...detail.linkedContent.roadmap.map((item) => ({
      id: `roadmap:${item.id}`,
      targetType: "roadmap" as const,
      label: item.status === "upcoming" ? "Roadmap note" : item.status === "live" ? "Roadmap live" : "Roadmap archive",
      title: item.title,
      description: item.description ?? null,
      timestamp: item.releasedAt ?? item.scheduledFor ?? item.updatedAt ?? item.createdAt,
      route: item.linkedCollection?.route ?? item.linkedChallenge?.route ?? "/drinks/roadmap",
    })),
    ...detail.linkedContent.promos.map((promo) => ({
      id: `promo:${promo.id}`,
      targetType: "promo" as const,
      label: promo.isActive ? "Promo active" : "Promo linked",
      title: `Promo code ${promo.code}`,
      description: `Applies to ${promo.collectionName}.`,
      timestamp: promo.startsAt ?? promo.createdAt ?? null,
      route: promo.route,
    })),
  ];

  return updates
    .sort((a, b) => new Date(b.timestamp ?? 0).getTime() - new Date(a.timestamp ?? 0).getTime())
    .slice(0, 8);
}

function formatCampaignPreflightAudience(audience: CreatorCampaignRolloutAudience | null | undefined) {
  if (audience === "members") return "members";
  if (audience === "followers") return "followers";
  return "public";
}

function campaignReadinessWindowLabel(value: string | null, fallback: string) {
  if (!value) return fallback;
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return fallback;
  return new Intl.DateTimeFormat("en-US", { month: "short", day: "numeric", hour: "numeric", minute: "2-digit" }).format(date);
}

function buildCampaignLaunchReadinessState(checks: CreatorCampaignLaunchReadinessCheck[]): CreatorCampaignLaunchReadinessState {
  const failCount = checks.filter((check) => check.status === "fail").length;
  const warningCount = checks.filter((check) => check.status === "warning").length;
  if (failCount >= 3) return "blocked";
  if (failCount >= 1) return "missing_key_items";
  if (warningCount >= 2) return "almost_ready";
  return "ready";
}

function buildCampaignLaunchReadinessScore(checks: CreatorCampaignLaunchReadinessCheck[]) {
  if (checks.length === 0) return 100;
  const score = checks.reduce((total, check) => total + (check.status === "pass" ? 100 : check.status === "warning" ? 65 : 20), 0) / checks.length;
  return Math.max(0, Math.min(100, Math.round(score)));
}

function summarizeCampaignReadiness(items: CreatorCampaignLaunchReadinessItem[]): CreatorCampaignLaunchReadinessSummary {
  return {
    totalCampaigns: items.length,
    readyCount: items.filter((item) => item.readinessState === "ready").length,
    almostReadyCount: items.filter((item) => item.readinessState === "almost_ready").length,
    missingKeyItemsCount: items.filter((item) => item.readinessState === "missing_key_items").length,
    blockedCount: items.filter((item) => item.readinessState === "blocked").length,
    launchCount: items.filter((item) => item.preflightKind === "launch").length,
    unlockCount: items.filter((item) => item.preflightKind === "unlock").length,
    dueSoonCount: items.filter((item) => {
      if (!item.targetAt) return false;
      const targetTime = new Date(item.targetAt).getTime();
      return Number.isFinite(targetTime) && targetTime <= Date.now() + (72 * 60 * 60 * 1000);
    }).length,
  };
}

function buildCampaignReadinessCandidateSortValue(input: {
  campaign: CreatorCampaignRecord;
  rollout: ReturnType<typeof deriveCreatorCampaignRollout>;
  nextDropAt: string | null;
  now: Date;
}) {
  const state = getCreatorCampaignState(input.campaign, input.now);
  const rolloutMissingUnlock = state === "active"
    && input.rollout.rolloutMode === "staged"
    && input.rollout.isRolloutActive
    && !input.rollout.nextUnlockAt;
  if (rolloutMissingUnlock) return input.now.getTime() - 1;
  const target = state === "upcoming"
    ? input.campaign.startsAt?.getTime() ?? (input.nextDropAt ? new Date(input.nextDropAt).getTime() : Number.POSITIVE_INFINITY)
    : input.rollout.nextUnlockAt
      ? new Date(input.rollout.nextUnlockAt).getTime()
      : input.nextDropAt
        ? new Date(input.nextDropAt).getTime()
        : Number.POSITIVE_INFINITY;
  return Number.isFinite(target) ? target : Number.POSITIVE_INFINITY;
}

function buildCampaignPreflightKind(input: {
  campaign: CreatorCampaignRecord;
  rollout: ReturnType<typeof deriveCreatorCampaignRollout>;
  nextDropAt: string | null;
  now: Date;
}) {
  const state = getCreatorCampaignState(input.campaign, input.now);
  if (state === "active" && (input.rollout.nextAudience || (input.rollout.rolloutMode === "staged" && input.rollout.isRolloutActive))) {
    const audience = formatCampaignPreflightAudience(input.rollout.nextAudience);
    return {
      preflightKind: "unlock" as const,
      preflightLabel: input.rollout.nextAudience
        ? `Preflight for ${audience} unlock`
        : "Preflight for next audience unlock",
      targetAt: input.rollout.nextUnlockAt ?? input.nextDropAt ?? null,
    };
  }
  const launchTarget = input.campaign.startsAt?.toISOString?.() ?? input.nextDropAt ?? null;
  return {
    preflightKind: "launch" as const,
    preflightLabel: input.nextDropAt && state !== "past"
      ? "Preflight for next scheduled launch beat"
      : "Preflight before launch",
    targetAt: launchTarget,
  };
}

export async function loadCreatorCampaignLaunchReadiness(creatorUserId: string, campaignId?: string | null) {
  if (!db) throw new Error("Database unavailable");

  const now = new Date();
  const campaigns = await db
    .select()
    .from(creatorCampaigns)
    .where(and(
      eq(creatorCampaigns.creatorUserId, creatorUserId),
      campaignId ? eq(creatorCampaigns.id, campaignId) : sql`true`,
    ))
    .orderBy(desc(creatorCampaigns.updatedAt))
    .limit(campaignId ? 1 : 120);

  if (campaigns.length === 0) {
    return {
      summary: summarizeCampaignReadiness([]),
      items: [] as CreatorCampaignLaunchReadinessItem[],
      attributionNotes: [
        "Launch readiness stays lightweight and rules-based. It only inspects campaign, rollout, linked content, CTA, update, and recovery signals the drinks platform already stores.",
        "Timing advisor still answers when to launch. Rollout advisor still answers which sequence to use. Readiness only answers whether the current campaign is prepared enough to launch or unlock.",
      ],
      generatedAt: now.toISOString(),
    };
  }

  const linkMap = await loadCreatorCampaignLinksByCampaignIds(campaigns.map((row) => row.id));
  const allDropIds = [...new Set(campaigns.flatMap((campaign) => (linkMap.get(campaign.id) ?? [])
    .filter((link) => link.targetType === "drop")
    .map((link) => link.targetId)))];
  const dropRows = allDropIds.length
    ? await db
      .select({ id: creatorDrops.id, scheduledFor: creatorDrops.scheduledFor })
      .from(creatorDrops)
      .where(inArray(creatorDrops.id, allDropIds))
    : [];
  const dropMap = new Map(dropRows.map((row) => [row.id, row]));

  const candidateCampaigns = campaignId
    ? campaigns
    : campaigns
      .filter((campaign) => {
        const rollout = deriveCreatorCampaignRollout(campaign, now);
        const state = getCreatorCampaignState(campaign, now);
        const nextDrop = (linkMap.get(campaign.id) ?? [])
          .filter((link) => link.targetType === "drop")
          .map((link) => dropMap.get(link.targetId))
          .filter((drop): drop is { id: string; scheduledFor: Date } => Boolean(drop))
          .filter((drop) => drop.scheduledFor > now)
          .sort((a, b) => a.scheduledFor.getTime() - b.scheduledFor.getTime())[0] ?? null;
        return state === "upcoming"
          || Boolean(rollout.nextAudience)
          || (state === "active" && rollout.rolloutMode === "staged" && rollout.isRolloutActive)
          || Boolean(nextDrop);
      })
      .sort((a, b) => {
        const rolloutA = deriveCreatorCampaignRollout(a, now);
        const rolloutB = deriveCreatorCampaignRollout(b, now);
        const nextDropA = (linkMap.get(a.id) ?? [])
          .filter((link) => link.targetType === "drop")
          .map((link) => dropMap.get(link.targetId))
          .filter((drop): drop is { id: string; scheduledFor: Date } => Boolean(drop))
          .filter((drop) => drop.scheduledFor > now)
          .sort((x, y) => x.scheduledFor.getTime() - y.scheduledFor.getTime())[0];
        const nextDropB = (linkMap.get(b.id) ?? [])
          .filter((link) => link.targetType === "drop")
          .map((link) => dropMap.get(link.targetId))
          .filter((drop): drop is { id: string; scheduledFor: Date } => Boolean(drop))
          .filter((drop) => drop.scheduledFor > now)
          .sort((x, y) => x.scheduledFor.getTime() - y.scheduledFor.getTime())[0];
        return buildCampaignReadinessCandidateSortValue({
          campaign: a,
          rollout: rolloutA,
          nextDropAt: nextDropA?.scheduledFor.toISOString() ?? null,
          now,
        }) - buildCampaignReadinessCandidateSortValue({
          campaign: b,
          rollout: rolloutB,
          nextDropAt: nextDropB?.scheduledFor.toISOString() ?? null,
          now,
        });
      })
      .slice(0, 8);

  const [healthCollection, details] = await Promise.all([
    loadCreatorCampaignHealth(creatorUserId),
    Promise.all(candidateCampaigns.map((campaign) => loadCreatorCampaignDetail(campaign, creatorUserId))),
  ]);
  const healthByCampaignId = new Map(healthCollection.items.map((item) => [item.campaignId, item]));

  const items: CreatorCampaignLaunchReadinessItem[] = details.map((detail, index) => {
    const campaign = candidateCampaigns[index]!;
    const rollout = detail.campaign.rollout ?? deriveCreatorCampaignRollout(campaign, now);
    const linkedDrops = detail.linkedContent.drops;
    const linkedCollections = detail.linkedContent.collections;
    const linkedPosts = detail.linkedContent.posts;
    const linkedPromos = detail.linkedContent.promos;
    const linkedRoadmap = detail.linkedContent.roadmap;
    const updates = buildCreatorCampaignUpdateItems(detail);
    const health = healthByCampaignId.get(campaign.id) ?? null;
    const recoveryPlan = health ? buildCampaignRecoveryPlan(health) : null;
    const nextDrop = linkedDrops
      .filter((drop) => new Date(drop.scheduledFor).getTime() > now.getTime())
      .sort((a, b) => new Date(a.scheduledFor).getTime() - new Date(b.scheduledFor).getTime())[0] ?? null;
    const { preflightKind, preflightLabel, targetAt } = buildCampaignPreflightKind({
      campaign,
      rollout,
      nextDropAt: nextDrop?.scheduledFor ?? null,
      now,
    });
    const targetAudience = preflightKind === "unlock" ? (rollout.nextAudience ?? rollout.currentAudience) : rollout.currentAudience;
    const recentUpdateWindowMs = 14 * 24 * 60 * 60 * 1000;
    const hasRecentUpdate = updates.some((update) => {
      const time = update.timestamp ? new Date(update.timestamp).getTime() : Number.NaN;
      return Number.isFinite(time) && (now.getTime() - time) <= recentUpdateWindowMs;
    });
    const publicFacingUpdateCount = linkedPosts.filter((post) => post.visibility === "public").length
      + linkedRoadmap.filter((item) => item.visibility === "public").length
      + linkedDrops.filter((drop) => drop.visibility === "public").length;
    const memberOnlyCollectionCount = linkedCollections.filter((collection) => collection.accessType === "membership_only").length;
    const hasMeaningfulLinkedContent = (linkedDrops.length + linkedCollections.length + linkedPosts.length + linkedPromos.length + linkedRoadmap.length) > 0;
    const hasActionableDestination = linkedDrops.length > 0 || linkedCollections.length > 0 || linkedPromos.length > 0 || linkedPosts.length > 0 || linkedRoadmap.length > 0;
    const hasCtaVariant = Boolean(detail.activeVariant) || detail.variants.length > 0;
    const checks: CreatorCampaignLaunchReadinessCheck[] = [];
    const pushCheck = (
      key: string,
      label: string,
      status: CreatorCampaignLaunchReadinessCheckStatus,
      note: string,
      suggestedFix?: string | null,
    ) => {
      checks.push({ key, label, status, note, suggestedFix });
    };

    pushCheck(
      "linked_launch_asset",
      "Linked launch asset",
      hasMeaningfulLinkedContent ? "pass" : "fail",
      hasMeaningfulLinkedContent
        ? `${linkedDrops.length} drops, ${linkedCollections.length} collections, ${linkedPosts.length} posts, and ${linkedRoadmap.length} roadmap notes are already linked.`
        : "Add at least one linked drop, collection, post, or roadmap item so this campaign points somewhere real.",
      hasMeaningfulLinkedContent ? null : "Link a drop or another campaign asset.",
    );

    pushCheck(
      "cta_path",
      "CTA path",
      hasCtaVariant ? "pass" : hasActionableDestination ? "warning" : "fail",
      hasCtaVariant
        ? "A campaign CTA variant is already configured."
        : hasActionableDestination
          ? "No CTA variant yet, but the campaign still has a default linked destination path."
          : "There is no CTA variant and no obvious linked destination path yet.",
      hasCtaVariant || hasActionableDestination ? "Optional: add a CTA variant to sharpen the ask." : "Add a CTA variant or link a launch destination.",
    );

    const pinnedStatus: CreatorCampaignLaunchReadinessCheckStatus = detail.campaign.isPinned
      ? "pass"
      : preflightKind === "launch" && detail.campaign.visibility === "public"
        ? "warning"
        : "warning";
    pushCheck(
      "spotlight_plan",
      "Pinned / spotlight plan",
      pinnedStatus,
      detail.campaign.isPinned
        ? "This campaign is already pinned for creator-side spotlighting."
        : preflightKind === "launch"
          ? "Not pinned yet. That is okay, but a near-launch campaign is easier to find when it has a spotlight plan."
          : "No pinned spotlight is set right now.",
      detail.campaign.isPinned ? null : "Consider pinning this campaign or featuring it on the creator page.",
    );

    pushCheck(
      "recent_update",
      "Recent creator update",
      hasRecentUpdate ? "pass" : updates.length > 0 ? "warning" : "warning",
      hasRecentUpdate
        ? "The campaign has a recent post, drop, roadmap note, or promo update."
        : updates.length > 0
          ? "The campaign has linked updates, but nothing fresh in roughly the last two weeks."
          : "No linked campaign updates or posts yet.",
      hasRecentUpdate ? null : "Publish one short campaign update before launch or unlock.",
    );

    const stagedNeedsFollowerUnlock = rollout.rolloutMode === "staged"
      && rollout.isRolloutActive
      && detail.campaign.visibility !== "members"
      && rollout.startsWithAudience === "members"
      && detail.campaign.visibility !== "members";
    const stagedNeedsPublicUnlock = rollout.rolloutMode === "staged"
      && rollout.isRolloutActive
      && detail.campaign.visibility === "public";
    const hasRequiredUnlockConfig = (!stagedNeedsFollowerUnlock || Boolean(rollout.unlockFollowersAt))
      && (!stagedNeedsPublicUnlock || Boolean(rollout.unlockPublicAt));

    pushCheck(
      "rollout_timing",
      "Rollout timing config",
      rollout.rolloutMode !== "staged"
        ? "pass"
        : hasRequiredUnlockConfig && (rollout.nextAudience ? Boolean(rollout.nextUnlockAt) : true)
          ? "pass"
          : "fail",
      rollout.rolloutMode !== "staged"
        ? `This campaign uses ${rollout.rolloutMode.replaceAll("_", " ")} instead of a staged unlock.`
        : hasRequiredUnlockConfig && (rollout.nextAudience ? Boolean(rollout.nextUnlockAt) : true)
          ? "Follower/public unlock times are configured for the current staged rollout."
          : "Staged rollout is enabled, but a required follower or public unlock time is still missing.",
      rollout.rolloutMode !== "staged" ? null : "Add the missing staged unlock timing in campaign rollout settings.",
    );

    const memberFocused = detail.campaign.visibility === "members"
      || rollout.startsWithAudience === "members"
      || rollout.currentAudience === "members"
      || rollout.nextAudience === "members";
    pushCheck(
      "member_destination",
      "Member-only destination",
      memberFocused
        ? memberOnlyCollectionCount > 0 || linkedDrops.some((drop) => drop.visibility === "members")
          ? "pass"
          : "fail"
        : "pass",
      memberFocused
        ? memberOnlyCollectionCount > 0 || linkedDrops.some((drop) => drop.visibility === "members")
          ? "A member-only collection or members-only drop is linked."
          : "This campaign is member-focused, but there is no linked member-only collection or members-only drop yet."
        : "This campaign is not currently member-gated, so a member-only asset is optional.",
      memberFocused && memberOnlyCollectionCount === 0 && !linkedDrops.some((drop) => drop.visibility === "members")
        ? "Link a member-only collection or members-only drop."
        : null,
    );

    const strategyImpliesRsvp = linkedDrops.length > 0 || linkedPromos.length > 0;
    pushCheck(
      "launch_support",
      "Launch support (RSVP / promo)",
      strategyImpliesRsvp
        ? linkedDrops.length > 0 || linkedPromos.length > 0
          ? "pass"
          : "warning"
        : "warning",
      strategyImpliesRsvp
        ? linkedDrops.length > 0
          ? `${linkedDrops.length} linked drops give this campaign an RSVP / Notify Me path.`
          : `${linkedPromos.length} linked promos are present, but there is no linked drop RSVP path yet.`
        : "No drop or promo support is linked yet. That can be okay for a content-first arc, but launch campaigns usually benefit from one.",
      linkedDrops.length > 0 ? null : "Link a scheduled drop or a lightweight promo support path.",
    );

    const nextAudienceNeedsPublicSignal = preflightKind === "unlock" && targetAudience === "public";
    pushCheck(
      "audience_unlock_preflight",
      preflightKind === "unlock" ? "Next audience unlock readiness" : "Launch audience readiness",
      nextAudienceNeedsPublicSignal
        ? (hasCtaVariant || publicFacingUpdateCount > 0 ? "pass" : "fail")
        : preflightKind === "unlock" && targetAudience === "followers"
          ? rollout.nextUnlockAt ? "pass" : "fail"
          : "pass",
      nextAudienceNeedsPublicSignal
        ? hasCtaVariant || publicFacingUpdateCount > 0
          ? "Public unlock has a public-facing CTA or update path."
          : "Public unlock is next, but there is no public-facing CTA variant or public update yet."
        : preflightKind === "unlock" && targetAudience === "followers"
          ? rollout.nextUnlockAt
            ? `Follower unlock is scheduled for ${campaignReadinessWindowLabel(rollout.nextUnlockAt, "the configured follower window")}.`
            : "Follower unlock is next, but the follower timing is missing."
          : "No extra audience unlock requirement is blocking this phase.",
      nextAudienceNeedsPublicSignal && !(hasCtaVariant || publicFacingUpdateCount > 0)
        ? "Add a public-facing CTA or one public campaign update before the unlock."
        : preflightKind === "unlock" && targetAudience === "followers" && !rollout.nextUnlockAt
          ? "Set the follower unlock time."
          : null,
    );

    const highPriorityRecoveryIssue = recoveryPlan?.actionState === "action_needed"
      && (recoveryPlan.rescuePriority === "urgent" || recoveryPlan.rescuePriority === "high");
    pushCheck(
      "recovery_risk",
      "High-priority recovery risk",
      highPriorityRecoveryIssue ? "fail" : health?.healthState === "watch" ? "warning" : "pass",
      highPriorityRecoveryIssue
        ? recoveryPlan?.riskReason ?? "A high-priority recovery issue is still unresolved."
        : health?.healthState === "watch"
          ? health.primaryConcern ?? "Campaign is on watch, so double-check momentum before the next step."
          : "No high-priority recovery blocker is currently unresolved.",
      highPriorityRecoveryIssue
        ? (recoveryPlan?.suggestedActions[0]?.label ? `${recoveryPlan.suggestedActions[0].label}.` : "Resolve the top recovery issue first.")
        : null,
    );

    const readinessState = buildCampaignLaunchReadinessState(checks);
    const readinessScore = buildCampaignLaunchReadinessScore(checks);
    const blockers = checks.filter((check) => check.status === "fail").map((check) => check.note);
    const warnings = checks.filter((check) => check.status === "warning").map((check) => check.note);
    const recommendedFixes = uniqueStringList(checks
      .map((check) => check.suggestedFix?.trim())
      .filter((value): value is string => Boolean(value)), 6);
    const nextLaunchStep = recommendedFixes[0]
      ?? (readinessState === "ready"
        ? preflightKind === "unlock" && rollout.nextAudience
          ? `Ready for the ${formatCampaignPreflightAudience(rollout.nextAudience)} unlock.`
          : "Ready to launch."
        : null);

    return {
      campaignId: campaign.id,
      campaignName: campaign.name,
      campaignSlug: campaign.slug,
      campaignRoute: detail.campaign.route,
      campaignState: detail.campaign.state,
      readinessState,
      readinessScore,
      preflightKind,
      preflightLabel,
      targetAt,
      currentAudience: rollout.currentAudience ?? null,
      nextAudience: rollout.nextAudience ?? null,
      checks,
      blockers,
      warnings,
      recommendedFixes,
      nextLaunchStep,
      linkedSummary: {
        drops: linkedDrops.length,
        collections: linkedCollections.length,
        promos: linkedPromos.length,
        posts: linkedPosts.length,
        roadmap: linkedRoadmap.length,
        memberOnlyCollections: memberOnlyCollectionCount,
        publicUpdates: publicFacingUpdateCount,
        recentUpdates: updates.length,
      },
    };
  }).sort((a, b) => {
    const aBlocked = a.readinessState === "blocked" ? 0 : a.readinessState === "missing_key_items" ? 1 : a.readinessState === "almost_ready" ? 2 : 3;
    const bBlocked = b.readinessState === "blocked" ? 0 : b.readinessState === "missing_key_items" ? 1 : b.readinessState === "almost_ready" ? 2 : 3;
    const aTime = a.targetAt ? new Date(a.targetAt).getTime() : Number.POSITIVE_INFINITY;
    const bTime = b.targetAt ? new Date(b.targetAt).getTime() : Number.POSITIVE_INFINITY;
    return aTime - bTime || aBlocked - bBlocked || a.readinessScore - b.readinessScore || a.campaignName.localeCompare(b.campaignName);
  });

  return {
    summary: summarizeCampaignReadiness(items),
    items,
    attributionNotes: [
      "Launch readiness is a lightweight checklist layer built from existing campaign records, rollout config, linked content, CTA variants, recent updates, and the existing health / recovery signals.",
      "It does not create a new workflow engine. Missing items are inferred from what the campaign already links or configures today.",
      "Timing advisor still covers when to launch or unlock. Rollout advisor still covers which audience sequence to use. Action center still prioritizes next moves. Recovery still handles rescue actions.",
    ],
    generatedAt: now.toISOString(),
  };
}

function summarizeCampaignUnlockReadinessAlerts(items: CreatorCampaignUnlockReadinessAlert[]): CreatorCampaignUnlockReadinessSummary {
  return {
    totalAlerts: items.length,
    readyCount: items.filter((item) => item.alertState === "ready").length,
    warningCount: items.filter((item) => item.alertState === "warning").length,
    blockedCount: items.filter((item) => item.alertState === "blocked").length,
    overdueCount: items.filter((item) => item.timingWindow === "overdue").length,
    within24HoursCount: items.filter((item) => item.timingWindow === "within_24h").length,
    within48HoursCount: items.filter((item) => item.timingWindow === "within_48h").length,
  };
}

function creatorCampaignUnlockTimeLabel(audience: CreatorCampaignRolloutAudience, hoursUntilUnlock: number | null, timingWindow: CreatorCampaignUnlockReadinessWindow) {
  const audienceLabel = audience === "followers" ? "Follower unlock" : audience === "public" ? "Public unlock" : "Member unlock";
  if (timingWindow === "overdue") return `${audienceLabel} overdue`;
  if (hoursUntilUnlock !== null && hoursUntilUnlock <= 1) return `${audienceLabel} within 1 hour`;
  if (hoursUntilUnlock !== null && hoursUntilUnlock < 24) return `${audienceLabel} in ${hoursUntilUnlock} hour${hoursUntilUnlock === 1 ? "" : "s"}`;
  if (hoursUntilUnlock !== null && hoursUntilUnlock <= 36) return `${audienceLabel} tomorrow`;
  if (hoursUntilUnlock !== null && hoursUntilUnlock <= 48) return `${audienceLabel} within 48 hours`;
  return audienceLabel;
}

function creatorCampaignUnlockStateRank(value: CreatorCampaignUnlockReadinessAlertState) {
  if (value === "blocked") return 0;
  if (value === "warning") return 1;
  return 2;
}

export async function loadCreatorCampaignUnlockReadinessAlerts(creatorUserId: string, campaignId?: string | null) {
  const readinessCollection = await loadCreatorCampaignLaunchReadiness(creatorUserId, campaignId);
  const now = new Date();
  const fortyEightHoursMs = 48 * 60 * 60 * 1000;
  const readinessCampaignIds = [...new Set(readinessCollection.items.map((item) => item.campaignId))];
  const campaignRows = readinessCampaignIds.length
    ? await db!
      .select()
      .from(creatorCampaigns)
      .where(and(
        eq(creatorCampaigns.creatorUserId, creatorUserId),
        inArray(creatorCampaigns.id, readinessCampaignIds),
      ))
    : [];
  const rolloutByCampaignId = new Map(campaignRows.map((campaign) => [campaign.id, deriveCreatorCampaignRollout(campaign, now)]));

  const items = readinessCollection.items
    .filter((item) => item.preflightKind === "unlock" && item.nextAudience)
    .map((item) => {
      const rollout = rolloutByCampaignId.get(item.campaignId);
      const unlockAt = rollout?.nextAudience === item.nextAudience ? rollout.nextUnlockAt ?? null : null;
      const targetTime = new Date(unlockAt ?? "").getTime();
      if (!Number.isFinite(targetTime)) return null;

      const deltaMs = targetTime - now.getTime();
      if (deltaMs > fortyEightHoursMs) return null;

      const timingWindow: CreatorCampaignUnlockReadinessWindow = deltaMs <= 0
        ? "overdue"
        : deltaMs <= (24 * 60 * 60 * 1000)
          ? "within_24h"
          : "within_48h";
      const hoursUntilUnlock = deltaMs <= 0 ? 0 : Math.max(1, Math.ceil(deltaMs / (60 * 60 * 1000)));
      const checkByKey = new Map(item.checks.map((check) => [check.key, check]));
      const tailoredBlockers = [...item.blockers];
      const tailoredWarnings = [...item.warnings];
      const recommendedFixes = [...item.recommendedFixes];

      const recentUpdateCheck = checkByKey.get("recent_update");
      const ctaPathCheck = checkByKey.get("cta_path");
      const linkedAssetCheck = checkByKey.get("linked_launch_asset");
      const audienceUnlockCheck = checkByKey.get("audience_unlock_preflight");

      if (item.nextAudience === "followers" && recentUpdateCheck?.status !== "pass") {
        tailoredWarnings.unshift("Followers will unlock soon, but there is no fresh follower-facing campaign update linked yet.");
        recommendedFixes.unshift("Add one short campaign update before follower unlock.");
      }

      if (item.nextAudience === "followers" && item.currentAudience === "members" && item.linkedSummary.drops === 0) {
        tailoredWarnings.unshift("Member-first campaign is unlocking to followers soon, but no linked drop is ready yet.");
        recommendedFixes.unshift("Link a drop before the follower unlock opens.");
      }

      if (item.nextAudience === "public" && ctaPathCheck?.status !== "pass") {
        tailoredBlockers.unshift("Public unlock is approaching, but the campaign is still missing a CTA path.");
        recommendedFixes.unshift("Add a CTA variant or link a public-facing destination before public unlock.");
      }

      if (item.nextAudience === "public" && audienceUnlockCheck?.status !== "pass") {
        tailoredBlockers.unshift("Public unlock is approaching, but there is still no public-facing CTA or update for that wider audience.");
        recommendedFixes.unshift("Add one public campaign update before the public unlock.");
      }

      if (linkedAssetCheck?.status === "fail" && item.nextAudience === "followers") {
        tailoredBlockers.unshift("Follower unlock is close, but the campaign still does not point to a linked drop, collection, post, or roadmap item.");
      }

      if ((item.readinessState === "missing_key_items" || item.readinessState === "blocked") && item.nextAudience === "public") {
        tailoredBlockers.unshift("Public unlock is approaching but the campaign still has blockers in launch readiness.");
      }

      const dedupedBlockers = uniqueStringList(tailoredBlockers, 6);
      const dedupedWarnings = uniqueStringList(tailoredWarnings, 6);
      const dedupedFixes = uniqueStringList(recommendedFixes.filter(Boolean), 6);
      const alertState: CreatorCampaignUnlockReadinessAlertState = dedupedBlockers.length > 0
        ? "blocked"
        : dedupedWarnings.length > 0 || item.readinessState === "almost_ready"
          ? "warning"
          : "ready";
      const unlockTimeLabel = creatorCampaignUnlockTimeLabel(item.nextAudience, hoursUntilUnlock, timingWindow);

      let title = "Unlock is on track";
      let message = `${unlockTimeLabel} — no action needed.`;

      if (alertState === "blocked" && item.nextAudience === "public" && ctaPathCheck?.status !== "pass") {
        title = `${unlockTimeLabel} — campaign is missing a CTA`;
        message = "Wider access is almost here, but the campaign still needs a clear CTA or public destination before opening up.";
      } else if (alertState === "blocked" && item.nextAudience === "public") {
        title = "Public unlock is approaching but campaign still has blockers";
        message = "The current rollout is about to widen to public access, but launch readiness still shows unresolved blockers.";
      } else if (alertState === "warning" && item.nextAudience === "followers" && recentUpdateCheck?.status !== "pass") {
        title = `${unlockTimeLabel} — add a campaign update`;
        message = "Followers are next in the rollout, and a fresh update would make that unlock feel intentional instead of silent.";
      } else if (alertState === "warning" && item.nextAudience === "followers" && item.currentAudience === "members" && item.linkedSummary.drops === 0) {
        title = `${unlockTimeLabel} — no linked drop yet`;
        message = "This member-first campaign is widening to followers soon, but there is still no linked drop for the broader audience to land on.";
      } else if (alertState === "ready") {
        title = "Unlock is on track";
        message = `${unlockTimeLabel} — no action needed right now.`;
      } else if (alertState === "warning") {
        title = `${unlockTimeLabel} — double-check final details`;
        message = "The unlock is close and mostly healthy, but there are still lightweight warnings worth cleaning up first.";
      }

      return {
        campaignId: item.campaignId,
        campaignName: item.campaignName,
        campaignSlug: item.campaignSlug,
        campaignRoute: item.campaignRoute,
        currentAudience: item.currentAudience,
        upcomingAudience: item.nextAudience,
        unlockAt,
        alertState,
        title,
        message,
        blockers: dedupedBlockers,
        warnings: dedupedWarnings,
        recommendedFixes: dedupedFixes,
        hoursUntilUnlock,
        timingWindow,
        readinessState: item.readinessState,
      } satisfies CreatorCampaignUnlockReadinessAlert;
    })
    .filter((item): item is CreatorCampaignUnlockReadinessAlert => Boolean(item))
    .sort((a, b) => {
      const aTime = a.unlockAt ? new Date(a.unlockAt).getTime() : Number.POSITIVE_INFINITY;
      const bTime = b.unlockAt ? new Date(b.unlockAt).getTime() : Number.POSITIVE_INFINITY;
      return creatorCampaignUnlockStateRank(a.alertState) - creatorCampaignUnlockStateRank(b.alertState)
        || aTime - bTime
        || a.campaignName.localeCompare(b.campaignName);
    });

  return {
    summary: summarizeCampaignUnlockReadinessAlerts(items),
    items,
    attributionNotes: [
      "Unlock readiness alerts are a lightweight, creator-private warning layer built from existing rollout timing plus the current launch-readiness checks already available in the drinks platform.",
      "This route does not schedule jobs or automate unlocks. It only derives upcoming follower/public warnings at read time within the next 48 hours, plus practical overdue unlocks.",
      "Launch readiness, rollout advisor, and timing advisor stay separate on purpose: this layer only answers whether an imminent staged unlock looks ready enough to happen cleanly.",
    ],
    generatedAt: now.toISOString(),
  };
}

async function loadCampaignAlertRecipientIds(
  campaign: Pick<CreatorCampaignRecord, "id" | "creatorUserId" | "visibility" | "startsAt" | "endsAt" | "isActive" | "createdAt" | "rolloutMode" | "startsWithAudience" | "unlockFollowersAt" | "unlockPublicAt" | "rolloutNotes" | "isRolloutActive" | "isRolloutPaused" | "rolloutPausedAt">,
  contentVisibility: "public" | "followers" | "members",
) {
  if (!db) return [];

  const followRows = await db
    .select({ userId: creatorCampaignFollows.userId })
    .from(creatorCampaignFollows)
    .where(eq(creatorCampaignFollows.campaignId, campaign.id));

  let recipientIds = [...new Set(
    followRows
      .map((row) => row.userId)
      .filter((userId): userId is string => Boolean(userId) && userId !== campaign.creatorUserId),
  )];

  if (!recipientIds.length) return [];

  const rolloutAudience = deriveCreatorCampaignRollout(campaign).currentAudience;
  const requiredAudience = rolloutAudience === "members" || campaign.visibility === "members" || contentVisibility === "members"
    ? "members"
    : rolloutAudience === "followers" || campaign.visibility === "followers" || contentVisibility === "followers"
      ? "followers"
      : "public";

  if (requiredAudience === "followers") {
    const followerRows = await db
      .select({ userId: follows.followerId })
      .from(follows)
      .where(and(eq(follows.followingId, campaign.creatorUserId), inArray(follows.followerId, recipientIds)));
    recipientIds = followerRows.map((row) => row.userId).filter(Boolean);
  } else if (requiredAudience === "members") {
    const membershipRows = await db
      .select()
      .from(creatorMemberships)
      .where(and(eq(creatorMemberships.creatorUserId, campaign.creatorUserId), inArray(creatorMemberships.userId, recipientIds)));
    const activeMemberSet = new Set(
      membershipRows
        .filter((membership) => isCreatorMembershipActiveRecord(membership))
        .map((membership) => membership.userId)
        .filter(Boolean),
    );
    recipientIds = recipientIds.filter((userId) => activeMemberSet.has(userId));
  }

  return recipientIds;
}

async function maybeSendCampaignLinkedContentAlerts(input: {
  targetType: "drop" | "post" | "promo";
  targetId: string;
  contentVisibility: "public" | "followers" | "members";
  title: string;
  message: string;
  creatorUserId: string;
  creatorUsername?: string | null;
  creatorAvatar?: string | null;
  metadata?: Partial<Pick<
    NonNullable<typeof notifications.$inferInsert["metadata"]>,
    "event" | "dropId" | "creatorPostId" | "postType" | "promotionId" | "collectionId" | "scheduledFor"
  >>;
}) {
  if (!db) return;

  const linkRows = await db
    .select({ campaignId: creatorCampaignLinks.campaignId })
    .from(creatorCampaignLinks)
    .where(and(eq(creatorCampaignLinks.targetType, input.targetType), eq(creatorCampaignLinks.targetId, input.targetId)));

  const campaignIds = [...new Set(linkRows.map((row) => row.campaignId).filter(Boolean))];
  if (!campaignIds.length) return;

  const campaigns = await db
    .select()
    .from(creatorCampaigns)
    .where(inArray(creatorCampaigns.id, campaignIds));

  for (const campaign of campaigns) {
    let recipientIds = await loadCampaignAlertRecipientIds(campaign, input.contentVisibility);
    if (!recipientIds.length) continue;

    const eventKey = input.metadata?.event ?? null;
    if (eventKey) {
      const existingRows = await db
        .select({ userId: notifications.userId })
        .from(notifications)
        .where(and(
          eq(notifications.type, DRINK_ALERT_TYPES.followedCampaignUpdate),
          inArray(notifications.userId, recipientIds),
          sql`${notifications.metadata}->>'campaignId' = ${campaign.id}`,
          sql`${notifications.metadata}->>'targetType' = ${input.targetType}`,
          sql`${notifications.metadata}->>'targetId' = ${input.targetId}`,
          sql`${notifications.metadata}->>'event' = ${eventKey}`,
        ));

      const existingUserIds = new Set(existingRows.map((row) => row.userId).filter(Boolean));
      recipientIds = recipientIds.filter((userId) => !existingUserIds.has(userId));
      if (!recipientIds.length) continue;
    }

    await sendFollowedCampaignUpdateAlerts({
      campaignId: campaign.id,
      campaignName: campaign.name,
      creatorUserId: input.creatorUserId,
      creatorUsername: input.creatorUsername ?? null,
      creatorAvatar: input.creatorAvatar ?? null,
      title: input.title,
      message: input.message,
      linkUrl: `/drinks/campaigns/${encodeURIComponent(campaign.slug)}`,
      recipientIds,
      metadata: {
        targetType: input.targetType,
        targetId: input.targetId,
        contentVisibility: input.contentVisibility,
        ...input.metadata,
      },
    });
  }
}

