function recoveryPriorityRank(priority: CreatorCampaignRecoveryPriority) {
  switch (priority) {
    case "urgent":
      return 4;
    case "high":
      return 3;
    case "medium":
      return 2;
    case "low":
      return 1;
    case "none":
    default:
      return 0;
  }
}

function healthWatchWeight(state: CreatorCampaignHealthState) {
  switch (state) {
    case "at_risk":
      return 3;
    case "watch":
      return 2;
    case "healthy":
      return 1;
    case "thriving":
    case "completed":
    default:
      return 0;
  }
}

function buildCampaignRecoveryAction(input: {
  actionType: CreatorCampaignRecoveryActionType;
  label: string;
  description: string;
  suggestedRoute: string | null;
  supportingSignals?: string[];
}) {
  return {
    actionType: input.actionType,
    label: input.label,
    description: input.description,
    suggestedRoute: input.suggestedRoute,
    supportingSignals: (input.supportingSignals ?? []).slice(0, 3),
  } satisfies CreatorCampaignRecoveryPlanAction;
}

function buildCampaignRecoveryPlan(item: CreatorCampaignHealthItem): CreatorCampaignRecoveryPlan {
  const riskReason = item.watchReasons[0] ?? item.primaryConcern ?? null;
  const actions: CreatorCampaignRecoveryPlanAction[] = [];
  const hasAction = (actionType: CreatorCampaignRecoveryActionType) => actions.some((action) => action.actionType === actionType);
  const pushAction = (action: CreatorCampaignRecoveryPlanAction | null | undefined) => {
    if (!action || hasAction(action.actionType)) return;
    actions.push(action);
  };

  const recommendationType = item.recommendation?.recommendationType ?? null;
  const recommendationRoute = item.recommendation?.suggestedRoute ?? item.route;
  const confidenceSignals = [riskReason, ...(item.watchReasons ?? [])].filter((value): value is string => Boolean(value));

  if (recommendationType === "publish_update"
    || item.linkedPostsCount === 0
    || item.watchReasons.some((reason) => reason.includes("No recent drops or updates"))
    || item.watchReasons.some((reason) => reason.includes("gone quiet"))) {
    pushAction(buildCampaignRecoveryAction({
      actionType: "publish_update",
      label: "Publish an update",
      description: "Re-open the campaign story with a short creator update before asking for a harder conversion action.",
      suggestedRoute: recommendationType === "publish_update" ? recommendationRoute : "/drinks/creator-dashboard#posts",
      supportingSignals: [
        item.linkedPostsCount === 0 ? "No linked creator updates yet" : `${item.linkedPostsCount} linked update${item.linkedPostsCount === 1 ? "" : "s"}`,
        item.recentActivityAt ? `Last activity ${new Date(item.recentActivityAt).toLocaleDateString("en-US", { month: "short", day: "numeric" })}` : "No recent campaign activity",
      ],
    }));
  }

  if (recommendationType === "add_drop"
    || (item.linkedDropsCount === 0 && (item.status === "active" || item.status === "upcoming"))) {
    pushAction(buildCampaignRecoveryAction({
      actionType: "add_drop",
      label: "Add a drop",
      description: "Give followers a concrete launch moment before pushing harder promotional asks.",
      suggestedRoute: recommendationType === "add_drop" ? recommendationRoute : "/drinks/creator-dashboard#campaigns",
      supportingSignals: [
        `${item.linkedDropsCount} linked drops`,
        `${item.recentFollowers} recent followers`,
      ],
    }));
  }

  if (recommendationType === "improve_cta"
    || item.watchReasons.some((reason) => reason.includes("weak conversion"))
    || item.watchReasons.some((reason) => reason.includes("into clicks"))) {
    pushAction(buildCampaignRecoveryAction({
      actionType: "strengthen_cta",
      label: "Strengthen CTA",
      description: "Tighten the campaign framing or CTA variant before layering in discount or promo pressure.",
      suggestedRoute: recommendationRoute,
      supportingSignals: [
        `${item.recentClicks} recent clicks`,
        `${item.recentPurchases} recent purchases`,
      ],
    }));
  }

  if (recommendationType === "push_rsvp"
    || (item.linkedDropsCount > 0 && item.recentRsvps <= Math.max(1, Math.floor(item.recentFollowers / 3)) && item.healthState !== "completed")) {
    pushAction(buildCampaignRecoveryAction({
      actionType: "push_rsvp",
      label: "Push RSVP / Notify Me",
      description: "After the campaign has a live drop or fresh update, make the RSVP path more explicit.",
      suggestedRoute: recommendationType === "push_rsvp" ? recommendationRoute : item.route,
      supportingSignals: [
        `${item.linkedDropsCount} linked drops`,
        `${item.recentRsvps} recent RSVPs`,
      ],
    }));
  }

  if (recommendationType === "launch_promo"
    || (item.recentClicks >= 8 && item.recentPurchases === 0 && item.linkedPromosCount === 0)) {
    pushAction(buildCampaignRecoveryAction({
      actionType: "launch_promo",
      label: item.linkedPromosCount > 0 ? "Refresh promo angle" : "Launch a promo",
      description: "Use a lightweight offer only after the CTA and destination are clear enough to convert attention.",
      suggestedRoute: recommendationType === "launch_promo" ? recommendationRoute : "/drinks/creator-dashboard#promotions",
      supportingSignals: [
        `${item.recentClicks} recent clicks`,
        `${item.linkedPromosCount} linked promos`,
      ],
    }));
  }

  if (recommendationType === "add_member_only_collection"
    || (item.visibility === "members" && item.linkedCollectionsCount === 0)) {
    pushAction(buildCampaignRecoveryAction({
      actionType: "add_member_only_collection",
      label: "Add a member-only collection",
      description: "Member-focused campaigns need a clear members-only destination, not just a private label.",
      suggestedRoute: recommendationType === "add_member_only_collection" ? recommendationRoute : "/drinks/collections",
      supportingSignals: [
        `Visibility: ${item.visibility}`,
        `${item.linkedCollectionsCount} linked collections`,
      ],
    }));
  }

  if (recommendationType === "promote_membership"
    || (item.visibility === "members" && item.recentMemberships === 0 && item.recentFollowers > 0)) {
    pushAction(buildCampaignRecoveryAction({
      actionType: "promote_membership",
      label: "Promote membership",
      description: "Spell out the member value inside the campaign once the member destination is in place.",
      suggestedRoute: recommendationType === "promote_membership" ? recommendationRoute : "/drinks/creator-dashboard#membership",
      supportingSignals: [
        `${item.recentFollowers} recent followers`,
        `${item.recentMemberships} recent memberships`,
      ],
    }));
  }

  if (recommendationType === "celebrate_milestone" || (item.milestoneCount > 0 && item.healthState === "watch" && item.linkedPostsCount === 0)) {
    pushAction(buildCampaignRecoveryAction({
      actionType: "celebrate_milestone",
      label: "Celebrate a milestone",
      description: "If the campaign has a real proof point already, use it to rebuild momentum with a quick highlight post.",
      suggestedRoute: recommendationType === "celebrate_milestone" ? recommendationRoute : "/drinks/creator-dashboard#posts",
      supportingSignals: [
        `${item.milestoneCount} achieved milestone${item.milestoneCount === 1 ? "" : "s"}`,
        `${item.completedGoalCount} completed goals`,
      ],
    }));
  }

  if (item.status === "past") {
    if (item.healthScore <= 55 || item.healthState === "at_risk" || item.watchReasons.length > 0) {
      pushAction(buildCampaignRecoveryAction({
        actionType: "close_out_campaign",
        label: "Close out the campaign",
        description: "Underperforming archived campaigns should end cleanly so the creator can move attention elsewhere.",
        suggestedRoute: item.route,
        supportingSignals: [
          item.primaryConcern ?? "Archived campaign still reads as unresolved",
        ],
      }));
    }
    if (recommendationType === "clone_successful_campaign" || recommendationType === "refresh_archived_campaign" || item.completedGoalCount > 0 || item.milestoneCount > 0) {
      pushAction(buildCampaignRecoveryAction({
        actionType: "clone_and_refresh",
        label: "Clone and refresh",
        description: "Keep what worked, reset the dates, and relaunch as a lighter follow-up season instead of rebuilding from scratch.",
        suggestedRoute: "/drinks/creator-dashboard#campaigns",
        supportingSignals: [
          `${item.completedGoalCount} completed goals`,
          `${item.milestoneCount} achieved milestones`,
        ],
      }));
    }
  }

  actions.sort((a, b) => {
    const order: CreatorCampaignRecoveryActionType[] = [
      "publish_update",
      "add_drop",
      "strengthen_cta",
      "push_rsvp",
      "launch_promo",
      "add_member_only_collection",
      "promote_membership",
      "celebrate_milestone",
      "clone_and_refresh",
      "close_out_campaign",
    ];
    return order.indexOf(a.actionType) - order.indexOf(b.actionType);
  });

  const actionState: CreatorCampaignRecoveryPlanState = item.healthState === "watch" || item.healthState === "at_risk"
    ? (actions.length > 0 ? "action_needed" : "monitor")
    : "no_action_needed";
  const rescuePriority: CreatorCampaignRecoveryPriority = item.healthState === "at_risk"
    ? (actions.length >= 2 ? "urgent" : "high")
    : item.healthState === "watch"
      ? (actions.length >= 2 ? "high" : actions.length === 1 ? "medium" : "low")
      : "none";

  const confidenceNote = actionState === "no_action_needed"
    ? "No recovery plan needed right now — this campaign reads healthy enough in the existing health layer."
    : confidenceSignals.length
      ? `Built from existing health signals: ${confidenceSignals.slice(0, 2).join(" • ")}.`
      : item.recommendation?.title
        ? `Built from the linked recommendation signal: ${item.recommendation.title}.`
        : "Built from existing health/watch signals already tracked for this campaign.";

  return {
    campaignId: item.campaignId,
    campaignName: item.name,
    campaignSlug: item.slug,
    campaignRoute: item.route,
    status: item.status,
    healthState: item.healthState,
    healthScore: item.healthScore,
    actionState,
    riskReason,
    rescuePriority,
    suggestedActions: item.healthState === "watch" || item.healthState === "at_risk" ? actions.slice(0, 4) : [],
    confidenceNote,
    recommendationTitle: item.recommendation?.title ?? null,
    generatedFrom: ["campaign_health", ...(item.recommendation ? ["campaign_recommendations"] : [])],
  };
}

export async function loadCreatorCampaignRecoveryPlans(creatorUserId: string) {
  const health = await loadCreatorCampaignHealth(creatorUserId);
  const plans = health.items.map(buildCampaignRecoveryPlan).sort((a, b) => {
    return healthWatchWeight(b.healthState) - healthWatchWeight(a.healthState)
      || recoveryPriorityRank(b.rescuePriority) - recoveryPriorityRank(a.rescuePriority)
      || b.suggestedActions.length - a.suggestedActions.length
      || a.healthScore - b.healthScore;
  });

  return {
    summary: {
      totalCampaigns: plans.length,
      actionNeededCount: plans.filter((plan) => plan.actionState === "action_needed").length,
      monitorCount: plans.filter((plan) => plan.actionState === "monitor").length,
      noActionNeededCount: plans.filter((plan) => plan.actionState === "no_action_needed").length,
      atRiskCount: plans.filter((plan) => plan.healthState === "at_risk").length,
      watchCount: plans.filter((plan) => plan.healthState === "watch").length,
    },
    items: plans,
    attributionNotes: [
      "Recovery plans are a focused rescue layer for watch / at-risk campaigns only, built from the existing health and recommendation signals already tracked in the drinks platform.",
      "Health describes current status. Recommendations remain general next-step ideas. Recovery plans turn slipping-state signals into a short ordered rescue path.",
      "Sequencing stays rules-based and lightweight: refresh the story or destination first, then push RSVP / promo / conversion asks.",
    ],
    generatedAt: health.generatedAt,
  };
}

function campaignActionPriorityRank(priority: CreatorCampaignActionCenterPriority) {
  switch (priority) {
    case "urgent":
      return 4;
    case "high":
      return 3;
    case "medium":
      return 2;
    case "low":
    default:
      return 1;
  }
}

function actionCenterPriorityFromRecommendation(
  priority: CreatorCampaignRecommendationPriority,
  healthState?: CreatorCampaignHealthState | null,
): CreatorCampaignActionCenterPriority {
  if (healthState === "at_risk" && priority === "high") return "urgent";
  if (healthState === "watch" && priority === "high") return "high";
  return priority;
}

function actionCenterPriorityFromLifecycle(
  confidence: CreatorCampaignLifecycleConfidence,
  healthState?: CreatorCampaignHealthState | null,
): CreatorCampaignActionCenterPriority {
  if (healthState === "at_risk" && confidence === "high") return "high";
  if (confidence === "high") return "high";
  if (confidence === "medium") return "medium";
  return "low";
}

function sourceTypeWeight(sourceType: CreatorCampaignActionCenterSourceType) {
  switch (sourceType) {
    case "recovery":
      return 6;
    case "goal":
      return 5;
    case "lifecycle":
      return 4;
    case "recommendation":
      return 3;
    case "health":
      return 2;
    case "milestone":
    default:
      return 1;
  }
}

function normalizeActionCenterRoute(route: string | null | undefined, fallbackRoute: string) {
  return route ?? fallbackRoute;
}

function uniqueStringList(values: Array<string | null | undefined>, limit = 5) {
  return [...new Set(values.filter((value): value is string => Boolean(value?.trim())).map((value) => value.trim()))].slice(0, limit);
}

function buildCampaignActionKey(campaignId: string, actionType: CreatorCampaignActionCenterActionType) {
  return `${campaignId}:${actionType}`;
}

function buildCampaignActionSignature(input: {
  campaignId: string;
  actionType: CreatorCampaignActionCenterActionType;
  sourceKey: string;
  priority: CreatorCampaignActionCenterPriority;
  title: string;
  message: string;
  targetRoute: string | null;
  supportingSignals: string[];
}) {
  return crypto.createHash("sha256").update(JSON.stringify(input), "utf8").digest("hex");
}

type ActionCenterDraft = Omit<CreatorCampaignActionCenterItem, "actionKey" | "sourceKey" | "sourceSignature" | "state" | "snoozedUntil"> & {
  sourceKeys: string[];
};

function mergeCampaignActionCenterItem(
  items: Map<string, CreatorCampaignActionCenterItem>,
  candidate: ActionCenterDraft,
) {
  const key = buildCampaignActionKey(candidate.campaignId, candidate.actionType);
  const existing = items.get(key);
  if (!existing) {
    const sourceKey = uniqueStringList(candidate.sourceKeys, 8).sort().join("||");
    items.set(key, {
      ...candidate,
      actionKey: key,
      sourceKey,
      sourceSignature: buildCampaignActionSignature({
        campaignId: candidate.campaignId,
        actionType: candidate.actionType,
        sourceKey,
        priority: candidate.priority,
        title: candidate.title,
        message: candidate.message,
        targetRoute: candidate.targetRoute,
        supportingSignals: uniqueStringList(candidate.supportingSignals, 8),
      }),
      sourceTypes: [...candidate.sourceTypes],
      supportingSignals: [...candidate.supportingSignals],
      sourceContexts: [...candidate.sourceContexts],
      state: "open",
      snoozedUntil: null,
    });
    return;
  }

  const existingPriority = campaignActionPriorityRank(existing.priority);
  const candidatePriority = campaignActionPriorityRank(candidate.priority);
  const candidateWins = candidatePriority > existingPriority
    || (candidatePriority === existingPriority && sourceTypeWeight(candidate.sourceType) > sourceTypeWeight(existing.sourceType));

  const sourceKey = uniqueStringList([...existing.sourceKey.split("||"), ...candidate.sourceKeys], 8).sort().join("||");
  const mergedSignals = uniqueStringList([...existing.supportingSignals, ...candidate.supportingSignals]);
  items.set(key, {
    ...existing,
    title: candidateWins ? candidate.title : existing.title,
    message: candidateWins ? candidate.message : existing.message,
    priority: candidateWins ? candidate.priority : existing.priority,
    sourceType: candidateWins ? candidate.sourceType : existing.sourceType,
    targetRoute: candidateWins ? candidate.targetRoute : existing.targetRoute ?? candidate.targetRoute,
    targetLabel: candidateWins ? candidate.targetLabel : existing.targetLabel ?? candidate.targetLabel,
    sourceKey,
    sourceTypes: uniqueStringList([...existing.sourceTypes, ...candidate.sourceTypes]) as CreatorCampaignActionCenterSourceType[],
    supportingSignals: mergedSignals,
    sourceContexts: uniqueStringList([...existing.sourceContexts, ...candidate.sourceContexts]),
    sourceSignature: buildCampaignActionSignature({
      campaignId: candidate.campaignId,
      actionType: candidate.actionType,
      sourceKey,
      priority: candidateWins ? candidate.priority : existing.priority,
      title: candidateWins ? candidate.title : existing.title,
      message: candidateWins ? candidate.message : existing.message,
      targetRoute: candidateWins ? candidate.targetRoute : existing.targetRoute ?? candidate.targetRoute,
      supportingSignals: mergedSignals,
    }),
    state: "open",
    snoozedUntil: null,
  });
}

function recommendationToActionType(recommendationType: CreatorCampaignRecommendationType): CreatorCampaignActionCenterActionType {
  switch (recommendationType) {
    case "add_drop":
      return "add_drop";
    case "publish_update":
      return "publish_update";
    case "improve_cta":
      return "strengthen_cta";
    case "promote_membership":
      return "promote_membership";
    case "add_member_only_collection":
      return "add_member_only_collection";
    case "launch_promo":
      return "launch_promo";
    case "push_rsvp":
      return "push_rsvp";
    case "clone_successful_campaign":
      return "clone_campaign";
    case "refresh_archived_campaign":
      return "refresh_campaign_copy";
    case "celebrate_milestone":
    default:
      return "celebrate_milestone";
  }
}

function recoveryToActionType(actionType: CreatorCampaignRecoveryActionType): CreatorCampaignActionCenterActionType {
  switch (actionType) {
    case "publish_update":
      return "publish_update";
    case "add_drop":
      return "add_drop";
    case "strengthen_cta":
      return "strengthen_cta";
    case "launch_promo":
      return "launch_promo";
    case "push_rsvp":
      return "push_rsvp";
    case "add_member_only_collection":
      return "add_member_only_collection";
    case "promote_membership":
      return "promote_membership";
    case "clone_and_refresh":
      return "clone_campaign";
    case "close_out_campaign":
      return "close_with_recap";
    case "celebrate_milestone":
    default:
      return "celebrate_milestone";
  }
}

function lifecycleToActionType(actionType: CreatorCampaignLifecycleAction): CreatorCampaignActionCenterActionType | null {
  switch (actionType) {
    case "add_phase_two_drop":
      return "add_drop";
    case "shift_to_membership":
      return "promote_membership";
    case "launch_promo_push":
      return "launch_promo";
    case "archive_campaign":
      return "archive_campaign";
    case "clone_for_next_season":
    case "convert_to_template":
      return "clone_campaign";
    case "refresh_cta":
      return "strengthen_cta";
    case "close_with_recap":
      return "close_with_recap";
    case "keep_running":
    default:
      return null;
  }
}

async function loadCreatorCampaignActionCenterRaw(creatorUserId: string, campaignId?: string | null) {
  if (!db) throw new Error("Database unavailable");

  const [
    campaigns,
    recommendations,
    recoveryPlans,
    lifecycle,
    health,
    performance,
  ] = await Promise.all([
    db
      .select()
      .from(creatorCampaigns)
      .where(eq(creatorCampaigns.creatorUserId, creatorUserId))
      .orderBy(desc(creatorCampaigns.updatedAt))
      .limit(120),
    loadCreatorCampaignRecommendations(creatorUserId),
    loadCreatorCampaignRecoveryPlans(creatorUserId),
    loadCreatorCampaignLifecycleSuggestions(creatorUserId),
    loadCreatorCampaignHealth(creatorUserId),
    loadCreatorCampaignPerformanceSnapshots(creatorUserId),
  ]);

  const filteredCampaigns = campaignId
    ? campaigns.filter((campaign) => campaign.id === campaignId)
    : campaigns;
  const allowedCampaignIds = new Set(filteredCampaigns.map((campaign) => campaign.id));
  const performanceByCampaignId = new Map(performance.items.map((item) => [item.campaignId, item]));
  const healthByCampaignId = new Map(health.items.map((item) => [item.campaignId, item]));
  const now = new Date();

  const goalRows = allowedCampaignIds.size
    ? await db
      .select()
      .from(creatorCampaignGoals)
      .where(inArray(creatorCampaignGoals.campaignId, [...allowedCampaignIds]))
      .orderBy(desc(creatorCampaignGoals.updatedAt), asc(creatorCampaignGoals.createdAt))
    : [];

  const goalsByCampaignId = new Map<string, CreatorCampaignGoalRecord[]>();
  for (const goal of goalRows) {
    const current = goalsByCampaignId.get(goal.campaignId) ?? [];
    current.push(goal);
    goalsByCampaignId.set(goal.campaignId, current);
  }

  const actionMap = new Map<string, CreatorCampaignActionCenterItem>();

  for (const item of recommendations.items) {
    if (!allowedCampaignIds.has(item.campaignId)) continue;
    const healthItem = healthByCampaignId.get(item.campaignId) ?? null;
    const actionType = recommendationToActionType(item.recommendationType);
    mergeCampaignActionCenterItem(actionMap, {
      campaignId: item.campaignId,
      campaignName: item.campaignName,
      campaignSlug: item.campaignSlug,
      campaignRoute: item.campaignRoute,
      actionType,
      title: item.title,
      message: item.message,
      priority: actionCenterPriorityFromRecommendation(item.priority, healthItem?.healthState),
      sourceType: "recommendation",
      sourceTypes: ["recommendation"],
      targetRoute: normalizeActionCenterRoute(item.suggestedRoute, item.campaignRoute),
      targetLabel: item.suggestedAction ?? "Open recommendation",
      supportingSignals: item.supportingSignals,
      sourceKeys: [`recommendation:${item.recommendationType}`],
      sourceContexts: [`Recommendation: ${item.title}`],
    });
  }

  for (const plan of recoveryPlans.items) {
    if (!allowedCampaignIds.has(plan.campaignId) || plan.actionState === "no_action_needed") continue;
    for (const action of plan.suggestedActions) {
      mergeCampaignActionCenterItem(actionMap, {
        campaignId: plan.campaignId,
        campaignName: plan.campaignName,
        campaignSlug: plan.campaignSlug,
        campaignRoute: plan.campaignRoute,
        actionType: recoveryToActionType(action.actionType),
        title: `${action.label} for ${plan.campaignName}`,
        message: `${action.description}${plan.riskReason ? ` ${plan.riskReason}` : ""}`,
        priority: plan.rescuePriority === "none" ? "low" : plan.rescuePriority,
        sourceType: "recovery",
        sourceTypes: ["recovery"],
        targetRoute: normalizeActionCenterRoute(action.suggestedRoute, plan.campaignRoute),
        targetLabel: action.label,
        supportingSignals: action.supportingSignals,
        sourceKeys: [
          `recovery:${action.actionType}`,
          `recovery-priority:${plan.rescuePriority}`,
        ],
        sourceContexts: [
          `Recovery: ${plan.rescuePriority.replaceAll("_", " ")} priority`,
          ...(plan.riskReason ? [plan.riskReason] : []),
        ],
      });
    }
  }

  for (const item of lifecycle.items) {
    if (!allowedCampaignIds.has(item.campaignId)) continue;
    const actionType = lifecycleToActionType(item.suggestedLifecycleAction);
    if (!actionType) continue;
    const healthItem = healthByCampaignId.get(item.campaignId) ?? null;
    mergeCampaignActionCenterItem(actionMap, {
      campaignId: item.campaignId,
      campaignName: item.campaignName,
      campaignSlug: item.campaignSlug,
      campaignRoute: item.campaignRoute,
      actionType,
      title: item.title,
      message: item.message,
      priority: actionCenterPriorityFromLifecycle(item.confidence, healthItem?.healthState),
      sourceType: "lifecycle",
      sourceTypes: ["lifecycle"],
      targetRoute: normalizeActionCenterRoute(item.suggestedRoute, item.campaignRoute),
      targetLabel: item.suggestedLifecycleAction === "convert_to_template" ? "Reuse this campaign" : "Open lifecycle move",
      supportingSignals: item.supportingSignals,
      sourceKeys: [
        `lifecycle:${item.suggestedLifecycleAction}`,
        `phase:${item.inferredPhase}`,
      ],
      sourceContexts: [`Lifecycle: ${item.inferredPhase.replaceAll("_", " ")}`],
    });
  }

  for (const campaign of filteredCampaigns) {
    const analytics = performanceByCampaignId.get(campaign.id);
    const healthItem = healthByCampaignId.get(campaign.id);
    const route = `/drinks/campaigns/${encodeURIComponent(campaign.slug)}`;
    const goals = analytics
      ? (goalsByCampaignId.get(campaign.id) ?? []).map((goal) => serializeCreatorCampaignGoal(goal, analytics))
      : [];
    const behindGoals = goals.filter((goal) => !goal.isComplete && goal.percentComplete < 100);
    const topBehindGoal = [...behindGoals].sort((a, b) => a.percentComplete - b.percentComplete)[0] ?? null;

    if (topBehindGoal) {
      mergeCampaignActionCenterItem(actionMap, {
        campaignId: campaign.id,
        campaignName: campaign.name,
        campaignSlug: campaign.slug,
        campaignRoute: route,
        actionType: "review_goal_progress",
        title: `Review goal pace for ${campaign.name}`,
        message: `${topBehindGoal.label?.trim() || topBehindGoal.metricLabel} is at ${topBehindGoal.percentComplete}% of target, so this campaign likely needs a practical next move chosen by the creator.`,
        priority: topBehindGoal.percentComplete < 35 || healthItem?.healthState === "at_risk"
          ? "high"
          : topBehindGoal.percentComplete < 60 || healthItem?.healthState === "watch"
            ? "medium"
            : "low",
        sourceType: "goal",
        sourceTypes: ["goal"],
        targetRoute: route,
        targetLabel: "Review goals",
        supportingSignals: [
          `${topBehindGoal.currentValue} / ${topBehindGoal.targetValue} ${topBehindGoal.metricLabel.toLowerCase()}`,
          `${behindGoals.length} goal${behindGoals.length === 1 ? "" : "s"} behind pace`,
        ],
        sourceKeys: [
          `goal:${topBehindGoal.goalType}`,
          `goal-count:${behindGoals.length}`,
        ],
        sourceContexts: [`Goal: ${topBehindGoal.label?.trim() || topBehindGoal.metricLabel}`],
      });
    } else if (healthItem && (healthItem.healthState === "watch" || healthItem.healthState === "at_risk")) {
      mergeCampaignActionCenterItem(actionMap, {
        campaignId: campaign.id,
        campaignName: campaign.name,
        campaignSlug: campaign.slug,
        campaignRoute: route,
        actionType: "review_goal_progress",
        title: `Review watchlist context for ${campaign.name}`,
        message: `This campaign is currently ${healthItem.healthState.replaceAll("_", " ")}. The action center keeps that status distinct from recommendations and recovery by pointing you back to the campaign's concrete goals and state.`,
        priority: healthItem.healthState === "at_risk" ? "high" : "medium",
        sourceType: "health",
        sourceTypes: ["health"],
        targetRoute: route,
        targetLabel: "Open campaign status",
        supportingSignals: uniqueStringList([
          healthItem.primaryConcern,
          healthItem.watchReasons[0],
          `${healthItem.goalsBehind} goals behind`,
        ]),
        sourceKeys: [
          `health:${healthItem.healthState}`,
          `goals-behind:${healthItem.goalsBehind}`,
        ],
        sourceContexts: [`Health: ${healthItem.healthState.replaceAll("_", " ")}`],
      });
    }

    const recentMilestone = analytics?.milestones
      .filter((milestone) => milestone.achieved)
      .sort((a, b) => {
        const aTime = a.achievedAt ? new Date(a.achievedAt).getTime() : 0;
        const bTime = b.achievedAt ? new Date(b.achievedAt).getTime() : 0;
        return bTime - aTime;
      })[0] ?? null;
    const recentMilestoneDays = recentMilestone?.achievedAt
      ? activityAgeInDays(new Date(recentMilestone.achievedAt), now)
      : Number.POSITIVE_INFINITY;

    if (recentMilestone && recentMilestoneDays <= 14) {
      mergeCampaignActionCenterItem(actionMap, {
        campaignId: campaign.id,
        campaignName: campaign.name,
        campaignSlug: campaign.slug,
        campaignRoute: route,
        actionType: "celebrate_milestone",
        title: `Celebrate ${recentMilestone.shortLabel}`,
        message: `This campaign recently reached "${recentMilestone.shortLabel}". A lightweight creator update can turn that milestone into another practical touchpoint without adding new workflow overhead.`,
        priority: recentMilestoneDays <= 5 ? "high" : "medium",
        sourceType: "milestone",
        sourceTypes: ["milestone"],
        targetRoute: "/drinks/creator-dashboard#posts",
        targetLabel: "Post an update",
        supportingSignals: [
          `Milestone: ${recentMilestone.shortLabel}`,
          recentMilestone.achievedAt ? `Hit ${new Date(recentMilestone.achievedAt).toLocaleDateString("en-US", { month: "short", day: "numeric" })}` : "Recently achieved",
        ],
        sourceKeys: [`milestone:${recentMilestone.type}`],
        sourceContexts: [`Milestone: ${recentMilestone.label}`],
      });
    }
  }

  const items = [...actionMap.values()].sort((a, b) => {
    const priorityDiff = campaignActionPriorityRank(b.priority) - campaignActionPriorityRank(a.priority);
    if (priorityDiff !== 0) return priorityDiff;
    const aHealth = healthByCampaignId.get(a.campaignId);
    const bHealth = healthByCampaignId.get(b.campaignId);
    return healthWatchWeight(bHealth?.healthState ?? "completed") - healthWatchWeight(aHealth?.healthState ?? "completed")
      || sourceTypeWeight(b.sourceType) - sourceTypeWeight(a.sourceType)
      || a.campaignName.localeCompare(b.campaignName);
  });

  return {
    items,
    attributionNotes: [
      "Action center is a practical next-move layer built by consolidating signals from recommendations, recovery plans, lifecycle suggestions, goals, milestones, and watchlist status.",
      "Health still describes current status. Recommendations still provide guidance. Recovery plans still handle rescue steps. Lifecycle suggestions still describe phase-change guidance. The action center only prioritizes the next concrete move.",
      "Actions are deduped by campaign plus action type so overlapping CTA, promo, membership, or wrap-up prompts collapse into one card instead of spamming multiple dashboard sections.",
    ],
    generatedAt: new Date().toISOString(),
  };
}

function summarizeCreatorCampaignActionCenter(
  items: CreatorCampaignActionCenterItem[],
  hiddenSummary?: Partial<Pick<CreatorCampaignActionCenterSummary, "hiddenCount" | "snoozedCount" | "dismissedCount" | "completedCount">>,
) {
  return {
    totalActions: items.length,
    campaignsWithActions: new Set(items.map((item) => item.campaignId)).size,
    urgentCount: items.filter((item) => item.priority === "urgent").length,
    highCount: items.filter((item) => item.priority === "high").length,
    mediumCount: items.filter((item) => item.priority === "medium").length,
    lowCount: items.filter((item) => item.priority === "low").length,
    hiddenCount: hiddenSummary?.hiddenCount ?? 0,
    snoozedCount: hiddenSummary?.snoozedCount ?? 0,
    dismissedCount: hiddenSummary?.dismissedCount ?? 0,
    completedCount: hiddenSummary?.completedCount ?? 0,
  } satisfies CreatorCampaignActionCenterSummary;
}

function resolveCreatorCampaignActionState(
  item: CreatorCampaignActionCenterItem,
  stateRecord: typeof creatorCampaignActionStates.$inferSelect | undefined,
  now: Date,
) {
  if (!stateRecord) {
    return { visible: true, item };
  }

  if (stateRecord.state === "snoozed" && stateRecord.snoozedUntil && stateRecord.snoozedUntil > now) {
    return {
      visible: false,
      bucket: "snoozed" as const,
      item: {
        ...item,
        state: "snoozed" as const,
        snoozedUntil: stateRecord.snoozedUntil.toISOString(),
      },
    };
  }

  const signatureMatches = stateRecord.sourceSignature === item.sourceSignature;
  if ((stateRecord.state === "dismissed" || stateRecord.state === "completed") && signatureMatches) {
    return {
      visible: false,
      bucket: stateRecord.state,
      item: {
        ...item,
        state: stateRecord.state as CreatorCampaignActionStateValue,
        snoozedUntil: stateRecord.snoozedUntil ? stateRecord.snoozedUntil.toISOString() : null,
      },
    };
  }

  return { visible: true, item };
}

export async function loadCreatorCampaignActionCenter(creatorUserId: string, campaignId?: string | null) {
  if (!db) throw new Error("Database unavailable");

  const raw = await loadCreatorCampaignActionCenterRaw(creatorUserId, campaignId);
  const actionKeys = raw.items.map((item) => item.actionKey);
  const stateRows = actionKeys.length
    ? await db
      .select()
      .from(creatorCampaignActionStates)
      .where(and(
        eq(creatorCampaignActionStates.userId, creatorUserId),
        inArray(creatorCampaignActionStates.actionKey, actionKeys),
      ))
    : [];

  const statesByActionKey = new Map(stateRows.map((row) => [row.actionKey, row]));
  const now = new Date();
  const visibleItems: CreatorCampaignActionCenterItem[] = [];
  const recentlyCompleted: Array<{ item: CreatorCampaignActionCenterItem; updatedAt: number }> = [];
  const hiddenSummary = {
    hiddenCount: 0,
    snoozedCount: 0,
    dismissedCount: 0,
    completedCount: 0,
  };

  for (const item of raw.items) {
    const resolved = resolveCreatorCampaignActionState(item, statesByActionKey.get(item.actionKey), now);
    if (resolved.visible) {
      visibleItems.push(resolved.item);
      continue;
    }
    hiddenSummary.hiddenCount += 1;
    if (resolved.bucket === "snoozed") hiddenSummary.snoozedCount += 1;
    if (resolved.bucket === "dismissed") hiddenSummary.dismissedCount += 1;
    if (resolved.bucket === "completed") {
      hiddenSummary.completedCount += 1;
      recentlyCompleted.push({
        item: resolved.item,
        updatedAt: statesByActionKey.get(item.actionKey)?.updatedAt?.getTime?.() ?? 0,
      });
    }
  }

  return {
    summary: summarizeCreatorCampaignActionCenter(visibleItems, hiddenSummary),
    items: visibleItems,
    recentlyCompleted: recentlyCompleted
      .sort((a, b) => b.updatedAt - a.updatedAt || a.item.campaignName.localeCompare(b.item.campaignName))
      .map((entry) => entry.item)
      .slice(0, campaignId ? 4 : 6),
    attributionNotes: [
      ...raw.attributionNotes,
      "Action tracking only affects surfacing. Dismissed, snoozed, and completed states reduce repeat noise without rewriting the underlying analytics or recommendation logic.",
    ],
    generatedAt: raw.generatedAt,
  };
}

